window.HADITH_CACHE["bukhari_4"] = {"2001":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنُهِيَ عَنْ لِبْسَتَيْنِ أَنْ يَحْتَبِيَ الرَّجُلُ فِي الثَّوْبِ الْوَاحِدِ ثُمَّ يَرْفَعَهُ عَلَى مَنْكِبِهِ وَعَنْ بَيْعَتَيْنِ اللِّمَاسِ وَالنِّبَاذِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Kami dilarang dari libsatain yaitu seseorang berselimut dengan orang lain dalam satu kain lalu mengangkat kain tersebut sampai pundaknya dan juga melarang mulamasah dan munabadzah\". "},"2002":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ وَعَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُلَامَسَةِ وَالْمُنَابَذَةِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Muhammad bin Yahya bin Habban] dan dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang mulamasah dan munabadzah\". "},"2003":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لِبْسَتَيْنِ وَعَنْ بَيْعَتَيْنِ الْمُلَامَسَةِ وَالْمُنَابَذَةِ","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid] telah menceritakan kepada kami ['Abdul A'la] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Atho' bin Yazid] dari [Abu Sa'id radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam melarang libsatain dan dua cara jual beli yaitu mulamasah dan munabadzah\". "},"2004":{"ar":"حَدَّثَنَا ابْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ الْأَعْرَجِ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُصَرُّوا الْإِبِلَ وَالْغَنَمَ فَمَنْ ابْتَاعَهَا بَعْدُ فَإِنَّهُ بِخَيْرِ النَّظَرَيْنِ بَعْدَ أَنْ يَحْتَلِبَهَا إِنْ شَاءَ أَمْسَكَ وَإِنْ شَاءَ رَدَّهَا وَصَاعَ تَمْرٍوَيُذْكَرُ عَنْ أَبِي صَالِحٍ وَمُجَاهِدٍ وَالْوَلِيدِ بْنِ رَبَاحٍ وَمُوسَى بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعَ تَمْرٍ وَقَالَ بَعْضُهُمْ عَنْ ابْنِ سِيرِينَ صَاعًا مِنْ طَعَامٍ وَهُوَ بِالْخِيَارِ ثَلَاثًا وَقَالَ بَعْضُهُمْ عَنْ ابْنِ سِيرِينَ صَاعًا مِنْ تَمْرٍ وَلَمْ يَذْكُرْ ثَلَاثًا وَالتَّمْرُ أَكْثَرُ","id":"Telah menceritakan kepada kami [Ibnu Bukair] telah menceritakan kepada kami [Al Laits] dari [Ja'far bin Rabi'ah] dari [Al A'raj] berkata, [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam: \"Janganlah kalian menahan susu unta dan kambing. Maka siapa yang telanjur telah membelinya maka dia punya hak pilih apakah akan tetap diambilnya atau dikembalikannya dengan menambah satu sha' kurma\". Dan disebutkan dari [Abu Shalih] dan [Mujahid] dan [Al Walid bin Rabah] dan [Musa bin Yasar] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam: Satu sha' kurma\". Dan [sebagian] mereka berkata, dari [Ibnu Sirin]: Satu sha' makanan dan dia punya hak pilih selama tiga hari\". Dan [sebagain] yang lain berkata, dari [Ibnu Sirin]: \"Satu sha' kurma\" dan tidak menyebut tiga hari dan riwayat yang menyebut kurma saja lebih banyak\". "},"2005":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي يَقُولُ حَدَّثَنَا أَبُو عُثْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَنْ اشْتَرَى شَاةً مُحَفَّلَةً فَرَدَّهَا فَلْيَرُدَّ مَعَهَا صَاعًا مِنْ تَمْرٍ وَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُلَقَّى الْبُيُوعُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mu'tamir] berkata, aku mendengar [Bapakku] berkata, telah menceritakan kepada kami [Abu 'Utsman] dari ['Abdullah bin Mas'ud radliallahu 'anhu] berkata: \"Siapa yang membeli kambing yang ditahan susunya lalu dia membatalkannya maka hendaklah dia mengembalikan kambing tersebut beserta satu sha' kurma\". Dan Nabi shallallahu 'alaihi wasallam melarang menyongsong dagangan (diluar pasar) \"."},"2006":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَلَقَّوْا الرُّكْبَانَ وَلَا يَبِعْ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ وَلَا تَنَاجَشُوا وَلَا يَبِعْ حَاضِرٌ لِبَادٍ وَلَا تُصَرُّوا الْغَنَمَ وَمَنْ ابْتَاعَهَا فَهُوَ بِخَيْرِ النَّظَرَيْنِ بَعْدَ أَنْ يَحْتَلِبَهَا إِنْ رَضِيَهَا أَمْسَكَهَا وَإِنْ سَخِطَهَا رَدَّهَا وَصَاعًا مِنْ تَمْرٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencegat rombongan dagang (sebelum sampai di pasar) dan jangan pula sebagian kalian membeli barang yang dibeli orang lain (sedang ditawar) dan janganlah melebihkan harga tawaran barang (yang sedang ditawar orang lain, dengan maksud menipu pembeli) dan janganlah orang kota membeli buat orang desa. Janganlah kalian menahan susu dari unta dan kambing (yang kurus dengan maksud menipu calon pembeli). Maka siapa yang membelinya setelah itu maka dia punya hak pilih, bila dia rela maka diambilnya dan bila dia tidak suka dikembalikannya dengan menambah satu sha' kurma\". "},"2007":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو حَدَّثَنَا الْمَكِّيُّ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي زِيَادٌ أَنَّ ثَابِتًا مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ زَيْدٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اشْتَرَى غَنَمًا مُصَرَّاةً فَاحْتَلَبَهَا فَإِنْ رَضِيَهَا أَمْسَكَهَا وَإِنْ سَخِطَهَا فَفِي حَلْبَتِهَا صَاعٌ مِنْ تَمْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amru] telah menceritakan kepada kami [Al Makkiy] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya [Ziyad] bahwa [Tsabit, sahaya 'Abdurrahman bin Zaid] mengabarkan kepadanya bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang membeli seekor kambing yang ditahan susunya maka jika ia rela dia boleh mengambilnya dan bila dia tidak suka dia kembalikan dengan menambah satu sha' kurma\"."},"2008":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ ��ُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ سَمِعَهُ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا زَنَتْ الْأَمَةُ فَتَبَيَّنَ زِنَاهَا فَلْيَجْلِدْهَا وَلَا يُثَرِّبْ ثُمَّ إِنْ زَنَتْ فَلْيَجْلِدْهَا وَلَا يُثَرِّبْ ثُمَّ إِنْ زَنَتْ الثَّالِثَةَ فَلْيَبِعْهَا وَلَوْ بِحَبْلٍ مِنْ شَعَرٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepada saya [Sa'id Al Maqbariy] dari [Bapaknya] dari [Abu Hurairah radliallahu 'anhu] bahwa dia mendengarnya berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang budak wanita berzina dan terbukti perzinahannya maka dia dihukum cambuk tanpa dicela dan dihinakan. Jika berzina lagi maka dihukum cambuk tanpa dicela dan dihinakan dan jika berzina lagi untuk ketiga kalinya maka juallah sekalipun dengan harga senilai sehelai rambut\"."},"2009":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْأَمَةِ إِذَا زَنَتْ وَلَمْ تُحْصِنْ قَالَ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَبِيعُوهَا وَلَوْ بِضَفِيرٍ قَالَ ابْنُ شِهَابٍ لَا أَدْرِي بَعْدَ الثَّالِثَةِ أَوْ الرَّابِعَةِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Ibnu Syihab] dari ['Ubaidullah] dari [Abu Hurairah] dan [Zaid bin Khalid] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam ditanya tentang seorang budak wanita bila berzina sedangkan dia belum menikah, maka Beliau bersabda: \"Jika dia berzina maka dihukum cambuk kemudian bila berzina lagi maka dijual sekalipun seharga seuntai rambut\". Ibnu Syihab berkata: \"Aku tidak tahu apakah dia dijual setelah tiga kali atau empat kali berzina\"."},"2010":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ عُرْوَةُ بْنُ الزُّبَيْرِ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَادَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرِي وَأَعْتِقِي فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ ثُمَّ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْعَشِيِّ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ مَا بَالُ أُنَاسٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَ فِي كِتَابِ اللَّهِ مَنْ اشْتَرَطَ شَرْطًا لَيْسَ فِي كِتَابِ اللَّهِ فَهُوَ بَاطِلٌ وَإِنْ اشْتَرَطَ مِائَةَ شَرْطٍ شَرْطُ اللَّهِ أَحَقُّ وَأَوْثَقُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy], berkata, ['Urwah bin Az Zubair] telah berkata, ['Aisyah radliallahu 'anha]: \"Rasulullah shallallahu 'alaihi wasallam datang menemuiku lalu aku ceritakan bahwa aku telah membeli budak, hanya keluarganya mensyaratkan bahwa wala\" tetap milik mereka. Kontan Rasulullah shallallahu 'alaihi wasallam bersabda \"Belilah, dan merdekakanlah, dan hak wala\" bagi yang memerdekakannya.\" Kemudian Nabi shallallahu 'alaihi wasallam berdiri menegakkan ibadah malam hari lalu memuji Allah sebagaimana menjadi hakNya kemudian berkata: \"Bagaimana bisa orang-orang membuat syarat-syarat yang tidak ada dalam Kitab Allah. Siapa yang membuat syarat yang tidak ada pada Ktab Allah maka merupakan syarat yang batal sekalipun dia membuat seratus syarat. Karena syarat yang dibuat Allah lebih hak dan lebih kokoh\". "},"2011":{"ar":"حَدَّثَنَا حَسَّانُ بْنُ أَبِي عَبَّادٍ حَدَّثَنَا هَمَّامٌ قَالَ سَمِعْتُ نَافِعًا يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا سَاوَمَتْ بَرِيرَةَ فَخَرَجَ إِلَى الصَّلَاةِ فَلَمَّا جَاءَ قَالَتْ إِنَّهُمْ أَبَوْا أَنْ يَبِيعُوهَا إِلَّا أَنْ يَشْتَرِطُوا الْوَلَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ قُلْتُ لِنَافِعٍ حُرًّا كَانَ زَوْجُهَا أَوْ عَبْدًا فَقَالَ مَا يُدْرِينِي","id":"Telah menceritakan kepada kami [Hassan bin 'Abbad] telah menceritakan kepada kami [Hammam] berkata, aku mendengar [Nafi'] menceritakan dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa 'Aisyah radliallahu 'anha menawar Barirah lalu Beliau shallallahu 'alaihi wasallam keluar untuk menunaikan shalat. Setelah Beliau datang, 'Aisyah radliallahu 'anha berkata: \"Mereka enggan untuk menjualnya kecuali meminta syarat wala' tetap milik mereka\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya wala\" (untuk budak) bagi siapa yang membebaskannya\". Aku bertanya kepada Nafi': \"Apakah suaminya orang merdeka atau budak?\" Dia menjawab: \"Aku tidak diberitahu\". "},"2012":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ سَمِعْتُ جَرِيرًا رَضِيَ اللَّهُ عَنْهُ يَقُولُبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالسَّمْعِ وَالطَّاعَةِ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari [Isma'il] dari [Qais] aku mendengar [Jarir radliallahu 'anhu] berkata: \"Aku berbai'at kepada Rasulullah shallallahu 'alaihi wasallam untuk bersyahadah Laa ilaaha illallah wa anna Muhammadar rasulullah, menegakkan shalat, menunaikan zakat, mendengar dan tho'at serta setia kepada setiap muslim\"."},"2013":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا مَعْمَرٌ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلَقَّوْا الرُّكْبَانَ وَلَا يَبِعْ حَاضِرٌ لِبَادٍ قَالَ فَقُلْتُ لِابْنِ عَبَّاسٍ مَا قَوْلُهُ لَا يَبِيعُ حَاضِرٌ لِبَادٍ قَالَ لَا يَكُونُ لَهُ سِمْسَارًا","id":"Telah menceritakan kepada kami [Ash-Shaltu bin Muhammad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Ma'mar] dari ['Abdullah bin Thawus] dari [Bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian songsong (cegat) kafilah dagang (sebelum mereka sampai di pasar) dan janganlah orang kota menjual kepada orang desa\". Aku bertanya kepada Ibnu 'Abbas radliallahu 'anhuma: \"Apa arti sabda Beliau; \"dan janganlah orang kota menjual untuk orang desa\". Dia menjawab: \"Janganlah seseorang jadi perantara (broker, calo) bagi orang kota\"."},"2014":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ صَبَّاحٍ حَدَّثَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ دِينَارٍ قَالَ حَدَّثَنِي أَبِي عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعَ حَاضِرٌ لِبَادٍ وَبِهِ قَالَ ابْنُ عَبَّاسٍ","id":"Telah menceritakan kepada saya ['Abdullah bin Shabbah] telah menceritakan kepada kami [Abu 'Ali Al Hanafiy] dari ['Abdurrahman bin 'Abdullah bin Dinar] berkata, telah menceritakan kepadaku [Bapakku] dari ['Abdullah bin 'Umar radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam melarang orang kota menjual untuk orang desa\": Hadits ini telah dikomentari oleh Ibnu 'Abbas radliallahu 'anhuma."},"2015":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبْتَاعُ الْمَرْءُ عَلَى بَيْعِ أَخِيهِ وَلَا تَنَاجَشُوا وَلَا يَبِعْ حَاضِرٌ لِبَادٍ","id":"Telah menceritakan kepada kami [Al Makkiy bin Ibrahim] berkata, telah mengabarkan kepada saya [Ibnu Juraij] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang membeli apa yang sedang dibeli saudaranya dan janganlah kalian melebihkan harga tawaran barang (yang sedang ditawar orang lain) dan janganlah orang kota menjual buat orang desa\". "},"2016":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذٌ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ قَالَ أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُنُهِينَا أَنْ يَبِيعَ حَاضِرٌ لِبَادٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Mu'adz] telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] bahwa [Anas bin Malik radliallahu 'anhu] berkata; \"Kami dilarang bila orang orang kota menjual kepada orang desa\". "},"2017":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا عُبَيْدُ اللَّهِ الْعُمَرِيُّ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّلَقِّي وَأَنْ يَبِيعَ حَاضِرٌ لِبَادٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami ['Ubaidullah Al 'Umariy] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam melarang menyongsong (mencegat kafilah dagang sebelum sampai di pasar) dan juga melarang orang orang kota menjual kepada orang desa."},"2018":{"ar":"حَدَّثَنِي عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَامَا مَعْنَى قَوْلِهِ لَا يَبِيعَنَّ حَاضِرٌ لِبَادٍ فَقَالَ لَا يَكُنْ لَهُ سِمْسَارًا","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid] telah menceritakan kepada kami ['Abdul A'laa] telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [Bapaknya] berkata; Aku bertanya kepada [Ibnu 'Abbas radliallahu 'anhuma]; \"Apa arti sabda Beliau \"Janganlah sekali-kali orang kota menjual kepada orang desa\". Dia menjawab: \"Janganlah seseorang jadi perantara (broker, calo) bagi orang kota\"."},"2019":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنِي التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَمَنْ اشْتَرَى مُحَفَّلَةً فَلْيَرُدَّ مَعَهَا صَاعًا قَالَ وَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ تَلَقِّي الْبُيُوعِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada saya [At-Taimiy] dari [Abu 'Utsman] dari ['Abdullah radliallahu 'anhu] berkata: \"Siapa yang membeli kambing yang ditahan susunya lalu dia membatalkannya maka hendaklah dia mengembalikan kambing tersebut beserta satu sha' kurma\". Dan Nabi shallallahu 'alaihi wasallam melarang menyongsong dagangan (diluar pasar) \"."},"2020":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ وَلَا تَلَقَّوْا السِّلَعَ حَتَّى يُهْبَطَ بِهَا إِلَى السُّوقِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sebagian kalian menjual diatas jualan sebagian yang lain dan janganlah pula kalian menyongsong dagangan hingga dagangan itu sampai di pasar-pasar\". "},"2021":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نَتَلَقَّى الرُّكْبَانَ فَنَشْتَرِي مِنْهُمْ الطَّعَامَ فَنَهَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَبِيعَ��ُ حَتَّى يُبْلَغَ بِهِ سُوقُ الطَّعَامِقَالَ أَبُو عَبْد اللَّهِ هَذَا فِي أَعْلَى السُّوقِ يُبَيِّنُهُ حَدِيثُ عُبَيْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] berkata, dari [Nafi'] dari ['Abdullah radliallahu 'anhu] berkata: \"Kami dahulu biasa menyongsong kafilah dagang lalu kami membeli makanan. Maka kemudian Nabi shallallahu 'alaihi wasallam melarang kami membelinya hingga makanan tersebut sampai di pasar makanan\". Berkata, Abu 'Abdullah Al Bukhariy: \"Ini larangan untuk transaksi diluar pasar sebagaimana dijelaskan oleh hadits 'Ubaidullah\". "},"2022":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانُوا يَبْتَاعُونَ الطَّعَامَ فِي أَعْلَى السُّوقِ فَيَبِيعُونَهُ فِي مَكَانِهِ فَنَهَاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعُوهُ فِي مَكَانِهِ حَتَّى يَنْقُلُوهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari ['Abdullah radliallahu 'anhu] berkata: \"Dahulu mereka berjual beli makanan jauh di luar pasar lalu menjualnya di tempat itu pula, maka Rasulullah shallallahu 'alaihi wasallam melarang menjual makanan di tempat (pembeliannya) hingga makanan itu dipindahkan lebih dahulu\"."},"2023":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْجَاءَتْنِي بَرِيرَةُ فَقَالَتْ كَاتَبْتُ أَهْلِي عَلَى تِسْعِ أَوَاقٍ فِي كُلِّ عَامٍ وَقِيَّةٌ فَأَعِينِينِي فَقُلْتُ إِنْ أَحَبَّ أَهْلُكِ أَنْ أَعُدَّهَا لَهُمْ وَيَكُونَ وَلَاؤُكِ لِي فَعَلْتُ فَذَهَبَتْ بَرِيرَةُ إِلَى أَهْلِهَا فَقَالَتْ لَهُمْ فَأَبَوْا ذَلِكَ عَلَيْهَا فَجَاءَتْ مِنْ عِنْدِهِمْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فَقَالَتْ إِنِّي قَدْ عَرَضْتُ ذَلِكَ عَلَيْهِمْ فَأَبَوْا إِلَّا أَنْ يَكُونَ الْوَلَاءُ لَهُمْ فَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَتْ عَائِشَةُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ خُذِيهَا وَاشْتَرِطِي لَهُمْ الْوَلَاءَ فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ فَفَعَلَتْ عَائِشَةُ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ مَا بَالُ رِجَالٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ مَا كَانَ مِنْ شَرْطٍ لَيْسَ فِي كِتَابِ اللَّهِ فَهُوَ بَاطِلٌ وَإِنْ كَانَ مِائَةَ شَرْطٍ قَضَاءُ اللَّهِ أَحَقُّ وَشَرْطُ اللَّهِ أَوْثَقُ وَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] berkata: \"Bahwa Barirah datang kepadaku seraya berkata: \"Tuanku telah menetapkan (tebusan untuk pembebasanku) sebanyak sembilan waq yang setiap tahunnya wajib kubayar satu waq, maka tolonglah aku\". Aku berkata: \"Jika tuanmu suka, aku akan bayar ketetapan tersebut kepada mereka dan perwalianmu ada padaku. Lalu aku penuhi. Kemudian Barirah datang kepada para sahabat sementara Rasulullah shallallahu 'alaihi wasallam sedang duduk, lalu dia berkata: \"Sungguh aku sudah menawarkan hal itu kepada mereka namun mereka enggan menerimanya kecuali bila perwalian tetap menjadi hak mereka\". Nabi shallallahu 'alaihi wasallam mendengar hal ini lalu 'Aisyah radliallahu 'anha mengabarkan kepada Nabi shallallahu 'alaihi wasallam, maka Beliau berkata: \"Ambillah dia (Barirah) dan berikan syarat perwalian kepada tuannya bahwa perwalian seorang budak adalah bagi yang memerdekakannya\". Maka 'Aisyah radliallahu 'anha melaksanakan perintah Beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri di hadapan manusia lalu memuji Allah dan mengagungkan-Nya kemudian bersabda: \"Bagaimana jadinya suatu kaum, mereka membuat persyaratan dengan syarat-syarat yang tidak ada pada Kitabulloh. Apapun bentuknya syarat yang tidak sesuai dengan Kitab Allah maka syarat itu batal sekalipun seratus kali persyaratan. Ketetapan Allah lebih berhaq (untuk ditunaikan) dan syarat (yang ditetapkan) Allah lebih kokoh. Sesungguhnya perwalian (seorang budak) adalah untuk yang memerdekakannya\"."},"2024":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ أَرَادَتْ أَنْ تَشْتَرِيَ جَارِيَةً فَتُعْتِقَهَا فَقَالَ أَهْلُهَا نَبِيعُكِهَا عَلَى أَنَّ وَلَاءَهَا لَنَا فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا يَمْنَعُكِ ذَلِكَ فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa 'Aisyah, Ummul Mu'minin radliallahu 'anha berkehendak untuk membeli seorang budak wanita lalu dibebaskannya. Tuannya berkata: \"Kami jual kepada anda namun perwaliannya tetap menjadi hak kami. Kemudian kejadian ini diceritakan kepada Rasulullah shallallahu 'alaihi wasallam. Maka Beliau bersabda: \"Janganlah menghalangi kamu persyaratan mereka itu, karena sesungguhnya perwalian (seorang budak) adalah untuk yang memerdekakannya\". "},"2025":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسٍ سَمِعَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبُرُّ بِالْبُرِّ رِبًا إِلَّا هَاءَ وَهَاءَ وَالشَّعِيرُ بِالشَّعِيرِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالتَّمْرُ بِالتَّمْرِ رِبًا إِلَّا هَاءَ وَهَاءَ","id":"Telah menceritakan kepada saya [Abu Al Walid] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Malik bin Aus] bahwa dia mendengar ['Umar radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jual beli beras dengan beras adalah riba' kecuali begini-begini (kontan, cash), gandum dengan gandum adalah riba' kecuali begini-begini (kontan, cash), kurma dengan kurma adalah riba' kecuali begini-begini (kontan, cash) \". "},"2026":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَابَنَةِ وَالْمُزَابَنَةُ بَيْعُ الثَّمَرِ بِالتَّمْرِ كَيْلًا وَبَيْعُ الزَّبِيبِ بِالْكَرْمِ كَيْلًا","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang Al Muzaabanah. Al Muzaabanah adalah menjual kurma matang dengan kurma mentah yang ditimbang dan menjual anggur kering dengan anggur basah yang ditimbang."},"2027":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَابَنَةِ قَالَ وَالْمُزَابَنَةُ أَنْ يَبِيعَ الثَّمَرَ بِكَيْلٍ إِنْ زَادَ فَلِي وَإِنْ نَقَصَ فَعَلَيَّ قَالَ وَحَدَّثَنِي زَيْدُ بْنُ ثَابِتٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْعَرَايَا بِخَرْصِهَا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam melarang Al Muzaabanah. Dia berkata: \"Al Muzaabanah adalah seseorang menjual buah dengan takaran, jika lebih maka berarti keuntunganku dan bila kurang berarti resikoku\". Dia berkata; Dan telah menceritakan kepada saya [Zaid bin Tsabit] bahwa Nabi shallallahu 'alaihi wasallam memberi kelonggaran pada 'ariyah dengan taksiran\". ('Ariyah jama'nya 'aroya adalah menjual kurma yang masih dalam tangkainya di kebun dengan taksiran sehingga ketika berlalu waktu menjadi banyak, pent)."},"2028":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسٍ أَخْبَرَهُ أَنَّهُ الْتَمَسَ صَرْفًا بِمِائَةِ دِينَارٍ فَدَعَانِي طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ فَتَرَاوَضْنَا حَتَّى اصْطَرَفَ مِنِّي فَأَخَذَ الذَّهَبَ يُقَلِّبُهَا فِي يَدِهِ ثُمَّ قَالَ حَتَّى يَأْتِيَ خَازِنِي مِنْ الْغَابَةِ وَعُمَرُ يَسْمَعُ ذَلِكَ فَقَالَ وَاللَّهِ لَا تُفَارِقُهُ حَتَّى تَأْخُذَ مِنْهُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الذَّهَبُ بِالذَّهَبِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالْبُرُّ بِالْبُرِّ رِبًا إِلَّا هَاءَ وَهَاءَ وَالشَّعِيرُ بِالشَّعِيرِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالتَّمْرُ بِالتَّمْرِ رِبًا إِلَّا هَاءَ وَهَاءَ","id":"Telah menceritakan kepada saya ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Malik bin Aus] mengabarkan kepadanya bahwa dia mencari sharf (barang dagangan) yang akan dibelinya dengan seratus dirham. Maka Tholhah bin 'Ubaidullah memanggilku lalu kami saling mengemukakan harga dia membeli dariku lalu dia mengambil emas sebagai ganti pembayarannya seraya berkata: \"Hingga tukang gudang kami datang dari hutan\". ['Umar] mendengar perkataan itu lalu berkata: \"Demi Allah, janganlah kamu meninggalkan dia hingga kamu ambil bayaran darinya karena Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jual beli emas dengan emas adalah riba' kecuali begini-begini (kontan, cash), beras dengan beras adalah riba' kecuali begini-begini (kontan, cash), gandum dengan gandum adalah riba' kecuali begini-begini (kontan, cash) dan kurma dengan kurma adalah riba' kecuali begini-begini (kontan, cash).\""},"2029":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ عُلَيَّةَ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي إِسْحَاقَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرَةَ قَالَ قَالَ أَبُو بَكْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَبِيعُوا الذَّهَبَ بِالذَّهَبِ إِلَّا سَوَاءً بِسَوَاءٍ وَالْفِضَّةَ بِالْفِضَّةِ إِلَّا سَوَاءً بِسَوَاءٍ وَبِيعُوا الذَّهَبَ بِالْفِضَّةِ وَالْفِضَّةَ بِالذَّهَبِ كَيْفَ شِئْتُمْ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadhal] telah mengabarkan kepada kami [Isma'il bin 'Ulayyah] berkata, telah menceritakan kepada saya [Yahya bin Abu Ishaq] telah menceritakan kepada kami ['Abdurrahman bin Abu Bakrah] berkata, [Abu Bakrah radliallahu 'anhu] berkata; Telah bersabda Rasulullah shallallahu 'alaihi wasallam: \"Janganlah kalian berjual beli emas dengan emas kecuali dengan jumlah yang sama, perak dengan perak kecuali dengan jumlah yang sama dan berjual belilah emas dengan perak atau perak dengan emas sesuai keinginan kalian\"."},"2030":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ حَدَّثَنَا عَمِّي حَدَّثَنَا ابْنُ أَخِي الزُّهْرِيِّ عَنْ عَمِّهِ قَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ حَدَّثَهُ مِثْلَ ذَلِكَ حَدِيثًاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَقِيَهُ عَبْدُ اللَّهِ بْنُ عُمَرَ فَقَالَ يَا أَبَا سَعِيدٍ مَا هَذَا الَّذِي تُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو سَعِيدٍ فِي الصَّرْفِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الذَّهَبُ بِالذَّهَبِ مِثْلًا بِمِثْلٍ وَالْوَرِقُ بِالْوَرِقِ مِثْلًا بِمِثْلٍ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'ad] telah menceritakan kepada kami [pamanku] telah menceritakan kepada saya [anak saudaraku Az Zuhriy] dari [pamannya] berkata, telah menceritakan kepada saya [Salim bin 'Abdullah] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa [Abu Sa'id Al Khudriy] menceritakan kepadanya seperti hadits tersebut dari Rasulullah shallallahu 'alaihi wasallam. Maka 'Abdullah bin 'Umar radliallahu 'anhuma menemuinya lalu berkata: \"Wahai Abu Sa'id, apa yang telah anda ceritakan dari hadits dari Rasulullah shallallahu 'alaihi wasallam?. Maka Abu Sa'id berkata: \"Tentang sharf (dagangan), aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jual beli emas dengan emas harus sama jumlahnya dan uang kertas dengan uang kertas harus sama pula jumlahnya\". "},"2031":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبِيعُوا الذَّهَبَ بِالذَّهَبِ إِلَّا مِثْلًا بِمِثْلٍ وَلَا تُشِفُّوا بَعْضَهَا عَلَى بَعْضٍ وَلَا تَبِيعُوا الْوَرِقَ بِالْوَرِقِ إِلَّا مِثْلًا بِمِثْلٍ وَلَا تُشِفُّوا بَعْضَهَا عَلَى بَعْضٍ وَلَا تَبِيعُوا مِنْهَا غَائِبًا بِنَاجِزٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Abu Sa'id Al Khudriy] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berjual beli emas dengan emas kecuali sama jumlahnya dan jangan kalian lebihkan yang satu atas lainnya dan janganlah kalian berjual beli uang kertas dengan uang kertas kecuali sama jumlahnya dan jangan kalian lebihkan yang satu atas lainnya dan janganlah kalian berjual beli yang disegerakan (hadir) dengan yang diakhirkan (ghoib, ditangguhkan) \"."},"2032":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّ أَبَا صَالِحٍ الزَّيَّاتَ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُيَقُولُ الدِّينَارُ بِالدِّينَارِ وَالدِّرْهَمُ بِالدِّرْهَمِفَقُلْتُ لَهُ فَإِنَّ ابْنَ عَبَّاسٍ لَا يَقُولُهُ فَقَالَ أَبُو سَعِيدٍ سَأَلْتُهُ فَقُلْتُ سَمِعْتَهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ وَجَدْتَهُ فِي كِتَابِ اللَّهِ قَالَ كُلَّ ذَلِكَ لَا أَقُولُ وَأَنْتُمْ أَعْلَمُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنِّي وَلَكِنْ أَخْبَرَنِي أُسَامَةُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا رِبًا إِلَّا فِي النَّسِيئَةِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Adh Dhahhak bin Makhlad] telah menceritakan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Amru bin Dinar] bahwa [Abu Shalih Az Zayyat] mengabarkan kelpadanya bahwa dia mendengar [Abu Sa'id Al Khudriy radliallahu 'anhu] berkata: \"Dinar dengan dinar dan dirham dengan dirham\". Aku berkata kepadanya bahwa [Ibnu 'Abbas radliallahu 'anhuma] tidak mengatakan seperti itu. Maka Abu Sa'id berkata: \"Aku pernah bertanya kepadanya dimana aku katakan apakah kamu mendengarnya dari Nabi shallallahu 'alaihi wasallam atau kamu mendapatkan keterangannya dari Kitab Allah?. Maka dia menjawab: \"Semuanya itu aku tidak pernah mengatakannya. Dan kalian lebih mengetahui Rasulullah shallallahu 'alaihi wasallam daripada aku namun [Usamah] mengabarkan kepadaku bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Tidak ada riba, kecuali riba' nasi'ah\" (riba dalam urusan pinjam meminjam dengan ada tambahan)."},"2033":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي حَبِيبُ بْنُ أَبِي ثَابِتٍ قَالَ سَمِعْتُ أَبَا الْمِنْهَالِ قَالَ سَأَلْتُ الْبَرَاءَ بْنَ عَازِبٍ وَزَيْدَ بْنَ أَرْقَمَ رَضِيَ اللَّهُ عَنْهُمْعَنْ الصَّرْفِ فَكُلُّ وَاحِدٍ مِنْهُمَا يَقُولُ هَذَا خَيْرٌ مِنِّي فَكِلَاهُمَا يَقُولُ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الذَّهَبِ بِالْوَرِقِ دَيْنًا","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada saya [Habib bin Abu Tsabit] berkata, aku mendengar [Abu Al Minhal] berkata; AKu bertanya kepada [Al Bara' bin 'Azib] dan [Zaid bin Arqam radliallahu 'anhum] tentang sharf (jual beli emas dengan dirham atau sebaliknya). Masing-masing dari keduanya berkata: \"Ini baik menurutku dan keduanya berkata: \"Rasulullah shallallahu 'alaihi wasallam telah melarang jual beli emas dengan uang kertas sebagai hutang\"."},"2034":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ أَخْبَرَنَا يَحْيَى بْنُ أَبِي إِسْحَاقَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرَةَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْفِضَّةِ بِالْفِضَّةِ وَالذَّهَبِ بِالذَّهَبِ إِلَّا سَوَاءً بِسَوَاءٍ وَأَمَرَنَا أَنْ نَبْتَاعَ الذَّهَبَ بِالْفِضَّةِ كَيْفَ شِئْنَا وَالْفِضَّةَ بِالذَّهَبِ كَيْفَ شِئْنَا","id":"Telah menceritakan kepada kami ['Imran bin Maisarah] telah menceritakan kepada kami ['Abbad bin Al 'Awwam] telah mengabarkan kepada kami [Yahya bin Abu Ishaq] telah menceritakan kepada kami ['Abdurrahman bin Abu Bakrah] dari [Bapaknya radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam melarang jual beli perak dengan perak dan emas dengan emas kecuali dengan jumlah yang sama, dan memerintahkan kami untuk berjual beli emas dengan perak terserah bagaimana keinginan kami dan perak dengan emas terserah bagaimana keinginan kami\"."},"2035":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبِيعُوا الثَّمَرَ حَتَّى يَبْدُوَ صَلَاحُهُ وَلَا تَبِيعُوا الثَّمَرَ بِالتَّمْرِقَالَ سَالِمٌ وَأَخْبَرَنِي عَبْدُ اللَّهِ عَنْ زَيْدِ بْنِ ثَابِتٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ بَعْدَ ذَلِكَ فِي بَيْعِ الْعَرِيَّةِ بِالرُّطَبِ أَوْ بِالتَّمْرِ وَلَمْ يُرَخِّصْ فِي غَيْرِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepada saya [Salim bin 'Abdullah] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjual kurma kecuali setelah jelas bagusnya dan janganlah kalian berjual beli kurma matang dengan kurma basah \". [Salim] berkata, dan telah mengabarkan kepada saya ['Abdullah] dari [Zaid bin Tsabit] bahwa Rasulullah shallallahu 'alaihi wasallam telah memberi kelonggaran dalam jual beli 'ariyyah yaitu kurma muda dengan kurma matang dan tidak memberi kelonggaran pada selainnya\"."},"2036":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَابَنَةِ وَالْمُزَابَنَةُ اشْتِرَاءُ الثَّمَرِ بِالتَّمْرِ كَيْلًا وَبَيْعُ الْكَرْمِ بِالزَّبِيبِ كَيْلًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang Al Muzaabanah. Al Muzaabanah adalah menjual kurma masak dengan kurma basah dengan timbangan tertentu dan menjual anggur kering dengan anggur basah dengan timbangan tertentu."},"2037":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ أَبِي سُفْيَانَ مَوْلَى ابْنِ أَبِي أَحْمَدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَابَنَةِ وَالْمُحَاقَلَةِ وَالْمُزَابَنَةُ اشْتِرَاءُ الثَّمَرِ بِالتَّمْرِ فِي رُءُوسِ النَّخْلِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Daud bin Al Hushain] dari [Abu Sufyan, sahaya Ibnu Abu Ahmad] dari [Abu Sa'id AL Khudriy] bahwa Rasulullah shallallahu 'alaihi wasallam melarang Al Muzaabanah dan AL Muhaqalah. Al Muzaabanah adalah membeli kurma masak dengan kurma basah yang masih berada di pohon\". "},"2038":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الشَّيْبَانِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُزَابَنَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Asy-Syaibaniy] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; \"Nabi shallallahu 'alaihi wasallam melarang Al Muhaqalah (jual beli buah yang masih ditangkai dengan gandum) dan Al Muzabanah (jual beli kurma yang masih dipohon dengan kurma yang sudah dipetik)."},"2039":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْخَصَ لِصَاحِبِ الْعَرِيَّةِ أَنْ يَبِيعَهَا بِخَرْصِهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar] dari [Zaid bin Tsabit radliallahu 'anhum] bahwa Rasulullah shallallahu 'alaihi wasallam memberi kelonggaran bagi pemilik 'Ariyyah untuk menjualnya dengan taksiran\". "},"2040":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ وَأَبِي الزُّبَيْرِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الثَّمَرِ حَتَّى يَطِيبَ وَلَا يُبَاعُ شَيْءٌ مِنْهُ إِلَّا بِالدِّينَارِ وَالدِّرْهَمِ إِلَّا الْعَرَايَا","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepada kami [Ibnu Wahab] telah mengabarkan kepada kami [Ibnu Juraij] dari ['Atho'] dan [Abu Az Zubair] dari [Jabir radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam melarang menjual buah (dari pohon) kecuali telah nampak baiknya dan tidak boleh dijual sesuatupun darinya kecuali dengan dinar dan dirham kecuali 'ariyyah\"."},"2041":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ قَالَ سَمِعْتُ مَالِكًا وَسَأَلَهُ عُبَيْدُ اللَّهِ بْنُ الرَّبِيعِ أَحَدَّثَكَ دَاوُدُ عَنْ أَبِي سُفْيَانَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي بَيْعِ الْعَرَايَا فِي خَمْسَةِ أَوْسُقٍ أَوْ دُونَ خَمْسَةِ أَوْسُقٍ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] berkata, aku mendengar [Malik] ketika ditanya oleh 'Ubaidullah bin Ar-Rabi'; \"Apakah [Daud] menceritakan kepadamu dari [Abu Sufyan] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam memberi kelonggaran dalam jual beli 'ariyyah dengan (menambah) lima wasaq atau lebih kecil dari lima wasaq?. Dia berkata: \"Ya, benar\"."},"2042":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ قَالَ يَحْيَى بْنُ سَعِيدٍ سَمِعْتُ بُشَيْرًا قَالَ سَمِعْتُ سَهْلَ بْنَ أَبِي حَثْمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثَّمَرِ بِالتَّمْرِ وَرَخَّصَ فِي الْعَرِيَّةِ أَنْ تُبَاعَ بِخَرْصِهَا يَأْكُلُهَا أَهْلُهَا رُطَبًا وَقَالَ سُفْيَانُ مَرَّةً أُخْرَى إِلَّا أَنَّهُ رَخَّصَ فِي الْعَرِيَّةِ يَبِيعُهَا أَهْلُهَا بِخَرْصِهَا يَأْكُلُونَهَا رُطَبًا قَالَ هُوَ سَوَاءٌ قَالَ سُفْيَانُ فَقُلْتُ لِيَحْيَى وَأَنَا غُلَامٌ إِنَّ أَهْلَ مَكَّةَ يَقُولُونَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي بَيْعِ الْعَرَايَا فَقَالَ وَمَا يُدْرِي أَهْلَ مَكَّةَ قُلْتُ إِنَّهُمْ يَرْوُونَهُ عَنْ جَابِرٍ فَسَكَتَ قَالَ سُفْيَانُ إِنَّمَا أَرَدْتُ أَنَّ جَابِرًا مِنْ أَهْلِ الْمَدِينَةِ قِيلَ لِسُفْيَانَ وَلَيْسَ فِيهِ نَهَى عَنْ بَيْعِ الثَّمَرِ حَتَّى يَبْدُوَ صَلَاحُهُ قَالَ لَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata,, berkata, [Yahya bin Sa'id]; aku mendengar [Busyair] berkata; aku mendengar [Sahal bin Abi Hatmah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang menjual kurma masak dengan kurma basah, damun Beliau memberi kelonggaran pada 'ariyyah untuk dijual dengan cara taksiran untuk dimakan ruthobnya (kurma basah yang masih muda) oleh pemilikya. Dan Sufyan berkata pada suatu kali; selain Beliau memberi keringanan pada 'ariyah, yang pemiliknya menjualnya dengan cara ditaksir, yang mereka boleh memakan ruthob. Ia berkata, itu sama saja. Sufyan berkata; lalu aku berkata kepada Yahya dan ketika itu aku masih remaja, sungguh orang-orang Makkah mengatakan bahwa Nabi shallallahu 'alaihi wasallam membolehkan menjual 'ariyah. Ia berkata; apa yang dimaksud penduduk Makkah? Aku menjawab; mereka meriwayatkannya dari Jabir, lalu ia terdiam. Sufyan berkata, hanyasanya yang aku maksud bahwa Jabir itu adalah orang Madinah. Lalu dikatakan kepada Sufyan; Apakah tidak ada larangan untuk menjual buah-buahan hingga benar-benar baik keadaannya? Ia menjawab: tidak."},"2043":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الْعَرَايَا أَنْ تُبَاعَ بِخَرْصِهَا كَيْلًاقَالَ مُوسَى بْنُ عُقْبَةَ وَالْعَرَايَا نَخَلَاتٌ مَعْلُومَاتٌ تَأْتِيهَا فَتَشْتَرِيهَا","id":"Telah menceritakan kepada kami [Muhammad] dia adalah anak dari Muqatil telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu 'Umar] dari [Zaid bin Tsabit] radliallahu 'anhum bahwa Rasulullah shallallahu 'alaihi wasallam telah memberi keringanan pada 'ariyah yang dijual dengan cara taksiran timbangan (berat). Berkata, Musa bin 'Uqbah: \"Dan yang dimaksud jual beli 'ariyyah adalah kurma-kurma yang sudah dikenal lalu kamu datang untuk membelinya\"."},"2044":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثِّمَارِ حَتَّى يَبْدُوَ صَلَاحُهَا نَهَى الْبَائِعَ وَالْمُبْتَاعَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang jual beli buah-buahan hingga sampai buah itu telah nampak jadinya. Beliau melarang untuk penjual dan pembeli."},"2045":{"ar":"حَدَّثَنَا ابْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ تُبَاعَ ثَمَرَةُ النَّخْلِ حَتَّى تَزْهُوَقَالَ أَبُو عَبْد اللَّهِ يَعْنِي حَتَّى تَحْمَرَّ","id":"Telah menceritakan kepada kami [Ibnu Muqatil] telah menceritakan kepada kami ['Abdullah] telah mengabarkan kepada kami [Humaid Ath-Thowil] dari [Anas radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang menjual buah kurma hingga telah sempurna. Berkata, Abu 'Abdullah: \"Maksudnya hingga nampak merah\"."},"2046":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَلِيمِ بْنِ حَيَّانَ حَدَّثَنَا سَعِيدُ بْنُ مِينَا قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُبَاعَ الثَّمَرَةُ حَتَّى تُشَقِّحَ فَقِيلَ وَمَا تُشَقِّحُ قَالَ تَحْمَارُّ وَتَصْفَارُّ وَيُؤْكَلُ مِنْهَا","id":"Telah menceritakan kepada kami [Musaddaad] telah menceritakan kepada kami [Yahya bin Yusuf] dari [Salim bin Hayyan] telah menceritakan kepada kami [Sa'id bin Mina]; Aku mendengar [Jabir bin 'Abdullah radliallahu 'anhu] berkata: Nabi shallallahu 'alaihi wasallam telah melarang menjual buah-buahan hingga 'tusyaqqah' alias sempurna. Ditanyakan apa ang dimaksud dengan 'tusyaqqah'. Dia menjawab: \"Jadi kemerahan dan kekuningan sehingga dapat dimakan\"."},"2047":{"ar":"حَدَّثَنِي عَلِيُّ بْنُ الْهَيْثَمِ حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ الرَّازِيُّ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ نَهَى عَنْ بَيْعِ الثَّمَرَةِ حَتَّى يَبْدُوَ صَلَاحُهَا وَعَنْ النَّخْلِ حَتَّى يَزْهُوَ قِيلَ وَمَا يَزْهُو قَالَ يَحْمَارُّ أَوْ يَصْفَارُّ","id":"Telah menceritakan kepadaku ['Ali bin Al Haitsam] telah menceritakan kepada kami [Mu'allaa bin Manshur Ar-Raziy] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid] telah menceritakan kepada kami [Anas bin Malik radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bahwa Beliau melarang menjual buah-buahan hingga jelas kebaikan dan (melarang pula menjual) kurma hinga sempurna. Ada yang bertanya; \"Apa tanda sempurnanya?\" Beliau menjawab: \"Ia menjadi merah atau kuning\". "},"2048":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الثِّمَارِ حَتَّى تُزْهِيَ فَقِيلَ لَهُ وَمَا تُزْهِي قَالَ حَتَّى تَحْمَرَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ إِذَا مَنَعَ اللَّهُ الثَّمَرَةَ بِمَ يَأْخُذُ أَحَدُكُمْ مَالَ أَخِيهِقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ لَوْ أَنَّ رَجُلًا ابْتَاعَ ثَمَرًا قَبْلَ أَنْ يَبْدُوَ صَلَاحُهُ ثُمَّ أَصَابَتْهُ عَاهَةٌ كَانَ مَا أَصَابَهُ عَلَى رَبِّهِ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتَبَايَعُوا الثَّمَرَ حَتَّى يَبْدُوَ صَلَاحُهَا وَلَا تَبِيعُوا الثَّمَرَ بِالتَّمْرِ","id":"Telah menceritakan kepadaku ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Humaid] dari [Anas bin Malik radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang menjual buah-buahan hingga sempurna. Ada yang bertanya apa; \"Apa tanda sempurnanya?\" Beliau menjawab: \"Ia menjadi merah \". Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Coba kau renungkan, bagaimana sekiranya Allah mencegah kurma menjadi masak hanya karena salah seorang diantara kalian mengambil harta saudaranya!\" [Al Laits] berkata; telah menceritakan kepada saya [Yunus] dari [Ibnu Syihab] berkata: \"Seandainya seseorang menjual buah sebelum nampak kebaikannya kemudian terserang hama (penyakit) maka tanggung jawabnya pada pemiliknya\". Telah mengabarkan kepada saya [Salim bin 'Abdullah] dari [Ibnu'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian saling berjual beli buah-buahan hingga tampak kebaikannya dab jangan pula menjual kurma matang dengan kurma mentah\"."},"2049":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ ذَكَرْنَا عِنْدَ إِبْرَاهِيمَ الرَّهْنَ فِي السَّلَفِ فَقَالَ لَا بَأْسَ بِهِ ثُمَّ حَدَّثَنَا عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى طَعَامًا مِنْ يَهُودِيٍّ إِلَى أَجَلٍ فَرَهَنَهُ دِرْعَهُ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [Bapakku] telah menceritakan kepada kami [Al A'masy] berkata; \"Kami pernah menceritakan dihadapan [Ibrahim] tentang menggadai sesuatu untuk pembayaran barang pada waktu yang akan datang, maka dia berkata: \"Tidak ada dosa padanya\". Kemudian dia menceritakan kepada kami dari [Al Aswad] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam pernah membeli makanan dari orang Yahudi untuk masa yang akan datang, lalu Beliau menggadaikan baju besi Beliau (sebagai jaminan) \"."},"2050":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ الْمَجِيدِ بْنِ سُهَيْلِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَعَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ رَجُلًا عَلَى خَيْبَرَ فَجَاءَهُ بِتَمْرٍ جَنِيبٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُلُّ تَمْرِ خَيْبَرَ هَكَذَا قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّا لَنَأْخُذُ الصَّاعَ مِنْ هَذَا بِالصَّاعَيْنِ وَالصَّاعَيْنِ بِالثَّلَاثَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَفْعَلْ بِعْ الْجَمْعَ بِالدَّرَاهِمِ ثُمَّ ابْتَعْ بِالدَّرَاهِمِ جَنِيبًا","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari ['Abdul Majid bin Suhail bin 'Abdurrahman] dari [Sa'id bin Al Musayyab] dari [Abu Sa'id Al Khudriy] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mempekerjakan sesorang di daerah Khaibar kemudian orang itu datang dengan membawa kurma pilihan yang terbaik Maka Rasulullah shallallahu 'alaihi wasallam: \"Apakah semua kurma Khaibar seperti ini?\" Orang itu berkata: \"Demi Allah, tidak wahai Rasulullah, sesungguhnya kami menukar (barter) satu sha' dari jenis kurma ini dengan dua sha' kurma lain dan dua sha' kurma ini dengan tiga sha' kurma lain. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu melakukannya, juallah semua dengan dirham kemudian beli dengan dirham pula\"."},"2051":{"ar":"قَالَ أَبُو عَبْد اللَّهِ و قَالَ لِي إِبْرَاهِيمُ أَخْبَرَنَا هِشَامٌ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ يُخْبِرُ عَنْ نَافِعٍ مَوْلَى ابْنِ عُمَرَ أَنَّهُ قَالَأَيُّمَا نَخْلٍ بِيعَتْ قَدْ أُبِّرَتْ لَمْ يُذْكَرْ الثَّمَرُ فَالثَّمَرُ لِلَّذِي أَبَّرَهَاوَكَذَلِكَ الْعَبْدُ وَالْحَرْثُ سَمَّى لَهُ نَافِعٌ هَؤُلَاءِ الثَّلَاثَ","id":"Telah berkata, Abu 'Abdullah; Dan berkata, kepadaku [Ibrahim] telah mengabarkan kepada kami [Hisyam] telah mengabarkan kepada kami [Ibnu Juraij] berkata; Aku mendengar [Ibnu Abi Mulaikah] yang mengabarkan dari [Nafi'], maula [Ibnu'Umar radliallahu 'anhuma] bahwa dia berkata: \"Pohon kurma mana saja yang telah dikawinkan lalu dijual namun tidak disebutkan sebagai buah (yang dijual) maka buahnya nanti menjadi hak orang yang mengawinkannya. Begitu juga budak dan kebun\". Nafi' menamakannya sebagai tiga hal yang sama ketentuannya. "},"2052":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَاعَ نَخْلًا قَدْ أُبِّرَتْ فَثَمَرُهَا لِلْبَائِعِ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang menjual pohon kurma yang telah dikawinkan maka buahnya nanti menjadi hak penjual kecuali disyaratkan oleh pembeli\"."},"2053":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُزَابَنَةِ أَنْ يَبِيعَ ثَمَرَ حَائِطِهِ إِنْ كَانَ نَخْلًا بِتَمْرٍ كَيْلًا وَإِنْ كَانَ كَرْمًا أَنْ يَبِيعَهُ بِزَبِيبٍ كَيْلًا وَإِنْ كَانَ زَرْعًا أَنْ يَبِيعَهُ بِكَيْلِ طَعَامٍ وَنَهَى عَنْ ذَلِكَ كُلِّهِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam melarang Al Muzaabanah (jual beli secara borongan tanpa diketahui takaran atau timbangannya), yaitu seseorang menjual buah kebunnya dengan ketentuan apabila pohon kurma dijual dengan buah kurma masak sebagai barter takarannya, apabila pohon anggur dijual dengan anggur kering sebagai barter takarannya, apabila benih dijual dengan makanan sebagai barter takarannya, dan Beliau melarang praktek semacam itu seluruhnya."},"2054":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرِئٍ أَبَّرَ نَخْلًا ثُمَّ بَاعَ أَصْلَهَا فَلِلَّذِي أَبَّرَ ثَمَرُ النَّخْلِ إِلَّا أَنْ يَشْتَرِطَهُ الْمُبْتَاعُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa saja yang telah mengawinkan pohon kurmanya lalu menjual pohonnya maka buah pohon kurma itu menjadi hak yang mengawinkannya kecuali bila disyaratkan oleh pembelinya\"."},"2055":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ وَهْبٍ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِسْحَاقُ بْنُ أَبِي طَلْحَةَ الْأَنْصَارِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُحَاقَلَةِ وَالْمُخَاضَرَةِ وَالْمُلَامَسَةِ وَالْمُنَابَذَةِ وَالْمُزَابَنَةِ","id":"Telah menceritakan kepada kami [Ishaq bin Wahab] telah menceritakan kepada kami ['Umar bin Yunus] berkata, telah menceritakan kepada saya [bapakku] telah menceritakan kepada saya [Ishaq bin Abi Tholhah Al Anshari] dari [Anas bin Malik] radliallahu 'anhu bahwa dia berkata: Rasulullah shallallahu 'alaihi wasallam melarang dari Al Muhaaqalah (jual beli buah yang masih ditangkai dengan gandum), Al Mukhodharoh (jual beli buah atau biji-bijian sebelum matang), Al Mulaamasah (terjadi jual beli jika calon pembeli memegang barang dagangan), Al Munaabadzah (jual beli dengan melempar barang dagangan) dan Al Muzaabanah (jual beli kurma yang masih dipohon dengan kurma yang sudah dipetik)."},"2056":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ ثَمَرِ التَّمْرِ حَتَّى يَزْهُوَ فَقُلْنَا لِأَنَسٍ مَا زَهْوُهَا قَالَ تَحْمَرُّ وَتَصْفَرُّ أَرَأَيْتَ إِنْ مَنَعَ اللَّهُ الثَّمَرَةَ بِمَ تَسْتَحِلُّ مَالَ أَخِيكَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam melarang menjual buah kurma hingga sempurna. Kami bertanya kepad Anas; \"Apa tanda sempurnanya?\" Dia menjawab: \"Apabila menjadi memerah dan menguning. Bagaimana pendapatmu jika Allah menghalangi buah hanya karena kamu menghalalkan harta saudaramu?\""},"2057":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَأْكُلُ جُمَّارًا فَقَالَ مِنْ الشَّجَرِ شَجَرَةٌ كَالرَّجُلِ الْمُؤْمِنِ فَأَرَدْتُ أَنْ أَقُولَ هِيَ النَّخْلَةُ فَإِذَا أَنَا أَحْدَثُهُمْ قَالَ هِيَ النَّخْلَةُ","id":"Telah menceritakan kepada kami [Abu Al Walid Hisyam bin 'Abdul Malik] telah menceritakan kepada kami [Abu 'Awanah] dari [Abi Bisyir] dari [Mujahid] dari [Ibnu'Umar radliallahu 'anhuma] berkata: \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam ketika Beliau sedang memakan kambium pohon kurma lalu bersabda: \"Diantara banyak pohon ada satu pohon yang dia seperti seorang mu'min\". Maka aku hendak mengatakannya bahwa yang dimaksud Beliau adalah pohon kurma namun saat itu aku adalah yang paling muda usia diantara mereka yang hadir (sehingga merasa malu untuk mengutarakannya). Kemudian Beliau bersabda: \"Dia adalah pohom kurma\"."},"2058":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَحَجَمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو طَيْبَةَ فَأَمَرَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَاعٍ مِنْ تَمْرٍ وَأَمَرَ أَهْلَهُ أَنْ يُخَفِّفُوا عَنْهُ مِنْ خَرَاجِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Humaid Ath-Thowil] dari [Anas bin Malik radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam pernah dibekam oleh Abu Thoyyibah lalu Rasulullah shallallahu 'alaihi wasallam memberi upah kepadanya dengan satu sha' kurma dan memerintahkan keluarganya agar meringankan pajaknya."},"2059":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاقَالَتْ هِنْدٌ أُمُّ مُعَاوِيَةَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَبَا سُفْيَانَ رَجُلٌ شَحِيحٌ فَهَلْ عَلَيَّ جُنَاحٌ أَنْ آخُذَ مِنْ مَالِهِ سِرًّا قَالَ خُذِي أَنْتِ وَبَنُوكِ مَا يَكْفِيكِ بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari ['Urwah] dari ['Aisyah radliallahu 'anha]; Hindun, ibu dari Mu'awiyah berkata, kepada Rasulullah shallallahu 'alaihi wasallam; \"Sesungguhnya Abu Sufyan adalah seorang yang kikir. Apakah dibenarkan bila aku mengambil dari hartanya secara sembunyi-sembunyi?\" Maka Beliau bersabda: \"Ambillah buatmu dan anak-anakmu sekedar apa yang patut untuk mencukupi kamu\". "},"2060":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا ابْنُ نُمَيْرٍ أَخْبَرَنَا هِشَامٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ سَلَّامٍ قَالَ سَمِعْتُ عُثْمَانَ بْنَ فَرْقَدٍ قَالَ سَمِعْتُ هِشَامَ بْنَ عُرْوَةَ يُحَدِّثُ عَنْ أَبِيهِ أَنَّهُ سَمِعَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاتَقُولُ{ وَمَنْ كَانَ غَنِيًّا فَلْيَسْتَعْفِفْ وَمَنْ كَانَ فَقِيرًا فَلْيَأْكُلْ بِالْمَعْرُوفِ }أُنْزِلَتْ فِي وَالِي الْيَتِيمِ الَّذِي يُقِيمُ عَلَيْهِ وَيُصْلِحُ فِي مَالِهِ إِنْ كَانَ فَقِيرًا أَكَلَ مِنْهُ بِالْمَعْرُوفِ","id":"Telah menceritakan kepada saya [Ishaq] telah menceritakan kepada kami [Ibnu Numair] telah mengabarkan kepada kami [Hisyam] dan diriwayatkan pula telah menceritakan kepada saya [Muhammad bin Salam] berkata; Aku mendengar ['Utsman bin Farqad] berkata; Aku mendengar [Hisyam bin 'Urwah] menceritakan dari [Bapaknya] bahwa dia mendengar ['Aisyah radliallahu 'anha] berkata, (tentang ayat QS. An-Nisaa' ayat 6 yang artinya (barangsiapa diantara pemelihara itu yang mampu maka hendaknya ia menehan diri dari memakan harta anak yatim itu, dan barangsiapa yang miskin maka ia boleh makan harta itu menurut yang patut), ayat ini turun pada wali anak yatim yang memelihara dan menjaga hartanya, dan jika ia seorang miskin maka ia boleh memakannya dengan cara ma'ruf (yang patut)."},"2061":{"ar":"حَدَّثَنِي مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّفْعَةَ فِي كُلِّ مَالٍ لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَصُرِّفَتْ الطُّرُقُ فَلَا شُفْعَةَ","id":"Telah menceritakan kepada saya [Mahmud] telah menceritakan kepada kami ['Abdur Razzaaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari [Abu Salamah] dari [Jabir radliallahu 'anhu]; Rasulullah shallallahu 'alaihi wasallam menjadikan Asy-Syuf'ah pada setiap harta yang belum dibagi. Apabila terdapat pembatas dan jalan yang terpisah maka tidak ada syuf'ah\". "},"2062":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالشُّفْعَةِ فِي كُلِّ مَالٍ لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَصُرِّفَتْ الطُّرُقُ فَلَا شُفْعَةَحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بِهَذَا وَقَالَ فِي كُلِّ مَا لَمْ يُقْسَمْ تَابَعَهُ هِشَامٌ عَنْ مَعْمَرٍ قَالَ عَبْدُ الرَّزَّاقِ فِي كُلِّ مَالٍ رَوَاهُ عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada saya [Muhammad bin Mahbub] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhriy] dari [Abu Salamah bin 'Abdurrahman] dari [Jabir bin 'Abdullah radliallahu 'anha]; Nabi shallallahu 'alaihi wasallam telah mementapkan hak Asy-Syuf'ah pada setiap harta yang belum dibagi. Apabila terdapat pembatas dan jalan yang terpisah maka tidak ada syuf'ah\". Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul Wahid] seperti ini dan berkata; Pada setiap harta yang belum dibagi\". Ini dikuatkan pula oleh [Hisyam] dari [Ma'mar] berkata, ['Abdur Razzaaq]: \"Pada setiap harta\". Ini diriwayatkan oleh ['Abdurrahman bin Ishaq] dari [Az Zuhriy]. "},"2063":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَرَجَ ثَلَاثَةُ نَفَرٍ يَمْشُونَ فَأَصَابَهُمْ الْمَطَرُ فَدَخَلُوا فِي غَارٍ فِي جَبَلٍ فَانْحَطَّتْ عَلَيْهِمْ صَخْرَةٌ قَالَ فَقَالَ بَعْضُهُمْ لِبَعْضٍ ادْعُوا اللَّهَ بِأَفْضَلِ عَمَلٍ عَمِلْتُمُوهُ فَقَالَ أَحَدُهُمْ اللَّهُمَّ إِنِّي كَانَ لِي أَبَوَانِ شَيْخَانِ كَبِيرَانِ فَكُنْتُ أَخْرُجُ فَأَرْعَى ثُمَّ أَجِيءُ فَأَحْلُبُ فَأَجِيءُ بِالْحِلَابِ فَآتِي بِهِ أَبَوَيَّ فَيَشْرَبَانِ ثُمَّ أَسْقِي الصِّبْيَةَ وَأَهْلِي وَامْرَأَتِي فَاحْتَبَسْتُ لَيْلَةً فَجِئْتُ فَإِذَا هُمَا نَائِمَانِ قَالَ فَكَرِهْتُ أَنْ أُوقِظَهُمَا وَالصِّبْيَةُ يَتَضَاغَوْنَ عِنْدَ رِجْلَيَّ فَلَمْ يَزَلْ ذَلِكَ دَأْبِي وَدَأْبَهُمَا حَتَّى طَلَعَ الْفَجْرُ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ عَنَّا فُرْجَةً نَرَى مِنْهَا السَّمَاءَ قَالَ فَفُرِجَ عَنْهُمْ وَقَالَ الْآخَرُ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنِّي كُنْتُ أُحِبُّ امْرَأَةً مِنْ بَنَاتِ عَمِّي كَأَشَدِّ مَا يُحِبُّ الرَّجُلُ النِّسَاءَ فَقَالَتْ لَا تَنَالُ ذَلِكَ مِنْهَا حَتَّى تُعْطِيَهَا مِائَةَ دِينَارٍ فَسَعَيْتُ فِيهَا حَتَّى جَمَعْتُهَا فَلَمَّا قَعَدْتُ بَيْنَ رِجْلَيْهَا قَالَتْ اتَّقِ اللَّهَ وَلَا تَفُضَّ الْخَاتَمَ إِلَّا بِحَقِّهِ فَقُمْتُ وَتَرَكْتُهَا فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ عَنَّا فُرْجَةً قَالَ فَفَرَجَ عَنْهُمْ الثُّلُثَيْنِ وَقَالَ الْآخَرُ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنِّي اسْتَأْجَرْتُ أَجِيرًا بِفَرَقٍ مِنْ ذُرَةٍ فَأَعْطَيْتُهُ وَأَبَى ذَاكَ أَنْ يَأْخُذَ فَعَمَدْتُ إِلَى ذَلِكَ الْفَرَقِ فَزَرَعْتُهُ حَتَّى اشْتَرَيْتُ مِنْهُ ب��قَرًا وَرَاعِيهَا ثُمَّ جَاءَ فَقَالَ يَا عَبْدَ اللَّهِ أَعْطِنِي حَقِّي فَقُلْتُ انْطَلِقْ إِلَى تِلْكَ الْبَقَرِ وَرَاعِيهَا فَإِنَّهَا لَكَ فَقَالَ أَتَسْتَهْزِئُ بِي قَالَ فَقُلْتُ مَا أَسْتَهْزِئُ بِكَ وَلَكِنَّهَا لَكَ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ عَنَّا فَكُشِفَ عَنْهُمْ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ada tiga orang yang sedang berjalan kemudian turun hujan lalu ketiganya masuk kedalam gua di sebuah gunung namun kemudian mereka tertutup oleh batu\". Beliau melanjutkan; \"Kemudian diantara mereka berkata kepada yang lainnya; Mintalah kepada Allah dengan perantaraan amal yang paling utama yang kalian pernah melakukannya. Orang pertama diantara mereka berkata; Ya Allah, aku memiliki kedua orangtua yang sudah renta. Suatu hari aku keluar untuk mengembala untuk mendapatkan susu kemudian aku datang membawa susu, lalu aku berikan kepada kedua orangtuaku, lalu keduanya meminum baru kemudian aku berikan minum untuk bayiku, keluarga dan isteriku. Pada suatu malam, aku mencari susu setelah aku kembali dan aku datangi mereka ternyata keduanya sudah tertidur. Dia berkata; Aku enggan untuk membangunkan keduanya untuk meminum susu sedangkan anakku menangis dibawah kakiku karena kelaparan, Begitulah kebiasaanku dan kebiasaan kedua orangtuaku hingga fajar. Ya Allah seandainya Engkau mengetahui apa yang aku kerjakan itu semata mencari ridha Mu, maka bukakanlah celah untuk kami agar kami dapat melihat matahari darinya\". Beliau shallallahu 'alaihi wasallam bersabda: \"Maka terbukalah sedikit celah untuk mereka. Orang kedua berkata: \"Ya Allah, sungguh Engkau mengetahui bahwa aku seorang lelaki yang sangat mencintai seorang wanitaputri dari pamanku seperti kebanyakan laki-laki mencintai wanita. Suatu hari dia berkata, bahwa aku tidak akan bisa mendapatkannya kecuali aku dapat memberi uang sebanyak seratus dinar. Maka aku bekerja dan berhasil mengumpulkan uang tersebut. Ketika aku sudah berhadapan dengannya dan aku hendak menyetubuinya, dia berkata; bertaqwalah kepada Allah, dan janganlah kamu renggut keperawanan kecuali dengan haq\". Maka aku berdiri lalu pergi meninggalkan wanita tersebut. Ya Allah seandainya Engkau mengetahui apa yang aku kerjakan itu semata mencari ridhaMu, maka bukakanlah celah untuk kami\". Beliau shallallahu 'alaihi wasallam bersabda: \"Maka terbukalah dua pertiga dari batu yang menutup pintu gua. Kemudian orang yang ketiga berkata: Ya Allah sungguh Engkau mengetahui bahwa aku pernah memperkerjakan seseorang untuk mengurusi satu benih tumbuhan lalu aku beri upah namun dia tidak mau menerimanya. Lalu aku sengaja mengembangkan benih tersebut sehingga darinya aku bisa membeli seekor sapi dan seorang pengembalanya. Kemudian di suatu hari orang itu datang kepadaku seraya berkata; \"Wahai 'Abdullah, berikanlah upahku yang dulu!\" Lalu aku katakan; Kemarilah lihat kepada seekor sapi dan pemngembalanya itu semua milikmu\". Dia berkata: \"Kamu jangan mengolok-olok aku!\" Dia berkata: Aku katakan: Aku tidak mengolok-olok kamu tetapi itu semua benar milikmu. Ya Allah seandainya Engkau mengetahui apa yang aku kerjakan itu semata mencari ridhaMu, maka bukakanlah celah untuk kami\". Akhirnya mereka bisa terbebas dari gua tersebut\"."},"2064":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَاءَ رَجُلٌ مُشْرِكٌ مُشْعَانٌّ طَوِيلٌ بِغَنَمٍ يَسُوقُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْعًا أَمْ عَطِيَّةً أَوْ قَالَ أَمْ هِبَةً قَالَ لَا بَلْ بَيْعٌ فَاشْتَرَى مِنْهُ شَاةً","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Abu 'Utsman] dari ['Abdurrahman bin Abu Bakar radliallahu 'anhuma] berkata: \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam tiba-tiba datang seorang lelaki musyrik dengan rambut panjang yang kusut dengan menggiring kambing. Maka Nabi shallallahu 'alaihi wasallam bertanya: \"Apakah untuk dijual atau diberikan?\" Atau sabdanya: \"Atau dihibahkan?\" Orang itu menjawab: \"Bukan, tapi untuk dijual\". Lalu Beliau shallallahu 'alaihi wasallam membeli seekor kambing darinya."},"2065":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَاجَرَ إِبْرَاهِيمُ عَلَيْهِ السَّلَام بِسَارَةَ فَدَخَلَ بِهَا قَرْيَةً فِيهَا مَلِكٌ مِنْ الْمُلُوكِ أَوْ جَبَّارٌ مِنْ الْجَبَابِرَةِ فَقِيلَ دَخَلَ إِبْرَاهِيمُ بِامْرَأَةٍ هِيَ مِنْ أَحْسَنِ النِّسَاءِ فَأَرْسَلَ إِلَيْهِ أَنْ يَا إِبْرَاهِيمُ مَنْ هَذِهِ الَّتِي مَعَكَ قَالَ أُخْتِي ثُمَّ رَجَعَ إِلَيْهَا فَقَالَ لَا تُكَذِّبِي حَدِيثِي فَإِنِّي أَخْبَرْتُهُمْ أَنَّكِ أُخْتِي وَاللَّهِ إِنْ عَلَى الْأَرْضِ مُؤْمِنٌ غَيْرِي وَغَيْرُكِ فَأَرْسَلَ بِهَا إِلَيْهِ فَقَامَ إِلَيْهَا فَقَامَتْ تَوَضَّأُ وَتُصَلِّي فَقَالَتْ اللَّهُمَّ إِنْ كُنْتُ آمَنْتُ بِكَ وَبِرَسُولِكَ وَأَحْصَنْتُ فَرْجِي إِلَّا عَلَى زَوْجِي فَلَا تُسَلِّطْ عَلَيَّ الْكَافِرَ فَغُطَّ حَتَّى رَكَضَ بِرِجْلِهِقَالَ الْأَعْرَجُ قَالَ أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ إِنَّ أَبَا هُرَيْرَةَ قَالَ قَالَتْ اللَّهُمَّ إِنْ يَمُتْ يُقَالُ هِيَ قَتَلَتْهُ فَأُرْسِلَ ثُمَّ قَامَ إِلَيْهَا فَقَامَتْ تَوَضَّأُ تُصَلِّي وَتَقُولُ اللَّهُمَّ إِنْ كُنْتُ آمَنْتُ بِكَ وَبِرَسُولِكَ وَأَحْصَنْتُ فَرْجِي إِلَّا عَلَى زَوْجِي فَلَا تُسَلِّطْ عَلَيَّ هَذَا الْكَافِرَ فَغُطَّ حَتَّى رَكَضَ بِرِجْلِهِ قَالَ عَبْدُ الرَّحْمَنِ قَالَ أَبُو سَلَمَةَ قَالَ أَبُو هُرَيْرَةَ فَقَالَتْ اللَّهُمَّ إِنْ يَمُتْ فَيُقَالُ هِيَ قَتَلَتْهُ فَأُرْسِلَ فِي الثَّانِيَةِ أَوْ فِي الثَّالِثَةِ فَقَالَ وَاللَّهِ مَا أَرْسَلْتُمْ إِلَيَّ إِلَّا شَيْطَانًا ارْجِعُوهَا إِلَى إِبْرَاهِيمَ وَأَعْطُوهَا آجَرَ فَرَجَعَتْ إِلَى إِبْرَاهِيمَ عَلَيْهِ السَّلَام فَقَالَتْ أَشَعَرْتَ أَنَّ اللَّهَ كَبَتَ الْكَافِرَ وَأَخْدَمَ وَلِيدَةً","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] berkata; Telah bersabda Nabi shallallahu 'alaihi wasallam: \"Nabi Ibrahim Alaihissalam berhijrah bersama isterinya Sarah lalu memasuki suatu kampung yang dipimpin oleh seorang raja atau seorang yang diktator diantara para penguasa bengis. Ada yang berkata; Nabi Ibrahim datang dengan seorang wanita yang paling cantik. Lalu Nabi Ibrahim dipanggil kemudian ditanya: Wahai Ibrahim, siapakah wanita yang bersamamu itu?\" Nabi Ibrahim berkata: \"Dia adalah saudariku\". Lalu Nabi Ibrahim kembali kepada Sarah dan berkata: \"Janganlah kamu mendustakan perkataanku karena aku telah mengabarkan kepada mereka bahwa kamu adalah saudaraku. Demi Allah sesungguhnya tidak ada orang beriman di tempat ini selain aku dan kamu\". Kemudian Sarah dibawa menghadap raja untuk hidup bersamanya. Maka Sarah berwudhu' lalu shalat seraya berdo'a: \"Ya Allah, sesungguhnya Engkau mengetahui bahwa aku beriman kepadaMu dan kepada RasulMu dan aku memelihara kemaluanku kecuali untuk suamiku maka janganlah Engkau satukan aku dengan orang kafir ini\". Maka tiba-tiba raja itu langkahnya terhenti hingga kakinya tidak menempel ke tanah selain ujung-ujung jari-jemari kakinya. Berkata [Al A'raj], berkata [Abu Salamah bin 'Abdurrahman], [Abu Hurairah radliallahu 'anhu] berkata; Sarah berdo'a: \"Ya Allah, seandainya dia mati nanti akan dikatakan bahwa wanita ini telah membunuhnya\". Maka Sarah dibawa kepada raja itu dan telah berdiri dihadapannya. Maka Sarah berwudhu' lalu shalat seraya berdoa: \"Ya Allah, sesungguhnya Engkau mengetahui bahwa aku beriman kepadaMu dan kepada RasulMu dan aku memelihara kemaluamku kecuali untuk suamiku maka janganlah Engkau satukan aku dengan orang kafir ini\". Secara tiba-tiba lagkah raja terhenti dan kakinya tidak menempel ke tanah selain ujung jari jemari kakinya. Berkata 'Abdurrahman, berkata Abu Salamah berkata, Abu Hurairah radliallahu 'anhu: Sarah berkata: \"Ya Allah, seandainya dia mati nanti akan dikatakan bahwa wanita ini telah membunuhnya\". Maka Sarah dibawa untuk kali kedua atau ketiga. Maka raja itu berkata: \"Demi Allah, tidaklah kalian bawa ke hadapanku melainkan syetan. Kembalikanlah wanita itu kepada Ibrahim dan berikan dia upah. Maka Sarah kembali kepada Ibrahim Alaihissalam lalu berkata: \"Apakah kamu menyadari bahwa Allah telah menghinakan orang kafir itu dan menjadikannya sebadai budak seorang hamba sahaya?\""},"2066":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْاخْتَصَمَ سَعْدُ بْنُ أَبِي وَقَّاصٍ وَعَبْدُ بْنُ زَمْعَةَ فِي غُلَامٍ فَقَالَ سَعْدٌ هَذَا يَا رَسُولَ اللَّهِ ابْنُ أَخِي عُتْبَةُ بْنُ أَبِي وَقَّاصٍ عَهِدَ إِلَيَّ أَنَّهُ ابْنُهُ انْظُرْ إِلَى شَبَهِهِ وَقَالَ عَبْدُ بْنُ زَمْعَةَ هَذَا أَخِي يَا رَسُولَ اللَّهِ وُلِدَ عَلَى فِرَاشِ أَبِي مِنْ وَلِيدَتِهِ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شَبَهِهِ فَرَأَى شَبَهًا بَيِّنًا بِعُتْبَةَ فَقَالَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ وَاحْتَجِبِي مِنْهُ يَا سَوْدَةُ بِنْتَ زَمْعَةَ فَلَمْ تَرَهُ سَوْدَةُ قَطُّ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa dia berkata: Sa'ad bin Abi Waqash berselisih dengan 'Abdu bin Zam'ah dalam perkara seorang anak. Sa'ad berkata: \"Wahai Rasulullah, dia ini anak dari saudaraku 'Utbah bin Abi Waqash yang bersumpah kepadaku bahwa dia adalah anaknya. Perhatikanlah tanda kemiripannya?\" Namun 'Abdu bin Zam'ah berkata: Wahai Rasulullah, ini saudaraku yang dilahirkan diatas tempat tidur Bapakku dari hamba sahayanya\". Kemudian Rasulullah shallallahu 'alaihi wasallam memperhatikan tanda kemiripan yang ada, maka Beliau melihat jelas sekali tanda kemiripan ada pada 'Utbah. Namun Beliau bersabda: \"Anak itu milikmu wahai 'Abdu bin Zam'ah. Anak itu milik si pemilik keranjang (suami) sedangkan untuk pezina baginya batu (rajam). Berhijablah engkau darinya, wahai Saudah binti Zam'ah\". Sejak itu Saudah tidak pernah melihatnya lagi. "},"2067":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدٍ عَنْ أَبِيهِ قَالَعَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ رَضِيَ اللَّهُ عَنْهُ لِصُهَيْبٍ اتَّقِ اللَّهَ وَلَا تَدَّعِ إِلَى غَيْرِ أَبِيكَ فَقَالَ صُهَيْبٌ مَا يَسُرُّنِي أَنَّ لِي كَذَا وَكَذَا وَأَنِّي قُلْتُ ذَلِكَ وَلَكِنِّي سُرِقْتُ وَأَنَا صَبِيٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Sa'ad] dari [Bapaknya], berkata, 'Abdurrahman bin 'Auf radliallahu 'anhu kepada [Shuhaib]: \"Bertaqwalah kepada Allah, janganlah engkau mengatas namakan keturunan kepada selain bapakmu\". Kemudian Suhaib berkata: \"Tidak ada yang membuatku gembira karena aku punya ini atau itu, akan tetapi aku mengatakan hal itu karena aku diculik ketika aku bayi\"."},"2068":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ حَكِيمَ بْنَ حِزَامٍ أَخْبَرَهُ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَرَأَيْتَ أُمُورًا كُنْتُ أَتَحَنَّثُ أَوْ أَتَحَنَّتُ بِهَا فِي الْجَاهِلِيَّةِ مِنْ صِلَةٍ وَعَتَاقَةٍ وَصَدَقَةٍ هَلْ لِي فِيهَا أَجْرٌ قَالَ حَكِيمٌ رَضِيَ اللَّهُ عَنْهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمْتَ عَلَى مَا سَلَفَ لَكَ مِنْ خَيْرٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syuhaib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya ['Urwah bin Az Zubair] bahwa [Hakim bin Hiram] mengabarkan kepadanya bahwa dia berkata: \"Wahai Rasulullah, bagaimana pendapatmu jika semasa masih di jaman Jahiliyah aku sering beribadah mendekatkan diri dengan cara bershadaqah, membebaskan budak dan juga menyambung silaturrahim, apakah dari itu semuanya aku akan mendapatkan pahala?\" Berkata, Hakim radliallahu 'anhu: \"Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kamu akan menerima kebaikan yang kamu lakukan dahulu\"."},"2069":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِشَاةٍ مَيِّتَةٍ فَقَالَ هَلَّا اسْتَمْتَعْتُمْ بِإِهَابِهَا قَالُوا إِنَّهَا مَيِّتَةٌ قَالَ إِنَّمَا حَرُمَ أَكْلُهَا","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Bapakku] dari [Shalih] berkata, telah menceritakan kepada saya [Ibnu Syihab] bahwa ['Ubaidullah bin 'Abdullah] mengabarkan kepadanya bahwa ['Abdullah bin 'Abbas radliallahu 'anhu] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah berjalan melewati seekor kambing yang sudah jadi bangkai lalu bersabda: \"Apakah kalian bersenang-senang dengan kulitnya (yang belum disamak) ini?\" Mereka berkata: \"Itu hanyalah bangkai!\" Beliau bersabda: \"Sesungguhnya yang diharamkan adalah jika memakannya\"."},"2070":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَيُوشِكَنَّ أَنْ يَنْزِلَ فِيكُمْ ابْنُ مَرْيَمَ حَكَمًا مُقْسِطًا فَيَكْسِرَ الصَّلِيبَ وَيَقْتُلَ الْخِنْزِيرَ وَيَضَعَ الْجِزْيَةَ وَيَفِيضَ الْمَالُ حَتَّى لَا يَقْبَلَهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Ibnu Al Musayyab] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Bersabda Rasulullah shallallahu 'alaihi wasallam: \"Demi Dzat yang jiwaku dalam genggamanNya, sungguh tiada lama lagi akan segera turun Ibnu Maryam (Isa Alaihissalam) yang akan menjadi hakim yang adil, menghancurkan salib, membunuh babi, membebaskan jizyah dan harta benda melimpa ruah sehingga tidak ada seorangpun yang mau menerimanya\"."},"2071":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ أَخْبَرَنِي طَاوُسٌ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُ بَلَغَ عُمَرَ بْنَ الْخَطَّابِأَنَّ فُلَانًا بَاعَ خَمْرًا فَقَالَ قَاتَلَ اللَّهُ فُلَانًا أَلَمْ يَعْلَمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَاتَلَ اللَّهُ الْيَهُودَ حُرِّمَتْ عَلَيْهِمْ الشُّحُومُ فَجَمَلُوهَا فَبَاعُوهَا","id":"Telah menceritakan kepada kami [AL Humaidiy] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru bin DInar] berkata, telah mengabarkan kepada saya [Thawus] bahwa dia mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata; sampai kabar kepada ['Umar bin Al Khaththob] bahwa fulan menjual khamar (minuman keras) lalu dia berkata; semoga Allah membinasakan si fulan, tidakkah dia mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Semoga Allah melaknat Yahudi, karena telah diharamkan atas mereka lemak hewan (sapi dan kambing) namun mereka mencairkannya lalu memperjual belikannya\". "},"2072":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَاتَلَ اللَّهُ يَهُودَ حُرِّمَتْ عَلَيْهِمْ الشُّحُومُ فَبَاعُوهَا وَأَكَلُوا أَثْمَانَهَاقَالَ أَبُو عَبْد اللَّهِ{ قَاتَلَهُمْ اللَّهُ }لَعَنَهُمْ{ قُتِلَ }لُعِنَ{ الْخَرَّاصُونَ }الْكَذَّابُونَ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab]; Aku mendengar [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah melaknat Yahudi, karena telah diharamkan atas mereka lemak hewan (sapi dan kambing) namun lalu memperjual belikannya dan memakan uang jual belinya\". Berkata, Abu 'Abdullah Al Bukoriy: ' Qaatalahumullah artinya Allah melaknat mereka. (qutila) artinya (lu'ina) seperti artinya: \"Terkutuklah orang-orang yang banyak berdusta.\""},"2073":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ أَخْبَرَنَا عَوْفٌ عَنْ سَعِيدِ بْنِ أَبِي الْحَسَنِ قَالَ كُنْتُ عِنْدَ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاإِذْ أَتَاهُ رَجُلٌ فَقَالَ يَا أَبَا عَبَّاسٍ إِنِّي إِنْسَانٌ إِنَّمَا مَعِيشَتِي مِنْ صَنْعَةِ يَدِي وَإِنِّي أَصْنَعُ هَذِهِ التَّصَاوِيرَ فَقَالَ ابْنُ عَبَّاسٍ لَا أُحَدِّثُكَ إِلَّا مَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَمِعْتُهُ يَقُولُ مَنْ صَوَّرَ صُورَةً فَإِنَّ اللَّهَ مُعَذِّبُهُ حَتَّى يَنْفُخَ فِيهَا الرُّوحَ وَلَيْسَ بِنَافِخٍ فِيهَا أَبَدًا فَرَبَا الرَّجُلُ رَبْوَةً شَدِيدَةً وَاصْفَرَّ وَجْهُهُ فَقَالَ وَيْحَكَ إِنْ أَبَيْتَ إِلَّا أَنْ تَصْنَعَ فَعَلَيْكَ بِهَذَا الشَّجَرِ كُلِّ شَيْءٍ لَيْسَ فِيهِ رُوحٌقَالَ أَبُو عَبْد اللَّهِ سَمِعَ سَعِيدُ بْنُ أَبِي عَرُوبَةَ مِنْ النَّضْرِ بْنِ أَنَسٍ هَذَا الْوَاحِدَ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] telah menceritakan kepada kami [Yazid bin Zurai'] telah mengabarkan kepada kami ['Auf] dari [Sa'id bin Abi Al Hasan] berkata; Aku pernah bersama [Ibnu 'Abbas] radliallahu 'anhu ketika datang seorang kepadanya seraya berkata; \"Wahai Abu 'Abbas, aku adalah seorang yang mata pencaharianku adalah dengan keahlian tanganku yaitu membuat lukisan seperti ini\". Maka Ibnu 'Abbas berkata: \"Aku tidaklah menyampaikan kepadamu perkataan melainkan dari apa yang pernah aku dengar dari Rasulullah shallallahu 'alaihi wasallam yang Beliau bersabda: \"Siapa yang membuat gambar lukisan, Allah akan menyiksanya hingga dia meniupkan ruh (nyawa) kepada gambarnya itu dan sekali-kali dian tidak akan bisa mendatangkanhya selamanya\". Maka orang tersebut sangat ketakutan dengan wajah yang pucat pasi lalu berkata: \"Bagaimana pendapatmu kalau aku tidak bisa meninggalkannya kecuali tetap menggambar?\" Dia (Ibnu 'Abbas) berkata: \"Gambarlah olehmu pepohonan dan setiap sesuatu yang tidak memiliki nyawa\". Berkata, Abu 'Abdullah Al Bukhariy: Said bin Abi 'Arubah mendengar dari An-Nadhar bin Anas sendirian."},"2074":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَالَمَّا نَزَلَتْ آيَاتُ سُورَةِ الْبَقَرَةِ عَنْ آخِرِهَا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ حُرِّمَتْ التِّجَارَةُ فِي الْخَمْرِ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Adh-Dhuhaa] dari [Masruq] dari ['Aisyah radliallahu 'anha]; Ketika turun ayat-ayat akhir dari Surah Al Baqarah, Nabi shallallahu 'alaihi wasallam keluar lalu bersabda: \"Telah diharamkan perdagangan khamar (minuman keras) \"."},"2075":{"ar":"حَدَّثَنِي بِشْرُ بْنُ مَرْحُومٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ إِسْمَاعِيلَ بْنِ أُمَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ ثَلَاثَةٌ أَنَا خَصْمُهُمْ يَوْمَ الْقِيَامَةِ رَجُلٌ أَعْطَى بِي ثُمَّ غَدَرَ وَرَجُلٌ بَاعَ حُرًّا فَأَكَلَ ثَمَنَهُ وَرَجُلٌ اسْتَأْجَرَ أَجِيرًا فَاسْتَوْفَى مِنْهُ وَلَمْ يُعْطِ أَجْرَهُ","id":"Telah menceritakan kepada saya [Bisyir bin Marhum] telah menceritakan kepada kami [Yahya bin Sulaim] dari [Isma'il bin Umayyah] dari [Sa'id bin Abi Sa'id] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: Ada tiga jenis orang yang Aku menjadi musuh mereka pada hari qiyamat, seseorang yang bersumpah atas namaku lalu mengingkarinya, seseorang yang menjual orang yang telah merdeka lalu memakan (uang dari) harganya dan seseorang yang memperkerjakan pekerja kemudian pekerja itu menyelesaikan pekerjaannya namun tidak dibayar upahnya\"."},"2076":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ فِي السَّبْيِ صَفِيَّةُ فَصَارَتْ إِلَى دَحْيَةَ الْكَلْبِيِّ ثُمَّ صَارَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas radliallahu 'anhu] berkata; Diantara tawanan (perang Khaibar) ada Shafiyah (binti Huyyay) kemudian dia menjadi hak milik Dihyah Al Kalbiy dan kemudian Shafiyah menjadi milik Nabi shallallahu 'alaihi wasallam."},"2077":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ مُحَيْرِيزٍ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ أَخْبَرَهُ أَنَّهُبَيْنَمَا هُوَ جَالِسٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا رَسُولَ اللَّهِ إِنَّا نُصِيبُ سَبْيًا فَنُحِبُّ الْأَثْمَانَ فَكَيْفَ تَرَى فِي الْعَزْلِ فَقَالَ أَوَإِنَّكُمْ تَفْعَلُونَ ذَلِكَ لَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا ذَلِكُمْ فَإِنَّهَا لَيْسَتْ نَسَمَةٌ كَتَبَ اللَّهُ أَنْ تَخْرُجَ إِلَّا هِيَ خَارِجَةٌ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Ibnu Muhairiz] bahwa [Abu Sa'id Al Khudriy radliallahu 'anhu] mengabarkannya bahwa ketika dia bermajelis bersama Nabi shallallahu 'alaihi wasallam dia berkata: \"Wahai Rasulullah, kami mendapatkan tawanan, hanya kami juga masih menyukai harganya, bagaimana pendapat anda bila kami melakukan 'azal?. Maka Beliau shallallahu 'alaihi wasallam bersabda: \"Apakah kalian melakukannya?. Tidak dosa kalian untuk melakukannya, namun tidak ada satu nyawapun yang telah Allah tetapkan akan keluar (jadi) kecuali dia pasti akan muncul juga\". "},"2078":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَبَاعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُدَبَّرَحَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُ بَاعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Isma'il] dari [Salamah bin Kuhail] dari ['Atho'] dari [Jabir radliallahu 'anhu] berkata: Nabi shallallahu 'alaihi wasallam membeli Al Mudabbar (seorang budak yang dijanjikan bebas jika tuannya meninggal). Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan] dari ['Amru] yang mendengar [Jabir bin 'Abdullah radliallahu 'anhu] berkata; \"Rasulullah shallallahu 'alaihi wasallam membelinya\"."},"2079":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ حَدَّثَ ابْنُ شِهَابٍ أَنَّ عُبَيْدَ اللَّهِ أَخْبَرَهُ أَنَّ زَيْدَ بْنَ خَالِدٍ وَأَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَاهُأَنَّهُمَا سَمِعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْأَلُ عَنْ الْأَمَةِ تَزْنِي وَلَمْ تُحْصَنْ قَالَ اجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ بِيعُوهَا بَعْدَ الثَّالِثَةِ أَوْ الرَّابِعَةِ","id":"Telah menceritakan kepada saya [Zuhair bin Harb] telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Bapakku] dari [Shalih] berkata, [Ibnu Syihab] menceritakan bahwa ['Ubaidullah] mengabarkannya bahwa [Zaid bin Khalid] dan [Abu Hurairah] radliallahu 'anhuma, keduanya mengabarkan bahwa mereka mendengar Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang seorang budak perempuan yang belum menikah berzina, maka Beliau bersabda: \"Cambuklah dia kemudian jika dia berzina kembali cambuklah kemudian juallah setelah melakukan untuk ketiga atau keempat kalinya\". "},"2080":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ أَخْبَرَنِي اللَّيْثُ عَنْ سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا زَنَتْ أَمَةُ أَحَدِكُمْ فَتَبَيَّنَ زِنَاهَا فَلْيَجْلِدْهَا الْحَدَّ وَلَا يُثَرِّبْ عَلَيْهَا ثُمَّ إِنْ زَنَتْ فَلْيَجْلِدْهَا الْحَدَّ وَلَا يُثَرِّبْ ثُمَّ إِنْ زَنَتْ الثَّالِثَةَ فَتَبَيَّنَ زِنَاهَا فَلْيَبِعْهَا وَلَوْ بِحَبْلٍ مِنْ شَعَرٍ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada saya [Al Laits] dari [Sa'id] dari [Bapaknya] dari [Abu Hurairah radliallahu 'anhu] berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang budak wanita berzina dan terbukti perzinahannya maka dia dihukum cambuk tanpa dicela dan dihinakan. Jika berzina lagi maka dihukum cambuk tanpa dicela dan dihinakan dan jika berzina lagi untuk ketiga kalinya maka juallah sekalipun dengan harga senilai sehelai rambut\"."},"2081":{"ar":"حَدَّثَنَا عَبْدُ الْغَفَّارِ بْنُ دَاوُدَ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ فَلَمَّا فَتَحَ اللَّهُ عَلَيْهِ الْحِصْنَ ذُكِرَ لَهُ جَمَالُ صَفِيَّةَ بِنْتِ حُيَيِّ بْنِ أَخْطَبَ وَقَدْ قُتِلَ زَوْجُهَا وَكَانَتْ عَرُوسًا فَاصْطَفَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِنَفْسِهِ فَخَرَجَ بِهَا حَتَّى بَلَغْنَا سَدَّ الرَّوْحَاءِ حَلَّتْ فَبَنَى بِهَا ثُمَّ صَنَعَ حَيْسًا فِي نِطَعٍ صَغِيرٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آذِنْ مَنْ حَوْلَكَ فَكَانَتْ تِلْكَ وَلِيمَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى صَفِيَّةَ ثُمَّ خَرَجْنَا إِلَى الْمَدِينَةِ قَالَ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَوِّي لَهَا وَرَاءَهُ بِعَبَاءَةٍ ثُمَّ يَجْلِسُ عِنْدَ بَعِيرِهِ فَيَضَعُ رُكْبَتَهُ فَتَضَعُ صَفِيَّةُ رِجْلَهَا عَلَى رُكْبَتِهِ حَتَّى تَرْكَبَ","id":"Telah menceritakan kepada kami ['Abdul Ghoffar bin Daud] telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman] dari ['Amru bin Abi 'Amru] dari [Anas bin Malik radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam memasuki Khaibar. Tatkala Allah menaklukan benteng Khaibar untuk kemenangan kepada Beliau, diceritakan kepada Beliau tentang kecantikan Shafiyah binti Huyyay bin Akhthob yang suaminya terbunuh sedangkan dia baru saja menjadi pengantin. Maka Rasulullah shallallahu 'alaihi wasallam memilihnya untuk diri Beliau. Kemudian Beliau keluar bersama Shafiyah hingga ketika kami sudah sampai di Saddar Rauhaa', dia berhenti untuk singgah maka dibuatkanlah baginya makanan yang terbuat dari kurma, tepung dan minyak samin dalam wadah kecil terbuat dari kulit. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Persilakanlah orang-orang yang ada di sekitarmu!\" Itulah walimah Rasulullah shallallahu 'alaihi wasallam dengan Shafiyah. Kemudian kami berangkat menuju Madinah. Dia (Anas bin Malik radliallahu 'anhu) berkata: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam mengangkat dan memasukkan Shafiyah kedalam mantel dibelakang lalu Beliau duduk diatas unta Beliau dan Beliau letakkan kaki Shafiyah diatas lutut Beliau hingga kemudian berjalan mengendarai."},"2082":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَامَ الْفَتْحِ وَهُوَ بِمَكَّةَ إِنَّ اللَّهَ وَرَسُولَهُ حَرَّمَ بَيْعَ الْخَمْرِ وَالْمَيْتَةِ وَالْخِنْزِيرِ وَالْأَصْنَامِ فَقِيلَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ شُحُومَ الْمَيْتَةِ فَإِنَّهَا يُطْلَى بِهَا السُّفُنُ وَيُدْهَنُ بِهَا الْجُلُودُ وَيَسْتَصْبِحُ بِهَا النَّاسُ فَقَالَ لَا هُوَ حَرَامٌ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ قَاتَلَ اللَّهُ الْيَهُودَ إِنَّ اللَّهَ لَمَّا حَرَّمَ شُحُومَهَا جَمَلُوهُ ثُمَّ بَاعُوهُ فَأَكَلُوا ثَمَنَهُقَالَ أَبُو عَاصِمٍ حَدَّثَنَا عَبْدُ الْحَمِيدِ حَدَّثَنَا يَزِيدُ كَتَبَ إِلَيَّ عَطَاءٌ سَمِعْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abi Habib] dari ['Atho' bin Abi Rabah] dari [Jabir bin 'Abdullah radliallahu 'anhu] bahwasanya dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda ketika Hari Penaklukan saat Beliau di Makkah: \"Allah dan RasulNya telah mengharamkan khamar, bangkai, babi dan patung-patung\". Ada yang bertanya: \"Wahai Rasulullah, bagaimana dengan lemak dari bangkai (sapi dan kambing) karena bisa dimanfaatkan untuk memoles sarung pedang atau meminyaki kulit-kulit dan sebagai bahan minyak untuk penerangan bagi manusia?. Beliau bersabda: \"Tidak, dia tetap haram\". Kemudian saat itu juga Rasulullah shallallahu 'alaihi wasallam bersabda: Semoga Allah melaknat Yahudi, karena ketika Allah mengharamkan lemak hewan (sapi dan kambing) mereka mencairkannya lalu memperjual belikannya dan memakan uang jual belinya\". Berkata, [Abu 'Ashim] telah menceritakan kepada kami ['Abdul Hamid] telah menceritakan kepada kami [Yazid]; ['Atho'] menulis surat kepadaku yang katanya dia mendengar [Jabir radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam. "},"2083":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Bakar bin 'Abdurrahman] dari [Abu Mas'ud Al Anshariy radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang uang hasil jual beli anjing, mahar seorang pezina dan upah bayaran dukun."},"2084":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَوْنُ بْنُ أَبِي جُحَيْفَةَ قَالَ رَأَيْتُ أَبِياشْتَرَى حَجَّامًا فَأَمَرَ بِمَحَاجِمِهِ فَكُسِرَتْ فَسَأَلْتُهُ عَنْ ذَلِكَ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الدَّمِ وَثَمَنِ الْكَلْبِ وَكَسْبِ الْأَمَةِ وَلَعَنَ الْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ وَآكِلَ الرِّبَا وَمُوكِلَهُ وَلَعَنَ الْمُصَوِّرَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada saya ['Aun bin Abu Juhaifah] berkata; Aku melihat [Bapakku] membeli tukang bekam lalu memerintahkan untuk menghancurkan alat-alat bekamnya. Kemudian aku tanyakan masalah itu. Lalu Bapakku berkata: \"Rasulullah shallallahu 'alaihi wasallam telah melarang harga (uang hasil jual beli) darah, anjing, memeras budak wanita dan melarang orang yang membuat tato dan yang minta ditato dan pemakan riba' dan yang meminjamkan riba, serta melaknat pembuat patung\"."},"2085":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ عُلَيَّةَ أَخْبَرَنَا ابْنُ أَبِي نَجِيحٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ أَبِي الْمِنْهَالِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَالنَّاسُ يُسْلِفُونَ فِي الثَّمَرِ الْعَامَ وَالْعَامَيْنِ أَوْ قَالَ عَامَيْنِ أَوْ ثَلَاثَةً شَكَّ إِسْمَاعِيلُ فَقَالَ مَنْ سَلَّفَ فِي تَمْرٍ فَلْيُسْلِفْ فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍحَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا إِسْمَاعِيلُ عَنْ ابْنِ أَبِي نَجِيحٍ بِهَذَا فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ","id":"Telah menceritakan kepada kami ['Amru bin Zurarah] telah mengabarkan kepada kami [Isma'il bin 'Ulayyah] telah mengabarkan kepada kami [Ibnu Abi Najih] dari ['Abdullah bin Katsir] dari [Abu Al Minhal] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Ketika Rasulullah shallallahu 'alaihi wasallam tiba di Madinah orang-orang mempraktekan jual beli buah-buahan dengan sistim salaf, yaitu membayar dimuka dan diterima barangnya setelah kurun waktu satu atau dua tahun kemudian atau katanya dua atau tiga tahun kemudian. Isma'il ragu dalam hal ini. Maka Beliau bersabda: \"Siapa yang mempraktekkan salaf dalam jual beli buah-buahan hendaklah dilakukannya dengan takaran dan timbangan yang diketahui (pasti) \". Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Isma'il] dari [Ibnu Abi Najih] seperti redaksi hadits ini: \"dengan takaran dan timbangan yang diketahui (pasti) \". "},"2086":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا ابْنُ عُيَيْنَةَ أَخْبَرَنَا ابْنُ أَبِي نَجِيحٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ أَبِي الْمِنْهَالِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَهُمْ يُسْلِفُونَ بِالتَّمْرِ السَّنَتَيْنِ وَالثَّلَاثَ فَقَالَ مَنْ أَسْلَفَ فِي شَيْءٍ فَفِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍحَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي ابْنُ أَبِي نَجِيحٍ وَقَالَ فَليُسْلِفْ فِي كَيْلٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ أَبِي الْمِنْهَالِ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍ","id":"Telah menceritakan kepada kami [Shadaqah] telah mengabarkan kepada kami [Ibnu 'Uyainah] telah mengabarkan kepada kami [Ibnu Abi Najih] dari ['Abdullah bin Katsir] dari [Abu Al Minhal] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Ketika Rasulullah shallallahu 'alaihi wasallam tiba di Madinah, mereka (penduduk Madinah) mempraktekan jual beli buah-buahan dengan sistim salaf, yaitu membayar dimuka dan diterima barangnya setelah kurun waktu dua atau tiga tahun kemudian, Maka Beliau bersabda: \"Siapa yang mempraktekkan salaf dalam jual beli buah-buahan hendaklah dilakukannya dengan takaran yang diketahui dan timbangan yang diketahui, serta sampai waktu yang di ketahui\". Telah menceritakan kepada kami [Ali] telah mengabarkan kepada kami [Sufyan], dia berkata; telah menceritakan kepadaku [Ibnu Abi Najih], dan beliau bersabda: \"maka hendaklah melakukan salaf dengan timbangan yang di ketahui dan sampai waktu yang di ketahui.\" Telah menceritakan kepada kami [Qutaibah] telah mengabarkan kepada kami [Sufyan] dari [Ibnu Abi Najih] dari [Abdullah bin Katsir], dari [Abu Minhal], dia berkata; aku mendengar ['Ibnu Abbas] radliallahu 'anhuma berkata; Nabi shallallahu 'alaihi wasallam tiba di Madinah, dan beliau bersabda: \"dengan takaran yang diketahui dan sampai waktu yang diketahui (pasti) \"."},"2087":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ ابْنِ أَبِي الْمُجَالِدِ و حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ أَبِي الْمُجَالِدِ حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي مُحَمَّدٌ أَوْ عَبْدُ اللَّهِ بْنُ أَبِي الْمُجَالِدِ قَالَ اخْتَلَفَ عَبْدُ اللَّهِ بْنُ شَدَّادِ بْنِ الْهَادِ وَأَبُو بُرْدَةَ فِي السَّلَفِ فَبَعَثُونِي إِلَى ابْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُ فَسَأَلْتُهُ فَقَالَإِنَّا كُنَّا نُسْلِفُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ فِي الْحِنْطَةِ وَالشَّعِيرِ وَالزَّبِيبِ وَالتَّمْرِوَسَأَلْتُ ابْنَ أَبْزَى فَقَالَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Ibnu Abi Al Mujalid] dan telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Muhammad bin Abi Al Mujalid] telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada saya [Muhammad] atau 'Abdullah bin Abi Al Mujalid berkata; 'Abdullah bin Syaddad bin Al Haad berselisih dengan Abu Burdah tentang sistim jual beli salaf kemudian mereka mengutus aku kepada [Ibnu Abi Aufaa] radliallahu 'anhu, lalu aku tanyakan kepadanya, maka dia berkata: \"Kami pernah mempraktekkan salaf di masa Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, 'Umar pada biji gandum, padi, anggur kering (kismis) dan kurma\". Aku juga menanyakan hal ini kepada [Ibnu Abzaa] lalu dia berkata seperti itu pula. "},"2088":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الشَّيْبَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي الْمُجَالِدِ قَالَ بَعَثَنِي عَبْدُ اللَّهِ بْنُ شَدَّادٍ وَأَبُو بُرْدَةَ إِلَى عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَا فَقَالَا سَلْهُهَلْ كَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْلِفُونَ فِي الْحِنْطَةِ قَالَ عَبْدُ اللَّهِ كُنَّا نُسْلِفُ نَبِيطَ أَهْلِ الشَّأْمِ فِي الْحِنْطَةِ وَالشَّعِيرِ وَالزَّيْتِ فِي كَيْلٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍ قُلْتُ إِلَى مَنْ كَانَ أَصْلُهُ عِنْدَهُ قَالَ مَا كُنَّا نَسْأَلُهُمْ عَنْ ذَلِكَثُمَّ بَعَثَانِي إِلَى عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى فَسَأَلْتُهُ فَقَالَ كَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْلِفُونَ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ نَسْأَلْهُمْ أَلَهُمْ حَرْثٌ أَمْ لَا حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ الشَّيْبَانِيِّ عَنْ مُحَمَّدِ بْنِ أَبِي مُجَالِدٍ بِهَذَا وَقَالَ فَنُسْلِفُهُمْ فِي الْحِنْطَةِ وَالشَّعِيرِ وَقَالَ عَبْدُ اللَّهِ بْنُ الْوَلِيدِ عَنْ سُفْيَانَ حَدَّثَنَا الشَّيْبَانِيُّ وَقَالَ وَالزَّيْتِ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الشَّيْبَانِيِّ وَقَالَ فِي الْحِنْطَةِ وَالشَّعِيرِ وَالزَّبِيبِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Asy-Syaibaniy] telah menceritakan kepada kami [Muhammad bin Abi Al Mujalid] berkata; 'Abdullah bin Syaddad dan Abu Burdah mengutusku untuk menemui ['Abdullah bin Abi Aufaa] radliallahu 'anhuma dan keduanya berkata; Tanyakanlah kepadanya apakah para sahabat Nabi shallallahu 'alaihi wasallam di zaman Nabi shallallahu 'alaihi wasallam mempraktekkan jual beli salaf pada biji gandum?\" Berkata 'Abdullah; \"Kami mempraktekkan salaf dengan orang-orang blasteran bangsa Syam pada biji gandum, beras dan kismis dengan takaran yang pasti sampai waktu yang pasti pula\". Aku tanyakan: \"Kepada siapa asalnya diserahkan?. Dia berkata: \"Kami tidak pernah menanyakan hal ini kepada mereka\". Kemudian keduanya mengutus aku untuk menemui ['Abdurrahman bin Abzaa] lalu aku tanyakan, maka dia berkata: \"Para sahabat Nabi shallallahu 'alaihi wasallam mempraktekkan salaf di zaman Nabi shallallahu 'alaihi wasallam dan kami tidak pernah menanyakan kepada mereka apakah mereka memiliki pertanian atau tidak?\" Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Khalid bin 'Abdullah] dari [Asy-Syaibaniy] dari [Muhammad bin Abi Mujalid] dengan redaksi seperti ini dan dia berkata: \"Kami mempraktekkan salaf pada biji gandum. Dan berkata, ['Abdullah bin Al Walid] dari [Sufyan] telah menceritakan kepada kami [Asy-Syaibaniy] dan berkata: \"Dan juga pada kismis\". Telah menceritakan kepada kami [Quaibah] telah menceritakan kepada kami [Jarir] dari [Asy-Syaibaniy] dan berkata: \"Pada biji gandum, padi dan kismis\". "},"2089":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا عَمْرٌو قَالَ سَمِعْتُ أَبَا الْبَخْتَرِيِّ الطَّائِيَّ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ السَّلَمِ فِي النَّخْلِ قَالَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ النَّخْلِ حَتَّى يُوكَلَ مِنْهُ وَحَتَّى يُوزَنَ فَقَالَ الرَّجُلُ وَأَيُّ شَيْءٍ يُوزَنُ قَالَ رَجُلٌ إِلَى جَانِبِهِ حَتَّى يُحْرَزَوَقَالَ مُعَاذٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو قَالَ أَبُو الْبَخْتَرِيِّ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami ['Amru] berkata; Aku mendengar [Abu Al Bakhtariy Ath-Tho'iy] berkata: \"Aku bertanya kepada [Ibnu 'Abbas radliallahu 'anhuma] tentang As-Salam pada pohon kurma. Maka dia berkata: \"Nabi shallallahu 'alaihi wasallam telah melarang menjual pohon kurma hingga buahnya layak dimakan dan ditimbang\". Berkata, seseorang: \"Bagaimana caranya ditimbang?\" Berkata, seseorang yang ada di sebelahnya: \"Hingga bisa dipelihara (dismpan). Dan berkata, [Mu'adz] telah menceritakan kepada kami [Syu'bah] dari ['Amru] berkata, [Abu Al Bakhtariy] aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam melarang hal yang semacam itu\"."},"2090":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو عَنْ أَبِي الْبَخْتَرِيِّ قَالَ سَأَلْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ السَّلَمِ فِي النَّخْلِ فَقَالَ نُهِيَ عَنْ بَيْعِ النَّخْلِ حَتَّى يَصْلُحَ وَعَنْ بَيْعِ الْوَرِقِ نَسَاءً بِنَاجِزٍوَسَأَلْتُ ابْنَ عَبَّاسٍ عَنْ السَّلَمِ فِي النَّخْلِ فَقَالَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ النَّخْلِ حَتَّى يُؤْكَلَ مِنْهُ أَوْ يَأْكُلَ مِنْهُ وَحَتَّى يُوزَنَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Amru] dari [Abu Al Bakhtariy] berkata: \"Aku bertanya kepada [Ibnu'Umar radliallahu 'anhuma] tentang As-Salam pada pohon kurma. Maka dia berkata: \"Dilarang menjual pohon kurma hingga buahnya baik (bisa dimakan) dan dilarang pula menjual emas dengan cara tempo\". Dan aku bertanya kepada [Ibnu 'Abbas radliallahu 'anhu] tentang As-Salam pada pohon kurma. Maka dia menjawab: \"Nabi shallallahu 'alaihi wasallam melarang jual beli pohon kurma hingga buahnya bisa dimakan atau dapat dimakan dan hingga ditimbang\"."},"2091":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو عَنْ أَبِي الْبَخْتَرِيِّ سَأَلْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ السَّلَمِ فِي النَّخْلِ فَقَالَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الثَّمَرِ حَتَّى يَصْلُحَ وَنَهَى عَنْ الْوَرِقِ بِالذَّهَبِ نَسَاءً بِنَاجِزٍوَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ النَّخْلِ حَتَّى يَأْكُلَ أَوْ يُؤْكَلَ وَحَتَّى يُوزَنَ قُلْتُ وَمَا يُوزَنُ قَالَ رَجُلٌ عِنْدَهُ حَتَّى يُحْرَزَ","id":"Telah menceritakan kepada kami [Muhammad bin BAsysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari ['Amru] dari [Abu Al Bakhtariy]: \"Aku bertanya kepada [Ibnu'Umar radliallahu 'anhuma] tentang As-Salam pada pohon kurma. Maka dia berkata: \"Nabi shallallahu 'alaihi wasallam telah melarang menjual buah-buahan hingga buahnya telah baik dan melarang menjual emas dengan emas dengan cara tempo\". Dan aku bertanya kepada [Ibnu 'Abbas radliallahu 'anhu], maka dia berkata: \"Nabi shallallahu 'alaihi wasallam melarang jual beli pohon kurma hingga buahnya bisa dimakan atau dapat dimakan dan hingga ditimbang\". Aku bertanya: \"Bagaimana caranya ditimbang?\" Berkata seseorang yang ada di sebelahnya: \"Hingga bisa dipelihara (disimpan) \". "},"2092":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَّامٍ حَدَّثَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاشْتَرَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا مِنْ يَهُودِيٍّ بِنَسِيئَةٍ وَرَهَنَهُ دِرْعًا لَهُ مِنْ حَدِيدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah menceritakan kepada kami [Ya'laa] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata; \"Rasulullah shallallahu 'alaihi wasallam membeli makanan dari orang Yahudi dengan cara pembayaran di belakang, dan Beliau gadaikan baju besi Beliau (sebagai jaminan) \"."},"2093":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مَحْبُوبٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ قَالَ تَذَاكَرْنَا عِنْدَ إِبْرَاهِيمَ الرَّهْنَ فِي السَّلَفِ فَقَالَ حَدَّثَنِي الْأَسْوَدُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى مِنْ يَهُودِيٍّ طَعَامًا إِلَى أَجَلٍ مَعْلُومٍ وَارْتَهَنَ مِنْهُ دِرْعًا مِنْ حَدِيدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Mahbub] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Al A'masy] berkata; \"Kami pernah saling menceritakan dihadapan [Ibrahim] tentang jual beli As-Salaf, maka dia berkata; Telah telah menceritakan kepada saya [Al Aswad] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam pernah membeli makanan dari orang Yahudi (dengan pembayaran di belakang dengan ketentuan waktu tertentu) dan beliau gadaikan baju besi Beliau (sebagai jaminan) \"."},"2094":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ عَنْ أَبِي الْمِنْهَالِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَهُمْ يُسْلِفُونَ فِي الثِّمَارِ السَّنَتَيْنِ وَالثَّلَاثَ فَقَالَ أَسْلِفُوا فِي الثِّمَارِ فِي كَيْلٍ مَعْلُومٍ إِلَى أَجَلٍ مَعْلُومٍوَقَالَ عَبْدُ اللَّهِ بْنُ الْوَلِيدِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ أَبِي نَجِيحٍ وَقَالَ فِي كَيْلٍ مَعْلُومٍ وَوَزْنٍ مَعْلُومٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abi Najih] dari ['Abdullah bin Katsir] dari [Abu Al Minhal] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Ketika Rasulullah shallallahu 'alaihi wasallam tiba di Madinah orang-orang mempraktekkan jual beli buah-buahan dengan sistim salaf, yaitu membayar dimuka dan diterima barangnya setelah kurun waktu dua atau tiga tahun. Maka Beliau bersabda: \"Lakukanlah jual beli salaf pada buah-buahan dengan takaran sampai waktu yang diketahui (pasti) \". Dan berkata ['Abdullah bin Al Walid] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnu Abi Najih] dan berkata: \"dengan takaran dan timbangan yang diketahui (pasti) \"."},"2095":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سُفْيَانُ عَنْ سُلَيْمَانَ الشَّيْبَانِيِّ عَنْ مُحَمَّدِ بْنِ أَبِي مُجَالِدٍ قَالَ أَرْسَلَنِي أَبُو بُرْدَةَ وَعَبْدُ اللَّهِ بْنُ شَدَّادٍ إِلَى عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى وَعَبْدِ اللَّهِ بْنِ أَبِي أَوْفَىفَسَأَلْتُهُمَا عَنْ السَّلَفِ فَقَالَا كُنَّا نُصِيبُ الْمَغَانِمَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يَأْتِينَا أَنْبَاطٌ مِنْ أَنْبَاطِ الشَّأْمِ فَنُسْلِفُهُمْ فِي الْحِنْطَةِ وَالشَّعِيرِ وَالزَّبِيبِ إِلَى أَجَلٍ مُسَمَّى قَالَ قُلْتُ أَكَانَ لَهُمْ زَرْعٌ أَوْ لَمْ يَكُنْ لَهُمْ زَرْعٌ قَالَا مَا كُنَّا نَسْأَلُهُمْ عَنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Sufyan] dari [Sulaiman Asy-Syaibaniy] dari [Muhammad bin Abi Al Mujalid] berkata; 'Abdullah bin Syaddad dan Abu Burdah mengutusku untuk menemui ['Abdurrahman bin Abzaa] dan ['Abdullah bin Abi Aufaa] lalu aku menanyakan keduanya tentang jual beli As-Salaf. Keduanya berkata: \"Kami pernah mendapatkan ghanimah (harta rampasan perang) bersama Rasulullah shallallahu 'alaihi wasallam lalu datang kepada kami bangsa blasteran dari penduduk negeri Syam, kemudian kami berjual beli dengan cara As-Salaf pada biji gandum, padi dan kismis untuk jangka waktu tertentu\". Dia berkata; Aku tanyakan: \"Apakah saat itu mereka memiliki pertanian atau tidak?\" Keduanya menjawab: \"Kami tidak pernah menanyakan hal itu kepada mereka.\""},"2096":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ أَخْبَرَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانُوا يَتَبَايَعُونَ الْجَزُورَ إِلَى حَبَلِ الْحَبَلَةِ فَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُ فَسَّرَهُ نَافِعٌ أَنْ تُنْتَجَ النَّاقَةُ مَا فِي بَطْنِهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah mengabarkan kepada kami [Juwairiyah] dari [Nafi'] dari ['Abdullah radliallahu 'anhu] berkata: \"Dahulu orang-orang Jahiliyah mempraktekkan jual beli apa yang ada didalam perut unta hingga unta itu melahirkan kemudian Nabi shallallahu 'alaihi wasallam melarangnya. Nafi' menafsirkan yang dimaksud dengan Al Jazur adalah: Unta melahirkan apa yang ada didalam perutnya\"."},"2097":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالشُّفْعَةِ فِي كُلِّ مَا لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَصُرِّفَتْ الطُّرُقُ فَلَا شُفْعَةَ","id":"Telah menceritakan kepada saya [Musaddad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhriy] dari [Abu Salamah bin 'Abdurrahman] dari [Jabir bin 'Abdullah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam telah menetapkan hak Asy-Syuf'ah pada setiap harta yang belum dibagi. Apabila terdapat pembatas dan jalan yang terpisah maka tidak ada syuf'ah\". "},"2098":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ مَيْسَرَةَ عَنْ عَمْرِو بْنِ الشَّرِيدِ قَالَ وَقَفْتُ عَلَى سَعْدِ بْنِ أَبِي وَقَّاصٍ فَجَاءَ الْمِسْوَرُ بْنُ مَخْرَمَةَ فَوَضَعَ يَدَهُ عَلَى إِحْدَى مَنْكِبَيَّ إِذْ جَاءَ أَبُو رَافِعٍ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَفَقَالَ يَا سَعْدُ ابْتَعْ مِنِّي بَيْتَيَّ فِي دَارِكَ فَقَالَ سَعْدٌ وَاللَّهِ مَا أَبْتَاعُهُمَا فَقَالَ الْمِسْوَرُ وَاللَّهِ لَتَبْتَاعَنَّهُمَا فَقَالَ سَعْدٌ وَاللَّهِ لَا أَزِيدُكَ عَلَى أَرْبَعَةِ آلَافٍ مُنَجَّمَةً أَوْ مُقَطَّعَةً قَالَ أَبُو رَافِعٍ لَقَدْ أُعْطِيتُ بِهَا خَمْسَ مِائَةِ دِينَارٍ وَلَوْلَا أَنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْجَارُ أَحَقُّ بِسَقَبِهِ مَا أَعْطَيْتُكَهَا بِأَرْبَعَةِ آلَافٍ وَأَنَا أُعْطَى بِهَا خَمْسَ مِائَةِ دِينَارٍ فَأَعْطَاهَا إِيَّاهُ","id":"Telah menceritakan kepada kami [Al Makkiy bin Ibrahim] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepada saya [Ibrahim bin Maisarah] dari ['Amru bin Asy-Syarid] berkata; Aku pernah duduk bersama Sa'ad bin Abi Waqash lalu datang Al Miswar bin Makhramah kemudian dia meletakkan tangannya pada salah satu pundakku lalu datang [Abu Rafi'] maula Nabi shallallahu 'alaihi wasallam seraya berkata: \"Wahai Sa'ad, belilah dua buah rumahku yang ada di kampungmu!\" Sa'ad berkata: \"Demi Allah, aku tidak akan membelinya\". Lalu Al Miswar berkata: \"Demi Allah, aku yang akan membelinya\". Maka Saad berkata: \"Demi Allah, aku tidak akan membelinya lebih dari empat ribu keping\". Abu Rafi' berkata: \"Sungguh aku telah memberikan kepadanya lima ratus dinar, seandainya aku tidak mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tetangga lebih patut dalam hal kedekatan, tidaklah akan aku berikan rumah itu dengan harga empat ribu keeping sekalipun, sedangkan kali ini hanya aku dapatkan lima ratus dinar.\" Dia pun lantas memberikan rumahnya."},"2099":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنِي عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو عِمْرَانَ قَالَ سَمِعْتُ طَلْحَةَ بْنَ عَبْدِ اللَّهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي جَارَيْنِ فَإِلَى أَيِّهِمَا أُهْدِي قَالَ إِلَى أَقْرَبِهِمَا مِنْكِ بَابًا","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Syu'bah] dan diriwayatkan pula, telah menceritakan kepada saya ['Ali bin 'Abdullah] telah menceritakan kepada kami [Syababah] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu 'Imran] berkata; Aku mendengar [Tholhah bin 'Abdullah] dari ['Aisyah radliallahu 'anha] ' Aku bertanya: \"Wahai Rasulullah, aku punya dua tetangga, kepada siapa dari keduanya yang paling berhak untuk aku beri hadiah?\" Beliau bersabda: \"Kepada yang paling dekat pintu rumahnya darimu\"."},"2100":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي بُرْدَةَ قَالَ أَخْبَرَنِي جَدِّي أَبُو بُرْدَةَ عَنْ أَبِيهِ أَبِي مُوسَى الْأَشْعَرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَازِنُ الْأَمِينُ الَّذِي يُؤَدِّي مَا أُمِرَ بِهِ طَيِّبَةً نَفْسُهُ أَحَدُ الْمُتَصَدِّقِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abu Burdah] berkata, telah mengabarkan kepada saya [kakekku Abu Burdah] dari [Bapaknya Abu Musa Al Anshariy radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Bendahara yang terpercaya yang menunaikan tugas yang diembannya dengan baik adalah terhitung salah satu Al Mutashaddiqin (orang yang bersedekah) \"."},"2101":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ قُرَّةَ بْنِ خَالِدٍ قَالَ حَدَّثَنِي حُمَيْدُ بْنُ هِلَالٍ حَدَّثَنَا أَبُو بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَأَقْبَلْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي رَجُلَانِ مِنْ الْأَشْعَرِيِّينَ فَقُلْتُ مَا عَمِلْتُ أَنَّهُمَا يَطْلُبَانِ الْعَمَلَ فَقَالَ لَنْ أَوْ لَا نَسْتَعْمِلُ عَلَى عَمَلِنَا مَنْ أَرَادَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Qurrah bin Khalid] berkata, telah menceritakan kepada saya [Humaid bin Hilal] telah menceritakan kepada kami [Abu Burdah] dari [Abu Musa radliallahu 'anhu] berkata; Aku menghadap menemui Nabi shallallahu 'alaihi wasallam bersama dua orang suku Al Asyariyyin, aku bertanya: \"Apa yang harus aku lakukan bila keduanya mengharapkan pekerjaan?\" Beliau bersabda: \"Sekali-kali jangan atau janganlah engkau memperkerjakan dalam urusan kita ini orang yang berambisi menginginkannya\"."},"2102":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَكِّيُّ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ جَدِّهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَعَثَ اللَّهُ نَبِيًّا إِلَّا رَعَى الْغَنَمَ فَقَالَ أَصْحَابُهُ وَأَنْتَ فَقَالَ نَعَمْ كُنْتُ أَرْعَاهَا عَلَى قَرَارِيطَ لِأَهْلِ مَكَّةَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Makkiy] telah menceritakan kepada kami ['Amru bin Yahya] dari [kakeknya] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah Allah mengutus seorang Nabi melainkan dia mengembalakan kambing\". Para sahabat bertanya: \"Termasuk engkau juga?\" Maka Beliau menjawab: \"Ya, aku pun mengembalakannya dengan upah beberapa qirat (keping dinar) milik penduduk Makkah\". "},"2103":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاوَاسْتَأْجَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ رَجُلًا مِنْ بَنِي الدِّيلِ ثُمَّ مِنْ بَنِي عَبْدِ بْنِ عَدِيٍّ هَادِيًا خِرِّيتًا الْخِرِّيتُ الْمَاهِرُ بِالْهِدَايَةِ قَدْ غَمَسَ يَمِينَ حِلْفٍ فِي آلِ الْعَاصِ بْنِ وَائِلٍ وَهُوَ عَلَى دِينِ كُفَّارِ قُرَيْشٍ فَأَمِنَاهُ فَدَفَعَا إِلَيْهِ رَاحِلَتَيْهِمَا وَوَاعَدَاهُ غَارَ ثَوْرٍ بَعْدَ ثَلَاثِ لَيَالٍ فَأَتَاهُمَا بِرَاحِلَتَيْهِمَا صَبِيحَةَ لَيَالٍ ثَلَاثٍ فَارْتَحَلَا وَانْطَلَقَ مَعَهُمَا عَامِرُ بْنُ فُهَيْرَةَ وَالدَّلِيلُ الدِّيلِيُّ فَأَخَذَ بِهِمْ أَسْفَلَ مَكَّةَ وَهُوَ طَرِيقُ السَّاحِلِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhriy] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha]: Nabi shallallahu 'alaihi wasallam dan Abu Bakar menyewa seorang dari suku Ad-Dil kemudian dari suku 'Abdi bin 'Adiy sebagai petunjuk jalan dan yang mahir menguasai seluk beluk perjalanan yang sebelumnya dia telah diambil sumpahnya pada keluarga Al 'Ash bin Wa'il dan masih memeluk agama kafir Quraisy. Maka keduanya mempercayakan kepadanya perjalanan keduanya lalu keduanya meminta kepadanya untuk singgah di gua Tsur setelah perjalanan tiga malam. Lalu orang itu meneruskan perjalanan keduanya waktu shubuh malam ketiga, maka keduanya melanjutkan perjalanan dan berangkat pula bersama keduanya 'Amir bin Fuhairah dan petunjuk jalan suku Ad-Diliy tersebut. Maka petunjuk jalan tersebut mengambil jalan dari belakang kota Makkah yaitu menyusuri jalan laut. "},"2104":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْوَاسْتَأْجَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ رَجُلًا مِنْ بَنِي الدِّيلِ هَادِيًا خِرِّيتًا وَهُوَ عَلَى دِينِ كُفَّارِ قُرَيْشٍ فَدَفَعَا إِلَيْهِ رَاحِلَتَيْهِمَا وَوَاعَدَاهُ غَارَ ثَوْرٍ بَعْدَ ثَلَاثِ لَيَالٍ بِرَاحِلَتَيْهِمَا صُبْحَ ثَلَاثٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] berkata, [Ibnu Syihab] telah mengabarkan kepada saya ['Urwah bin Az Zubair] bahwa ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam berkata: Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar menyewa seorang dari suku Ad-Dil sebagai petunjuk jalan yang dipercaya yang orang itu masih memeluk agama kafir Quraisy. Maka keduanya mempercayakan kepadanya perjalanan keduanya lalu keduanya meminta kepadanya untuk singgah di gua Tsur setelah perjalanan tiga malam. "},"2105":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عُلَيَّةَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ يَعْلَى بْنِ أُمَيَّةَ رَضِيَ اللَّهُ عَنْهُ قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَيْشَ الْعُسْرَةِ فَكَانَ مِنْ أَوْثَقِ أَعْمَالِي فِي نَفْسِي فَكَانَ لِي أَجِيرٌ فَقَاتَلَ إِنْسَانًا فَعَضَّ أَحَدُهُمَا إِصْبَعَ صَاحِبِهِ فَانْتَزَعَ إِصْبَعَهُ فَأَنْدَرَ ثَنِيَّتَهُ فَسَقَطَتْ فَانْطَلَقَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهْدَرَ ثَنِيَّتَهُ وَقَالَ أَفَيَدَعُ إِصْبَعَهُ فِي فِيكَ تَقْضَمُهَا قَالَ أَحْسِبُهُ قَالَ كَمَا يَقْضَمُ الْفَحْلُقَالَ ابْنُ جُرَيْجٍ وَحَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ عَنْ جَدِّهِ بِمِثْلِ هَذِهِ الصِّفَةِ أَنَّ رَجُلًا عَضَّ يَدَ رَجُلٍ فَأَنْدَرَ ثَنِيَّتَهُ فَأَهْدَرَهَا أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Atha'] dari [Shafwan bin Ya'laa] dari [Ya'laa bin Umayyah radliallahu 'anhu] berkata; Aku ikut perang dalam pasukan masa paceklik (pasukan perang Tabuk) dan itu merupakan amalku yang paling berkesan dalam jiwaku. Saat itu aku memiliki orang bayaran lalu dia memerangi seorang musuh salah satu diantaranya menggigit jari lawannya hingga jari lawannya putus lalu jatuh. Lalu dia menemui Nabi shallallahu 'alaihi wasallam lalu Beliau tidak menerapkan diyat atau tebusan kepada salah satunya dan bersabda: \"Apakah dia melepaskan jarinya dalam mulutmu?\" Orang itu berkata: \"Aku kira begitu\". Lalu Beliau bersabda: \"Seperti unta mengigitnya\". Berkata, [Ibnu Juraij] dan telah menceritakan kepada saya ['Abdullah bin Abi Mulaikah] dari [kakeknya] seperti redaksi hadits ini, yang salah seorang menggigit jari lawannya lalu dibebasakan dari segala tuntutan oleh Abu Bakar radliallahu 'anhu."},"2106":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي يَعْلَى بْنُ مُسْلِمٍ وَعَمْرُو بْنُ دِينَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ يَزِيدُ أَحَدُهُمَا عَلَى صَاحِبِهِ وَغَيْرُهُمَا قَالَ قَدْ سَمِعْتُهُ يُحَدِّثُهُ عَنْ سَعِيدٍ قَالَ قَالَ لِي ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَا فَوَجَدَا جِدَارًا يُرِيدُ أَنْ يَنْقَضَّقَالَ سَعِيدٌ بِيَدِهِ هَكَذَا وَرَفَعَ يَدَيْهِ فَاسْتَقَامَ قَالَ يَعْلَى حَسِبْتُ أَنْ سَعِيدًا قَالَ فَمَسَحَهُ بِيَدِهِ فَاسْتَقَامَ{ لَوْ شِئْتَ لَاتَّخَذْتَ عَلَيْهِ أَجْرًا }قَالَ سَعِيدٌ أَجْرًا نَأْكُلُهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] mengabarkan mereka berkata, telah mengabarkan kepada saya [Ya'laa bin Muslim] dan ['Amru bin Dinar] dari [Sa'id bin Jubair] salah satu diantara keduanya menambahkan kepada temannya dan selain keduanya berkata, aku mendengar dia menceritakan dari Sa'id berkata; Berkata, kepadaku [Ibnu 'Abbas radliallahu 'anhuma] telah menceritakan kepada saya [Ubay bin Ka'ab] berkata, telah bersabda Rasulullah shallallahu 'alaihi wasallam: \"(Keduanya berangkat lalu mendapatkan dinding yang hampir roboh lalu ditegakkan kembali\"). Berkata, Sa'id: \"Ditegakkan dengan tangannya begini\". Maka Beliau mengangkat tangannya maka dinding itu kembali tegak kokoh\". Ya'laa berkata: \"Aku menduga bahwa Sa'id berkata: Maka diusapnya dinding itu dengan tangannya lalu tegak kembali\". (\"Seandainya engkau mau kamu berhak atas upah\"), Berkata, Sa'id: Upah yang bisa kita nikmati\"."},"2107":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُكُمْ وَمَثَلُ أَهْلِ الْكِتَابَيْنِ كَمَثَلِ رَجُلٍ اسْتَأْجَرَ أُجَرَاءَ فَقَالَ مَنْ يَعْمَلُ لِي مِنْ غُدْوَةَ إِلَى نِصْفِ النَّهَارِ عَلَى قِيرَاطٍ فَعَمِلَتْ الْيَهُودُ ثُمَّ قَالَ مَنْ يَعْمَلُ لِي مِنْ نِصْفِ النَّهَارِ إِلَى صَلَاةِ الْعَصْرِ عَلَى قِيرَاطٍ فَعَمِلَتْ النَّصَارَى ثُمَّ قَالَ مَنْ يَعْمَلُ لِي مِنْ الْعَصْرِ إِلَى أَنْ تَغِيبَ الشَّمْسُ عَلَى قِيرَاطَيْنِ فَأَنْتُمْ هُمْ فَغَضِبَتْ الْيَهُودُ وَالنَّصَارَى فَقَالُوا مَا لَنَا أَكْثَرَ عَمَلًا وَأَقَلَّ عَطَاءً قَالَ هَلْ نَقَصْتُكُمْ مِنْ حَقِّكُمْ قَالُوا لَا قَالَ فَذَلِكَ فَضْلِي أُوتِيهِ مَنْ أَشَاءُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Perumpamaan kalian dibandingkan Ahul Kitab seperti seseorang yang menyewa para pekerja yang dia berkata; \"Siapa yang mau bekerja untukku dari pagi hingga pertengahan siang dengan upah satu qirath, maka orang-orang Yahudi melaksanakannya. Kemudian dia berkata, \"Siapa yang mau bekerja untukku dari pertengahan siang hingga shalat 'Ashar dengan upah satu qirath, maka orang-orang Nashrani mengerjakannya. Kemudain orang itu berkata, lagi: \"Siapa yang mau bekerja untukku dari 'Ashar hinga terbenamnya matahari dengan upah dua qirath, maka kalianlah orang yang mengerjakannya. Maka orang-orang Yahudi dan Nashrani marah seraya berkata: \"Bagaimana bisa, kami yang mengerjakan lebih banyak pekerjaan namun lebih sedikit upah yang kami terima!\" Lalu orang itu berkata: \"Apakah ada hak kalian yang aku kurangi?\" Mereka menjawab: \"Tidak ada\". Orang itu berkata: \"Itulah karunia dariku yang aku memberikannya kepada siapa yang aku kehendaki\"."},"2108":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا مَثَلُكُمْ وَالْيَهُودُ وَالنَّصَارَى كَرَجُلٍ اسْتَعْمَلَ عُمَّالًا فَقَالَ مَنْ يَعْمَلُ لِي إِلَى نِصْفِ النَّهَارِ عَلَى قِيرَاطٍ قِيرَاطٍ فَعَمِلَتْ الْيَهُودُ عَلَى قِيرَاطٍ قِيرَاطٍ ثُمَّ عَمِلَتْ النَّصَارَى عَلَى قِيرَاطٍ قِيرَاطٍ ثُمَّ أَنْتُمْ الَّذِينَ تَعْمَلُونَ مِنْ صَلَاةِ الْعَصْرِ إِلَى مَغَارِبِ الشَّمْسِ عَلَى قِيرَاطَيْنِ قِيرَاطَيْنِ فَغَضِبَتْ الْيَهُودُ وَالنَّصَارَى وَقَالُوا نَحْنُ أَكْثَرُ عَمَلًا وَأَقَلُّ عَطَاءً قَالَ هَلْ ظَلَمْتُكُمْ مِنْ حَقِّكُمْ شَيْئًا قَالُوا لَا فَقَالَ فَذَلِكَ فَضْلِي أُوتِيهِ مَنْ أَشَاءُ","id":"Telah menceritakan kepada kami [Isma'il bin Abi Uwais] berkata, telah menceritakan kepadaku [Malik] dari ['Abdullah bin Dinar, maula 'Abdullah bin 'Umar] dari ['Abdullah bin 'Umar bin Al Khaththab radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perumpamaan kalian dibandingkan orang-orang Yahudi dan Nashrani seperti seseorang yang memperkerjakan para pekerja yang dia berkata; \"Siapa yang mau bekerja untukku hingga pertengahan siang dengan upah satu qirath, maka orang-orang Yahudi melaksanakannya dengan upah satu qirath per satu qirath. Lalu orang-orang Nashrani mengerjakannya dengan upah satu qirath per satu qirath. Kemudian kalian mengerjakan mulai dari shalat 'Ashar hingga terbenamnya matahari dengan upah dua qirath per dua qirath. Maka orang-orang Yahudi dan Nashrani marah seraya berkata: \"Kami yang lebih banyak amal namun lebih sedikit upah!\" Lalu orang itu berkata; \"Apakah ada yang aku zhalimi dari hak kalian?\" Mereka menjawab; \"Tidak ada\". Orang itu berkata; \"Itulah karunia dari-Ku yang Aku memberikannya kepada siapa yang aku kehendaki\". "},"2109":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ سُلَيْمٍ عَنْ إِسْمَاعِيلَ بْنِ أُمَيَّةَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ تَعَالَى ثَلَاثَةٌ أَنَا خَصْمُهُمْ يَوْمَ الْقِيَامَةِ رَجُلٌ أَعْطَى بِي ثُمَّ غَدَرَ وَرَجُلٌ بَاعَ حُرًّا فَأَكَلَ ثَمَنَهُ وَرَجُلٌ اسْتَأْجَرَ أَجِيرًا فَاسْتَوْفَى مِنْهُ وَلَمْ يُعْطِهِ أَجْرَهُ","id":"Telah menceritakan kepada saya [Yusuf bin Muhammad] berkata, telah menceritakan kepada saya [Yahya bin Sulaim] dari [Isma'il bin Umayyah] dari [Sa'id bin Abi Sa'id] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: Ada tiga jenis orang yag aku berperang melawan mereka pada hari qiyamat, seseorang yang bersumpah atas namaku lalu mengingkarinya, seseorang yang berjualan orang merdeka lalu memakan (uang dari) harganya dan seseorang yang memperkerjakan pekerja kemudian pekerja itu menyelesaikan pekerjaannya namun tidak dibayar upahnya\"."},"2110":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْمُسْلِمِينَ وَالْيَهُودِ وَالنَّصَارَى كَمَثَلِ رَجُلٍ اسْتَأْجَرَ قَوْمًا يَعْمَلُونَ لَهُ عَمَلًا يَوْمًا إِلَى اللَّيْلِ عَلَى أَجْرٍ مَعْلُومٍ فَعَمِلُوا لَهُ إِلَى نِصْفِ النَّهَارِ فَقَالُوا لَا حَاجَةَ لَنَا إِلَى أَجْرِكَ الَّذِي شَرَطْتَ لَنَا وَمَا عَمِلْنَا بَاطِلٌ فَقَالَ لَهُمْ لَا تَفْعَلُوا أَكْمِلُوا بَقِيَّةَ عَمَلِكُمْ وَخُذُوا أَجْرَكُمْ كَامِلًا فَأَبَوْا وَتَرَكُوا وَاسْتَأْجَرَ أَجِيرَيْنِ بَعْدَهُمْ فَقَالَ لَهُمَا أَكْمِلَا بَقِيَّةَ يَوْمِكُمَا هَذَا وَلَكُمَا الَّذِي شَرَطْتُ لَهُمْ مِنْ الْأَجْرِ فَعَمِلُوا حَتَّى إِذَا كَانَ حِينُ صَلَاةِ الْعَصْرِ قَالَا لَكَ مَا عَمِلْنَا بَاطِلٌ وَلَكَ الْأَجْرُ الَّذِي جَعَلْتَ لَنَا فِيهِ فَقَالَ لَهُمَا أَكْمِلَا بَقِيَّةَ عَمَلِكُمَا مَا بَقِيَ مِنْ النَّهَارِ شَيْءٌ يَسِيرٌ فَأَبَيَا وَاسْتَأْجَرَ قَوْمًا أَنْ يَعْمَلُوا لَهُ بَقِيَّةَ يَوْمِهِمْ فَعَمِلُوا بَقِيَّةَ يَوْمِهِمْ حَتَّى غَابَتْ الشَّمْسُ وَاسْتَكْمَلُوا أَجْرَ الْفَرِيقَيْنِ كِلَيْهِمَا فَذَلِكَ مَثَلُهُمْ وَمَثَلُ مَا قَبِلُوا مِنْ هَذَا النُّورِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Alaa'] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Perumpamaan Kaum Muslimin dibandingkan orang-orang Yahudi dan Nashrani seperti seseorang yang memperkerjakan kaum yang bekerja untuknya pada suatu hari hingga malam dengan upah yang ditentukan. Maka diantara mereka ada yang melaksanakan pekerjaan hingga pertengahan siang lalu berkata: Kami tidak memerlukan upah darimu sebagaimana yang kamu persyaratkan kepada kami (bekerja hingga malam) dan apa yang telah kami kerjakan biarlah nggak apa-apa\". Maka orang itu berkata: \"Selesaikanlah sisa pekerjaan, nanti baru kalian boleh mengambil upahnya dengan penuh\". Maka mereka tidak mau dan tidak melanjutkan pekerjaan mereka. Kemudian dia memperkerjakan dua orang pekerja setelah mereka untuk menuntaskan sisa pekerjaan dan berkata, kepada keduanya: \"Selesaikanlah sisa waktu hari kalian ini dan bagi kalian berdua akan mendapatkan upah sebagaimana yang aku syaratkan kepada mereka. Maka mereka berdua mengerjakannya hingga ketika sampai saat shalat 'Ashar, keduanya berkata, \" Tidaklah yang kami telah kerjakan sia-sia dan kamu wajib membayar upah seperti yang kamu janjikan kepada kami berdua\". Maka orang itu berkata, kepada keduanya: \"Selesaikanlah sisa pekerjaan kalian berdua yang tidak sampai separuh hari ini\". Namun kedua orang itu enggan melanjutkannya. Lalu orang itu memperkerjakan suatu kaum yang mengerjakan sisa hari. Maka kaum itu mengerjakan sisa pekerjaan hingga terbenam matahari dan mereka mendapatkan upah secara penuh termasuk upah dari pekerjaan yang sudah dikerjakan oleh dua golongan orang sebelum mereka. Itulah perumpamaan mereka dan mereka ang menerima cahaya (Islam) ini\". "},"2111":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ انْطَلَقَ ثَلَاثَةُ رَهْطٍ مِمَّنْ كَانَ قَبْلَكُمْ حَتَّى أَوَوْا الْمَبِيتَ إِلَى غَارٍ فَدَخَلُوهُ فَانْحَدَرَتْ صَخْرَةٌ مِنْ الْجَبَلِ فَسَدَّتْ عَلَيْهِمْ الْغَارَ فَقَالُوا إِنَّهُ لَا يُنْجِيكُمْ مِنْ هَذِهِ الصَّخْرَةِ إِلَّا أَنْ تَدْعُوا اللَّهَ بِصَالِحِ أَعْمَالِكُمْ فَقَالَ رَجُلٌ مِنْهُمْ اللَّهُمَّ كَانَ لِي أَبَوَانِ شَيْخَانِ كَبِيرَانِ وَكُنْتُ لَا أَغْبِقُ قَبْلَهُمَا أَهْلًا وَلَا مَالًا فَنَأَى بِي فِي طَلَبِ شَيْءٍ يَوْمًا فَلَمْ أُرِحْ عَلَيْهِمَا حَتَّى نَامَا فَحَلَبْتُ لَهُمَا غَبُوق��هُمَا فَوَجَدْتُهُمَا نَائِمَيْنِ وَكَرِهْتُ أَنْ أَغْبِقَ قَبْلَهُمَا أَهْلًا أَوْ مَالًا فَلَبِثْتُ وَالْقَدَحُ عَلَى يَدَيَّ أَنْتَظِرُ اسْتِيقَاظَهُمَا حَتَّى بَرَقَ الْفَجْرُ فَاسْتَيْقَظَا فَشَرِبَا غَبُوقَهُمَا اللَّهُمَّ إِنْ كُنْتُ فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَفَرِّجْ عَنَّا مَا نَحْنُ فِيهِ مِنْ هَذِهِ الصَّخْرَةِ فَانْفَرَجَتْ شَيْئًا لَا يَسْتَطِيعُونَ الْخُرُوجَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ الْآخَرُ اللَّهُمَّ كَانَتْ لِي بِنْتُ عَمٍّ كَانَتْ أَحَبَّ النَّاسِ إِلَيَّ فَأَرَدْتُهَا عَنْ نَفْسِهَا فَامْتَنَعَتْ مِنِّي حَتَّى أَلَمَّتْ بِهَا سَنَةٌ مِنْ السِّنِينَ فَجَاءَتْنِي فَأَعْطَيْتُهَا عِشْرِينَ وَمِائَةَ دِينَارٍ عَلَى أَنْ تُخَلِّيَ بَيْنِي وَبَيْنَ نَفْسِهَا فَفَعَلَتْ حَتَّى إِذَا قَدَرْتُ عَلَيْهَا قَالَتْ لَا أُحِلُّ لَكَ أَنْ تَفُضَّ الْخَاتَمَ إِلَّا بِحَقِّهِ فَتَحَرَّجْتُ مِنْ الْوُقُوعِ عَلَيْهَا فَانْصَرَفْتُ عَنْهَا وَهِيَ أَحَبُّ النَّاسِ إِلَيَّ وَتَرَكْتُ الذَّهَبَ الَّذِي أَعْطَيْتُهَا اللَّهُمَّ إِنْ كُنْتُ فَعَلْتُ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ عَنَّا مَا نَحْنُ فِيهِ فَانْفَرَجَتْ الصَّخْرَةُ غَيْرَ أَنَّهُمْ لَا يَسْتَطِيعُونَ الْخُرُوجَ مِنْهَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ الثَّالِثُ اللَّهُمَّ إِنِّي اسْتَأْجَرْتُ أُجَرَاءَ فَأَعْطَيْتُهُمْ أَجْرَهُمْ غَيْرَ رَجُلٍ وَاحِدٍ تَرَكَ الَّذِي لَهُ وَذَهَبَ فَثَمَّرْتُ أَجْرَهُ حَتَّى كَثُرَتْ مِنْهُ الْأَمْوَالُ فَجَاءَنِي بَعْدَ حِينٍ فَقَالَ يَا عَبْدَ اللَّهِ أَدِّ إِلَيَّ أَجْرِي فَقُلْتُ لَهُ كُلُّ مَا تَرَى مِنْ أَجْرِكَ مِنْ الْإِبِلِ وَالْبَقَرِ وَالْغَنَمِ وَالرَّقِيقِ فَقَالَ يَا عَبْدَ اللَّهِ لَا تَسْتَهْزِئُ بِي فَقُلْتُ إِنِّي لَا أَسْتَهْزِئُ بِكَ فَأَخَذَهُ كُلَّهُ فَاسْتَاقَهُ فَلَمْ يَتْرُكْ مِنْهُ شَيْئًا اللَّهُمَّ فَإِنْ كُنْتُ فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ عَنَّا مَا نَحْنُ فِيهِ فَانْفَرَجَتْ الصَّخْرَةُ فَخَرَجُوا يَمْشُونَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] telah menceritakan kepada saya [Salim bin 'Abdullah] bahwa ['Abdullah bin 'Umar radliallahu 'anhuma] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga orang dari kalangan orang sebelum kalian yang sedang bepergian hingga ketika mereka singgah dalam gua lalu mereka memasuki gua tersebut hingga akhirnya ada sebuah batu yang jatuh dari gunung hingga metutupi gua. Mereka berkata; Tidak akan ada yang dapat menyelamatkan kalian dari batu ini kecuali bila kalian berdoa meminta kepada Allah dengan perantaraan kebaikan amal kalian. Maka seorang diantara mereka berkata; \"Ya Allah, aku memiliki kedua orangtua yang sudah renta. Dan aku tidaklah pernah memberi minum susu keluargaku pada akhir siang sebelum keduanya. Suatu hari aku keluar untuk mencari sesuatu dan aku tidak beristirahat mencarinya hingga keduanya tertidur, aku pulang namun aku dapati keduanya sudah tertidur dan aku tidak mau mendahului keduanya meminum susu untuk keluargaku. Maka kemudian aku terlena sejenak dengan bersandar kepada kedua tanganku sambil aku menunggu keduanya bangun sampai fajar terbit, lalu keduanya terbangun dan meminum susu jatah akhir siangnya. Ya Allah seandainya aku kerjakan itu semata mencari ridhoMu, maka bukakanlah celah batu ini. Maka batu itu sedikit bergeser namun mereka belum dapat keluar. Nabi shallallahu 'alaihi wasallam berkata: Kemudian berkata, yang lain: \"Ya Allah, bersamaku ada putri pamanku yang menjadi orang yang paling mencintaiku. Suatu hari aku menginginkannya namun dia menolak aku. Kemudian berlalu masa beberapa tahun hingga kemudian dia datang kepadaku lalu aku berikan dia seratus dua puluh dinar agar aku dan dia bersenang-senang lalu dia setuju hiingga ketika aku sudah menguasainya dia berkata; tidak dihalalkan bagimu merusak keperawanan kecuali dengan cara yang haq. Maka aku selamat dari kejadian itu. Lalu aku pergi meninggalkannya padahal dia wanita yang paling aku cintai dan aku tinggalkan pula emas perhiasan yang aku berikan kepadanya. Ya Allah seandainya apa yang aku kerjakan itu semata mencari ridhoMu, maka bukakanlah celah pintu gua ini dimana kami terjebak didalamnya. Maka terbukalah sedikit batu itu namun mereka tetap belum bisa keluar. Bersabda Nabi shallallahu 'alaihi wasallam: Kemudian orang yang ketiga berkata: Ya Allah aku pernah memperkerjakan orang-orang lalu aku memberi upah mereka kecuali satu orang dari mereka yang meninggalkan haknya lalu dia pergi. Kemudian upah orang tersebut aku kembangkan hingga beberapa waktu kemudian ketika sudah banyak harta dari hasil yang aku kembangkan tersebut orang itu datang kepadaku lalu berkata; \"wahai 'Abdullah, berikanlah hak upah saya!\" Lalu aku katakan kepadanya; Itulah semua apa yang kamu lihat adalah upahmu berupa unta, sapi, kambing dan pengembalanya\". Dia berkata; \"wahai 'Abdullah, kamu jangan mengolok-olok aku!\" Aku katakan: Aku tidak mengolok-olok!\" Maka orang itu mengambil seluruhnya dan tidak ada yang disisakan sedikitpun. Ya Allah seandainya apa yang aku kerjakan itu semata mencari ridhoMu, maka bukakanlah celah batu gua yang kami terjebak didalamnya\". Maka batu itu terbuka akhirnya mereka dapat keluar dan pergi\"."},"2112":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْقُرَشِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَرَنَا بِالصَّدَقَةِ انْطَلَقَ أَحَدُنَا إِلَى السُّوقِ فَيُحَامِلُ فَيُصِيبُ الْمُدَّ وَإِنَّ لِبَعْضِهِمْ لَمِائَةَ أَلْفٍ قَالَ مَا تَرَاهُ إِلَّا نَفْسَهُ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Qurasyiy] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abu Mas'ud Al Anshariy radliallahu 'anhu] berkata: \"Adalah Nabi shallallahu 'alaihi wasallam bila memerintahkan kami bershadaqah, maka seseorang dari kami akan berangkat menuju pasar lalu dia bekerja dengan sungguh-sungguh hingga mendapatkan rezeki satu mud. Ada sebagian dari mereka bisa mendapatkan seratus ribu kalinya\". Dia berkata: \"Tidaklah kamu melihatnya melainkan adalah dirinya sendiri\". "},"2113":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَانَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُتَلَقَّى الرُّكْبَانُ وَلَا يَبِيعَ حَاضِرٌ لِبَادٍ قُلْتُ يَا ابْنَ عَبَّاسٍ مَا قَوْلُهُ لَا يَبِيعُ حَاضِرٌ لِبَادٍ قَالَ لَا يَكُونُ لَهُ سِمْسَارًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thowus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma]; Rasulullah shallallahu 'alaihi wasallam melarang menyongsong (mencegat) kafilah dagang (sebelum mereka tahu harga di pasar) dan melarang pula orang kota menjual kepada orang desa. Aku bertanya kepada Ibnu 'Abbas radliallahu 'anhuma: \"Apa arti sabda Beliau \" dan janganlah orang kota menjual kepada orang desa \". Dia menjawab: \"Janganlah seseorang jadi perantara bagi orang kota\"."},"2114":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ حَدَّثَنَا خَبَّابٌ قَالَكُنْتُ رَجُلًا قَيْنًا فَعَمِلْتُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَ لِي عِنْدَهُ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لَا وَاللَّهِ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ فَقُلْتُ أَمَا وَاللَّهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ فَلَا قَالَ وَإِنِّي لَمَيِّتٌ ثُمَّ مَبْعُوثٌ قُلْتُ نَعَمْ قَالَ فَإِنَّهُ سَيَكُونُ لِي ثَمَّ مَالٌ وَوَلَدٌ فَأَقْضِيكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] telah menceritakan kepada kami [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan emas lalu aku bekerja pada Al 'Ash bin Wa'il lalu upahku aku kumpulkan kepadanya kemudian aku menagih agar dia membayarnya. Dia berkata: \"Demi Allah, aku tidak akan membayarnya kepadamu kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Adapun aku, demi Allah tidak akan kufur sampai kamu mati lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah aku sampai aku mati lalu dibangkitkan\". Aku katakan: Baik kalau begitu\". Dia berkata: \"Sungguh aku akan mendapatkan harta dan anak lalu aku akan bayar hutang kepadamu\". Maka Allah Ta'ala menurunkan QS Maryam ayat yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan \"pasti Aku akan diberi harta dan anak\") (QS. Maryam 77)."},"2115":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَانْطَلَقَ نَفَرٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفْرَةٍ سَافَرُوهَا حَتَّى نَزَلُوا عَلَى حَيٍّ مِنْ أَحْيَاءِ الْعَرَبِ فَاسْتَضَافُوهُمْ فَأَبَوْا أَنْ يُضَيِّفُوهُمْ فَلُدِغَ سَيِّدُ ذَلِكَ الْحَيِّ فَسَعَوْا لَهُ بِكُلِّ شَيْءٍ لَا يَنْفَعُهُ شَيْءٌ فَقَالَ بَعْضُهُمْ لَوْ أَتَيْتُمْ هَؤُلَاءِ الرَّهْطَ الَّذِينَ نَزَلُوا لَعَلَّهُ أَنْ يَكُونَ عِنْدَ بَعْضِهِمْ شَيْءٌ فَأَتَوْهُمْ فَقَالُوا يَا أَيُّهَا الرَّهْطُ إِنَّ سَيِّدَنَا لُدِغَ وَسَعَيْنَا لَهُ بِكُلِّ شَيْءٍ لَا يَنْفَعُهُ فَهَلْ عِنْدَ أَحَدٍ مِنْكُمْ مِنْ شَيْءٍ فَقَالَ بَعْضُهُمْ نَعَمْ وَاللَّهِ إِنِّي لَأَرْقِي وَلَكِنْ وَاللَّهِ لَقَدْ اسْتَضَفْنَاكُمْ فَلَمْ تُضَيِّفُونَا فَمَا أَنَا بِرَاقٍ لَكُمْ حَتَّى تَجْعَلُوا لَنَا جُعْلًا فَصَالَحُوهُمْ عَلَى قَطِيعٍ مِنْ الْغَنَمِ فَانْطَلَقَ يَتْفِلُ عَلَيْهِ وَيَقْرَأُ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ فَكَأَنَّمَا نُشِطَ مِنْ عِقَالٍ فَانْطَلَقَ يَمْشِي وَمَا بِهِ قَلَبَةٌ قَالَ فَأَوْفَوْهُمْ جُعْلَهُمْ الَّذِي صَالَحُوهُمْ عَلَيْهِ فَقَالَ بَعْضُهُمْ اقْسِمُوا فَقَالَ الَّذِي رَقَى لَا تَفْعَلُوا حَتَّى نَأْتِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَذْكُرَ لَهُ الَّذِي كَانَ فَنَنْظُرَ مَا يَأْمُرُنَا فَقَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرُوا لَهُ فَقَالَ وَمَا يُدْرِيكَ أَنَّهَا رُقْيَةٌ ثُمَّ قَالَ قَدْ أَصَبْتُمْ اقْسِمُوا وَاضْرِبُوا لِي مَعَكُمْ سَهْمًا فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عَبْد اللَّهِ وَقَالَ شُعْبَةُ حَدَّثَنَا أَبُو بِشْرٍ سَمِعْتُ أَبَا الْمُتَوَكِّلِ بِهَذَا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyir] dari [Abu Al Mutawakkil] dari [Abu Sa'id radliallahu 'anhu] berkata; Ada rombongan beberapa orang dari sahabat Nabi shallallahu 'alaihi wasallam yang bepergian dalam suatu perjalanan hingga ketika mereka sampai di salah satu perkampungan Arab penduduk setempat mereka meminta agar bersedia menerima mereka sebagai tamu peenduduk tersebut namun penduduk menolak. Kemudian kepala suku kampung tersebut terkena sengatan binatang lalu diusahakan segala sesuatu untuk menyembuhkannya namun belum berhasil. Lalu diantara mereka ada yang berkata: \"Coba kalian temui rambongan itu semoga ada diantara mereka yang memiliki sesuatu. Lalu mereka mendatangi rambongan dan berkata: \"Wahai rambongan, sesunguhnya kepala suku kami telah digigit binatang dan kami telah mengusahakan pengobatannya namun belum berhasil, apakah ada diantara kalian yang dapat menyembuhkannya?\" Maka berkata, seorang dari rambongan: \"Ya, demi Allah aku akan mengobati namun demi Allah kemarin kami meminta untuk menjadi tamu kalian namun kalian tidak berkenan maka aku tidak akan menjadi orang yang mengobati kecuali bila kalian memberi upah. Akhirnya mereka sepakat dengan imbalan puluhan ekor kambing. Maka dia berangkat dan membaca Alhamdulillah rabbil 'alamiin (QS Al Fatihah) seakan penyakit lepas dari ikatan tali padahal dia pergi tidak membawa obat apapun. Dia berkata: \"Maka mereka membayar upah yang telah mereka sepakati kepadanya. Seorang dari mereka berkata: \"Bagilah kambing-kambing itu!\" Maka orang yang mengobati berkata: \"Jangan kalain bagikan hingga kita temui Nabi shallallahu 'alaihi wasallam lalu kita ceritakan kejadian tersebut kepada Beliau shallallahu 'alaihi wasallam dan kita tunggu apa yang akan Beliau perintahkan kepada kita\". Akhirnya rombongan menghadap Rasulullah shallallahu 'alaihi wasallam lalu mereka menceritakan peristiwa tersebut. Beliau berkata: \"Kamu tahu dari mana kalau Al Fatihah itu bisa sebagai ruqyah (obat)?\" Kemudian Beliau melanjutkan: \"Kalian telah melakukan perbuatan yang benar, maka bagilah upah kambing-kambing tersebut dan masukkanlah aku dalam sebagai orang yangmenerima upah tersebut\". Maka Rasulullah shallallahu 'alaihi wasallam tertawa. Abu 'Abdullah Al Bukhariy berkata, dan berkata, [Syu'bah] telah menceritakan kepada kami [Abu Bisyir] aku mendengar [Abu Al Mutawakkil] seperti hadits ini."},"2116":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَحَجَمَ أَبُو طَيْبَةَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ لَهُ بِصَاعٍ أَوْ صَاعَيْنِ مِنْ طَعَامٍ وَكَلَّمَ مَوَالِيَهُ فَخَفَّفَ عَنْ غَلَّتِهِ أَوْ ضَرِيبَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Humaid Ath-Thowil] dari [Anas bin Malik radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam pernah dibekam oleh Abu Thoyyibah lalu Beliau memberi upah kepadanya dengan satu sha' atau dua sha' makanan dan berbicara kepada penarik pajaknya untuk meringankan pajaknya."},"2117":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَعْطَى الْحَجَّامَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thowus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam berbekam dan memberi upah tukang bekamnya."},"2118":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَعْطَى الْحَجَّامَ أَجْرَهُ وَلَوْ عَلِمَ كَرَاهِيَةً لَمْ يُعْطِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam berbekam dan memperi upah tukang bekamnya. Seandainya Beliau mengetahui bahwa berbekam makruh tentu Beliau tidak memberi upah."},"2119":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ عَمْرِو بْنِ عَامِرٍ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَجِمُ وَلَمْ يَكُنْ يَظْلِمُ أَحَدًا أَجْرَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Mis'ar] dari ['Amru bin 'Amir] berkata; Aku mendengar [Anas radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam berbekam dan Beliau tidak pernah menzhalimi upah seorangpun. "},"2120":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُلَامًا حَجَّامًا فَحَجَمَهُ وَأَمَرَ لَهُ بِصَاعٍ أَوْ صَاعَيْنِ أَوْ مُدٍّ أَوْ مُدَّيْنِ وَكَلَّمَ فِيهِ فَخُفِّفَ مِنْ ضَرِيبَتِهِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Humaid Ath-Thowil] dari [Anas bin Malik radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam memanggil seorang budak tukang bekam. Maka dia membekam Bel; iau dan Beliau memberi satu sha' atau dua sha atau satu mud atau dua mud dan berpesan agar pajaknya diringankan."},"2121":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Ibnu Syihab] dari [Abu Bakar bin 'Abdurrahman bin Al Harits bin Hisyam] dari [Abu Mas'ud Al Anshariy radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang uang hasil jual beli anjing, mahar seorang pezina dan upah bayaran dukun."},"2122":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْإِمَاءِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Juhadah] dari [Abu Hazim] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam telah melarang uang bayaran zina. "},"2123":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ وَإِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَسْبِ الْفَحْلِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul Warits] dan [Isma'il bin Ibrahim] dari ['Ali bin Al Hakam] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam telah melarang uang bayaran zina. "},"2124":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَأَعْطَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ الْيَهُودَ أَنْ يَعْمَلُوهَا وَيَزْرَعُوهَا وَلَهُمْ شَطْرُ مَا يَخْرُجُ مِنْهَاوَأَنَّ ابْنَ عُمَرَ حَدَّثَهُ أَنَّ الْمَزَارِعَ كَانَتْ تُكْرَى عَلَى شَيْءٍ سَمَّاهُ نَافِعٌ لَا أَحْفَظُهُ وَأَنَّ رَافِعَ بْنَ خَدِيجٍ حَدَّثَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ كِرَاءِ الْمَزَارِعِ وَقَالَ عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ حَتَّى أَجْلَاهُمْ عُمَرُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah bin Asma'] dari [Nafi'] dari ['Abdullah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam mengadakan kerjasama kepada orang Yahudi dari tanah khaibar agar dimanfaatkan dan dijadikan ladang pertanian dan mereka mendapat separuh hasilnya. Dan bahwa [Ibnu'Umar radliallahu 'anhuma] menceritakan kepadanya bahwa ladang pertanian tersebut disewakan untuk sesuatu yang lain, yang disebutkan oleh Nafi', tapi aku lupa. Dan bahwa [Rafi' bin Khadij] menceritakan bahwa Nabi shallallahu 'alaihi wasallam melarang menyewakan ladang pertanian (untuk usaha selaian bercocok tanam). Dan berkata, ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma]; Hingga akhirnya 'Umar mengusir mereka (orang Yahudi)."},"2125":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَطْلُ الْغَنِيِّ ظُلْمٌ فَإِذَا أُتْبِعَ أَحَدُكُمْ عَلَى مَلِيٍّ فَلْيَتْبَعْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menunda membayar hutang bagi orang kaya adalah kezhaliman dan apabila seorang dari kalian hutangnya dialihkan kepada orang kaya, hendaklah dia ikuti\". "},"2126":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ ذَكْوَانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَطْلُ الْغَنِيِّ ظُلْمٌ وَمَنْ أُتْبِعَ عَلَى مَلِيٍّ فَلْيَتَّبِعْ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Dzakwan] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Menunda membayar hutang bagi orang kaya adalah kezhaliman dan apabila seorang dari kalian hutangnya dialihkan kepada orang kaya, hendaklah ia ikuti\"."},"2127":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أُتِيَ بِجَنَازَةٍ فَقَالُوا صَلِّ عَلَيْهَا فَقَالَ هَلْ عَلَيْهِ دَيْنٌ قَالُوا لَا قَالَ فَهَلْ تَرَكَ شَيْئًا قَالُوا لَا فَصَلَّى عَلَيْهِ ثُمَّ أُتِيَ بِجَنَازَةٍ أُخْرَى فَقَالُوا يَا رَسُولَ اللَّهِ صَلِّ عَلَيْهَا قَالَ هَلْ عَلَيْهِ دَيْنٌ قِيلَ نَعَمْ قَالَ فَهَلْ تَرَكَ شَيْئًا قَالُوا ثَلَاثَةَ دَنَانِيرَ فَصَلَّى عَلَيْهَا ثُمَّ أُتِيَ بِالثَّالِثَةِ فَقَالُوا صَلِّ عَلَيْهَا قَالَ هَلْ تَرَكَ شَيْئًا قَالُوا لَا قَالَ فَهَلْ عَلَيْهِ دَيْنٌ قَالُوا ثَلَاثَةُ دَنَانِيرَ قَالَ صَلُّوا عَلَى صَاحِبِكُمْ قَالَ أَبُو قَتَادَةَ صَلِّ عَلَيْهِ يَا رَسُولَ اللَّهِ وَعَلَيَّ دَيْنُهُ فَصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Al Makkiy bin Ibrahim] telah menceritakan kepada kami [Yazid bin Abi 'Ubaid] dari [Salamah bin Al Akwa' radliallahu 'anhu] berkata: \"Kami pernah duduk bermajelis dengan Nabi shallallahu 'alaihi wasallam ketika dihadirkan kepada Beliau satu jenazah kemudian orang-orang berkata: \"Shalatilah jenazah ini\". Maka Beliau bertanya: \"Apakah orang ini punya hutang?\" Mereka berkata: \"Tidak\". Kemudian Beliau bertanya kembali: \"Apakah dia meninggalkan sesuatu?\" Mereka menjawab: \"Tidak\". Akhirnya Beliau menyolatkan jenazah tersebut. Kemudian didatangkan lagi jenazah lain kepada Beliau, lalu orang-orang berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam, holatilah jenazah ini\". Maka Beliau bertanya: \"Apakah orang ini punya hutang?\" Dijawab: \"Ya\". Kemudian Beliau bertanya kembali: \"Apakah dia meninggalkan sesuatu?\" Mereka menjawab: \"Ada, sebanyak tiga dinar\". Maka Beliau bersabda: \"Shalatilah saudaramu ini\". Berkata, Abu Qatadah: \"Shalatilah wahai Rasulullah, nanti hutangnya aku yang menanggungnya\". Maka Beliau shallallahu 'alaihi wasallam menyolatkan jenazah itu."},"2128":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ إِدْرِيسَ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ }قَالَ وَرَثَةً{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ }قَالَ كَانَ الْمُهَاجِرُونَ لَمَّا قَدِمُوا الْمَدِينَةَ يَرِثُ الْمُهَاجِرُ الْأَنْصَارِيَّ دُونَ ذَوِي رَحِمِهِ لِلْأُخُوَّةِ الَّتِي آخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمْ فَلَمَّا نَزَلَتْ{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ }نَسَخَتْ ثُمَّ قَالَ{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ }إِلَّا النَّصْرَ وَالرِّفَادَةَ وَالنَّصِيحَةَ وَقَدْ ذَهَبَ الْمِيرَاثُ وَيُوصِي لَهُ","id":"Telah menceritakan kepada kami [Ash-Shaltu bin Muhammad] telah menceritakan kepada kami [Abu Usamah] dari [Idris] dari [Tholhah bin Musharrif] dari [Said bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma]: Firman Allah yang berbunyi (Dan bagi harta peninggalan kami jadikan para pewaris), dia berkata; artinya: itulah warisan. Dan ayat (Dan orang-orang yang kamu telah bersumpah setia dengan mereka) ia berkata: ketika orang-orang muhajirin sampai di Madinah, seorang Muhajir mewarisi orang Anshar yang tidak memiliki hubungan kekeluargaan karena persaudaraan yang dipersaudarakan oleh Nabi shallallahu 'alaihi wasallam diantara mereka. Ketika ayat ini turun maka ayat ini menghapus ketentuan tersebut. Dan ayat tidak dipraktekkan lagi kecuali saling tolong menolong (antara Muhajirin - Anshar), pemberian dan nasehat sedangkan warisan telah dihapus dan diberi wasiat. "},"2129":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ ��َنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمَ عَلَيْنَا عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ فَآخَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُ وَبَيْنَ سَعْدِ بْنِ الرَّبِيعِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas radliallahu 'anhu] berkata, 'Abdurrahman bin 'Auf datang menemui kami lalu Rasulullah shallallahu 'alaihi wasallam mempersaudarakan dia dengan Sa'ad bin Ar-Rabi'."},"2130":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ زَكَرِيَّاءَ حَدَّثَنَا عَاصِمٌ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَبَلَغَكَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا حِلْفَ فِي الْإِسْلَامِ فَقَالَ قَدْ حَالَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ قُرَيْشٍ وَالْأَنْصَارِ فِي دَارِي","id":"Telah menceritakan kepada kami [Muhammad bin Ash-Shabbah] telah menceritakan kepada kami [Isma'il bin Zakariya'] telah menceritakan kepada kami ['Ashim] berkata; Aku bertanya kepada [Anas bin Malik radliallahu 'anhu]; Apakah sampai kepadanya sabda Nabi shallallahu 'alaihi wasallam yang berbunyi: \"Tidak ada perjanjian dalam Islam\". Maka dia berkata: \"Sungguh Nabi shallallahu 'alaihi wasallam pernah membuat perjanjian antara orang Quraisy dan Anshar di rumahku\"."},"2131":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِجَنَازَةٍ لِيُصَلِّيَ عَلَيْهَا فَقَالَ هَلْ عَلَيْهِ مِنْ دَيْنٍ قَالُوا لَا فَصَلَّى عَلَيْهِ ثُمَّ أُتِيَ بِجَنَازَةٍ أُخْرَى فَقَالَ هَلْ عَلَيْهِ مِنْ دَيْنٍ قَالُوا نَعَمْ قَالَ صَلُّوا عَلَى صَاحِبِكُمْ قَالَ أَبُو قَتَادَةَ عَلَيَّ دَيْنُهُ يَا رَسُولَ اللَّهِ فَصَلَّى عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Yazid bin Abi 'Ubaid] dari [Salamah bin Al Akwa' radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam dihadirkan kepada Beliau satu jenazah agar dishalatkan. Maka Beliau bertanya: \"Apakah orang ini punya hutang?\" Mereka berkata: \"Tidak\". Maka Beliau menyolatkan jenazah tersebut. Kemudian didatangkan lagi jenazah lain kepada Beliau, maka Beliau bertanya kembali: \"Apakah orang ini punya hutang?\" Mereka menjawab: \"Ya\". Maka Beliau bersabda: \"Shalatilah saudaramu ini\". Berkata, Abu Qatadah: \"Biar nanti aku yang menanggung hutangnya\". Maka Beliau shallallahu 'alaihi wasallam menyolatkan jenazah itu."},"2132":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو سَمِعَ مُحَمَّدَ بْنَ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمْ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ قَدْ جَاءَ مَالُ الْبَحْرَيْنِ قَدْ أَعْطَيْتُكَ هَكَذَا وَهَكَذَا وَهَكَذَا فَلَمْ يَجِئْ مَالُ الْبَحْرَيْنِ حَتَّى قُبِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا جَاءَ مَالُ الْبَحْرَيْنِ أَمَرَ أَبُو بَكْرٍ فَنَادَى مَنْ كَانَ لَهُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِدَةٌ أَوْ دَيْنٌ فَلْيَأْتِنَا فَأَتَيْتُهُ فَقُلْتُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِي كَذَا وَكَذَا فَحَثَى لِي حَثْيَةً فَعَدَدْتُهَا فَإِذَا هِيَ خَمْسُ مِائَةٍ وَقَالَ خُذْ مِثْلَيْهَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru] dia mendengar [Muhammad bin 'Ali] dari [Jabir bin 'Abdullah radliallahu 'anhum] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Seandainya tiba kepada kita harta dari negeri Bahrain aku pasti memberikan kepadamu sekian, sekian dan sekian\". namun harta dari Bahrain tidak kunjung datang hingga Nabi shallallahu 'alaihi wasallam wafat. Ketika harta dari Bahrain datang Abu Bakar memerintahkan dan berseru: \"Siapa yang telah dijanjikan sesuatu atau dihutangi oleh Nabi shallallahu 'alaihi wasallam hendaklah menemui kami\". Maka aku mendatanginya dan aku katakan bahwa Nabi shallallahu 'alaihi wasallam telah berkata kepadaku begini dan begitu, lalu ia (Abu Bakar) memberiku setangkup, lalu aku menghitungnya ternyata ia berjumlah lima ratus, lalu ia berkata; \"Ambillah dua kali lagi seperti itu\"."},"2133":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُؤْتَى بِالرَّجُلِ الْمُتَوَفَّى عَلَيْهِ الدَّيْنُ فَيَسْأَلُ هَلْ تَرَكَ لِدَيْنِهِ فَضْلًا فَإِنْ حُدِّثَ أَنَّهُ تَرَكَ لِدَيْنِهِ وَفَاءً صَلَّى وَإِلَّا قَالَ لِلْمُسْلِمِينَ صَلُّوا عَلَى صَاحِبِكُمْ فَلَمَّا فَتَحَ اللَّهُ عَلَيْهِ الْفُتُوحَ قَالَ أَنَا أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ فَمَنْ تُوُفِّيَ مِنْ الْمُؤْمِنِينَ فَتَرَكَ دَيْنًا فَعَلَيَّ قَضَاؤُهُ وَمَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam pernah disodorkan kepada beliau seorang yang sudah merninggal dunia (jenazah) yang meninggalkan hutang maka Beliau bertanya: \"Apakah dia meninggalkan harta untuk membayar hutangnya?\" Jika diceritakan bahwa jenazah tersebut ada meninggalkan sesuatu untuk melunasi hutangnya maka Beliau menyolatinya, jika tidak maka Beliau berkata, kepada Kaum Muslimin: \"Shalatilah saudara kalian ini\". Ketika Allah telah membukakan kemenangan kepada Beliau di berbagai negeri Beliau bersabda: \"Aku lebih utama menjamin untuk orang-orang beriman dibanding diri mereka sendiri, maka siapa yang mneninggal dunia dari kalangan Kaum Mukminin lalu meninggalkan hutang akulah yang wajib membayarnya dan siapa yang meninggalkan harta maka harta itu untuk pewarisnya\". "},"2134":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَمْ أَعْقِلْ أَبَوَيَّ قَطُّ إِلَّا وَهُمَا يَدِينَانِ الدِّينَ وَقَالَ أَبُو صَالِحٍ حَدَّثَنِي عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمْ أَعْقِلْ أَبَوَيَّ قَطُّ إِلَّا وَهُمَا يَدِينَانِ الدِّينَ وَلَمْ يَمُرَّ عَلَيْنَا يَوْمٌ إِلَّا يَأْتِينَا فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَفَيْ النَّهَارِ بُكْرَةً وَعَشِيَّةً فَلَمَّا ابْتُلِيَ الْمُسْلِمُونَ خَرَجَ أَبُو بَكْرٍ مُهَاجِرًا قِبَلَ الْحَبَشَةِ حَتَّى إِذَا بَلَغَ بَرْكَ الْغِمَادِ لَقِيَهُ ابْنُ الدَّغِنَةِ وَهُوَ سَيِّدُ الْقَارَةِ فَقَالَ أَيْنَ تُرِيدُ يَا أَبَا بَكْرٍ فَقَالَ أَبُو بَكْرٍ أَخْرَجَنِي قَوْمِي فَأَنَا أُرِيدُ أَنْ أَسِيحَ فِي الْأَرْضِ فَأَعْبُدَ رَبِّي قَالَ ابْنُ الدَّغِنَةِ إِنَّ مِثْلَكَ لَا يَخْرُجُ وَلَا يُخْرَجُ فَإِنَّكَ تَكْسِبُ الْمَعْدُومَ وَتَصِلُ الرَّحِمَ وَتَحْمِلُ الْكَلَّ وَتَقْرِي الضَّيْفَ وَتُعِينُ عَلَى نَوَائِبِ الْحَقِّ وَأَنَا لَكَ جَارٌ فَارْجِعْ فَاعْبُدْ رَبَّكَ بِبِلَادِكَ فَارْتَحَلَ ابْنُ الدَّغِنَةِ فَرَجَعَ مَعَ أَبِي بَكْرٍ فَطَافَ فِي أَشْرَافِ كُفَّارِ قُرَيْشٍ فَقَالَ لَهُمْ إِنَّ أَبَا بَكْرٍ لَا يَخْرُجُ مِثْلُهُ وَلَا يُخْرَجُ أَتُخْرِجُونَ رَجُلًا يُكْسِبُ الْمَعْدُومَ وَيَصِلُ الرَّحِمَ وَيَحْمِلُ الْكَلَّ وَيَقْرِي الضَّيْفَ وَيُعِينُ عَلَى نَوَائِبِ الْحَقِّ فَأَنْفَذَتْ قُرَيْشٌ جِوَارَ ابْنِ الدَّغِنَةِ وَآمَنُوا أَبَا بَكْرٍ وَقَالُوا لِابْنِ الدَّغِنَةِ مُرْ أَبَا بَكْرٍ فَلْيَعْبُدْ رَبَّهُ فِي دَارِهِ فَلْيُصَلِّ وَلْيَقْرَأْ مَا شَاءَ وَلَا يُؤْذِينَا بِذَلِكَ وَلَا يَسْتَعْلِنْ بِهِ فَإِنَّا قَدْ خَشِينَا أَنْ يَفْتِنَ أَبْنَاءَنَا وَنِسَاءَنَا قَالَ ذَلِكَ ابْنُ الدَّغِنَةِ لِأَبِي بَكْرٍ فَطَفِقَ أَبُو بَكْرٍ يَعْبُدُ رَبَّهُ فِي دَارِهِ وَلَا يَسْتَعْلِنُ بِالصَّلَاةِ وَلَا الْقِرَاءَةِ فِي غَيْرِ دَارِهِ ثُمَّ بَدَا لِأَبِي بَكْرٍ فَابْتَنَى مَسْجِدًا بِفِنَاءِ دَارِهِ وَبَرَزَ فَكَانَ يُصَلِّي فِيهِ وَيَقْرَأُ الْقُرْآنَ فَيَتَقَصَّفُ عَلَيْهِ نِسَاءُ الْمُشْرِكِينَ وَأَبْنَاؤُهُمْ يَعْجَبُونَ وَيَنْظُرُونَ إِلَيْهِ وَكَانَ أَبُو بَكْرٍ رَجُلًا بَكَّاءً لَا يَمْلِكُ دَمْعَهُ حِينَ يَقْرَأُ الْقُرْآنَ فَأَفْزَعَ ذَلِكَ أَشْرَافَ قُرَيْشٍ مِنْ الْمُشْرِكِينَ فَأَرْسَلُوا إِلَى ابْنِ الدَّغِنَةِ فَقَدِمَ عَلَيْهِمْ فَقَالُوا لَهُ إِنَّا كُنَّا أَجَرْنَا أَبَا بَكْرٍ عَلَى أَنْ يَعْبُدَ رَبَّهُ فِي دَارِهِ وَإِنَّهُ جَاوَزَ ذَلِكَ فَابْتَنَى مَسْجِدًا بِفِنَاءِ دَارِهِ وَأَعْلَنَ الصَّلَاةَ وَالْقِرَاءَةَ وَقَدْ خَشِينَا أَنْ يَفْتِنَ أَبْنَاءَنَا وَنِسَاءَنَا فَأْتِهِ فَإِنْ أَحَبَّ أَنْ يَقْتَصِرَ عَلَى أَنْ يَعْبُدَ رَبَّهُ فِي دَارِهِ فَعَلَ وَإِنْ أَبَى إِلَّا أَنْ يُعْلِنَ ذَلِكَ فَسَلْهُ أَنْ يَرُدَّ إِلَيْكَ ذِمَّتَكَ فَإِنَّا كَرِهْنَا أَنْ نُخْفِرَكَ وَلَسْنَا مُقِرِّينَ لِأَبِي بَكْرٍ الِاسْتِعْلَانَ قَالَتْ عَائِشَةُ فَأَتَى ابْنُ الدَّغِنَةِ أَبَا بَكْرٍ فَقَالَ قَدْ عَلِمْتَ الَّذِي عَقَدْتُ لَكَ عَلَيْهِ فَإِمَّا أَنْ تَقْتَصِرَ عَلَى ذَلِكَ وَإِمَّا أَنْ تَرُدَّ إِلَيَّ ذِمَّتِي فَإِنِّي لَا أُحِبُّ أَنْ تَسْمَعَ الْعَرَبُ أَنِّي أُخْفِرْتُ فِي رَجُلٍ عَقَدْتُ لَهُ قَالَ أَبُو بَكْرٍ إِنِّي أَرُدُّ إِلَيْكَ جِوَارَكَ وَأَرْضَى بِجِوَارِ اللَّهِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ بِمَكَّةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُرِيتُ دَارَ هِجْرَتِكُمْ رَأَيْتُ سَبْخَةً ذَاتَ نَخْلٍ بَيْنَ لَابَتَيْنِ وَهُمَا الْحَرَّتَانِ فَهَاجَرَ مَنْ هَاجَرَ قِبَلَ الْمَدِينَةِ حِينَ ذَكَرَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجَعَ إِلَى الْمَدِينَةِ بَعْضُ مَنْ كَانَ هَاجَرَ إِلَى أَرْضِ الْحَبَشَةِ وَتَجَهَّزَ أَبُو بَكْرٍ مُهَاجِرًا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكَ فَإِنِّي أَرْجُو أَنْ يُؤْذَنَ لِي قَالَ أَبُو بَكْرٍ هَلْ تَرْجُو ذَلِكَ بِأَبِي أَنْتَ قَالَ نَعَمْ فَحَبَسَ أَبُو بَكْرٍ نَفْسَهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَصْحَبَهُ وَعَلَفَ رَاحِلَتَيْنِ كَانَتَا عِنْدَهُ وَرَقَ السَّمُرِ أَرْبَعَةَ أَشْهُرٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] berkata, [Ibnu Syihab] maka dia mengabarkan keada saya ['Urwah bin Az Zubair] bahwa ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam berkata; \"Aku belum lagi baligh ketika bapakku sudah memeluk Islam\". Dan berkata, [Abu Shalih] telah menceritakan kepada saya ['Abdullah] dari [Yunus] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya ['Urwah bin Az Zubair] bahwa ['Aisyah radliallahu 'anha] berkata; \"Aku belum lagi baligh ketika bapakku sudah memeluk Islam dan tidak berlalu satu haripun melainkan Rasulullah shallallahu 'alaihi wasallam datang menemui kami di sepanjang hari baik pagi ataupun petang. Ketika Kaum Muslimin mendapat ujian, Abu Bakar keluar berhijrah menuju Habasyah (Ethiopia) hingga ketika sampai di Barkal Ghomad dia didatangi oleh Ibnu Ad-Daghinah seorang kepala suku seraya berkata; \"Kamu hendak kemana, wahai Abu Bakar?\" Maka Abu Bakar menjawab: \"Kaumku telah mengusirku maka aku ingin keliling dunia agar aku bisa beribadah kepada Tuhanku\". Ibnu Ad-Daghinah berkata: \"Seharusnya orang seperti anda tidak patut keluar dan tidap patut pula diusir karena anda termasuk orang yang bekerja untuk mereka yang tidak berpunya, menyambung silaturahim, menanggung orang-orang yang lemah, menjamu tamu dan selalu menolong di jalan kebenaran. Maka aku akan menjadi pelindung anda untuk itu kembalilah dan sembahlah Tuhanmudi negeri kelahiranmu. Maka Ibnu Ad-Daghinah bersiap-siap dan kembali bersama Abu Bakar lalu berjalan di hadapan Kafir Quraisy seraya berkata, kepada mereka: \"Sesungguhnya orang sepeti Abu Bakar tidak patut keluar dan tidak patut pula diusir. Apakah kalian mengusir orang yang suka bekerja untuk mereka yang tidak berpunya, menyambung silaturahim, menanggung orang-orang yang lemah, menjamu tamu dan selalu menolong di jalan kebenaran?\" Akhirnya orang-orang Quraisy menerima perlindungan Ibnu Ad-Daghinah dan mereka memberikan keamanan kepada Abu Bakar lalu berkata, kepada Ibnu Ad-Daghinah: \"Perintahkanlah Abu Bakar agar beribadah menyembah Tuhannya di rumahnya saja dan shalat serta membaca Al Qur'an sesukanya dan dia jangan mengganggu kami dengan kegiatannya itu dan jangan mengeraskannya karena kami telah khawatir akan menimbulkan fitnah terhadap anak-anak dan isteri-isteri kami\". Maka Ibnu Ad-Daghinah menyampaikan hal ini kepada Abu Bakar. Maka Abu Bakar mulai beribadah di rumahnya dan tidak mengeraskan shalat bacaan Al Qur'an diluar rumahnya. Kemudian AbuBakar membangun tempat shalat di halaman rumahnya sedikit melebar keluar dimana dia shalat disana dan membaca Al Qur'an. Lalu istrei-isteri dan anak-anak Kaum Musyrikin berkumpul disana dengan penuh keheranan dan menanti selesainya Abu Bakar beribadah. Dan sebagaimana diketahui Abu Bakar adalah seorang yang suka menangis yang tidak sanggup menahan air matanya ketika membaca Al Qur'an. Maka kemudian kagetlah para pembesar Quraisy dari kalangan Musyrikin yang akhirnya mereka memanggil Ibnu Ad-Daghinah ke hadapan mereka dan berkata, kepadanya: \"Sesungguhnya kami telah memberikan perlindungan kepada Abu Bakr agar dia mberibadah di rumahnya namun dia melanggar hal tersebut dengan membangun tempat shalat di halaman rumahnya serta mengeraskan shalat dan bacaan padahal kami khawatir hal itu akan dapat mempengaruhi isteri-isteri dan anak-anak kami dan ternyata benar-benar terjadi. Jika dia suka untuk tetap beribadah di rumahnya silakan namun jika dia menolak dan tetap menampakkan ibadahnya itu mintalah kepadanya agar dia mengembalikan perlindungan anda karena kami tidak suka bila kamu melanggar perjanjian dan kami tidak setuju bersepakat dengan Abu Bakar\". Berkata, 'Aisyah radliallahu 'anha: Maka Ibnu Ad-Daghinah menemui Abu Bakar dan berkata: \"Kamu telah mengetahui perjanjian yang kamu buat, maka apakah kamu tetap memeliharanya atau mengembalikan perlindunganku kepadaku karena aku tidak suka bila orang-orang Arab mendengar bahwa aku telah melanggar perjanjian hanya karena seseorang yang telah aku berjanji kepadanya\". Maka Abu Bakar berkata: \"Aku kembalikan jaminanmu kepadamu dan aku ridho hanya dengan perlindungan Allah dan RasulNya shallallahu 'alaihi wasallam. Kejadian ini adalah di Makkah. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku telah ditampakkan negeri tempat hijrah kalian dan aku melihat negeri yang subur ditumbuhi dengan pepohonan kurma diantara dua bukit yang kokoh. Maka berhijrahlah orang yang berhijrah menuju Madinah ketika Rasulullah shallallahu 'alaihi wasallam menyebutkanhal itu. Dan kembali pula berdatangan ke Madinah sebagian dari mereka yang pernah hijrah ke Habasyah sementara Abu Bakar telah bersiap-siap pula untuk berhijrah. Maka Rasulullah shallallahu 'alaihi wasallam berkata, kepadanya: \"Janganlah kamu tergesa-gesa karena aku berharap aku akan diizinkan (untuk berhijrah) \". Abu Bakar berkata: \"Sungguh demi bapakku tanggungannya, apakah benar Tuan mengharapkan itu?\" Beliau bersabda: \"Ya benar\". Maka Abu Bakar berharap dalam dirinya bahwa dia benar-benar dapat mendampingi Rasulullah shallallahu 'alaihi wasallam dalam berhijrah. Maka dia memberi makan dua hewan tunggangan yang dimilikinya dengan dedaunan Samur selama empat bulan."},"2135":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَتَصَدَّقَ بِجِلَالِ الْبُدْنِ الَّتِي نُحِرَتْ وَبِجُلُودِهَا","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abi Najih] dari [Mujahid] dari ['Abdurrahman bin Abi Lailaa] dari ['Ali radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan aku agar menyedekahkan apa yang ada diatas punggung unta (pelana) yang kami sembelih begitu juga kulitnya."},"2136":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ غَنَمًا يَقْسِمُهَا عَلَى صَحَابَتِهِ فَبَقِيَ عَتُودٌ فَذَكَرَهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِّ بِهِ أَنْتَ","id":"Telah menceritakan kepada kami ['Amru bin Khalid] telah menceritakan kepada kami [Al Laits] dari [Yazid] dari [Abu Al Khair] dari ['Uqbah bin 'Amir radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam memberikan kepadanya seekor kambing yang Beliau bagikan untuk para sahabat Beliau dan tersisa anak kambing yang sudah bisa berdiri sendiri. Kemudian diceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam maka Beliau bersabda: \"Ambillah buatmu\"."},"2137":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي يُوسُفُ بْنُ الْمَاجِشُونِ عَنْ صَالِحِ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَاتَبْتُ أُمَيَّةَ بْنَ خَلَفٍ كِتَابًا بِأَنْ يَحْفَظَنِي فِي صَاغِيَتِي بِمَكَّةَ وَأَحْفَظَهُ فِي صَاغِيَتِهِ بِالْمَدِينَةِ فَلَمَّا ذَكَرْتُ الرَّحْمَنَ قَالَ لَا أَعْرِفُ الرَّحْمَنَ كَاتِبْنِي بِاسْمِكَ الَّذِي كَانَ فِي الْجَاهِلِيَّةِ فَكَاتَبْتُهُ عَبْدَ عَمْرٍو فَلَمَّا كَانَ فِي يَوْمِ بَدْرٍ خَرَجْتُ إِلَى جَبَلٍ لِأُحْرِزَهُ حِينَ نَامَ النَّاسُ فَأَبْصَرَهُ بِلَالٌ فَخَرَجَ حَتَّى وَقَفَ عَلَى مَجْلِسٍ مِنْ الْأَنْصَارِ فَقَالَ أُمَيَّةُ بْنُ خَلَفٍ لَا نَجَوْتُ إِنْ نَجَا أُمَيَّةُ فَخَرَجَ مَعَهُ فَرِيقٌ مِنْ الْأَنْصَارِ فِي آثَارِنَا فَلَمَّا خَشِيتُ أَنْ يَلْحَقُونَا خَلَّفْتُ لَهُمْ ابْنَهُ لِأَشْغَلَهُمْ فَقَتَلُوهُ ثُمَّ أَبَوْا حَتَّى يَتْبَعُونَا وَكَانَ رَجُلًا ثَقِيلًا فَلَمَّا أَدْرَكُونَا قُلْتُ لَهُ ابْرُكْ فَبَرَكَ فَأَلْقَيْتُ عَلَيْهِ نَفْسِي لِأَمْنَعَهُ فَتَخَلَّلُوهُ بِالسُّيُوفِ مِنْ تَحْتِي حَتَّى قَتَلُوهُ وَأَصَابَ أَحَدُهُمْ رِجْلِي بِسَيْفِهِ وَكَانَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ يُرِينَا ذَلِكَ الْأَثَرَ فِي ظَهْرِ قَدَمِهِقَالَ أَبُو عَبْد اللَّهِ سَمِعَ يُوسُفُ صَالِحًا وَإِبْرَاهِيمُ أَبَاهُ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada saya [Yusuf bin Al Majisyun] dari [Shalih bin Ibrahim bin 'Abdurrahman bin 'Auf] dari [bapaknya] dari [kakeknya, 'Abdurrahman bin 'Auf radliallahu 'anhu] berkata: \"Aku mengirim surat kepada Umayah bin Khalaf agar ia menjagaku dalam urusan keluargaku dan harta bendaku di Makkah dan aku akan menjaganya dalam urusan keluarganya dan harta bendanya di Madinah. Ketika aku menyebut nama Ar-Rahman ia berkata; \"Aku tidak mengenal Ar-Rahman, tulislah namamu ketika engkau masih di jahiliyah\". Maka aku menulis namaku 'Abdu 'Amru. Ketika terjadi perang Badar aku keluar ke gunung untuk menjaganya ketika orang-orang tidur. Kemudian Bilal melihatnya, lalu ia keluar hingga sampai di majlis orang-orang Anshar. Lalu Umayyah bin Khalaf berkata: \"Aku tidak akan selamat jika Umayah selamat. Kemudian beberapa orang Anshar keluar bersamanya mendekati kami, ketika aku khawatir mereka akan menemukan kami maka aku keluarkan anaknya kearah mereka agar mereka tersibukkan dengannya, namun mereka membunuhnya dan mereka enggan kembali hingga mereka menemui kami, ketika itu ia adalah seorang lelaki yang gemuk, ketika mereka menemui kami aku berkata, kepadanya merunduklah, lalu iapun merunduk dan aku meletakkan badanku diatasnya untuk melindunginya, kemudian mereka (kaum muslimin) berusaha menusuknya dengan mengarahkan pedang mereka melalui bawahku hingga mereka membunuhnya, kakiku terkena pedang salah seseorang dari mereka. Dan 'Abdurrahman bin 'Auf memperlihatkan luka bekas pedang itu pada kami dipunggung kakinya. Abu 'Abdullah berkata, Yusuf mendengar Shaleh begitu juga Ibrahim, bapaknya."},"2138":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الْمَجِيدِ بْنِ سُهَيْلِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَأَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ رَجُلًا عَلَى خَيْبَرَ فَجَاءَهُمْ بِتَمْرٍ جَنِيبٍ فَقَالَ أَكُلُّ تَمْرِ خَيْبَرَ هَكَذَا فَقَالَ إِنَّا لَنَأْخُذُ الصَّاعَ مِنْ هَذَا بِالصَّاعَيْنِ وَالصَّاعَيْنِ بِالثَّلَاثَةِ فَقَالَ لَا تَفْعَلْ بِعْ الْجَمْعَ بِالدَّرَاهِمِ ثُمَّ ابْتَعْ بِالدَّرَاهِمِ جَنِيبًا وَقَالَ فِي الْمِيزَانِ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdul Majid bin Suhail bin 'Abdurrahman bin 'Auf] dari [Sa'id bin Al Musayyab] dari [Abu Sa'id Al Khudriy] dan [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam memperkerjakan seorang di tanah Khaibar lalu dia membawakan kurma yang banyak kepada mereka lalu Beliau shallallahu 'alaihi wasallam bertanya: \"Apakah semua kurma Khaibar seperti ini?\" Maka orang itu menjawab: \"Sesungguhnya kami mengambil satu sha'jenis kurma ini dengan dua sha' kurma lain dan dua sha'kurma ini dengan tiga sha' kurma lain\". Maka Beliau bersabda: \"Janganlah kamu berbuat seperti itu. Juallah dengan dirham kemudian belilah dengan dirham pula\". Dan bersabda: \"Dan dengan timbangan seperti itu pula\"."},"2139":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ سَمِعَ الْمُعْتَمِرَ أَنْبَأَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ أَنَّهُ سَمِعَ ابْنَ كَعْبِ بْنِ مَالِكٍ يُحَدِّثُ عَنْ أَبِيهِأَنَّهُ كَانَتْ لَهُمْ غَنَمٌ تَرْعَى بِسَلْعٍ فَأَبْصَرَتْ جَارِيَةٌ لَنَا بِشَاةٍ مِنْ غَنَمِنَا مَوْتًا فَكَسَرَتْ حَجَرًا فَذَبَحَتْهَا بِهِ فَقَالَ لَهُمْ لَا تَأْكُلُوا حَتَّى أَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ أُرْسِلَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَسْأَلُهُ وَأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَاكَ أَوْ أَرْسَلَ فَأَمَرَهُ بِأَكْلِهَاقَالَ عُبَيْدُ اللَّهِ فَيُعْجِبُنِي أَنَّهَا أَمَةٌ وَأَنَّهَا ذَبَحَتْ تَابَعَهُ عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dia mendengar [Al Mu'tamir] memberitakan kepada kami ['Ubaidulloh] dari [Nafi'] bahwa dia mendengar [Ibnu Ka'ab bin Malik] bercerita dari [bapaknya] bahwasanya dia memiliki kambing yang mencari makan didekat pepohonan. Lalu budak wanita kami melihat ada satu ekor kambing yang mati. Maka dia mengambil batu lalu menyembelihnya dengan batu tersebut dan berkata, kepada mereka; \"Janganlah kalian makan sampai aku menanyakannya kepada Nabi shallallahu 'alaihi wasallam atau kita utus seseorang untuk menanyakannya kepada Nabi shallallahu 'alaihi wasallam. Lalu dia menanyakan Nabi shallallahu 'alaihi wasallam tentang maalah ini atau mengutus seseorang. Maka Beliau shallallahu 'alaihi wasallam memerintahkan untuk memakannya. 'Ubaidullah berkata: \"Maka hal ini menakjubkan aku karena dia seorang budak wanita dan dia juga yang menyembelihnya\". Hadits ini diikuti pula oleh ['Abdah] dari ['Ubaidullah]. "},"2140":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ لِرَجُلٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِنٌّ مِنْ الْإِبِلِ فَجَاءَهُ يَتَقَاضَاهُ فَقَالَ أَعْطُوهُ فَطَلَبُوا سِنَّهُ فَلَمْ يَجِدُوا لَهُ إِلَّا سِنًّا فَوْقَهَا فَقَالَ أَعْطُوهُ فَقَالَ أَوْفَيْتَنِي أَوْفَى اللَّهُ بِكَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خِيَارَكُمْ أَحْسَنُكُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; Ada seorang laki-laki yang dijanjikan diberi seekor anak unta oleh Nabi shallallahu 'alaihi wasallam maka dia datang kepada Beliau untuk menagihnya. Maka Beliau bersabda: \"Berikanlah\". Maka para sahabat mencarikan anak unta namun tidak mendapatkannya kecuali satu ekor anak unta yang umurnya lebih diatas yang semestinya. Maka Beliau bersabda: \"Berikanlah kepadanya\". Orang tersebut berkata: \"Engkau telah menepati janji kepadaku semoga Allah membalasnya buat Tuan\". Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang terbaik diantara kalian adalah siapa yang paling baik menunaikan janji\". "},"2141":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَقَاضَاهُ فَأَغْلَظَ فَهَمَّ بِهِ أَصْحَابُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهُ فَإِنَّ لِصَاحِبِ الْحَقِّ مَقَالًا ثُمَّ قَالَ أَعْطُوهُ سِنًّا مِثْلَ سِنِّهِ قَالُوا يَا رَسُولَ اللَّهِ إِلَّا أَمْثَلَ مِنْ سِنِّهِ فَقَالَ أَعْطُوهُ فَإِنَّ مِنْ خَيْرِكُمْ أَحْسَنَكُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] aku mendengar [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] berkata; Ada seorang laki-laki yang datang menemui Nabi shallallahu 'alaihi wasallam untuk menagih apa yang dijanjikan kepadanya. Maka para sahabat marah kepadanya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkanlah dia karena bagi orang yang benar ucapannya wajib dipenuhi\". Kemudian Beliau berkata: \"Berikanlah untuknya seekor anak unta\". Mereka berkata: \"Wahai Rasulullah, tidakada kecuali yang umurnya lebih tua\". Maka Beliau bersabda: \"Berikanlah kepadanya, karena sesungguhnya yang terbaik diantara kalian adalah yang paling baik menunaikan janji\".  "},"2142":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ وَزَعَمَ عُرْوَةُ أَنَّ مَرْوَانَ بْنَ الْحَكَمِ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ حِينَ جَاءَهُ وَفْدُ هَوَازِنَ مُسْلِمِينَ فَسَأَلُوهُ أَنْ يَرُدَّ إِلَيْهِمْ أَمْوَالَهُمْ وَسَبْيَهُمْ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ الْحَدِيثِ إِلَيَّ أَصْدَقُهُ فَاخْتَارُوا إِحْدَى الطَّائِفَتَيْنِ إِمَّا السَّبْيَ وَإِمَّا الْمَالَ وَقَدْ كُنْتُ اسْتَأْنَيْتُ بِهِمْ وَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتَظَرَهُمْ بِضْعَ عَشْرَةَ لَيْلَةً حِينَ قَفَلَ مِنْ الطَّائِفِ فَلَمَّا تَبَيَّنَ لَهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ رَادٍّ إِلَيْهِمْ إِلَّا إِحْدَى الطَّائِفَتَيْنِ قَالُوا فَإِنَّا نَخْتَارُ سَبْيَنَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمُسْلِمِينَ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ إِخْوَانَكُمْ هَؤُلَاءِ قَدْ جَاءُونَا تَائِبِينَ وَإِنِّي قَدْ رَأَيْتُ أَنْ أَرُدَّ إِلَيْهِمْ سَبْيَهُمْ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يُطَيِّبَ بِذَلِكَ فَلْيَفْعَلْ وَمَنْ أَحَبَّ مِنْكُمْ أَنْ يَكُونَ عَلَى حَظِّهِ حَتَّى نُعْطِيَهُ إِيَّاهُ مِنْ أَوَّلِ مَا يُفِيءُ اللَّهُ عَلَيْنَا فَلْيَفْعَلْ فَقَالَ النَّاسُ قَدْ طَيَّبْنَا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا لَا نَدْرِي مَنْ أَذِنَ مِنْكُمْ فِي ذَلِكَ مِمَّنْ لَمْ يَأْذَنْ فَارْجِعُوا حَتَّى يَرْفَعُوا إِلَيْنَا عُرَفَاؤُكُمْ أَمْرَكُمْ فَرَجَعَ النَّاسُ فَكَلَّمَهُمْ عُرَفَاؤُهُمْ ثُمَّ رَجَعُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرُوهُ أَنَّهُمْ قَدْ طَيَّبُوا وَأَذِنُوا","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, telah menceritakan kepada saya [Al Laits] berkata, telah menceritakan kepada saya ['Uqail] dari [Ibnu Syihab] berkata; dan ['Urwah] menduga bahwa [Marwan bin Al Hakam] dan [Al Miswar bin Makhramah] keduanya mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam berdiri ketika datang kepada Beliau suku Hawazin yang telah ditundukkan lalu mereka meminta kepada Beliau agar mengembalikan harta dan para tawanan mereka. Maka Rasulullah shallallahu 'alaihi wasallam berkata, kepada mereka: \"Ucapan yang paling aku sukai adalah yang paling benar. Maka pilihlah salah satu dari dua hal apakah tawanan atau harta dan sungguh aku akan memberi kesempatan terhadap mereka\". Rasulullah shallallahu 'alaihi wasallam telah menanti mereka sekitar sepuluh malam ketika akhirnya mereka kembali dari Tho'if. Setelah jelas bagi mereka bahwa Rasulullah shallallahu 'alaihi wasallam tidak akan mengembalikan kepada mereka kecuali salah satu dari dua pilihan, mereka berkata; \"Kami memilih tawanan\". Maka Rasulullah shallallahu 'alaihi wasallam berdiri di hadapan Kaum Muslimin kemudian memuji Allah yang memang Dia paling berhak untuk dipuji lalu bersabda: \"Kemudian dari pada itu, sesungguhnya saudara-saudara kalian ini telah datang kepada kita dengan bertobat dan sungguh aku berpikir akan mengembalikan para tawanan. Maka siapa diantara kalian yang suka berbuat baik (dengan membebaskan tawanan) dalam masalah ini maka lakukanlah dan siapa diantara kalian yang ingin tetap menjadikannya sebagai haknya hingga kami berikan kepadanya harta fa'i yang Allah karuniakan kepada kita, lakukanlah\". Maka orang-orang berkata: \"Kami serahkan mereka untuk Rasulullah shallallahu 'alaihi wasallam \". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak tahu siapa diantara kalian yang berhak memberi izin dan siapa yang bukan, maka itu kembalilah hingga kalian bawa para pimpinan yang mengurusi urusan kalian\". Akhirnya mereka pulang dan berbicara dengan para pimpinan mereka lalu kembali menghadap Rasulullah shallallahu 'alaihi wasallam dan mereka mengabarkan bahwa mereka telah menyetujui dan memberi izin\". "},"2143":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ وَغَيْرِهِ يَزِيدُ ب��عْضُهُمْ عَلَى بَعْضٍ وَلَمْ يُبَلِّغْهُ كُلُّهُمْ رَجُلٌ وَاحِدٌ مِنْهُمْ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَكُنْتُ عَلَى جَمَلٍ ثَفَالٍ إِنَّمَا هُوَ فِي آخِرِ الْقَوْمِ فَمَرَّ بِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ هَذَا قُلْتُ جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَ مَا لَكَ قُلْتُ إِنِّي عَلَى جَمَلٍ ثَفَالٍ قَالَ أَمَعَكَ قَضِيبٌ قُلْتُ نَعَمْ قَالَ أَعْطِنِيهِ فَأَعْطَيْتُهُ فَضَرَبَهُ فَزَجَرَهُ فَكَانَ مِنْ ذَلِكَ الْمَكَانِ مِنْ أَوَّلِ الْقَوْمِ قَالَ بِعْنِيهِ فَقُلْتُ بَلْ هُوَ لَكَ يَا رَسُولَ اللَّهِ قَالَ بَلْ بِعْنِيهِ قَدْ أَخَذْتُهُ بِأَرْبَعَةِ دَنَانِيرَ وَلَكَ ظَهْرُهُ إِلَى الْمَدِينَةِ فَلَمَّا دَنَوْنَا مِنْ الْمَدِينَةِ أَخَذْتُ أَرْتَحِلُ قَالَ أَيْنَ تُرِيدُ قُلْتُ تَزَوَّجْتُ امْرَأَةً قَدْ خَلَا مِنْهَا قَالَ فَهَلَّا جَارِيَةً تُلَاعِبُهَا وَتُلَاعِبُكَ قُلْتُ إِنَّ أَبِي تُوُفِّيَ وَتَرَكَ بَنَاتٍ فَأَرَدْتُ أَنْ أَنْكِحَ امْرَأَةً قَدْ جَرَّبَتْ خَلَا مِنْهَا قَالَ فَذَلِكَ فَلَمَّا قَدِمْنَا الْمَدِينَةَ قَالَ يَا بِلَالُ اقْضِهِ وَزِدْهُ فَأَعْطَاهُ أَرْبَعَةَ دَنَانِيرَ وَزَادَهُ قِيرَاطًا قَالَ جَابِرٌ لَا تُفَارِقُنِي زِيَادَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَكُنْ الْقِيرَاطُ يُفَارِقُ جِرَابَ جَابِرِ بْنِ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Al Makkiy bin Ibrahim] telah menceritakan kepada kami [Ibnu Juraij] dari ['Atha' nin Abi Rabah] dan sebagian diantara mereka menambahkan dan tidak seorangpun yang menyampaikan seluruhnya kepadanya dari [Jabir bin 'Abdullah radliallahu 'anhuma] berkata: \"Aku pernah bepergian bersama Nabi shallallahu 'alaihi wasallam dengan mengendarai unta yang lambat sehingga menjadi yang terakhir sampai diantara rambongan. Lalu Nabi shallallahu 'alaihi wasallam lewat di depanku seraya berkata: \"Siapa ini?\" Aku menjawab: \"Jabir bin 'Abdullah\". Beliau bertanya: \"Ada apa dengan kamu?\" Aku jawab: \"Aku mengendarai unta yang lambat\". Beliau bertanya: \"Apakah kamu punya tongkat? Aku jawab: \"Ya punya\". Beliau berkata: \"Berikanlah kepadaku\". Maka aku berikan kepada Beliau lalu Beliau memukulkannya kepada untaku hingga dia berjalan cepat dan sejak dari tempat itu dia menjadi yang terdepan diantara rambongan. Beliau berkata: \"Juallah kepadaku\". Aku katakan: \"Bahkan ini untuk Tuan, wahai Rasulullah\". Beliau berkata: \"Juallah kepadaku karena aku akan membelinya dengan empat dinar dan kamu boleh menungganginya hingga tiba di Madinah\". Ketika kami hampir tiba di Madinah aku berjalan untuk pergi. Beliau bertanya: \"Kamu mau kemana?\" Aku katakan: \"Aku hendak menikah dengan seorang wanita yang pernah berkeluarga\". Beliau bertanya: \"Kenapa tidak dengan seorang gadis sehingga kamu bisa bersenang-senang dengannya dan diapun bisa bersenang-sengang denganmu\". Aku katakan: \"Sesungguhnya bapakku telah meninggal dunia dan meninggalkan anak-anak perempuan yang masih kecil-kecil maka aku ingin menikahi seorang wanita yang sudah berpengalaman dalam berumah tangga\". Beliau berkata: \"Oh begitu\". Ketika kami telah tiba di Madinah Beliau bersabda: \"Wahai Bilal, berikanlah kepadanya dan lebihkanlah\". Maka Bilal memberinya empat dinar dan ditambah dengan satu qirath. Jabir berkata: \"Semoga tanbahan yang Rasulullah shallallahu 'alaihi wasallam berikan tidak berpisah dariku\". Maka sejak itu pemberian qirath tersebut tidak pernah berpisah dari tas kulit Jabir bin 'Abdullah. "},"2144":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي قَدْ وَهَبْتُ لَكَ مِنْ نَفْسِي فَقَالَ رَجُلٌ زَوِّجْنِيهَا قَالَ قَدْ زَوَّجْنَاكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Hazim] dari [Sahal bin Sa'ad] berkata; Seorang wanita datang menemui Rasulullah shallallahu 'alaihi wasallam lalu berkata: \"Wahai Rasulullah, aku menawarkan diriku untuk Tuan\". Tiba-tiba ada seorang laki-laki berkata: \"Nikahkanlah aku dengannya\". Beliau berkata: \"Kami nikahkan kamu dengannya dengan mahar bacaan Al Qur'an yang ada padamu\"."},"2145":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا مُعَاوِيَةُ هُوَ ابْنُ سَلَّامٍ عَنْ يَحْيَى قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَبْدِ الْغَافِرِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ بِلَالٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَمْرٍ بَرْنِيٍّ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَيْنَ هَذَا قَالَ بِلَالٌ كَانَ عِنْدَنَا تَمْرٌ رَدِيٌّ فَبِعْتُ مِنْهُ صَاعَيْنِ بِصَاعٍ لِنُطْعِمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ أَوَّهْ أَوَّهْ عَيْنُ الرِّبَا عَيْنُ الرِّبَا لَا تَفْعَلْ وَلَكِنْ إِذَا أَرَدْتَ أَنْ تَشْتَرِيَ فَبِعْ التَّمْرَ بِبَيْعٍ آخَرَ ثُمَّ اشْتَرِهِ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Yahya bin Shalih] telah menceritakan kepada kami [Mu'awiyah, dia adalah Ibnu Sallam] dari [Yahya] berkata; Aku mendengar ['Uqbah bin 'Abdul Ghofir] bahwasanya dia mendengar [Abu Sa'id Al Khudriy radliallahu 'anhu] berkata: \"Bilal datang menemui Nabi shallallahu 'alaihi wasallam dengan membawa kurma Barni (jenis kurma terbaik) maka Nabi shallallahu 'alaihi wasallam berkata, kepadanya: \"Dari mana kurma ini?\" Bilal menjawab: \"Kami memiliki kurma yang jelek lalu kami jual dua sha' kurma tersebut dengan satu sha' kurma yang baik agar kami dapat menghidangkannya kepada Nabi shallallahu 'alaihi wasallam. Maka saat itu juga Nabi shallallahu 'alaihi wasallam berkata: \"Celaka celaka, ini benar-benar riba. Janganlah kamu lakukan seperti itu. Jika kamu mau membeli kurma maka juallah kurmamu dengan harga tertentu kemudian belilah kurma yang baik ini\". "},"2146":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَفِي صَدَقَةِ عُمَرَ رَضِيَ اللَّهُ عَنْهُ لَيْسَ عَلَى الْوَلِيِّ جُنَاحٌ أَنْ يَأْكُلَ وَيُؤْكِلَ صَدِيقًا لَهُ غَيْرَ مُتَأَثِّلٍ مَالًافَكَانَ ابْنُ عُمَرَ هُوَ يَلِي صَدَقَةَ عُمَرَ يُهْدِي لِنَاسٍ مِنْ أَهْلِ مَكَّةَ كَانَ يَنْزِلُ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru] berkata, tentang shadaqahnya 'Umar radliallahu 'anhu: \"Tidak ada dosa bagi seorang wali untuk memakannya dan memberi makan temannya kecuali orang yang mengambil harta anak yatim kedalam hartanya. Kemudian [Ibnu 'Umar] meneruskan shadaqahnya 'Umar yaitu memberikannya kepada orang-orang dari penduduk Makkah yang singgah kepada mereka."},"2147":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ أَخْبَرَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ زَيْدِ بْنِ خَالِدٍ وَأَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَاغْدُ يَا أُنَيْسُ إِلَى امْرَأَةِ هَذَا فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا","id":"Telah menceritakan kepada kami [Abu Al Walid] telah mengabarkan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari [Zaid bin Khalid] dan [Abu Hurairah] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam bersabda: \"Berilah tangguh wanita ini sampai besok wahai Unais.Jika ia mengaku maka rajamlah\"."},"2148":{"ar":"حَدَّثَنَا ابْنُ سَلَّامٍ أَخْبَرَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَجِيءَ بِالنُّعَيْمَانِ أَوْ ابْنِ النُّعَيْمَانِ شَارِبًا فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ فِي الْبَيْتِ أَنْ يَضْرِبُوا قَالَ فَكُنْتُ أَنَا فِيمَنْ ضَرَبَهُ فَضَرَبْنَاهُ بِالنِّعَالِ وَالْجَرِيدِ","id":"Telah menceritakan kepada kami [Ibnu Salam] telah mengabarkan kepada kami ['Abdul Wahhab Ats-Tsaqafiy] dari [Ayyub] dari [Ibnu Abu Mulaikah] dari ['Uqbah bin Al Harits] berkata; Telah didatangkan An-Nu'aiman atau Abu An-Nu'aiman dalam keadaan mabuk maka Rasulullah shallallahu 'alaihi wasallam memerintahkan orang yang ada di Baitullah agar memukulnya. Dia berkata: \"Aku termasuk diantara orang yang memukulnya dimana kami melemparinya dengan sandal dan pelepah kurma\"."},"2149":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ حَزْمٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّهَا أَخْبَرَتْهُ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاأَنَا فَتَلْتُ قَلَائِدَ هَدْيِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيَّ ثُمَّ قَلَّدَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيْهِ ثُمَّ بَعَثَ بِهَا مَعَ أَبِي فَلَمْ يَحْرُمْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ أَحَلَّهُ اللَّهُ لَهُ حَتَّى نُحِرَ الْهَدْيُ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepada saya [Malik] dari ['Abdullah bin Abu Bakar bin Hazm] dari ['Amrah binti 'Abdurrahman] bahwasanya dia mengabarkan kepadanya, ['Aisyah radliallahu 'anha] berkata: \"Aku mengikatkan tali pada hewan qurban Rasulullah shallallahu 'alaihi wasallam dengan tanganku kemudian Rasulullah shallallahu 'alaihi wasallam mengikatnya kembali dengan tangan Beliau lalu mengirimnya kepada bapakku. Maka sejak itu tidak ada yang diharamkan lagi bagi Rasulullah shallallahu 'alaihi wasallam dari apa-apa yang Allah halalkan hingga hewan qurban disembelih\""},"2150":{"ar":"حَدَّثَنِي يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ أَبُو طَلْحَةَ أَكْثَرَ الْأَنْصَارِ بِالْمَدِينَةِ مَالًا وَكَانَ أَحَبَّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءَ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَاءٍ فِيهَا طَيِّبٍ فَلَمَّا نَزَلَتْ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَامَ أَبُو طَلْحَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ تَعَالَى يَقُولُ فِي كِتَابِهِ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }وَإِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءَ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ شِئْتَ فَقَالَ بَخٍ ذَلِكَ مَالٌ رَائِحٌ ذَلِكَ مَالٌ رَائِحٌ قَدْ سَمِعْتُ مَا قُلْتَ فِيهَا وَأَرَى أَنْ تَجْعَلَهَا فِي الْأَقْرَبِينَ قَالَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَمَهَا أَبُو طَلْحَةَ فِي أَقَارِبِهِ وَبَنِي عَمِّهِتَابَعَهُ إِسْمَاعِيلُ عَنْ مَالِكٍ وَقَالَ رَوْحٌ عَنْ مَالِكٍ رَابِحٌ","id":"Telah menceritakan kepada saya [Yahya bin Yahya] berkata, aku membacakan kepada [Malik] dari [Ishaq bin 'Abdullah] bahwa dia mendengar [Anas bin Malik radliallahu 'anhu] berkata; Abu Tholhah adalah orang yang paling banyak hartanya dari kalangan Anshar di kota Madinah berupa dan harta yang paling dicintainya adalah Bairuha' (ladang berikut sumur yang ada di kebun itu) yang menghadap ke masjid dan Rasulullah shallallahu 'alaihi wasallam senantiasa mamemasuki kebun itu dan meminum airnya yang baik tersebut. Ketika turun firman Allah Ta'ala (QS Alu 'Imran: 92 yang artinya): \"Kamu sekali-kali tidak akan sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sehahagian harta yang kamu cintai\", Abu Tholhah mendatangi Rasulullah shallallahu 'alaihi wasallam lalu berkata; \"Wahai Rasulullah, sesungguhnya Allah Ta'ala telah berfirman: \"Kamu sekali-kali tidak akan sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sehahagian harta yang kamu cintai\", dan sesungguhnya harta yang paling aku cintai adalah Bairuha' itu dan aku menshadaqahkannya di jalan Allah dengan berharap kebaikan dan simpanan pahala di sisiNya, maka ambillah wahai Rasulullah kapanpun baginda mau\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: Wah, inilah harta yang menguntungkan, inilah harta yang menguntungkan. Sungguh aku sudah mendengar apa yang kamu ucapkan dan aku berpendapat sebaiknya kamu shadaqahkan buat kerabatmu\". Maka Abu Tholhah berkata: \"Aku akan laksanakan wahai Rasululloloh. Maka Abu Tholhah membagi untuk kerabatnya dan anak-anak pamannya\". Hadits ini juga diikuti oleh [Isma'il] dari [Malik]. Dan [Rauh] berkata dari [Malik]: \"Pahalanya mengalir terus\" "},"2151":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَازِنُ الْأَمِينُ الَّذِي يُنْفِقُ وَرُبَّمَا قَالَ الَّذِي يُعْطِي مَا أُمِرَ بِهِ كَامِلًا مُوَفَّرًا طَيِّبًا نَفْسُهُ إِلَى الَّذِي أُمِرَ بِهِ أَحَدُ الْمُتَصَدِّقَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Alaa'] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin 'Abdullah] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang bendahara yang amanah, yang dia melaksanakan tugasnya (dengan baik) \" --Dan adakalanya Beliau bersabda--: \"Yaitu yang dia melaksanakan apa yang dperintahkan kepadanya dengan sempurna dan jujur serta memiliki jiwa lapang dada, yang dia mengeluarkannya (shadaqah) kepada orang yang berhak sebagaimana diperintahkan adalah termasuk salah satu dari Al Mutashaddiqin\"."},"2152":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ ح و حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمٍ يَغْرِسُ غَرْسًا أَوْ يَزْرَعُ زَرْعًا فَيَأْكُلُ مِنْهُ طَيْرٌ أَوْ إِنْسَانٌ أَوْ بَهِيمَةٌ إِلَّا كَانَ لَهُ بِهِ صَدَقَةٌوَقَالَ لَنَا مُسْلِمٌ حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah]. Dan diriwayatkan pula telah menceritakan kepada saya ['Abdurrahman bin Al Mubarak] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas bin Malik radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslimpun yang bercocok tanam atau menanam satu tanaman lalu tanaman itu dimakan oleh burung atau menusia atau hewan melainkan itu menjadi shadaqah baginya\". Dan berkata, kewpada kami [Muslim] telah menceritakan kepada saya [Aban] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas] dari Nabi shallallahu 'alaihi wasallam."},"2153":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَالِمٍ الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ الْأَلْهَانِيُّ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ قَالَ وَرَأَى سِكَّةً وَشَيْئًا مِنْ آلَةِ الْحَرْثِ فَقَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَدْخُلُ هَذَا بَيْتَ قَوْمٍ إِلَّا أَدْخَلَهُ اللَّهُ الذُّلَّقَالَ أَبُو عَبْد اللَّهِ وَاسْمُ أَبِي أُمَامَةَ صُدَيُّ بْنُ عَجْلَانَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada saya ['Abdullah bin Salim Al Himshiy] telah menceritakan kepada kami [Muhammad bin Zaiyad Al Alhaniy] dari [Abu Umamah Al Bahiliy] berkata, ketika ia melihat cangkul atau sesuatu dari alat bercocok tanam, lalu ia berkata, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barang seperti ini tidak masuk kerumah suatu kaum kecuali Allah akan memberikan kehinaan padanya\". Abu Abdullah Al Bukhariy berkata: \"Dan nama Abu Umamah adalah Shuday bin 'Ajlan\"."},"2154":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَمْسَكَ كَلْبًا فَإِنَّهُ يَنْقُصُ كُلَّ يَوْمٍ مِنْ عَمَلِهِ قِيرَاطٌ إِلَّا كَلْبَ حَرْثٍ أَوْ مَاشِيَةٍقَالَ ابْنُ سِيرِينَ وَأَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا كَلْبَ غَنَمٍ أَوْ حَرْثٍ أَوْ صَيْدٍ وَقَالَ أَبُو حَازِمٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلْبَ صَيْدٍ أَوْ مَاشِيَةٍ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abi Katsir] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang menyentuh anjing berarti sepanjang hari itu dia telah menghapus amalnya sebanyak satu qirath kecuali menyentuh anjing ladang atau anjing jinak\". Berkata, [Ibnu Sirin] dan [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam: \"Kecuali anjing untuk mengembalakan kambing atau ladang atau anjing pemburu\". Dan berkata, [Abu Hazim] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam: \"Anjing pemburu atau anjing yang jinak\". "},"2155":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ أَنَّ السَّائِبَ بْنَ يَزِيدَ حَدَّثَهُ أَنَّهُ سَمِعَ سُفْيَانَ بْنَ أَبِي زُهَيْرٍ رَجُلًا مِنْ أَزْدِ شَنُوءَةَ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اقْتَنَى كَلْبًا لَا يُغْنِي عَنْهُ زَرْعًا وَلَا ضَرْعًا نَقَصَ كُلَّ يَوْمٍ مِنْ عَمَلِهِ قِيرَاطٌ قُلْتُ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِي وَرَبِّ هَذَا الْمَسْجِدِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Yazid bin Khushaifah] bahwa [As Sa'ib bin Yazid] menceritakan kepadanya bahwa dia mendengar [Sufyan bin Abi Zuhair], seorang yang berasal dari suku Azdi Syanu'ah yang juga merupakan shahabat Nabi shallallahu 'alaihi wasallam berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang memelihara anjing yang bukan digunakan untuk menjaga ladang atau mengembalakan ternak berarti sepanjang hari itu dia telah menghapus amalnya sebanyak satu qirath\". Aku (as-Sa'ib) bertanya; \"Apakah benar kamu mendengar ini dari Rasulullah shallallahu 'alaihi wasallam? Dia menjawab: \"Ya demi Rabb masjid ini\". "},"2156":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ سَمِعْتُ أَبَا سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَجُلٌ رَاكِبٌ عَلَى بَقَرَةٍ الْتَفَتَتْ إِلَيْهِ فَقَالَتْ لَمْ أُخْلَقْ لِهَذَا خُلِقْتُ لِلْحِرَاثَةِ قَالَ آمَنْتُ بِهِ أَنَا وَأَبُو بَكْرٍ وَعُمَرُ وَأَخَذَ الذِّئْبُ شَاةً فَتَبِعَهَا الرَّاعِي فَقَالَ لَهُ الذِّئْبُ مَنْ لَهَا يَوْمَ السَّبُعِ يَوْمَ لَا رَاعِيَ لَهَا غَيْرِي قَالَ آمَنْتُ بِهِ أَنَا وَأَبُو بَكْرٍ وَعُمَرُ قَالَ أَبُو سَلَمَةَ وَمَا هُمَا يَوْمَئِذٍ فِي الْقَوْمِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Saad bin Ibrahim] berkata; Aku mendengar [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"(Nanti pada hari qiyamat) orang yang menunggang sapi betina akan diremukkan oleh sapi tersebut seraya berkata; Aku diciptakan bukan untuk ini, tapi aku diciptakan untuk membawajak \". Beliau shallallahu 'alaihi wasallam bersabda; \"Aku beriman tentang kejadian itu, begitu juga Abu Bakar dan 'Umar\". Dan akan ada pula seekor serigala yang memakan kambing lalu pengembalanya mengikutinya. Maka serigala berkata kepada penggembala itu: \"Siapa yang mengawasi kambing itu pada hari berburu ini yang tidak ada yang menjaganya kecuali aku?\" Beliau bersabda: \"Aku beriman tentang kejadian itu, begitu juga Abu Bakar dan 'Umar\". Berkata, Abu Salamah: \"Saat itu Abu Bakar dan 'Umar tidak berada ditengah-tengah orang saat Beliau menceritakan.\""},"2157":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَتْ الْأَنْصَارُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْسِمْ بَيْنَنَا وَبَيْنَ إِخْوَانِنَا النَّخِيلَ قَالَ لَا فَقَالُوا تَكْفُونَا الْمَئُونَةَ وَنَشْرَكْكُمْ فِي الثَّمَرَةِ قَالُوا سَمِعْنَا وَأَطَعْنَا","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] berkata; Orang-orang Anshar berkata, kepada Nabi shallallahu 'alaihi wasallam: \"Bagilah untuk kami dan saudara-saudara kami kebun kurma ini\". Beliau menjawab: \"Tidak\". Mereka (Kaum Muhajirin) berkata; \"Cukup kalian berikan kami pekerjaan untuk mengurus kebun kurma tersebut nanti kami mendapat bagian dari hasil buahnya\". Mereka (Kaum Anshar) berkata; \"Kami dengar dan kami taat\". "},"2158":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ وَلَهَا يَقُولُ حَسَّانُ وَهَانَ عَلَى سَرَاةِ بَنِي لُؤَيٍّحَرِيقٌ بِالْبُوَيْرَةِ مُسْتَطِيرُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bahwa Beliau membakar kebun pohon kurma Bani An Nadhir dan menebanginya yang berada di Al Buwairah dan kepada kebun itu Hassan bersya'ir: Kehinaanlah bagi para pembesar Bani Lu'ay. Telah tersebar kebakaran di Buwairah"},"2159":{"ar":"بَاب حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حَنْظَلَةَ بْنِ قَيْسٍ الْأَنْصَارِيِّ سَمِعَ رَافِعَ بْنَ خَدِيجٍ قَالَكُنَّا أَكْثَرَ أَهْلِ الْمَدِينَةِ مُزْدَرَعًا كُنَّا نُكْرِي الْأَرْضَ بِالنَّاحِيَةِ مِنْهَا مُسَمًّى لِسَيِّدِ الْأَرْضِ قَالَ فَمِمَّا يُصَابُ ذَلِكَ وَتَسْلَمُ الْأَرْضُ وَمِمَّا يُصَابُ الْأَرْضُ وَيَسْلَمُ ذَلِكَ فَنُهِينَا وَأَمَّا الذَّهَبُ وَالْوَرِقُ فَلَمْ يَكُنْ يَوْمَئِذٍ","id":"Bab. Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yahya bin Sa'id] dari [Hanzhalah bin Qais Al Anshariy] dia mendengar [Rafi' bin Khudaij] berkata: \"Di Madinah kami adalah orang-orang yang paling banyak bercocok tanam, sering kami menyewa tanah di sebuah kawasan tertentu milik tuan tanah, diantaranya ada yang gagal dan tanah masih seperti apa adanya, dan diantaranya ada yang berhasil sehingga tanah menjadi rusak, sehingga di kemudian hari kami dilarang sewa-menyewa tanah ini. Ketika itu, emas dan uang belum ada. "},"2160":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَلَ خَيْبَرَ بِشَطْرِ مَا يَخْرُجُ مِنْهَا مِنْ ثَمَرٍ أَوْ زَرْعٍ فَكَانَ يُعْطِي أَزْوَاجَهُ مِائَةَ وَسْقٍ ثَمَانُونَ وَسْقَ تَمْرٍ وَعِشْرُونَ وَسْقَ شَعِيرٍ فَقَسَمَ عُمَرُ خَيْبَرَ فَخَيَّرَ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْطِعَ لَهُنَّ مِنْ الْمَاءِ وَالْأَرْضِ أَوْ يُمْضِيَ لَهُنَّ فَمِنْهُنَّ مَنْ اخْتَارَ الْأَرْضَ وَمِنْهُنَّ مَنْ اخْتَارَ الْوَسْقَ وَكَانَتْ عَائِشَةُ اخْتَارَتْ الْأَرْضَ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Anas bin 'Iyadh] dari ['Ubaidullah] dari [Nafi'] bahwa ['Abdullah bin 'Umar radliallahu 'anhuma] mengabarkannya bahwa Nabi shallallahu 'alaihi wasallam memperkerjakan orang untuk memanfaatkan tanah Khaibar dengan ketentuan separuh dari hasilnya berupa kurma atau sayuran untuk pekerja. Beliau membagikan hasilnya kepada isteri-isteri Beliau sebanyak seratus wasaq, delapan puluh wasaq kurma dan dua puluh wasaq gandum. Pada zamannya, 'Umar radliallahu 'anhu membagi-bagikan tanah Khaibar. Maka isteri-isteri Nabi shallallahu 'alaihi wasallam ada yang mendapatkan air (sumur), tanah atau seperti hak mereka sebelumnya. Dan diantara mereka ada yag memilih tanah dan ada juga yang memilih menerima haq dari hasilnya. Sedangkan 'Aisyah radliallahu 'anha memilih tanah\"."},"2161":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَعَامَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ بِشَطْرِ مَا يَخْرُجُ مِنْهَا مِنْ ثَمَرٍ أَوْ زَرْعٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata: Nabi shallallahu 'alaihi wasallam memperkerjakan orang untuk memanfaatkan tanah Khaibar dengan ketentuan separuh dari hasilnya berupa kurma atau sayuran untuk pekerja. "},"2162":{"ar":"بَاب حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو قُلْتُ لِطَاوُسٍ لَوْ تَرَكْتَ الْمُخَابَرَةَ فَإِنَّهُمْ يَزْعُمُونَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُ قَالَ أَيْ عَمْرُو إِنِّي أُعْطِيهِمْ وَأُغْنِيهِمْ وَإِنَّ أَعْلَمَهُمْ أَخْبَرَنِي يَعْنِي ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَنْهَ عَنْهُ وَلَكِنْ قَالَ أَنْ يَمْنَحَ أَحَدُكُمْ أَخَاهُ خَيْرٌ لَهُ مِنْ أَنْ يَأْخُذَ عَلَيْهِ خَرْجًا مَعْلُومًا","id":"Bab. Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata, ['Amru]; Aku berkata, kepada [Thowus]: \"Mengapa tidak kau tinggalkan sewa-menyewa sementara mereka beranggapan bahwa Nabi shallallahu 'alaihi wasallam melarang mereka?\" Dia, yaitu 'Amru berkata: \"Sungguh aku telah memberi dan mengenalkan pengetahuan yang cukup kepada mereka dan sesungguhnya orang yang paling mengerti dari mereka telah mengabarkan kepadaku, yakni [Ibnu 'Abbas radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam tidak melarang dari itu tetapi Beliau bersabda: \"Seorang dari kalian memberikan kepada saudaranya lebih baik baginya dari pada dia mengambil dengan upah tertentu\". "},"2163":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَى خَيْبَرَ الْيَهُودَ عَلَى أَنْ يَعْمَلُوهَا وَيَزْرَعُوهَا وَلَهُمْ شَطْرُ مَا خَرَجَ مِنْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami n ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan tanah Khaibar kepada orang Yahudi untuk dimanfaatkan dan ditanami tumbuhan dan mereka mendapat separuh dari hasilnya\"."},"2164":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ يَحْيَى سَمِعَ حَنْظَلَةَ الزُّرَقِيَّ عَنْ رَافِعٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا أَكْثَرَ أَهْلِ الْمَدِينَةِ حَقْلًا وَكَانَ أَحَدُنَا يُكْرِي أَرْضَهُ فَيَقُولُ هَذِهِ الْقِطْعَةُ لِي وَهَذِهِ لَكَ فَرُبَّمَا أَخْرَجَتْ ذِهِ وَلَمْ تُخْرِجْ ذِهِ فَنَهَاهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadhol] telah mengabarkan kepada kami [Ibnu 'Uyainah] dari [Yahya] bahwa dia mendengar [Hanzhalah Az Zuraqiy] dari [Rafi' radliallahu 'anhu] berkata: \"Kami adalah orang yang paling banyak memiliki kebun di Madinah dan diantara kami ada yang memperkerjakan orang untuk menggarap ladang dan berkata, kepada penggarapnya: \"Ini bagian untukku dan ini untukmu dan seandainya tidak menghasilkan maka kamu tidak mendapatkan apa-apa\". Maka kemudian Nabi shallallahu 'alaihi wasallam melarang praktek ini\". "},"2165":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا ثَلَاثَةُ نَفَرٍ يَمْشُونَ أَخَذَهُمْ الْمَطَرُ فَأَوَوْا إِلَى غَارٍ فِي جَبَلٍ فَانْحَطَّتْ عَلَى فَمِ غَارِهِمْ صَخْرَةٌ مِنْ الْجَبَلِ فَانْطَبَقَتْ عَلَيْهِمْ فَقَالَ بَعْضُهُمْ لِبَعْضٍ انْظُرُوا أَعْمَالًا عَمِلْتُمُوهَا صَالِحَةً لِلَّهِ فَادْعُوا اللَّهَ بِهَا لَعَلَّهُ يُفَرِّجُهَا عَنْكُمْ قَالَ أَحَدُهُمْ اللَّهُمَّ إِنَّهُ كَانَ لِي وَالِدَانِ شَيْخَانِ كَبِيرَانِ وَلِي صِبْيَةٌ صِغَارٌ كُنْتُ أَرْعَى عَلَيْهِمْ فَإِذَا رُحْتُ عَلَيْهِمْ حَلَبْتُ فَبَدَأْتُ بِوَالِدَيَّ أَسْقِيهِمَا قَبْلَ بَنِيَّ وَإِنِّي اسْتَأْخَرْتُ ذَاتَ يَوْمٍ فَلَمْ آتِ حَتَّى أَمْسَيْتُ فَوَجَدْتُهُمَا نَامَا فَحَلَبْتُ كَمَا كُنْتُ أَحْلُبُ فَقُمْتُ عِنْدَ رُءُوسِهِمَا أَكْرَهُ أَنْ أُوقِظَهُمَا وَأَكْرَهُ أَنْ أَسْقِيَ الصِّبْيَةَ وَالصِّبْيَةُ يَتَضَاغَوْنَ عِنْدَ قَدَمَيَّ حَتَّى طَلَعَ الْفَجْرُ فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُهُ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ لَنَا فَرْجَةً نَرَى مِنْهَا السَّمَاءَ فَفَرَجَ اللَّهُ فَرَأَوْا السَّمَاءَ وَقَالَ الْآخَرُ اللَّهُمَّ إِنَّهَا كَانَتْ لِي بِنْتُ عَمٍّ أَحْبَبْتُهَا كَأَشَدِّ مَا يُحِبُّ الرِّجَالُ النِّسَاءَ فَطَلَبْتُ مِنْهَا فَأَبَتْ عَلَيَّ حَتَّى أَتَيْتُهَا بِمِائَةِ دِينَارٍ فَبَغَيْتُ حَتَّى جَمَعْتُهَا فَلَمَّا وَقَعْتُ بَيْنَ رِجْلَيْهَا قَالَتْ يَا عَبْدَ اللَّهِ اتَّقِ اللَّهَ وَلَا تَفْتَحْ الْخَاتَمَ إِلَّا بِحَقِّهِ فَقُمْتُ فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُهُ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ عَنَّا فَرْجَةً فَفَرَجَ وَقَالَ الثَّالِثُ اللَّهُمَّ إِنِّي اسْتَأْجَرْتُ أَجِيرًا بِفَرَقِ أَرُزٍّ فَلَمَّا قَضَى عَمَلَهُ قَالَ أَعْطِنِي حَقِّي فَعَرَضْتُ عَلَيْهِ فَرَغِبَ عَنْهُ فَلَمْ أَزَلْ أَزْرَعُهُ حَتَّى جَمَعْتُ مِنْهُ بَقَرًا وَرَاعِيَهَا فَجَاءَنِي فَقَالَ اتَّقِ اللَّهَ فَقُلْتُ اذْهَبْ إِلَى ذَلِكَ الْبَقَرِ وَرُعَاتِهَا فَخُذْ فَقَالَ اتَّقِ اللَّهَ وَلَا تَسْتَهْزِئْ بِي فَقُلْتُ إِنِّي لَا أَسْتَهْزِئُ بِكَ فَخُذْ فَأَخَذَهُ فَإِنْ كُنْتَ تَعْلَمُ أَنِّي فَعَلْتُ ذَلِكَ ابْتِغَاءَ وَجْهِكَ فَافْرُجْ مَا بَقِيَ فَفَرَجَ اللَّهُقَالَ أَبُو عَبْد اللَّهِ وَقَالَ إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ بْنِ عُقْبَةَ عَنْ نَافِعٍ فَسَعَيْتُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Abu Dhamrah] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam berkata: \"Ada tiga orang yang sedang bepergian lalu hujan turun hingga akhirnya mereka masuk ke dalam gua pada suatu gunung. Lalu sebuah batu yang jatuh dari gunung di depan mulut gua sehingga menutupi mereka. Satu sama lain diantara berkata; Perhatikanlah amal amal yang pernah kalian amalkan semata karena Allah lalu berdoalah dengan perantaraan amal amal tersebut semoga Allah Ta'ala berkenan membukakan batu tersebut untuk kalian. Seorang diantara mereka berkata; \"Ya Allah, aku memiliki kedua orangtua yang sudah renta dan aku juga mempunyai anak yang masih kecil dimana aku mengembalakan hewan untuk makan minum mereka. Apabila aku sudah selesai aku memeras susu dan aku mulai memberikan susu tersebut untuk kedua orang tua, aku mendahuluinya untuk kedua orangtuaku sebelum anakku. Pada suatu hari aku terlambat pulang hingga malam dan aku dapati kedanya sudah tertidur. Maka aku mencoba menawarkan susu kepada keduanya, aku hampiri di dekat keduanya dan aku khawatir dapat membangunkannya dan aku juga tidak mau memberikan susu ini untuk anak kecilku padahal dia sedang menangis dibawah kakiku meminta minum hingga terbit fajar. Ya Allah seandainya Engkau mengetahui apa yang aku kerjakan itu semata mencari ridhoMu, maka bukakanlah celah batu ini sehingga dari nya kami dapat melihat matahari. Maka Allah membukakan batu itu hinga mereka sedikit dapat melihat matahari\". Kemudian berkata, yang lain: \"Ya Allah, bersamaku ada putri pamanku yang merupakan orang yang paling aku cintai sebagaimana umumnya laki-laki mencintai wanita. Suatu hari aku menginginkannya namun dia menolak aku hingga kemudian aku datang kepadanya denagn membawa seratus dua puluh dinar agar aku bisa berbuat mesum dan menyetubuinya. Ketika aku sudah berada diantara kedua kakinya dia berkata; \"Wahai 'Abdullah, bertaqwalah kepada Allah dan janganlah kamu renggut keperawanan kecuali dengan cara yang haq. Maka bangkit. Ya Allah seandainya Engkau mengetahui apa yang aku kerjakan itu semata mencari ridhoMu, maka bukakanlah celah pintu gua ini untuk kami. Maka batu itu kembali terbuka. Kemudian orang yang ketiga berkata: Ya Allah aku pernah memperkerjakan orang pada ladang padi. Ketika sudah selesai dia meminta upahnya, aku memberikannya namun dia enggan menerimanya. Sejak itu aku meneruskan bertani, hingga aku dapat mengumpulkan harta yang banyak dari hasil yang aku kembangkan tersebut orang itu datang kepadaku lalu berkata \"Bertaqwalah kamu kepada Allah\". Aku katakan: \"Pergilah lihat sapi itu beserta pengembalanya dan ambillah\". Dia berkata: \"Bertaqwalah kepada Allah dan jangan mengolok-olok aku!\" Aku katakan: \"Aku tidak mengolok-olok kamu, ambillah. Maka dia mengambilnya. Jika aku kerjakan itu semata mencari ridhoMu, maka bukakanlah celah batu gua yang masih tersisa\". Maka Allah membukakannya. Berkata, Abu 'Abdullah dan berkata, [Isma'il bin Ibrahim bin 'Uqbah] dari [Nafi']: makna Fabaghaitu maksudnya fasa'aitu (Aku bersungguh-sunguh untuk menyetubuinya)."},"2166":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُلَوْلَا آخِرُ الْمُسْلِمِينَ مَا فَتَحْتُ قَرْيَةً إِلَّا قَسَمْتُهَا بَيْنَ أَهْلِهَا كَمَا قَسَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ","id":"Telah menceritakan kepada kami [Shadaqah] telah mengabarkan kepada kami ['Abdurrahman] dari [Malik] dari [Zaid bin Aslam] dari [bapaknya] berkata; ['Umar radliallahu 'anhu] berkata: \"Kalaulah tidak memikirkan Kaum Muslimin yang lain tentulah aku sudah membagi-bagikan setiap wilayah yang aku taklukan sebagaimana Nabi shallallahu 'alaihi wasallam telah membagi-bagikan tanah Khaibar\"."},"2167":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْمَرَ أَرْضًا لَيْسَتْ لِأَحَدٍ فَهُوَ أَحَقُّقَالَ عُرْوَةُ قَضَى بِهِ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فِي خِلَافَتِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Ubaidullah bin Abi Ja'far] dari [Muhammad bin 'Abdurrahman] dari ['Urwah] dari ['Aisyah radliallahu 'anha] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang memanfaatkan tanah yang tidak ada pemiliknya (tanah tak bertuan), maka orang itu yang paling berhak atasnya\". 'Urwah berkata: 'Umar radliallahu 'anhu menerapkannya dalam kekhilafahannya."},"2168":{"ar":"بَاب حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيَ وَهُوَ فِي مُعَرَّسِهِ مِنْ ذِي الْحُلَيْفَةِ فِي بَطْنِ الْوَادِي فَقِيلَ لَهُ إِنَّكَ بِبَطْحَاءَ مُبَارَكَةٍ فَقَالَ مُوسَى وَقَدْ أَنَاخَ بِنَا سَالِمٌ بِالْمُنَاخِ الَّذِي كَانَ عَبْدُ اللَّهِ يُنِيخُ بِهِ يَتَحَرَّى مُعَرَّسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ أَسْفَلُ مِنْ الْمَسْجِدِ الَّذِي بِبَطْنِ الْوَادِي بَيْنَهُ وَبَيْنَ الطَّرِيقِ وَسَطٌ مِنْ ذَلِكَ","id":"Bab. Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Musa bin 'Uqbh] dari [Salim bin 'Abdullah bin 'Umar] dari [bapaknya radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam: \" Malaikat diperlihatkan kepada Beliau ketika Beliau singgah untuk beristirahat di Dzul Hulaifah di dasar lembah dan dikatakan kepada Beliau; \"Sesungguhnya anda sekarang sedang berada di Bathha' yang penuh berkah\". Dan berkata, Musa; Saat itu Salim beristirahat bersama kami di tempat singgahnya 'Abdullah ketika sedang mencari tempat singgah yang tepat untuk peristirahatan Rasulullah shallallahu 'alaihi wasallam, yaitu pada posisi bawah dari masjid yang ada di dasar lembah itu. Dimana letaknya berada di tengah antara mereka dan jalan yang mereka lalui."},"2169":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا شُعَيْبُ بْنُ إِسْحَاقَ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي يَحْيَى عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّيْلَةَ أَتَانِي آتٍ مِنْ رَبِّي وَهُوَ بِالْعَقِيقِ أَنْ صَلِّ فِي هَذَا الْوَادِي الْمُبَارَكِ وَقُلْ عُمْرَةٌ فِي حَجَّةٍ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Syu'aib bin Ishaq] dari [Al A'raj] berkata, telah menceritakan kepadaku [Yahya] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhu] dari [Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Malam ini Malaikat yang diutus oleh Rabbku datang kepadaku\". Saat itu Beliau sedang berada di lembah Al 'Aqiq dan Malaikat itu berkata; \"Shalatlah di lembah yang penuh barakah ini dan katakanlah: \"Aku berniat melaksanakan 'umrah dalam 'ibadah hajji ini\"."},"2170":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْمِقْدَامِ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى أَخْبَرَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُمَا أَجْلَى الْيَهُودَ وَالنَّصَارَى مِنْ أَرْضِ الْحِجَازِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا ظَهَرَ عَلَى خَيْبَرَ أَرَادَ إِخْرَاجَ الْيَهُودِ مِنْهَا وَكَانَتْ الْأَرْضُ حِينَ ظَهَرَ عَلَيْهَا لِلَّهِ وَلِرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِلْمُسْلِمِينَ وَأَرَادَ إِخْرَاجَ الْيَهُودِ مِنْهَا فَسَأَلَتْ الْيَهُودُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُقِرَّهُمْ بِهَا أَنْ يَكْفُوا عَمَلَهَا وَلَهُمْ نِصْفُ الثَّمَرِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُقِرُّكُمْ بِهَا عَلَى ذَلِكَ مَا شِئْنَا فَقَرُّوا بِهَا حَتَّى أَجْلَاهُمْ عُمَرُ إِلَى تَيْمَاءَ وَأَرِيحَاءَ","id":"Telah menceritakan kepada kami [Ahmad bin Al Miqdam] telah menceritakan kepada kami [Fudhoil bin Sulaiman] telah menceritakan kepada kami [Musa] telah mengabarkan kepada kami [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam \". Dan berkata, ['Abdur Razzaaq] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah menceritakan kepadaku [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu 'Umar] bahwa 'Umar bin Al Khaththab radliallahu 'anhu mengusir Yahudi dan Nashrani dari tanah Hijaz. Dan Rasulullah shallallahu 'alaihi wasallam ketika menaklukan Khaibar berkehendak untuk mengusir Kaum Yahudi dari wilayah tersebut. Dan ketika Beliau menguasainya tanah Khaibar Beliau manfaatkan untuk Allah, RasulNya dan Kaum Muslimin dan Beliau berkehendak mengusir Kaum Yahudi darinya, namun Kaum Yahudi meminta kepada Rasulullah shallallahu 'alaihi wasallam agar Beliau mengizinkan mereka tetap tinggal disana untuk memanfaatkannya dan mereka mendapat hak bagian separuh dari hasil buah-buahannya, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tetapkan kalian tinggal dan memberdayakannya sesuai kehendak kami\". Maka mereka menetap disana hingga akhirnya 'Umar radliallahu 'anhu mengusir mereka ke daerah Taima' dan Ariha'."},"2171":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا الْأَوْزَاعِيُّ عَنْ أَبِي النَّجَاشِيِّ مَوْلَى رَافِعِ بْنِ خَدِيجٍ سَمِعْتُ رَافِعَ بْنَ خَدِيجِ بْنِ رَافِعٍ عَنْ عَمِّهِ ظُهَيْرِ بْنِ رَافِعٍقَالَ ظُهَيْرٌ لَقَدْ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَمْرٍ كَانَ بِنَا رَافِقًا قُلْتُ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهُوَ حَقٌّ قَالَ دَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا تَصْنَعُونَ بِمَحَاقِلِكُمْ قُلْتُ نُؤَاجِرُهَا عَلَى الرُّبُعِ وَعَلَى الْأَوْسُقِ مِنْ التَّمْرِ وَالشَّعِيرِ قَالَ لَا تَفْعَلُوا ازْرَعُوهَا أَوْ أَزْرِعُوهَا أَوْ أَمْسِكُوهَا قَالَ رَافِعٌ قُلْتُ سَمْعًا وَطَاعَةً","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Al Awza'iy] dari [Abu An-Nahasyiy], maula Rafi' bin Khudaij aku mendengar [Rafi' bin Khudaij bin Rafi'] dari pamannya,, [Zhuhjair bin Rafi'] berkata, Zhuhair: \"Rasulullah shallallahu 'alaihi wasallam telah melarang kami dari suatu urusan yang kami dapat mengambil manfaat darinya\". Aku bertanya: \"Apa yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam yang sudah pasti suatu kebenaran?\" Dia berkata: \"Rasulullah shallallahu 'alaihi wasallam memanggil aku seraya bertanya: \"Apa yang kalian kerjakan dengan tanah ladang kalian?\" Aku jawab: \"Kami memberi upah untuk pekerja dengan pembayaran seperempat bagian' atau sewasaq dari kurma atau gandum\". Beliau bersabda: \"Janganlah kalian kerjakan tapi tanamilah oleh kalian sendiri atau pekerjakan orang tanpa bayaran atau kalian biarkan tanah kalian\". Rafi' berkata; Aku katakan: \"Kami mendengar dan kami taati\". "},"2172":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَخْبَرَنَا الْأَوْزَاعِيُّ عَنْ عَطَاءٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانُوا يَزْرَعُونَهَا بِالثُّلُثِ وَالرُّبُعِ وَالنِّصْفِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ لِيَمْنَحْهَا فَإِنْ لَمْ يَفْعَلْ فَلْيُمْسِكْ أَرْضَهُوَقَالَ الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ حَدَّثَنَا مُعَاوِيَةُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ لِيَمْنَحْهَا أَخَاهُ فَإِنْ أَبَى فَلْيُمْسِكْ أَرْضَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] telah mengabarkan kepada kami [Al Awza'iy] dari ['Atha'] dari [Jabir radliallahu 'anhu] berkata: \"Dahulu orang-orang mempraktekkan pemanfaatan tanah ladang dengan upah sepertiga, seperempat atau setengah maka Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang memiliki tanah ladang hendaklah dia garap untuk bercocok tanam atau dia hibahkan. Jika dia tidak lakukan maka hendaklah dia biarkan tanahnya\". Dan berkata, [Ar-Rabi' bin Nafi' Abu Taubah] telah menceritakan kepada kami [Mu'awiyah] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang memiliki tanah ladang hendaklah dia garap untuk bercocok tanam atau dia berikan kepada saudaranya (untuk digarap). Jika dia tidak lakukan maka hendaklah dia biarkan tanahnya\". "},"2173":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ ذَكَرْتُهُ لِطَاوُسٍ فَقَالَ يُزْرِعُ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَنْهَ عَنْهُ وَلَكِنْ قَالَ أَنْ يَمْنَحَ أَحَدُكُمْ أَخَاهُ خَيْرٌ لَهُ مِنْ أَنْ يَأْخُذَ شَ��ْئًا مَعْلُومًا","id":"Bab. Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari ['Amru] berkata; Aku ceritakan kepada [Thowus] maka dia berkata: \"Ditanami\". Berkata, [Ibnu 'Abbas radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam tidak melarang dari itu tetapi Beliau bersabda: \"Seorang dari kalian memberikan kepada saudaranya (tanahnya untuk digarap) lebih baik baginya dari pada dia memungut bayaran tertentu.\""},"2174":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ يُكْرِي مَزَارِعَهُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ وَصَدْرًا مِنْ إِمَارَةِ مُعَاوِيَةَ ثُمَّ حُدِّثَ عَنْ رَافِعِ بْنِ خَدِيجٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ كِرَاءِ الْمَزَارِعِ فَذَهَبَ ابْنُ عُمَرَ إِلَى رَافِعٍ فَذَهَبْتُ مَعَهُ فَسَأَلَهُ فَقَالَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كِرَاءِ الْمَزَارِعِ فَقَالَ ابْنُ عُمَرَ قَدْ عَلِمْتَ أَنَّا كُنَّا نُكْرِي مَزَارِعَنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا عَلَى الْأَرْبِعَاءِ وَبِشَيْءٍ مِنْ التِّبْنِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] bahwa [Ibnu'Umar radliallahu 'anhuma] mempraktekkan sistim upah bagi penggarap ladang pada masa Nabi shallallahu 'alaihi wasallam, Abu Bakar, 'Umar, 'Utsman dan di awal pemerintahan Mu'awiyah kemudian diceritakan dari [Rafi' bin Khudaij] bahwa Nabi shallallahu 'alaihi wasallam melarang menyewakan ladang lalu Ibnu'Umar radliallahu 'anhuma pergi menemui Rafi' dan aku pergi besamanya, lalu bertanya kepadanya maka dia menjawab bahwa Nabi shallallahu 'alaihi wasallam melarang menyewakan ladang maka Ibnu'Umar radliallahu 'anhuma berkata: \"Sungguh kamu telah mengetahui bahwa kami menyewakan ladang pada masa Rasulullah shallallahu 'alaihi wasallam dengan bagian seperempat atau dengan jerami yang harus kami bayarkan. "},"2175":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَالِمٌ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنْتُ أَعْلَمُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْأَرْضَ تُكْرَى ثُمَّ خَشِيَ عَبْدُ اللَّهِ أَنْ يَكُونَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَحْدَثَ فِي ذَلِكَ شَيْئًا لَمْ يَكُنْ يَعْلَمُهُ فَتَرَكَ كِرَاءَ الْأَرْضِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] telah menceritakan kepadaku [Salim] bahwa ['Abdullah bin 'Umar radliallahu 'anhuma] berkata; \"Aku mengetahui bahwa ladang biasa disewakan pada zaman Rasulullah shallallahu 'alaihi wasallam\". Kemudian 'Abdullah bin 'Umar radliallahu 'anhuma takut kalau Nabi shallallahu 'alaihi wasallam telah mengeluarkan sabda lain tentang masalah itu yang dia tidak mengetahui sehingga akhirnya dia meninggalkan menyewakan tanah ladang."},"2176":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا اللَّيْثُ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ حَنْظَلَةَ بْنِ قَيْسٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ حَدَّثَنِي عَمَّايَأَنَّهُمْ كَانُوا يُكْرُونَ الْأَرْضَ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا يَنْبُتُ عَلَى الْأَرْبِعَاءِ أَوْ شَيْءٍ يَسْتَثْنِيهِ صَاحِبُ الْأَرْضِ فَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقُلْتُ لِرَافِعٍ فَكَيْفَ هِيَ بِالدِّينَارِ وَالدِّرْهَمِ فَقَالَ رَافِعٌ لَيْسَ بِهَا بَأْسٌ بِالدِّينَارِ وَالدِّرْهَمِوَقَالَ اللَّيْثُ وَكَانَ الَّذِي نُهِيَ عَنْ ذَلِكَ مَا لَوْ نَظَرَ فِيهِ ذَوُو الْفَهْمِ بِالْحَلَالِ وَالْحَرَامِ لَمْ يُجِيزُوهُ لِمَا فِيهِ مِنْ الْمُخَاطَرَةِ","id":"Telah menceritakan kepada kamu ['Amru bin Khalid] telah menceritakan kepada kami [Al Laits] dari [Rabi'ah bin ABi 'Abdurrahman] dari [Hanzhalah bin Qais] dari [Rafi' bin Khudaij] berkata, telah menceritakan kepadaku [kedua pamanku] bahwasanya mereka menyewakan tanah ladang pada zaman Nabi shallallahu 'alaihi wasallam atas apa yang tumbuh diatasnya dengan bagian seperempat atau sesuatu yang dikecualikan oleh pemilik tanah, maka kemudian Nabi shallallahu 'alaihi wasallam melarangnya. Lalu aku bertanya kepada Rafi': \"Bagaimana bila pembayarannya dengan dinar atau dirham?\" Maka Rafi' berkata: \"Tidak dosa (boleh) dengan dinar dan dirham\". Berkata, Al Laits: \"Pelarangan tentang itu karena bila dipandang oleh orang yang faham tentang halal haram bisa tidak diperbolehkan karena khawatir ada bahayanya\"."},"2177":{"ar":"بَاب حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحٌ حَدَّثَنَا هِلَالٌ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا فُلَيْحٌ عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَوْمًا يُحَدِّثُ وَعِنْدَهُ رَجُلٌ مِنْ أَهْلِ الْبَادِيَةِ أَنَّ رَجُلًا مِنْ أَهْلِ الْجَنَّةِ اسْتَأْذَنَ رَبَّهُ فِي الزَّرْعِ فَقَالَ لَهُ أَلَسْتَ فِيمَا شِئْتَ قَالَ بَلَى وَلَكِنِّي أُحِبُّ أَنْ أَزْرَعَ قَالَ فَبَذَرَ فَبَادَرَ الطَّرْفَ نَبَاتُهُ وَاسْتِوَاؤُهُ وَاسْتِحْصَادُهُ فَكَانَ أَمْثَالَ الْجِبَالِ فَيَقُولُ اللَّهُ دُونَكَ يَا ابْنَ آدَمَ فَإِنَّهُ لَا يُشْبِعُكَ شَيْءٌ فَقَالَ الْأَعْرَابِيُّ وَاللَّهِ لَا تَجِدُهُ إِلَّا قُرَشِيًّا أَوْ أَنْصَارِيًّا فَإِنَّهُمْ أَصْحَابُ زَرْعٍ وَأَمَّا نَحْنُ فَلَسْنَا بِأَصْحَابِ زَرْعٍ فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Bab. Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih] telah menceritakan kepada kami [Hilal]. Dan diriwaatkan pula, telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Fulaih] dari [Hilal bin 'Ali] dari ['Atha' bin Yasar] dari [Abu Hurairah radliallahu 'anhu] bahwa pada suatu hari Nabi shallallahu 'alaihi wasallam berbicara dan disamping Beliau ada seorang laki-laki penduduk Baduy: \"Ada seorang dari penduduk surga meminta izin kepada Rabbnya untuk bercocok tanam. Maka Rabbnya berkata, kepadanya: \"Bukankah kamu bebas melakukan apa saja yang kamu mau?\" Orang itu berkata: \"Benar, tapi aku suka bercocok tanam\". Beliau berkata: \"Maka orang itu bersegera menanam benih sehingga tumbuh berkembang dengan sangat banyak hingga ketika panen hasilnya sebanyak gunung. Maka Allah berfirman: \"Tidak ada yang melebihi kamu wahai anak Adam\". Maka laki-laki Baduy itu berkata: \"Demi Allah, tidak akan anda temui orang seperti itu selain Kaum Quraisy dan Anshar karena mereka para petani sedangkan kami bukanlah petani\". Maka Nabi shallallahu 'alaihi wasallam tertawa."},"2178":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَإِنَّا كُنَّا نَفْرَحُ بِيَوْمِ الْجُمُعَةِ كَانَتْ لَنَا عَجُوزٌ تَأْخُذُ مِنْ أُصُولِ سِلْقٍ لَنَا كُنَّا نَغْرِسُهُ فِي أَرْبِعَائِنَا فَتَجْعَلُهُ فِي قِدْرٍ لَهَا فَتَجْعَلُ فِيهِ حَبَّاتٍ مِنْ شَعِيرٍ لَا أَعْلَمُ إِلَّا أَنَّهُ قَالَ لَيْسَ فِيهِ شَحْمٌ وَلَا وَدَكٌ فَإِذَا صَلَّيْنَا الْجُمُعَةَ زُرْنَاهَا فَقَرَّبَتْهُ إِلَيْنَا فَكُنَّا نَفْرَحُ بِيَوْمِ الْجُمُعَةِ مِنْ أَجْلِ ذَلِكَ وَمَا كُنَّا نَتَغَدَّى وَلَا نَقِيلُ إِلَّا بَعْدَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman] dari [Abi Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] bahwa dia berkata: \"Kami selalu bergembira bila datang hari Jum'at karena ada seorang wanita tua yang mencabut ubi milik kami yang kami tanam di selokan kebun lalu dia memasaknya dengan mencampurnya dengan biji gandum\". Ya'qub berkata: \"Aku tidak tahu kecuali dia mengatakan bahwa tidak ada lemak dan minyak.\"Apabila kami telah selesai shalat Jum'at maka kami datang ke rumah wanita itu lalu dia menyuguhkan masakannya itu kepada kami. Itulah mengapa kami bergembira dengan kehadiran hari Jum'at karena adanya makanan yang disuguhkannya itu. Dan kami tidaklah makan siang dan tidak pula tidur siang (qailulah) melainkan setelah selesai shalat Jum'at\"."},"2179":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَيَقُولُونَ إِنَّ أَبَا هُرَيْرَةَ يُكْثِرُ الْحَدِيثَ وَاللَّهُ الْمَوْعِدُ وَيَقُولُونَ مَا لِلْمُهَاجِرِينَ وَالْأَنْصَارِ لَا يُحَدِّثُونَ مِثْلَ أَحَادِيثِهِ وَإِنَّ إِخْوَتِي مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَإِنَّ إِخْوَتِي مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ عَمَلُ أَمْوَالِهِمْ وَكُنْتُ امْرَأً مِسْكِينًا أَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مِلْءِ بَطْنِي فَأَحْضُرُ حِينَ يَغِيبُونَ وَأَعِي حِينَ يَنْسَوْنَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا لَنْ يَبْسُطَ أَحَدٌ مِنْكُمْ ثَوْبَهُ حَتَّى أَقْضِيَ مَقَالَتِي هَذِهِ ثُمَّ يَجْمَعَهُ إِلَى صَدْرِهِ فَيَنْسَى مِنْ مَقَالَتِي شَيْئًا أَبَدًا فَبَسَطْتُ نَمِرَةً لَيْسَ عَلَيَّ ثَوْبٌ غَيْرُهَا حَتَّى قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَالَتَهُ ثُمَّ جَمَعْتُهَا إِلَى صَدْرِي فَوَالَّذِي بَعَثَهُ بِالْحَقِّ مَا نَسِيتُ مِنْ مَقَالَتِهِ تِلْكَ إِلَى يَوْمِي هَذَا وَاللَّهِ لَوْلَا آيَتَانِ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُكُمْ شَيْئًا أَبَدًا{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ الرَّحِيمُ }","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] berkata: Sesungguhgnya orang-orang mengatakan: \"Abu Hurairah adalah yang paling banyak menyampaikan hadits dan Allah Maha Memenuhi janji. Dan mereka berkata: \"Mengapa Muhajirin dan Anshar menampaikan hadits tidak sebanyak yang aku sampaikan?\" Sesungguhnya saudara-saudaraku dari kalangan Muhajirin mereka disibukkan dengan berdagang di pasar-pasar dan saudara-saudaraku dari kalangan Anshar mereka disibukkan dengan pekerjaan mereka dalam mengurus harta mereka (bercocok tanam). Adapun aku adalah seorang yang miskin, aku selalu bermulazamah (mendampingi) Rasulullah shallallahu 'alaihi wasallam dengan isi perut sekedar kebutuhan pokok, dan aku selalu hadir (dalam majelis) saat mereka tidak bisa hadir dan dapat menjaga hafalan saat mereka lupa\". Dan pada suatu hari Nabi shallallahu 'alaihi wasallam bersabda: \"Sekali-kali janganlah seorang dari kalian menghamparkan kainnya sebelum aku selesai menyampaikan sabdaku ini lalu dia mengumpulkannya dalam dadanya yang akhirnya dia melupakan sesuatu dari sabdaku untuk selamanya\". Maka aku hamparkan kainku yang bermotif karena aku tidak memiliki kain yang lain hingga Nabi shallallahu 'alaihi wasallam selesai menyampaikan sabda Beliau lalu aku kumpulkan dalam dadaku\". Maka demi Dzat yang mengutus Beliau dengan haq, tidaklah aku lupa satupun dari sabda Beliau hingga hari ini dan demi Allah, kalau bukan karena dua ayat dalam Kitabulloh maka aku tidak akan menyampaikannya sesuatu haditspun kepada kalian selamanya\". (Lalu dia membaca ayat 159 dan 160 dari surah Al Baqarah yang artinya: ('Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa penjelasan dan petunjuk ……hingga akhir ayat.. Allah Maha Penyayang) "},"2180":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَدَحٍ فَشَرِبَ مِنْهُ وَعَنْ يَمِينِهِ غُلَامٌ أَصْغَرُ الْقَوْمِ وَالْأَشْيَاخُ عَنْ يَسَارِهِ فَقَالَ يَا غُلَامُ أَتَأْذَنُ لِي أَنْ أُعْطِيَهُ الْأَشْيَاخَ قَالَ مَا كُنْتُ لِأُوثِرَ بِفَضْلِي مِنْكَ أَحَدًا يَا رَسُولَ اللَّهِ فَأَعْطَاهُ إِيَّاهُ","id":"Telah menceritakan kepada kami [Sa'id bin Abi Maryam] telah menceritakan kepada kami [Abu Ghassan] berkata, telah menceritakan kepadaku [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] berkata; Kepada Nabi shallallahu 'alaihi wasallam disodorkan segelas minuman lalu Beliau meminumnya sementara disamping kanan Beliau ada seorang anak kecil yang paling muda diantara kaum yang hadir sedangkan para orang-orang tua ada di sebelah kiri Beliau. Beliau berkata: \"Wahai anak kecil, apakah kamu mengizinkan aku untuk memberi minuman ini kepada para orang tua?\" Anak kecil itu berkata: \" aku tidak akan mendahulukan seorangpun daripada diriku karena keutamaanku selain anda wahai Rasulullah\". Maka Beliau memberikan kepadanya."},"2181":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّهَا حُلِبَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاةٌ دَاجِنٌ وَهِيَ فِي دَارِ أَنَسِ بْنِ مَالِكٍ وَشِيبَ لَبَنُهَا بِمَاءٍ مِنْ الْبِئْرِ الَّتِي فِي دَارِ أَنَسٍ فَأَعْطَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَدَحَ فَشَرِبَ مِنْهُ حَتَّى إِذَا نَزَعَ الْقَدَحَ مِنْ فِيهِ وَعَلَى يَسَارِهِ أَبُو بَكْرٍ وَعَنْ يَمِينِهِ أَعْرَابِيٌّ فَقَالَ عُمَرُ وَخَافَ أَنْ يُعْطِيَهُ الْأَعْرَابِيَّ أَعْطِ أَبَا بَكْرٍ يَا رَسُولَ اللَّهِ عِنْدَكَ فَأَعْطَاهُ الْأَعْرَابِيَّ الَّذِي عَلَى يَمِينِهِ ثُمَّ قَالَ الْأَيْمَنَ فَالْأَيْمَنَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepadaku [Anas bin Malik radliallahu 'anhu] bahwa kepada Rasulullah shallallahu 'alaihi wasallam disiapkan susu hasil perasan kambing peliharaan yang ada di rumah Anas bin Malik dan susu tersebut dicampur dengan air sumur yang ada di rumah Anas, lalu disuguhkan kepada Rasulullah shallallahu 'alaihi wasallam segelas minuman tersebut, lalu Beliau meminumnya hingga ketika Beliau sudah melepas gelas tersebut dari mulut Beliau, sementara di samping kiri Beliau ada Abu Bakar sedangkan di sebelah kanannya ada seorang Baduy, maka 'Umar berkata dalam keadaan khawatir kalau-kalau gelas tersebut diberikan kepada orang Baduy tersebut: \"Berikanlah kepada Abu Bakar wahai Rasulullah yang ada disamping anda\". Namun Beliau memberikannya kepada orang Baduy yang berada di samping kanan Beliau itu seraya bersabda: \"Hendaknya minuman diperuntukkan ke sebelah kanan dan ke kanan seterusnya \"."},"2182":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُمْنَعُ فَضْلُ الْمَاءِ لِيُمْنَعَ بِهِ الْكَلَأُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Jangan kelebihan air ditahan, dengan maksud untuk menahan tumbuhnya tanaman.\" "},"2183":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَمْنَعُوا فَضْلَ الْمَاءِ لِتَمْنَعُوا بِهِ فَضْلَ الْكَلَإِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Ibnu Al Musayyab] dan [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian tahan kelebihan air dengan maksud menahan tumbuhnya tanaman.\""},"2184":{"ar":"حَدَّثَنَا مَحْمُودٌ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَعْدِنُ جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْعَجْمَاءُ جُبَارٌ وَفِي الرِّكَازِ الْخُمْسُ","id":"Telah menceritakan kepada kami [Mahmud] telah mengabarkan kepada kami ['Ubaidullah] dari [Isra'il] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang tambang yang menjadikan celaka tidak ada tuntutan diyat, sumur yang menjadikan celaka tidak ada tuntutan denda, binatang yang menjadikan celaka tidak ada tuntutan diyat, dan harta terpendam (bila ditemukan seseorang) zakatnya seperlima\". "},"2185":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ هُوَ عَلَيْهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }الْآيَةَفَجَاءَ الْأَشْعَثُ فَقَالَ مَا حَدَّثَكُمْ أَبُو عَبْدِ الرَّحْمَنِ فِيَّ أُنْزِلَتْ هَذِهِ الْآيَةُ كَانَتْ لِي بِئْرٌ فِي أَرْضِ ابْنِ عَمٍّ لِي فَقَالَ لِي شُهُودَكَ قُلْتُ مَا لِي شُهُودٌ قَالَ فَيَمِينُهُ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفَ فَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثَ فَأَنْزَلَ اللَّهُ ذَلِكَ تَصْدِيقًا لَهُ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Syaqiq] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah yang dengan sumpahnya itu dia bermaksud mengambil harta seorang Muslim maka dia telah berbuat kedurhakaan dan akan berjumpa dalam keadaan Allah murka kepadanya\". Maka turunlah firman Allah QS Alu 'Imran ayat 77 yang artinya (\"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit…\"). Maka datang [Al Asy'ats] seraya berkata; \"Apa yang Abu 'Abdurrahman katakan kepada kalian sehubungan dengan turunnya ayat ini? Aku dahulu memiliki sumur yang berada di rumah anak pamanku\". Beliau berkata, kepadaku: \"Siapa yang menjadi saksi atas ucapanmu ini?\" Aku menjawab: \"Aku tidak punya saksi\". Beliau berkata: \"Maka dia harus bersumpah\". Aku katakan: \"Wahai Rasulullah, kalau begitu dia pasti akan bersumpah\". Maka Nabi shallallahu 'alaihi wasallam menyebutkan hadits ini lalu turunlah ayat ini sebagai pembenaran atasnya. "},"2186":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ أَبَا صَالِحٍ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يَنْظُرُ اللَّهُ إِلَيْهِمْ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ كَانَ لَهُ فَضْلُ مَاءٍ بِالطَّرِيقِ فَمَنَعَهُ مِنْ ابْنِ السَّبِيلِ وَرَجُلٌ بَايَعَ إِمَامًا لَا يُبَايِعُهُ إِلَّا لِدُنْيَا فَإِنْ أَعْطَاهُ مِنْهَا رَضِيَ وَإِنْ لَمْ يُعْطِهِ مِنْهَا سَخِطَ وَرَجُلٌ أَقَامَ سِلْعَتَهُ بَعْدَ الْعَصْرِ فَقَالَ وَاللَّهِ الَّذِي لَا إِلَهَ غَيْرُهُ لَقَدْ أَعْطَيْتُ بِهَا كَذَا وَكَذَا فَصَدَّقَهُ رَجُلٌ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Wahid bin Ziyad] dari [Al A'masy] berkata, aku mendengar [Abu Shalih] berkata, aku mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga jenis orang yang Allah Ta'ala tidak akan melihat mereka pada hari qiyamat dan tidak mensucikan mereka dan bagi mereka disediakan siksa yang pedih, yaitu seorang yang memiliki kelebihan air di jalan lalu dia tidak memberikannya kepada musafir, seorang yang membai'at imam dan dia tidak membai'atnya kecuali karena kepentingan-kepentingan duniawi, kalau dia diberikan dunia dia ridho kepadanya dan bila tidak dia marah dan seorang yang menjual dagangannya setelah 'Ashar lalu dia bersumpah; demi Allah Dzat yang tidak ada Ilah selain Dia subgguh aku telah memberikan (shadaqah) ini dan itu lalu sumpahnya itu dibenarkan oleh seseorang\". Kemudian Beliau membaca ayat ini: artinya (\"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit…\"). "},"2187":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا النَّخْلَ فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ فَاخْتَصَمَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ أَسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ الْمَاءَ إِلَى جَارِكَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ يَا زُبَيْرُ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنِّي لَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku [Ibnu Syihab] dari ['Urwah] dari ['Abdullah bin Az Zubair radliallahu 'anhuma] bahwasanya dia menceritakan bahwa ada seorang dari kalangan Anshar bersengketa dengan Az Zubair di hadapan Nabi shallallahu 'alaihi wasallam tentang aliran air di daerah Al Harrah yang mereka gunakan untuk menyirami pepohonan kurma. Berkata, orang Anshar tersebut: \"Bukalah air agar bisa mengalir?\" Az Zubair menolaknya lalu keduanya bertengkar di hadapan Nabi shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam berkata, kepada Az Zubair: \"Wahai Zubair, berilah air dan kirimlah buat tetanggamu\". Maka orang Anshar itu marah seraya berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka wajah Rasulullah shallallahu 'alaihi wasallam memerah kemudian berkata: \"Wahai Zubair, berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang\". Maka Az Zubair berkata: \"Demi Allah, sungguh aku menganggap bahwa ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…)."},"2188":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ قَالَخَاصَمَ الزُّبَيْرَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا زُبَيْرُ اسْقِ ثُمَّ أَرْسِلْ فَقَالَ الْأَنْصَارِيُّ إِنَّهُ ابْنُ عَمَّتِكَ فَقَالَ عَلَيْهِ السَّلَام اسْقِ يَا زُبَيْرُ ثُمَّ يَبْلُغُ الْمَاءُ الْجَدْرَ ثُمَّ أَمْسِكْ فَقَالَ الزُّبَيْرُ فَأَحْسِبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Urwah] berkata: Ada seorang dari Kaum Anshar bersengketa dengan Az Zubair lalu Nabi shallallahu 'alaihi wasallam berkata: \" Wahai Zubair, berilah air dan kirimlah buat tetanggamu\". Lalu orang Anshar itu berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka Beliau shallallahu 'alaihi wasallam berkata: \"Wahai Zubair, berilah air kemudian biarkanlah air memenuhi dasar ladang lalu bendunglah\". Kemudian Az Zubair berkata: \"Aku menganggap bahwa ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…)."},"2189":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ أَخْبَرَنَا مَخْلَدُ بْنُ يَزِيدَ الْحَرَّانِيُّ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّهُ حَدَّثَهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ خَاصَمَ الزُّبَيْرَ فِي شِرَاجٍ مِنْ الْحَرَّةِ يَسْقِي بِهَا النَّخْلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ يَا زُبَيْرُ فَأَمَرَهُ بِالْمَعْرُوفِ ثُمَّ أَرْسِلْ إِلَى جَارِكَ فَقَالَ الْأَنْصَارِيُّ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ ثُمَّ احْبِسْ يَرْجِعَ الْمَاءُ إِلَى الْجَدْرِ وَاسْتَوْعَى لَهُ حَقَّهُ فَقَالَ الزُّبَيْرُ وَاللَّهِ إِنَّ هَذِهِ الْآيَةَ أُنْزِلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ }قَالَ لِي ابْنُ شِهَابٍ فَقَدَّرَتْ الْأَنْصَارُ وَالنَّاسُ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْقِ ثُمَّ احْبِسْ حَتَّى يَرْجِعَ إِلَى الْجَدْرِ وَكَانَ ذَلِكَ إِلَى الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Muhammad, dia adalah anak dari Salam] telah mengabarkan kepada kami [Makhlad bin Yazid Al Harraniy] berkata, telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ibnu Syihab] dari ['Urwah bin Az Zubair] bahwasanya dia menceritakan ada seorang dari kalangan Anshar bersengketa dengan Az Zubair di hadapan Nabi shallallahu 'alaihi wasallam tentang aliran air di daerah Al Harrah yang mereka gunakan untuk menyirami pepohonan kurma. Maka Rasulullah shallallahu 'alaihi wasallam berkata kepada Az Zubair: \"Wahai Zubair. Beliau memerintahkannya berbuat ma'ruf.\"Kemudian kirimlah buat tetanggamu\". Orang Anshar itu berkata; \"Tentu saja kamu bela dia karena dia putra bibimu\". Maka wajah Rasulullah shallallahu 'alaihi wasallam memerah kemudian berkata: \"Berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang dan tunaikanlah haknya\". Maka Az Zubair berkata: \"Demi Allah, sungguh ayat ini turun tentang kasus ini, yaitu firman Allah dalam surah An-Nisa ayat 65 yang artinya: (\"Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim terhadap perkara yang mereka perselisihkan…). Ibnu Sihab berkata, kepadaku: \"Maka orang Anshar dan yang lainnya mengukur apa yang Nabi shallallahu 'alaihi wasallam sabdakan tadi: \"Berilah air kemudian bendunglah hingga air itu kembali ke dasar ladang\", dan saat itu mencapai setinggi mata kaki."},"2190":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا رَجُلٌ يَمْشِي فَاشْتَدَّ عَلَيْهِ الْعَطَشُ فَنَزَلَ بِئْرًا فَشَرِبَ مِنْهَا ثُمَّ خَرَجَ فَإِذَا هُوَ بِكَلْبٍ يَلْهَثُ يَأْكُلُ الثَّرَى مِنْ الْعَطَشِ فَقَالَ لَقَدْ بَلَغَ هَذَا مِثْلُ الَّذِي بَلَغَ بِي فَمَلَأَ خُفَّهُ ثُمَّ أَمْسَكَهُ بِفِيهِ ثُمَّ رَقِيَ فَسَقَى الْكَلْبَ فَشَكَرَ اللَّهُ لَهُ فَغَفَرَ لَهُ قَالُوا يَا رَسُولَ اللَّهِ وَإِنَّ لَنَا فِي الْبَهَائِمِ أَجْرًا قَالَ فِي كُلِّ كَبِدٍ رَطْبَةٍ أَ��ْرٌتَابَعَهُ حَمَّادُ بْنُ سَلَمَةَ وَالرَّبِيعُ بْنُ مُسْلِمٍ عَنْ مُحَمَّدِ بْنِ زِيَادٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada seorang laki-laki yang sedang berjalan lalu dia merasakan kehausan yang sangat sehingga dia turun ke suatu sumur lalu minum dari air sumur tersebut. Ketika dia keluar didapatkannya seekor anjing yang sedang menjulurkan lidahnya menjilat-jilat tanah karena kehausan. Orang itu berkata: \"Anjing ini sedang kehausan seperti yang aku alami tadi\". Maka dia (turun kembali ke dalam sumur) dan diisinya sepatunya dengan air dan sambil menggigit sepatunya dengan mulutnya dia naik keatas lalu memberi anjing itu minum. Kemudian dia bersyukur kepada Allah maka Allah mengampuninya\". Para sahabat bertanya: \"Wahai Rasulullah, apakah kita akan dapat pahala dengan berbuat baik kepada hewan?\" Beliau shallallahu 'alaihi wasallam menjawab: \"Terhadap setiap makhluq bernyawa diberi pahala\". Hadits ini diikuti pula oleh [Hammad bin Salamah] dan [Ar-Rabi' bin Muslim] dari [Muhammad bin Ziyad]."},"2191":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أَسْمَاءَ ��ِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةَ الْكُسُوفِ فَقَالَ دَنَتْ مِنِّي النَّارُ حَتَّى قُلْتُ أَيْ رَبِّ وَأَنَا مَعَهُمْ فَإِذَا امْرَأَةٌ حَسِبْتُ أَنَّهُ قَالَ تَخْدِشُهَا هِرَّةٌ قَالَ مَا شَأْنُ هَذِهِ قَالُوا حَبَسَتْهَا حَتَّى مَاتَتْ جُوعًا","id":"Telah menceritakan kepada kami [Ibnu Abi Maryam] telah menceritakan kepada kami [Nafi' bin 'Umar] dari [Ibnu Abi Mulaikah] dari [Asma' binti Abi Bakar RAa] bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat kusuf (gerhana) lalu bersabda: \"Neraka didekatkan kepadaku hingga aku berkata; \"wahai Rabb, aku bersama mereka. Manakala saat itu aku melihat seorang wanita\". Nafi' berkata: Aku menduga dia (Ibnu Abu Mulaikah) mengatakan: \"dicakar-cakar oleh seekor kucing\". Aku bertanya: \"Apa yang menyebabkan demikian? Mereka menjawab: \"Wanita tersebut menahan kucing tersebut hingga mati karena kelaparan\". "},"2192":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُذِّبَتْ امْرَأَةٌ فِي هِرَّةٍ حَبَسَتْهَا حَتَّى مَاتَتْ جُوعًا فَدَخَلَتْ فِيهَا النَّارَ قَالَ فَقَالَ وَاللَّهُ أَعْلَمُ لَا أَنْتِ أَطْعَمْتِهَا وَلَا سَقَيْتِهَا حِينَ حَبَسْتِيهَا وَلَا أَنْتِ أَرْسَلْتِهَا فَأَكَلَتْ مِنْ خَشَاشِ الْأَرْضِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada seorang wanita disiksa disebabkan mengurung seekor kucing hingga mati kelaparan lalu wanita itupun masuk neraka\". Nafi' berkata; Beliau berkata: \"Sungguh Allah Maha Mengetahui bahwa kamu tidak memberinya makan dan minum ketika engkau mengurungnya dan tidak membiarkannya berkeliaran sehingga dia dapat memakan serangga tanah\"."},"2193":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَدَحٍ فَشَرِبَ وَعَنْ يَمِينِهِ غُلَامٌ هُوَ أَحْدَثُ الْقَوْمِ وَالْأَشْيَاخُ عَنْ يَسَارِهِ قَالَ يَا غُلَامُ أَتَأْذَنُ لِي أَنْ أُعْطِيَ الْأَشْيَاخَ فَقَالَ مَا كُنْتُ لِأُوثِرَ بِنَصِيبِي مِنْكَ أَحَدًا يَا رَسُولَ اللَّهِ فَأَعْطَاهُ إِيَّاهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul 'Aziz] dari [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhuma] berkata; Kepada Nabi shallallahu 'alaihi wasallam disodorkan segelas minuman lalu Beliau meminumnya sementara disamping kanan Beliau ada seorang anak kecil yang paling muda diantara kaum yang hadir sedangkan para orang-orang tua ada di sebelah kiri Beliau. Beliau berkata: \"Wahai anak kecil, apakah kamu mengizinkan aku untuk memberi minuman ini kepada para orang tua?\" Anak kecil itu berkata: \"Aku tidak akan mendahulukan seorangpun daripadaku selain anda wahai Rasulullah\". Maka Beliau memberikan kepadanya."},"2194":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَذُودَنَّ رِجَالًا عَنْ حَوْضِي كَمَا تُذَادُ الْغَرِيبَةُ مِنْ الْإِبِلِ عَنْ الْحَوْضِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad]; Aku mendengar [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada dalam genggamanNya, sungguh akan banyak laki-laki yang ditolak dari telagaku sebagaimana dihalaunya unta asing dari telaga (pemilik unta) \""},"2195":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ وَكَثِيرِ بْنِ كَثِيرٍ يَزِيدُ أَحَدُهُمَا عَلَى الْآخَرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُ اللَّهُ أُمَّ إِسْمَاعِيلَ لَوْ تَرَكَتْ زَمْزَمَ أَوْ قَالَ لَوْ لَمْ تَغْرِفْ مِنْ الْمَاءِ لَكَانَتْ عَيْنًا مَعِينًا وَأَقْبَلَ جُرْهُمُ فَقَالُوا أَتَأْذَنِينَ أَنْ نَنْزِلَ عِنْدَكِ قَالَتْ نَعَمْ وَلَا حَقَّ لَكُمْ فِي الْمَاءِ قَالُوا نَعَمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah mengabarkan kepada kami ['Abdur Razaaq] telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] dan [Katsir bin Katsir] yang satu sama lain saling melengklapi dari [Sa'id bin Jubair] berkata; [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Allah merahmati Ummu Isma'il (Siti Hajar) karena kalau dia membiarkan air zamzam\" atau Beliau bersabda: \"kalau dia tidak membendung air zamzam\", tentulah air itu akan menjadi air yang mengalir\". Kemudian datang para musafir kepadanya dan berkata: \"Apakah kamu mengizinkan kami singgah di tempat kamu\"? Siti Hajar berkata: \"Ya boleh namun kalian tidak berhak memilikii air ini\". Mereka menjawab: \"Baik\"."},"2196":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ يَوْمَ الْقِيَامَةِ وَلَا يَنْظُرُ إِلَيْهِمْ رَجُلٌ حَلَفَ عَلَى سِلْعَةٍ لَقَدْ أَعْطَى بِهَا أَكْثَرَ مِمَّا أَعْطَى وَهُوَ كَاذِبٌ وَرَجُلٌ حَلَفَ عَلَى يَمِينٍ كَاذِبَةٍ بَعْدَ الْعَصْرِ لِيَقْتَطِعَ بِهَا مَالَ رَجُلٍ مُسْلِمٍ وَرَجُلٌ مَنَعَ فَضْلَ مَاءٍ فَيَقُولُ اللَّهُ الْيَوْمَ أَمْنَعُكَ فَضْلِي كَمَا مَنَعْتَ فَضْلَ مَا لَمْ تَعْمَلْ يَدَاكَقَالَ عَلِيٌّ حَدَّثَنَا سُفْيَانُ غَيْرَ مَرَّةٍ عَنْ عَمْرٍو سَمِعَ أَبَا صَالِحٍ يَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Abu Shalih Tabi'in (As-Samman] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ada tiga jenis orang yang Allah Ta'ala tidak akan berbicara dengan mereka dan tidak akan melihat mereka pada hari qiyamat, yaitu seorang penjual yang bersumpah terhadap dagangannya dan dia mengaku telah memberi lebih kepada si pembeli dibandingkan yang ia berikan kepada manusia lainnya, padahal dia berdusta, dan seorang yang bersumpah dengan sumpah palsu setelah 'Ashar yang dengan sumpahnya itu dia berambisi untuk mengambil harta orang muslim, dan seseorang yang menolak membagi-bagikan kelebihan air sehingga Allah akan berfirman pada hari kiamat: \"Aku tidak akan beri karuniaKu kepadamu karena kamu telah menghalangi sesutau yang bukan buah hasil kerja kamu\". ['Ali] berkata, telah menceritakan kepada kami [Sufyan] berulang kali dari ['Amru] yang dia mendengar [Abu Shalih] yang katanya dia dapat dari Nabi shallallahu 'alaihi wasallam. "},"2197":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ الصَّعْبَ بْنَ جَثَّامَةَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا حِمَى إِلَّا لِلَّهِ وَلِرَسُولِهِيَحْيَى وَقَالَ بَلَغَنَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَمَى النَّقِيعَ وَأَنَّ عُمَرَ حَمَى السَّرَفَ وَالرَّبَذَةَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa [Ash Sha'ba bin Jutsamah] berkata; Bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Tidak ada himaa kecuali kepada Allah dan RasulNya\". Yahya berkata; Telah sampai kepada kami bahwa Nabi shallallahu 'alaihi wasallam pernah menetapkan himaa di Naqi' sedang 'Umar pernah menetapkan hima di As-Saraf dan Ar-Rabdzah\"."},"2198":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ لِرَجُلٍ أَجْرٌ وَلِرَجُلٍ سِتْرٌ وَعَلَى رَجُلٍ وِزْرٌ فَأَمَّا الَّذِي لَهُ أَجْرٌ فَرَجُلٌ رَبَطَهَا فِي سَبِيلِ اللَّهِ فَأَطَالَ بِهَا فِي مَرْجٍ أَوْ رَوْضَةٍ فَمَا أَصَابَتْ فِي طِيَلِهَا ذَلِكَ مِنْ الْمَرْجِ أَوْ الرَّوْضَةِ كَانَتْ لَهُ حَسَنَاتٍ وَلَوْ أَنَّهُ انْقَطَعَ طِيَلُهَا فَاسْتَنَّتْ شَرَفًا أَوْ شَرَفَيْنِ كَانَتْ آثَارُهَا وَأَرْوَاثُهَا حَسَنَاتٍ لَهُ وَلَوْ أَنَّهَا مَرَّتْ بِنَهَرٍ فَشَرِبَتْ مِنْهُ وَلَمْ يُرِدْ أَنْ يَسْقِيَ كَانَ ذَلِكَ حَسَنَاتٍ لَهُ فَهِيَ لِذَلِكَ أَجْرٌ وَرَجُلٌ رَبَطَهَا تَغَنِّيًا وَتَعَفُّفًا ثُمَّ لَمْ يَنْسَ حَقَّ اللَّهِ فِي رِقَابِهَا وَلَا ظُهُورِهَا فَهِيَ لِذَلِكَ سِتْرٌ وَرَجُلٌ رَبَطَهَا فَخْرًا وَرِيَاءً وَنِوَاءً لِأَهْلِ الْإِسْلَامِ فَهِيَ عَلَى ذَلِكَ وِزْرٌ وَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحُمُرِ فَقَالَ مَا أُنْزِلَ عَلَيَّ فِيهَا شَيْءٌ إِلَّا هَذِهِ الْآيَةُ الْجَامِعَةُ الْفَاذَّةُ{ فَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ }","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik bin Anas] dari [Zaid bin Aslam] dari [Abu Shalih As Samman] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kuda itu ada yang bagi seseorang membawa pahala, ada yang menjadi penyelesaian atau solusi hidup dan ada yang mendatangkan dosa. Adapun orang yang mendapatkan pahala adalah orang yang menggunakan kudanya di jalan Allah dengan dia rawat dan pelihara kudanya di ladang hijau atau rerumputan yang setiap kali tali ikatannya mengenai tanaman atau rerumputan itu maka baginya hasanah (kebaikan) dan seandainya talinya terputus lalu kuda itu lari menjauh lalu mendaki satu atau dua bukit maka bekas dan apa yang diinjaknya menjadi kebaikan baginya dan seandainya kuda itu melewati sungai lalu minum dari air sungai tersebut sedangkan dia tidak berkehendak memberinya minum maka baginya hasanah dan itulah pahala baginya. Yang kedua, seorang yang menjadikan kudanya seagai alat untuk mencari kebutuhan hidup, namun dia tidak melupakan hak Allah pada kaki dan punggung kudanya maka kuda itu menjadi pelindung baginya. Dan yang ketiga, seorang yang menjadikan kudanya sebagai kebanggaan, pamer dan untuk permusuhan melawan Ummat Islam maka baginya mendatangkan dosa\". Kemudian Rasulullah shallallahu 'alaihi wasallam ditanya tentang keledai maka beliau menjawab: \"Tidak ada wahyu yang diturunkan kepadaku tentang hal itu melainkan firman Allah yang mencakup manfaat yang besar yaitu QS. Al Zalzalah ayat 7 dan 8 (yang artinya): (\"Barangsiapa yang mengerjakan kebaikan seberat biji sawi sekalipun, niscaya dia akan melihat (balasan) nya. Dan barangsiapa yang mengerjakan kejahatan sebesar seberat biji sawi sekalipun, niscaya dia akan melihat (balasan) nya pula\")."},"2199":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مَالِكٌ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ اللُّقَطَةِ فَقَالَ اعْرِفْ عِفَاصَهَا وَوِكَاءَهَا ثُمَّ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَشَأْنَكَ بِهَا قَالَ فَضَالَّةُ الْغَنَمِ قَالَ هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ فَضَالَّةُ الْإِبِلِ قَالَ مَا لَكَ وَلَهَا مَعَهَا سِقَاؤُهَا وَحِذَاؤُهَا تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ حَتَّى يَلْقَاهَا رَبُّهَا","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Malik] dari [Rabi'ah bin Abi 'Abdurrahman] dari [Yazid, maula Al Munba'its] dari [Zaid bin Khalid Al Juhaniy radliallahu 'anhu] berkata; \"Datang seorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam lalu bertanya kepada Beliau tentang barang temuan. Maka Beliau bersabda: \"Kamu kenali tutup bungkus dan talinya kemudian umumkan selama satu tahun dan jika datang pemiliknya maka berikanlah namun bila tidak maka menjadi kewenanganmu dengan barang tersebut\". Orang itu bertanya lagi tentang hukum bila menemukan kambing. Maka Beliau menjawab: \"Itu untuk kamu atau saudaramu atau serigala\". Lalu orang itu bertanya lagi tentang menemukan unta. Maka Beliau menjawab: \"Bagaimana kamu ini, padahal unta itu mempunyai kantong air (yang terisi air) dan sepatunya sehingga dia bisa hilir mudik mencari air dan makan rerumputan hingga pemiliknya menemukannya\"."},"2200":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ يَأْخُذَ أَحَدُكُمْ أَحْبُلًا فَيَأْخُذَ حُزْمَةً مِنْ حَطَبٍ فَيَبِيعَ فَيَكُفَّ اللَّهُ بِهِ وَجْهَهُ خَيْرٌ مِنْ أَنْ يَسْأَلَ النَّاسَ أُعْطِيَ أَمْ مُنِعَ","id":"Telah menceritakan kepada kami [Mu'allaa bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Hisyam] dari [bapaknya] dari [Az Zubair bin Al 'Awwam radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh seorang dari kalian yang mengambil talinya lalu dia mencari seikat kayu bakar dan dibawa dengan punggungnya kemudian dia menjualnya lalu Allah mencukupkannya dengan kayu itu lebih baik baginya daripada dia meminta-minta kepada manusia, baik manusia itu memberinya atau menolaknya\"."},"2201":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَحْتَطِبَ أَحَدُكُمْ حُزْمَةً عَلَى ظَهْرِهِ خَيْرٌ لَهُ مِنْ أَنْ يَسْأَلَ أَحَدًا فَيُعْطِيَهُ أَوْ يَمْنَعَهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abu 'Ubaid, maula 'Abdurrahman bin 'Auf] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh seorang dari kalian yang memanggul kayu bakar dengan punggungnya lebih baik baginya daripada dia meminta-minta kepada seseorang, baik orang itu memberinya atau menolaknya\"."},"2202":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنِ بْنِ عَلِيٍّ عَنْ أَبِيهِ حُسَيْنِ بْنِ عَلِيٍّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُمْ أَنَّهُ قَالَأَصَبْتُ شَارِفًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَغْنَمٍ يَوْمَ بَدْرٍ قَالَ وَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَارِفًا أُخْرَى فَأَنَخْتُهُمَا يَوْمًا عِنْدَ بَابِ رَجُلٍ مِنْ الْأَنْصَارِ وَأَنَا أُرِيدُ أَنْ أَحْمِلَ عَلَيْهِمَا إِذْخِرًا لِأَبِيعَهُ وَمَعِي صَائِغٌ مِنْ بَنِي قَيْنُقَاعَ فَأَسْتَعِينَ بِهِ عَلَى وَلِيمَةِ فَاطِمَةَ وَحَمْزَةُ بْنُ عَبْدِ المُطَّلِبِ يَشْرَبُ فِي ذَلِكَ الْبَيْتِ مَعَهُ قَيْنَةٌ فَقَالَتْ أَلَا يَا حَمْزُ لِلشُّرُفِ النِّوَاءِفَثَارَ إِلَيْهِمَا حَمْزَةُ بِالسَّيْفِ فَجَبَّ أَسْنِمَتَهُمَا وَبَقَرَ خَوَاصِرَهُمَا ثُمَّ أَخَذَ مِنْ أَكْبَادِهِمَا قُلْتُ لِابْنِ شِهَابٍ وَمِنْ السَّنَامِ قَالَ قَدْ جَبَّ أَسْنِمَتَهُمَا فَذَهَبَ بِهَا قَالَ ابْنُ شِهَابٍ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَنَظَرْتُ إِلَى مَنْظَرٍ أَفْظَعَنِي فَأَتَيْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ زَيْدُ بْنُ حَارِثَةَ فَأَخْبَرْتُهُ الْخَبَرَ فَخَرَجَ وَمَعَهُ زَيْدٌ فَانْطَلَقْتُ مَعَهُ فَدَخَلَ عَلَى حَمْزَةَ فَتَغَيَّظَ عَلَيْهِ فَرَفَعَ حَمْزَةُ بَصَرَهُ وَقَالَ هَلْ أَنْتُمْ إِلَّا عَبِيدٌ لِآبَائِي فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَهْقِرُ حَتَّى خَرَجَ عَنْهُمْ وَذَلِكَ قَبْلَ تَحْرِيمِ الْخَمْرِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] bahwa [Ibnu Juraij] mengabarkan kepada mereka berkata, telah menceritakan kepadaku [Ibnu Syihab] dari ['Ali bin Husain bin 'Ali] dari [Bapaknya, Husain bin 'Ali] dari ['Ali bin Abi Tholib] radliallahu 'anhum bahwasanya dia berkata, \"Aku memiliki anak unta yang bagus bersama Rasulullah shallallahu 'alaihi wasallam dari harta ghonimah perang Badar\". Dia berkata: \"Dan Rasulullah shallallahu 'alaihi wasallam memberiku lagi anak unta yang lain. Suatu hari aku ikat dua anak unta itu di depan pintu rumah seseorang Kaum Anshar saat aku hendak mencarikan rerumputan untuk kedua unta tersebut. Bersamaku ada seorang tukang emas dari suku Qainuqa' yang kepadanya aku meminta tolong untuk walimah (resepsi pernikahan) Fathimah dan Hamzah bin 'Abdul Muthollib yang dia minum di rumah itu. Ketika itu bersama dia seorang budak penyanyi yang bersyair: \"Siapakah orang yang kuat untuk menghadapi anak unta ini\"? Maka Hamzah tampil dengan menghunus pedang lalu memotong punuk kedua anak unta itu lalu membelah peruknya dan mengambil hatinya\". Aku bertanya kepada Ibnu Syihab; \"Apakah dipotong dari punduknya?\" Dia berkata: Dia telah memotong punuknya dan membawanya\". Berkata Ibnu Syihab, berkata 'Ali radliallahu 'anhu: \"Maka aku melihat ke suatu penglihatan yang mengerikan aku lalu aku temui Nabi shallallahu 'alaihi wasallam yang saat itu bersama Beliau ada Zaid bin Haritsah maka aku kabarkan kejadian tadi. Maka Beliau keluar bersama Zaid dan akupun turut serta lalu Beliau menemui Hamzah dan Beliau marah kepadanya. Hamzah membuka matanya dan berkata: \"Tidaklah kalian selain budak-budak orangtuaku\". Maka Rasulullah shallallahu 'alaihi wasallam kembali ke belakang hingga meninggalkan mereka. Kejadian ini sebelum diharamkannya khamar."},"2203":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ قَالَأَرَادَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْطِعَ مِنْ الْبَحْرَيْنِ فَقَالَتْ الْأَنْصَارُ حَتَّى تُقْطِعَ لِإِخْوَانِنَا مِنْ الْمُهَاجِرِينَ مِثْلَ الَّذِي تُقْطِعُ لَنَا قَالَ سَتَرَوْنَ بَعْدِي أَثَرَةً فَاصْبِرُوا حَتَّى تَلْقَوْنِي","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] berkata, aku mendengar [Anas radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam berkehendak untuk membagi tanah di negeri Bahrain maka orang-orang Anshar berkata: \"Apakah baginda akan membagikannya untuk saudara-saudara kami dari kalangan Muhajirin sama dengan bagian kami?\" Beliau menjawab: \"Kelak kalian akan melihat setelah aku nanti suatu utsrah (sikap individualis). Maka itu bersabarlah hingga kalian bertemu dengan aku\"."},"2204":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُلَيْحٍ قَالَ حَدَّثَنِي أَبِي عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ حَقِّ الْإِبِلِ أَنْ تُحْلَبَ عَلَى الْمَاءِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Muhammad bin Fulaih] berkata, telah menceritakan kepadaku [bapakku] dari [Hilal bin 'Ali] dari ['Abdurrahman bin Abi 'Amrah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Diantara hak unta adalah memberi minum susu untuk orang-orang miskin\" (zakat bagi pemiliknya)."},"2205":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ابْتَاعَ نَخْلًا بَعْدَ أَنْ تُؤَبَّرَ فَثَمَرَتُهَا لِلْبَائِعِ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُ وَمَنْ ابْتَاعَ عَبْدًا وَلَهُ مَالٌ فَمَالُهُ لِلَّذِي بَاعَهُ إِلَّا أَنْ يَشْتَرِطَ الْمُبْتَاعُوَعَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ فِي الْعَبْدِ","id":"Telah mengabarkan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku [Ibnu Syihab] dari [Salim bin 'Abdullah] dari [bapaknya radliallahu 'anhu] berkata, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda \"Siapa yang membeli pohon kurma setelah dikawinkan maka buahnya milik penjualnya kecuali bila disyaratkan oleh pembelinya dan siapa yang membeli budak dan dia memiliki harta maka harta itu milik penjualnya kecuali bila disyaratkan oleh pembelinya\". Dan dari [Malik] dari [Nafi'] dari [Ibnu 'Umar] dan ['Umar] dalam perkara budak."},"2206":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُمْ قَالَرَخَّصَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُبَاعَ الْعَرَايَا بِخَرْصِهَا تَمْرًا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Nafi'] dari [Ibnu 'Umar] dari [Zaid bin Tsabit radliallahu 'anhum] berkata, bahwa Rasulullah shallallahu 'alaihi wasallam memberi kelonggaran bagi pemilik 'Ariyyah untuk menjual buahnya dengan taksiran\". "},"2207":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَانَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُخَابَرَةِ وَالْمُحَاقَلَةِ وَعَنْ الْمُزَابَنَةِ وَعَنْ بَيْعِ الثَّمَرِ حَتَّى يَبْدُوَ صَلَاحُهَا وَأَنْ لَا تُبَاعَ إِلَّا بِالدِّينَارِ وَالدِّرْهَمِ إِلَّا الْعَرَايَا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Ibnu Juraij] dari ['Atha'] dia mendengar [Jabir bin 'Abdullah radliallahu 'anhuma]; Nabi shallallahu 'alaihi wasallam melarang Al Mukhaobarah, Al Muhaaqalah, Al Muzaabanah dan jual beli buah-buahan (dari pohon) hingga telah nampak baiknya dan tidak boleh dijual sesuatupun darinya selain dengan dinar dan dirham kecuali 'ariyyah\"."},"2208":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ أَخْبَرَنَا مَالِكٌ عَنْ دَاوُدَ بْنِ حُصَيْنٍ عَنْ أَبِي سُفْيَانَ مَوْلَى ابْنِ أَبِي أَحْمَدَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَرَخَّصَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْعِ الْعَرَايَا بِخَرْصِهَا مِنْ التَّمْرِ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ أَوْ فِي خَمْسَةِ أَوْسُقٍ شَكَّ دَاوُدُ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] telah mengabarkan kepada kami [Malik] dari [Daud bin Hushain] dari [Abu Sufyan, maulanya Ibnu Abu Ahmad] dari [Abu Hurairah radliallahu 'anhu] berkata, Nabi shallallahu 'alaihi wasallam memberi kelonggaran pada jual beli 'ariyyah pada buah-buahannya apabila kurang dari lima wasaq atau dalam jumlah lima wasaq\". Daud ragu dalam masalah jumlah ini. "},"2209":{"ar":"حَدَّثَنَا زَكَرِيَّاءُ بْنُ يَحْيَى أَخْبَرَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنِي الْوَلِيدُ بْنُ كَثِيرٍ قَالَ أَخْبَرَنِي بُشَيْرُ بْنُ يَسَارٍ مَوْلَى بَنِي حَارِثَةَ أَنَّ رَافِعَ بْنَ خَدِيجٍ وَسَهْلَ بْنَ أَبِي حَثْمَةَ حَدَّثَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُزَابَنَةِ بَيْعِ الثَّمَرِ بِالتَّمْرِ إِلَّا أَصْحَابَ الْعَرَايَا فَإِنَّهُ أَذِنَ لَهُمْقَالَ أَبُو عَبْد اللَّهِ وَقَالَ ابْنُ إِسْحَاقَ حَدَّثَنِ�� بُشَيْرٌ مِثْلَهُ","id":"Telah menceritakan kepada kami [Zakariya' bin Yahya] telah mengabarkan kepada kami [Abu Usamah] berkata, telah menceritakan kepadaku [Ali-Walid bin Katsir] berkata, telah menceritakan kepadaku [Busyair bin Yasar, maula Bani Haritsah] bahwa [Rafi' bin Khudaij] dan [Sahal bin Abi Hatsmah] keduanya menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam melarang Al Muzaabanah, yaitu menjual kurma masak dengan kurma mentah (barter) kecuali para pemilik 'Ariyah, yang Beliau mengijinkan mereka\". Abu 'Abdullah Al Bukhariy berkata, dan [Ibnu Ishaq] berkata, telah menceritakan kapadaku [Busyair] seperti riwayat ini."},"2210":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا جَرِيرٌ عَنْ الْمُغِيرَةِ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَيْفَ تَرَى بَعِيرَكَ أَتَبِيعُنِيهِ قُلْتُ نَعَمْ فَبِعْتُهُ إِيَّاهُ فَلَمَّا قَدِمَ الْمَدِينَةَ غَدَوْتُ إِلَيْهِ بِالْبَعِيرِ فَأَعْطَانِي ثَمَنَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Jarir] dari [Al Mughirah] dari [Asy-Sya'biy] dari [Jabir bin 'Abdullah radliallahu 'anhuma] berkata: \"Aku berperang bersama Nabi shallallahu 'alaihi wasallam, dan Beliau bertanya: \"Bagaimana pendapat kamu tentang unta kamu, apakah kamu mau menjualnya kepadaku?\" Aku jawab: \"Ya\". Maka aku menjualnya kepada Beliau. Ketika Beliau tiba di Madinah pagi-pagi aku temui Beliau dengan membawa unta itu lalu Beliau membayar uangnya kepadaku\". "},"2211":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ قَالَ تَذَاكَرْنَا عِنْدَ إِبْرَاهِيمَ الرَّهْنَ فِي السَّلَمِ فَقَالَ حَدَّثَنِي الْأَسْوَدُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى طَعَامًا مِنْ يَهُودِيٍّ إِلَى أَجَلٍ وَرَهَنَهُ دِرْعًا مِنْ حَدِيدٍ","id":"Telah menceritakan kepada kami [Mu'allaa bin Asad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Al A'masy] berkata; \"Kami pernah saling menceritakan dihadapan [Ibrahim] tentang gadai dalam jual beli As Salam, maka dia berkata, telah menceritakan kepadaku [Al Aswad] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam pernah membeli makanan dari orang Yahudi (yang pembayaranya) di masa yang akan datang lalu Beliau menggadaikan baju besi Beliau (sebagai jaminan) \"."},"2212":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَخَذَ أَمْوَالَ النَّاسِ يُرِيدُ أَدَاءَهَا أَدَّى اللَّهُ عَنْهُ وَمَنْ أَخَذَ يُرِيدُ إِتْلَافَهَا أَتْلَفَهُ اللَّهُ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah Al Uwaisiy] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Tsaur bin Zaid] dari [Abu Al Goits] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengambil harta manusia (berhutang) disertai maksud akan membayarnya maka Allah akan membayarkannya untuknya, sebaliknya siapa yang mengambilnya dengan maksud merusaknya (merugikannya) maka Allah akan merusak orang itu\". "},"2213":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَبْصَرَ يَعْنِي أُحُدًا قَالَ مَا أُحِبُّ أَنَّهُ تَحَوَّلَ لِي ذَهَبًا يَمْكُثُ عِنْدِي مِنْهُ دِينَارٌ فَوْقَ ثَلَاثٍ إِلَّا دِينَارًا أُرْصِدُهُ لِدَيْنٍ ثُمَّ قَالَ إِنَّ الْأَكْثَرِينَ هُمْ الْأَقَلُّونَ إِلَّا مَنْ قَالَ بِالْمَالِ هَكَذَا وَهَكَذَا وَأَشَارَ أَبُو شِهَابٍ بَيْنَ يَدَيْهِ وَعَنْ يَمِينِهِ وَعَنْ شِمَالِهِ وَقَلِيلٌ مَا هُمْ وَقَالَ مَكَانَكَ وَتَقَدَّمَ غَيْرَ بَعِيدٍ فَسَمِعْتُ صَوْتًا فَأَرَدْتُ أَنْ آتِيَهُ ثُمَّ ذَكَرْتُ قَوْلَهُ مَكَانَكَ حَتَّى آتِيَكَ فَلَمَّا جَاءَ قُلْتُ يَا رَسُولَ اللَّهِ الَّذِي سَمِعْتُ أَوْ قَالَ الصَّوْتُ الَّذِي سَمِعْتُ قَالَ وَهَلْ سَمِعْتَ قُلْتُ نَعَمْ قَالَ أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ مَنْ مَاتَ مِنْ أُمَّتِكَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ قُلْتُ وَإِنْ فَعَلَ كَذَا وَكَذَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Syihab] dari [Al A'masy] dari [Zaid bin Wahb] dari [Abu Dzar radliallahu 'anhu] berkata; \"Aku duduk-duduk bersama Nabi shallallahu 'alaihi wasallam dan ketika Beliau melihat bukit Uhud, Beliau bersabda: \"Aku tidak menyukainya seandainya bukit itu dirubah untukku menjadi emas dalam bentuk dinar lalu berada padaku melebihi tiga hari kecuali satu dinar saja yang aku siapkan untuk membayar hutang\". Kemudian Beliau melanjutkan: \"Sesungguhnya kebanyakan orang dalam masalah harta, hanya sedikit saja dari mereka (yang selamat) kecuali orang yang berkata tentang harta begini begini.\" Abu Syihab memberi isyarat dengan tangannya ke arah kanan dan kiri: \"Dan sedikit sekali mereka yang selamat\". Beliau shallallahu 'alaihi wasallam berkata: \"Tetaplah kamu pada tempatmu\". Lalu Beliau melangkah tidak terlalu jauh lalu aku mendengar suara. Semula aku hendak mendatangi Beliau namun aku teringat perintah Beliau; \"Tetaplah kamu pada tempatmu hingga aku datang\". Ketika Beliau sudah datang aku bertanya: \"Wahai Rasulullah, apa yang aku dengar tadi atau suara apakah yang aku dengar tadi?\" Beliau menjawab: \"Apakah kamu mendengar sesuatu\". Aku jawab: \"Ya\". Beliau menjelaskan: \"Tadi Jibril 'alaihissalam datang kepadaku seraya berkata: \"Siapa saja yang mati dari ummatmu dan dia tidak menyekutukan Allah dengan sesuatu apapun pasti akan masuk surga\". Aku bertanya: \"Sekalipun dia berbuat begini begini?\" Jibril menjawab: \"Ya\". "},"2214":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ شَبِيبِ بْنِ سَعِيدٍ حَدَّثَنَا أَبِي عَنْ يُونُسَ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ لِي مِثْلُ أُحُدٍ ذَهَبًا مَا يَسُرُّنِي أَنْ لَا يَمُرَّ عَلَيَّ ثَلَاثٌ وَعِنْدِي مِنْهُ شَيْءٌ إِلَّا شَيْءٌ أُرْصِدُهُ لِدَيْنٍرَوَاهُ صَالِحٌ وَعُقَيْلٌ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Ahmad bin Syabib bin Sa'id] telah menceritakan kepada kami [bapakku] dari [Yunus] berkata, [Ibnu Syihab] telah menceritakan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah] berkata, [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya aku memiliki emas sebesar bukit Uhud yang membuat aku senang tentu tidak akan bersamaku melebihi tiga hari dan bagiku tidak akan ada yang tersisa kecuali satu saja yang aku siapkan untuk membayar hutang\". Hadits ini juga diriwayatkan oleh [Shalih] dan ['Uqail] dari [Az Zuhriy]."},"2215":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا سَلَمَةُ بْنُ كُهَيْلٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ بِمِنًى يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا تَقَاضَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَغْلَظَ لَهُ فَهَمَّ بِهِ أَصْحَابُهُ فَقَالَ دَعُوهُ فَإِنَّ لِصَاحِبِ الْحَقِّ مَقَالًا وَاشْتَرُوا لَهُ بَعِيرًا فَأَعْطُوهُ إِيَّاهُ وَقَالُوا لَا نَجِدُ إِلَّا أَفْضَلَ مِنْ سِنِّهِ قَالَ اشْتَرُوهُ فَأَعْطُوهُ إِيَّاهُ فَإِنَّ خَيْرَكُمْ أَحْسَنُكُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami [Salamah bin Kuhail] berkata, aku mendengar [Abu Salamah] di Mina menceritakan dari [Abu Hurairah radliallahu 'anhu] bahwa ada seorang laki-laki yang datang menemui Nabi shallallahu 'alaihi wasallam untuk menagih apa yang dijanjikan kepadanya. Maka para sahabat marah kepadanya. Beliau shallallahu 'alaihi wasallam bersabda: \"Biarkanlah dia karena bagi orang yang benar ucapannya wajib dipenuhi, belikanlah untuknya seekor unta dan berikanlah kepadanya\". Dan mereka berkata: \"Kami tidak mendapatkannya kecuali yang umurnya lebih tua\". Maka Beliau bersabda: \"Beli dan berikanlah kepadanya, karena yang terbaik diantara kalian adalah yang paling baik menunaikan janji\". "},"2216":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ عَنْ رِبْعِيٍّ عَنْ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَاتَ رَجُلٌ فَقِيلَ لَهُ قَالَ كُنْتُ أُبَايِعُ النَّاسَ فَأَتَجَوَّزُ عَنْ الْمُوسِرِ وَأُخَفِّفُ عَنْ الْمُعْسِرِ فَغُفِرَ لَهُقَالَ أَبُو مَسْعُودٍ سَمِعْتُهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] dari ['Abdul Malik] dari [Rib'iy] dari [Hudzaifah radliallahu 'anhu] berkata, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Ada seorang yang mati lalu ia ditanya, dan menjawab; Aku pernah berjual beli dengan banyak orang, aku menagih orang-orang yang dalam kelonggaran saja, dan meringankan siapa yang sedang kesulitan\". Maka orang itu diampuni dosanya\". Berkata, [Abu Mas'ud] aku mendengar dari Nabi shallallahu 'alaihi wasallam. "},"2217":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي سَلَمَةُ بْنُ كُهَيْلٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَقَاضَاهُ بَعِيرًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطُوهُ فَقَالُوا مَا نَجِدُ إِلَّا سِنًّا أَفْضَلَ مِنْ سِنِّهِ فَقَالَ الرَّجُلُ أَوْفَيْتَنِي أَوْفَاكَ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطُوهُ فَإِنَّ مِنْ خِيَارِ النَّاسِ أَحْسَنَهُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Sufyan] berkata, telah menceritakan kepadaku [Salamah bin Kuhail] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] bahwa ada seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam untuk menagih unta yang dijanjikan kepadanya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikanlah\". Mereka berkata: \"Kami tidak mendapatkannya kecuali yang umurnya lebih tua\". Orang itu berkata: \"Berikanlah kepadaku nanti Allah akan membalasnya\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikanlah kepadanya, karena yang terbaik diantara manusia adalah mereka yang paling baik menunaikan janji\"."},"2218":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ لِرَجُلٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِنٌّ مِنْ الْإِبِلِ فَجَاءَهُ يَتَقَاضَاهُ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطُوهُ فَطَلَبُوا سِنَّهُ فَلَمْ يَجِدُوا لَهُ إِلَّا سِنًّا فَوْقَهَا فَقَالَ أَعْطُوهُ فَقَالَ أَوْفَيْتَنِي وَفَى اللَّهُ بِكَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خِيَارَكُمْ أَحْسَنُكُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Abu Nu'aim] dari [Sufyan] dari [Salamah] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; Ada seorang laki-laki pernah dijanjikan seekor anak unta oleh Nabi shallallahu 'alaihi wasallam lalu orang itu datang kepada Beliau untuk menagihnya. Maka Beliau shallallahu 'alaihi wasallam bersabda: \"Berikanlah\". Maka orang-orang mencari anak unta namun mereka tidak mendapatkannya kecuali anak unta yang lebih tua umurnya, maka Beliau bersabda: \"Berikanlah kepadanya\". Orang itu berkata: \"Anda telah memberikannya kepadaku semoga Allah membalas anda\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang terbaik diantara kalian adalah siapa yang paling baik menunaikan janji\". "},"2219":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا مِسْعَرٌ حَدَّثَنَا مُحَارِبُ بْنُ دِثَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْمَسْجِدِ قَالَ مِسْعَرٌ أُرَاهُ قَالَ ضُحًى فَقَالَ صَلِّ رَكْعَتَيْنِ وَكَانَ لِي عَلَيْهِ دَيْنٌ فَقَضَانِي وَزَادَنِي","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Mis'ar] telah menceritakan kepada kami [Muharib bin Ditsar] dari [Jabir bin 'Abdullah radliallahu 'anhuma] berkata: \"Aku menemui Nabi shallallahu 'alaihi wasallam saat Beliau berada di masjid\". Mis'ar berkata: \"Aku menduga dia berkata,, \"saat waktu dhuha\". Berkata, Jabir bin 'Abdullah: \"Beliau mengerjakan shalat dua raka'at\". Ketika itu Beliau mempunyai hutang kepadaku. Maka Beliau membayarnya dan memberi tambahan kepadaku\". "},"2220":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي ابْنُ كَعْبِ بْنِ مَالِكٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ أَبَاهُ قُتِلَ يَوْمَ أُحُدٍ شَهِيدًا وَعَلَيْهِ دَيْنٌ فَاشْتَدَّ الْغُرَمَاءُ فِي حُقُوقِهِمْ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُمْ أَنْ يَقْبَلُوا تَمْرَ حَائِطِي وَيُحَلِّلُوا أَبِي فَأَبَوْا فَلَمْ يُعْطِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَائِطِي وَقَالَ سَنَغْدُو عَلَيْكَ فَغَدَا عَلَيْنَا حِينَ أَصْبَحَ فَطَافَ فِي النَّخْلِ وَدَعَا فِي ثَمَرِهَا بِالْبَرَكَةِ فَجَدَدْتُهَا فَقَضَيْتُهُمْ وَبَقِيَ لَنَا مِنْ تَمْرِهَا","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy] berkata, telah menceritakan kepadaku [Ibnu Kaab bin Malik] bahwa [Jabir bin 'Abdullah radliallahu 'anhuma] mengabarkan kepadanya bahwa bapaknya terbunuh dalam perang Uhud sebagai syahid sementara dia meninggalkan hutang, lalu para pemilik piutang mendesak agar hak-hak mereka ditunaikan, maka aku datang menemui Nabi shallallahu 'alaihi wasallam, Beliau meminta agar para pemilik piutang mau menerima kebunku sebagai pembayaran dan pelunasan hutang bapakku namun mereka menolaknya sehingga Nabi shallallahu 'alaihi wasallam berkata: \"Tunggu sampai besok\". Akhirnya besok paginya Beliau mengelilingi pohon-pohon kurma lalu berdoa minta keberkahan pada buah-buahannya. Maka aku dapatkan buah-buha kurma itu tumbuh banyak lalu aku berikan untuk membayar hutang kepada mereka dan buahnya masih tersisa untuk kami.\""},"2221":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسٌ عَنْ هِشَامٍ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ أَخْبَرَهُأَنَّ أَبَاهُ تُوُفِّيَ وَتَرَكَ عَلَيْهِ ثَلَاثِينَ وَسْقًا لِرَجُلٍ مِنْ الْيَهُودِ فَاسْتَنْظَرَهُ جَابِرٌ فَأَبَى أَنْ يُنْظِرَهُ فَكَلَّمَ جَابِرٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَشْفَعَ لَهُ إِلَيْهِ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَلَّمَ الْيَهُودِيَّ لِيَأْخُذَ ثَمَرَ نَخْلِهِ بِالَّذِي لَهُ فَأَبَى فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّخْلَ فَمَشَى فِيهَا ثُمَّ قَالَ لِجَابِرٍ جُدَّ لَهُ فَأَوْفِ لَهُ الَّذِي لَهُ فَجَدَّهُ بَعْدَمَا رَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَوْفَاهُ ثَلَاثِينَ وَسْقًا وَفَضَلَتْ لَهُ سَبْعَةَ عَشَرَ وَسْقًا فَجَاءَ جَابِرٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُخْبِرَهُ بِالَّذِي كَانَ فَوَجَدَهُ يُصَلِّي الْعَصْرَ فَلَمَّا انْصَرَفَ أَخْبَرَهُ بِالْفَضْلِ فَقَالَ أَخْبِرْ ذَلِكَ ابْنَ الْخَطَّابِ فَذَهَبَ جَابِرٌ إِلَى عُمَرَ فَأَخْبَرَهُ فَقَالَ لَهُ عُمَرُ لَقَدْ عَلِمْتُ حِينَ مَشَى فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُبَارَكَنَّ فِيهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Anas] dari [Hisyam] dari [Wahb bin Kaisan] dari [Jabir bin 'Abdullah radliallahu 'anhuma] bahwa dia mengabarkan kepadanya bahwa bapaknya wafat dan meninggalkan hutang sebanyak tiga puluh wasaq kepada orang Yahudi kemudian Jabir meminta penangguhan pelunasannya namun orang Yahudi itu menolaknya lalu Jabir menceritakannya kepada Rasulullah shallallahu 'alaihi wasallam agar membantuya dalam permasalahannya dengan orang itu. Maka Rasulullah shallallahu 'alaihi wasallam mendatangi dan berbicara dengan orang Yahudi tersebut agar bersedia menerima kebun kurma Jabir sebagai pelunasan hutang bapaknya namun orang Yahudi tersebut tetap tidak mau. Kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi pohon korma milik Jabir lalu mengelilinginya kemudian berkata kepada Jabir: Bersungguh-sungguhlah kamu untuk membayar hutang dengan buah yang ada pada pohon kurma ini\". Maka Jabir menandainya setelah Rasulullah shallallahu 'alaihi wasallam pergi lalu dia melunasi hutang sebanyak tiga puluh wasaq dan masih tersisa sebanyak tujuh belas wasaq kemudian Jabir datang menemui Rasulullah shallallahu 'alaihi wasallam untuk mengabarkan apa yang terjadi namun didapatinya Beliau sedang melaksanakan shalat 'Ashar. Ketika sudah selesai, Jabir mengabarkan kepada Beliau tentang sisa buah kurma tersebut. Maka Beliau bersabda: \"Kabarkanlah hal ini kepada 'Umar bin Al Khaththob\". Maka Jabir pergi menemui 'Umar lalu mengabarkannya, maka 'Umar berkata: \"Sungguh aku sudah mengetahui ketika Beliau mengelilingi pohon kurma tersebut untuk memberkahinya\"."},"2222":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فِي الصَّلَاةِ وَيَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْمَأْثَمِ وَالْمَغْرَمِ فَقَالَ لَهُ قَائِلٌ مَا أَكْثَرَ مَا تَسْتَعِيذُ يَا رَسُولَ اللَّهِ مِنْ الْمَغْرَمِ قَالَ إِنَّ الرَّجُلَ إِذَا غَرِمَ حَدَّثَ فَكَذَبَ وَوَعَدَ فَأَخْلَفَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy]. Dan diriwayatkan pula, telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [saudaraku] dari [Sulaiman] dari [Muhammad bin Abi 'Atiq] dari [Ibnu Syihab] dari ['Urwah] bahwa ['Aisyah radliallahu 'anha] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam berdo'a dalam shalat: \"Allahumma innii a'uudzu bika minal ma'tsami wal maghram\" (Ya Allah aku berlindung kepadamu dari berbuat dosa dan terlilit hutang). Lalu ada seseorang yang bertanya: \"Mengapa anda banyak meminta perlindungan dari hutang, wahai Rasulullah?\" Beliau menjawab: \"Sesungguhnya seseorang apabila sedang berhutang ketika dia berbicara biasanya berdusta dan bila berjanji sering menyelisihinya\"."},"2223":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ وَمَنْ تَرَكَ كَلًّا فَإِلَيْنَا","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Adiy bin Tsabit] dari [Abu Hazim] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang (mati) meninggalkan harta maka hartanya itu untuk ahli warisnya dan siapa yang meninggalkan keluarga yang miskin maka menjadi tangungan kami\". "},"2224":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا فُلَيْحٌ عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُؤْمِنٍ إِلَّا وَأَنَا أَوْلَى بِهِ فِي الدُّنْيَا وَالْآخِرَةِ اقْرَءُوا إِنْ شِئْتُمْ{ النَّبِيُّ أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ }فَأَيُّمَا مُؤْمِ��ٍ مَاتَ وَتَرَكَ مَالًا فَلْيَرِثْهُ عَصَبَتُهُ مَنْ كَانُوا وَمَنْ تَرَكَ دَيْنًا أَوْ ضَيَاعًا فَلْيَأْتِنِي فَأَنَا مَوْلَاهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammd] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Fulaih] dari [Hilal bin 'Ali] dari ['Abdurrahman bin Abi 'Amrah] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang mu'min melainkan aku lebih utama untuk menanggung mereka daripada mereka sendiri baik di dunia maupun di akhirat. Bacalah kalau kalian mau; Annabiyyu awlaa bilmu'miniina min anfusihim (Nabi itu lebih utama bagi orang-orang beriman dari diri mereka sendiri). Maka siapa saja dari orang mu'min yang meninggal dunia dan meninggalkan harta benda, maka harta itu diwariskan untuk keluarganya yang ada dan siapa yang meninggalkan hutang atau kehilangan sesuatu maka datanglah kepadaku karena aku adalah maula (pelindung) nya\". "},"2225":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ أَخِي وَهْبِ بْنِ مُنَبِّهٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَطْلُ الْغَنِيِّ ظُلْمٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul A'laa] dari [Ma'mar] dari [Hammam bin Munabbih, saudaranya Wahb bin Munabbih] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Menunda pembayaran hutang bagi orang kaya adalah kezhaliman\"."},"2226":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ سَلَمَةَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ يَتَقَاضَاهُ فَأَغْلَظَ لَهُ فَهَمَّ بِهِ أَصْحَابُهُ فَقَالَ دَعُوهُ فَإِنَّ لِصَاحِبِ الْحَقِّ مَقَالًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Salamah] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu]: Ada seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam untuk menagih apa yang dijanjikan kepadanya. Maka para sahabat marah kepadanya. Maka Beliau shallallahu 'alaihi wasallam bersabda: \"Biarkanlah saja dia, karena orang yang benar berhak memperoleh tempat untuk menyampaikan kebenarannya \". "},"2227":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ أَخْبَرَهُ أَنَّ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَدْرَكَ مَالَهُ بِعَيْنِهِ عِنْدَ رَجُلٍ أَوْ إِنْسَانٍ قَدْ أَفْلَسَ فَهُوَ أَحَقُّ بِهِ مِنْ غَيْرِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepadaku [Abu Bakar bin Muhammad bin 'Amru bin Hazm] bahwa ['Umar bin 'Abdul 'Aziz] mengabarkan kepadanya bahwa [Abu Bakar bin 'Abdurrahman bin Al Harits bin Hisyam] mengabarkan kepadanya bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda atau katanya; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mendapatkan hartanya pada seseorang namun sudah rusak maka orang itu yang paling berhak tentang harta itu dari pada orang lain\"."},"2228":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ حَدَّثَنَا عَطَاءُ بْنُ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَعْتَقَ رَجُلٌ غُلَامًا لَهُ عَنْ دُبُرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَشْتَرِيهِ مِنِّي فَاشْتَرَاهُ نُعَيْمُ بْنُ عَبْدِ اللَّهِ فَأَخَذَ ثَمَنَهُ فَدَفَعَهُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Husain Al Mu'allim] telah menceritakan kepada kami ['Atha' bin Abu Ribah] dari [Jabir bin 'Abdullah radliallahu 'anhuma] berkata; Ada seorang membebaskan budak sepeninggal tuannya lalu Nabi shallallahu 'alaihi wasallam berkata: \"Siapa yang mau membelinya dariku?\" Maka budak itu dibeli oleh Nu'aim bin 'Abdullah lalu Beliau mengambil uang pembelian tersebut kemudian memberikan uang itu kepada orang laki-laki tadi\"."},"2229":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ عَامِرٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَأُصِيبَ عَبْدُ اللَّهِ وَتَرَكَ عِيَالًا وَدَيْنًا فَطَلَبْتُ إِلَى أَصْحَابِ الدَّيْنِ أَنْ يَضَعُوا بَعْضًا مِنْ دَيْنِهِ فَأَبَوْا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَشْفَعْتُ بِهِ عَلَيْهِمْ فَأَبَوْا فَقَالَ صَنِّفْ تَمْرَكَ كُلَّ شَيْءٍ مِنْهُ عَلَى حِدَتِهِ عِذْقَ ابْنِ زَيْدٍ عَلَى حِدَةٍ وَاللِّينَ عَلَى حِدَةٍ وَالْعَجْوَةَ عَلَى حِدَةٍ ثُمَّ أَحْضِرْهُمْ حَتَّى آتِيَكَ فَفَعَلْتُ ثُمَّ جَاءَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَعَدَ عَلَيْهِ وَكَالَ لِكُلِّ رَجُلٍ حَتَّى اسْتَوْفَى وَبَقِيَ التَّمْرُ كَمَا هُوَ كَأَنَّهُ لَمْ يُمَسَّ وَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاضِحٍ لَنَا فَأَزْحَفَ الْجَمَلُ فَتَخَلَّفَ عَلَيَّ فَوَكَزَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَلْفِهِ قَالَ بِعْنِيهِ وَلَكَ ظَهْرُهُ إِلَى الْمَدِينَةِ فَلَمَّا دَنَوْنَا اسْتَأْذَنْتُ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي حَدِيثُ عَهْدٍ بِعُرْسٍ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا تَزَوَّجْتَ بِكْرًا أَمْ ثَيِّبًا قُلْتُ ثَيِّبًا أُصِيبَ عَبْدُ اللَّهِ وَتَرَكَ جَوَارِيَ صِغَارًا فَتَزَوَّجْتُ ثَيِّبًا تُعَلِّمُهُنَّ وَتُؤَدِّبُهُنَّ ثُمَّ قَالَ ائْتِ أَهْلَكَ فَقَدِمْتُ فَأَخْبَرْتُ خَالِي بِبَيْعِ الْجَمَلِ فَلَامَنِي فَأَخْبَرْتُهُ بِإِعْيَاءِ الْجَمَلِ وَبِالَّذِي كَانَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَكْزِهِ إِيَّاهُ فَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَوْتُ إِلَيْهِ بِالْجَمَلِ فَأَعْطَانِي ثَمَنَ الْجَمَلِ وَالْجَمَلَ وَسَهْمِي مَعَ الْقَوْمِ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari ['Amir] dari [Jabir radliallahu 'anhu] berkata; 'Abdullah meninggal dunia dan meninggalkan keluarga yang perlu ditanggung dan hutang. Maka aku meminta kepada para pemilik piutang agar membebaskan sebagian dari hutangnya namun mereka menolaknya. Lalu aku menemui Nabi shallallahu 'alaihi wasallam untuk meminta bantuan Beliau untuk meminta keringanan kepada mereka namun mereka tetap menolaknya. Maka Beliau berkata: \"Pisahkanlah buah kurma kamu dari segala sesuatunya dari pohonnya, kurma jenis Ibnu Zaid dari pohonnya, kurma jenis Al Lain dari pohonnya, serta kurma jenis al-Ajwa' dari pohonnya kemudian bawalah kepada mereka hingga aku datang kepadamu\". Maka aku kerjakan semua perintah Beliau itu kemudian Beliau shallallahu 'alaihi wasallam datang lalu duduk dan membayar bagi setiap piutang hingga lunas dan buah kurmanya masih tersisa sebagaimana semula seolah belum pernah disentuh sedikitpun. Lalu aku berperang bersama Nabi shallallahu 'alaihi wasallam pada suatu peperangan dan unta tungganganku telah memperlambat aku hingga akhirnya unta itu dipukul oleh Nabi shallallahu 'alaihi wasallam dari belakangnya lalu Beliau berkata; \"Juallah kepadaku unta ini dan kamu boleh menungganginya sampai Madinah\". Ketika sudah sampai aku meminta izin dan setelah itu aku katakan kepada Beliau: \"Wahai Rasulullah, aku baru saja menikah\". Beliau bertanya: \"Kamu menikah dengan seorang gadis atau janda?\" Aku jawab: \"Dengan janda, karena 'Abdullah (bapakku) telah wafat dan meninggalkan anak-anak yag masih kecil maka aku menikahi seorang janda agar ia dapat mengajarkan dan mendidik mereka\". Kemudian Beliau berkata: \"Bawalah keluargamu kepadaku \". Maka aku datang dan mengabarkan pamanku tentang penjualan unta dan perdamaianku (tentang hutang) dan aku kabarkan pula tentang lambannya untaku dan peristiwa yang terjadi dengan Nabi shallallahu 'alaihi wasallam tentang pemukulan unta yang dilakukan Beliau. Ketika Nabi shallallahu 'alaihi wasallam datang, aku pagi-pagi segera menemui Beliau dengan membawa unta maka Beliau memberikan uang pembayaran unta tersebut serta memberikan unta itu kepadaku sementara sahamku tetap untuk orang-orang\". "},"2230":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَجُلٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أُخْدَعُ فِي الْبُيُوعِ فَقَالَ إِذَا بَايَعْتَ فَقُلْ لَا خِلَابَةَ فَكَانَ الرَّجُلُ يَقُولُهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Dinar] berkata, aku mendengar ['Abdullah bin 'Umar radliallahu 'anhuma] berkata; Ada seorang laki-laki berkata kepada Nabi shallallahu 'alaihi wasallam: \"Aku tertipu dalam berjual beli\". Maka Beliau bersabda: \"Jika kamu berjual beli katakanlah tidak boleh ada (penipuan dalam jual beli) \". Kemudian orang itu mengatakannya."},"2231":{"ar":"حَدَّثَنَا عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ وَرَّادٍ مَوْلَى الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ حَرَّمَ عَلَيْكُمْ عُقُوقَ الْأُمَّهَاتِ وَوَأْدَ الْبَنَاتِ وَمَنَعَ وَهَاتِ وَكَرِهَ لَكُمْ قِيلَ وَقَالَ وَكَثْرَةَ السُّؤَالِ وَإِضَاعَةَ الْمَالِ","id":"Telah menceritakan kepada kami ['Utsman] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Asy-Sya'biy] dari [Warrad, maula Al Mughirah bin Syu'bah] dari [Al Mughirah bin Syu'bah] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesunhgguhnya Allah mengharamkan atas kalian durhaka kepada ibu, mengubur anak wanita hidup-hidup dan serta membenci kalian dari qiila wa qaola (memberitakan setiaapa yang didengar), banyak bertanya dan menyia-nyiakan harta\"."},"2232":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّكُمْ رَاعٍ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ فَالْإِمَامُ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ وَالرَّجُلُ فِي أَهْلِهِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ وَالْمَرْأَةُ فِي بَيْتِ زَوْجِهَا رَاعِيَةٌ وَهِيَ مَسْئُولَةٌ عَنْ رَعِيَّتِهَا وَالْخَادِمُ فِي مَالِ سَيِّدِهِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ قَالَ فَسَمِعْتُ هَؤُلَاءِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَحْسِبُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالرَّجُلُ فِي مَالِ أَبِيهِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] berkata, dari [Az Zuhriy] berkata, telah mengabarkan kepadaku [Salim bin 'Abdullah] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Setiap kalian adalah pemimpin dan setiap pemimpin akan diminta pertanggung jawaban atas yang dipimpinnya. Imam (kepala Negara) adalah pemimpin yang akan diminta pertanggung jawaban atas rakyatnya. Seorang suami dalam keluarganya adalah pemimpin dan akan diminta pertanggung jawaban atas keluarganya. Seorang isteri adalah pemimpin di dalam urusan rumah tangga suaminya dan akan diminta pertanggung jawaban atas urusan rumah tangga tersebut. Seorang pembantu adalah pemimpin dalam urusan harta tuannya dan akan diminta pertanggung jawaban atas urusan tanggung jawabnya tersebut\". Dia ('Abdullah bin 'Umar radliallahu 'anhuma) berkata: \"Aku mendengar semua itu dari Rasulullah shallallahu 'alaihi wasallam dan aku munduga Nabi shallallahu 'alaihi wasallam juga bersabda\"; \"Dan seorang laki-laki pemimpin atas harta bapaknya dan akan diminta pertanggung jawaban atasnya dan setiap kalian adalah pemimpin dan setiap pemimpin akan diminta pertanggung jawaban atas yang dipimpinnya. "},"2233":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ عَبْدُ الْمَلِكِ بْنُ مَيْسَرَةَ أَخْبَرَنِي قَالَ سَمِعْتُ النَّزَّالَ بْنَ سَبْرَةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ يَقُولُسَمِعْتُ رَجُلًا قَرَأَ آيَةً سَمِعْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِلَافَهَا فَأَخَذْتُ بِيَدِهِ فَأَتَيْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كِلَاكُمَا مُحْسِنٌ قَالَ شُعْبَةُ أَظُنُّهُ قَالَ لَا تَخْتَلِفُوا فَإِنَّ مَنْ كَانَ قَبْلَكُمْ اخْتَلَفُوا فَهَلَكُوا","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] berkata, ['Abdul Malik bin Maisarah] telah menceritakan kepadaku yang berkata, aku mendengar [An Nazzaal bin Sabrah] berkata, aku mendengar ['Abdullah] berkata; aku mendengar seseorang membaca satu ayat yang berbeda dengan apa yang aku dengar dari Nabi shallallahu 'alaihi wasallam. Maka orang itu aku pegang lalu aku bawa menghadap Rasulullah shallallahu 'alaihi wasallam. Maka Beliau bersabda: \"Cara kalian membaca keduanya benar\". Syu'bah berkata: Aku menduga Beliau bersabda: \"Janganlah kalian berselisih karena orang-orang sebelum kalian berselisih hingga akhirnya mereka binasa\"."},"2234":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَعَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَاسْتَبَّ رَجُلَانِ رَجُلٌ مِنْ الْمُسْلِمِينَ وَرَجُلٌ مِنْ الْيَهُودِ قَالَ الْمُسْلِمُ وَالَّذِي اصْطَفَى مُحَمَّدًا عَلَى الْعَالَمِينَ فَقَالَ الْيَهُودِيُّ وَالَّذِي اصْطَفَى مُوسَى عَلَى الْعَالَمِينَ فَرَفَعَ الْمُسْلِمُ يَدَهُ عِنْدَ ذَلِكَ فَلَطَمَ وَجْهَ الْيَهُودِيِّ فَذَهَبَ الْيَهُودِيُّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِمَا كَانَ مِنْ أَمْرِهِ وَأَمْرِ الْمُسْلِمِ فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمَ فَسَأَلَهُ عَنْ ذَلِكَ فَأَخْبَرَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُخَيِّرُونِي عَلَى مُوسَى فَإِنَّ النَّاسَ يَصْعَقُونَ يَوْمَ الْقِيَامَةِ فَأَصْعَقُ مَعَهُمْ فَأَكُونُ أَوَّلَ مَنْ يُفِيقُ فَإِذَا مُوسَى بَاطِشٌ جَانِبَ الْعَرْشِ فَلَا أَدْرِي أَكَانَ فِيمَنْ صَعِقَ فَأَفَاقَ قَبْلِي أَوْ كَانَ مِمَّنْ اسْتَثْنَى اللَّهُ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Ibnu Syihab] dari [Abu Salamah] dan ['Abdurrahman Al A'raj] dari [Abu Hurairah radliallahu 'anhu] berkata; Ada dua orang laki-laki yang sedang saling mencaci, yang satunya seorang Muslim dan satunya lagi orang Yahudi. Berkata, laki-laki Muslim: \"Demi Dzat yang telah memilih Muhammad untuk seluruh alam\". Dan berkata, laki-laki Yahudi: \"Demi Dzat yang telah memilih Musa untuk seluruh alam\". Seketika itu laki-laki muslim mengangkat tangannya dan menampar wajah orang Yahudi itu. Maka orang Yahudi itu pergi menemui Nabi shallallahu 'alaihi wasallam dan mengabarkan peristiwa yang terjadi antara dirinya dan orang Muslim itu. Kemudian Nabi shallallahu 'alaihi wasallam memanggil orang Muslim itu dan bertanya tentang kejadian itu, lalu orang Muslim itu memberitahukan Beliau. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu lebihkan aku terhadap Musa karena nanti saat seluruh manusia dimatikan pada hari qiyamat, aku pun akan dimatikan bersama mereka dan akulah orang yang pertama kali dibangkitkan (dihidupkan) namun saat itu aku melihat Musa sedang berpegangan di sisi 'Arsy. Aku tidak tahu apakah dia termasuk orang yang dimatikan lalu bangkit lebih dahulu daripada aku, atau dia termasuk diantara orang-orang yang dikecualikan (tidak dimatikan) \". "},"2235":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ جَاءَ يَهُودِيٌّ فَقَالَ يَا أَبَا الْقَاسِمِ ضَرَبَ وَجْهِي رَجُلٌ مِنْ أَصْحَابِكَ فَقَالَ مَنْ قَالَ رَجُلٌ مِنْ الْأَنْصَارِ قَالَ ادْعُوهُ فَقَالَ أَضَرَبْتَهُ قَالَ سَمِعْتُهُ بِالسُّوقِ يَحْلِفُ وَالَّذِي اصْطَفَى مُوسَى عَلَى الْبَشَرِ قُلْتُ أَيْ خَبِيثُ عَلَى مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَتْنِي غَضْبَةٌ ضَرَبْتُ وَجْهَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُخَيِّرُوا بَيْنَ الْأَنْبِيَاءِ فَإِنَّ النَّاسَ يَصْعَقُونَ يَوْمَ الْقِيَامَةِ فَأَكُونُ أَوَّلَ مَنْ تَنْشَقُّ عَنْهُ الْأَرْضُ فَإِذَا أَنَا بِمُوسَى آخِذٌ بِقَائِمَةٍ مِنْ قَوَائِمِ الْعَرْشِ فَلَا أَدْرِي أَكَانَ فِيمَنْ صَعِقَ أَمْ حُوسِبَ بِصَعْقَةِ الْأُولَى","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami ['Amru bin Yahya] dari [bapaknya] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam sedang duduk bermajelis tiba-tiba datang seorang Yahudi seraya berkata; \"Wahai Abu Al Qasim, seorang shahabatmu telah memukul wajahku\". Lalu dia menebutkan seseorang dari kalangan Anshar. Maka Beliau berkata: \"Panggillah\". Kemudian Beliau bertanya: \"Apakah benar kamu memukulnya?\" Orang itu berkata; \"Aku mendengar di pasar dia bersumpah; \"Demi Dzat yang telah memilih Musa untuk seluruh manusia. Aku katakan; (Apakah kamu bermaksud untuk mengatakan) \"Aku benci Muhammad shallallahu 'alaihi wasallam\". Maka kemarahanku memuncak lalu aku pukul wajahnya\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian banding-bandingkan (lebihkan) sesama para Nabi karena nanti saat seluruh manusia dimatikan pada hari qiyamat, akulah orang yang pertama kali dibangkitkan dari bumi namun saat itu dihadapanku telah ada Musa Aalaihissalam yang sedang berpegangan pada salah satu tiang 'Arsy, dan aku tidak tahu apakah dia termasuk orang yang dibangkitkan (lebih dahulu) atau termasuk orang yang dihisab (sehingga diselamatkan) dengan hari kegoncangan yang pertama?\""},"2236":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ يَهُودِيًّا رَضَّ رَأْسَ جَارِيَةٍ بَيْنَ حَجَرَيْنِ قِيلَ مَنْ فَعَلَ هَذَا بِكِ أَفُلَانٌ أَفُلَانٌ حَتَّى سُمِّيَ الْيَهُودِيُّ فَأَوْمَأَتْ بِرَأْسِهَا فَأُخِذَ الْيَهُودِيُّ فَاعْتَرَفَ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُضَّ رَأْسُهُ بَيْنَ حَجَرَيْنِ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas radliallahu 'anhu] bahwa ada seorang Yahudi yang menjepit kepala seorang budak wanita hingga bocor dengan dua batu. Lalu ditanyakan; Siapakah yang melakukan ini terhadapmu, apakah si fulan atau si fulan, hingga disebutlah orang Yahudi namun ia menggelengkan kepalanya. Akhirnya didatangkan seorang Yahudi lain lalu dia mengakuinya, maka Nabi shallallahu 'alaihi wasallam memerintahkan agar orang Yahudi ini dijepit pula kepalanya hingga bocor dengan dua batu. "},"2237":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَجُلٌ يُخْدَعُ فِي الْبَيْعِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَايَعْتَ فَقُلْ لَا خِلَابَةَ فَكَانَ يَقُولُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul 'Aziz bin Muslim] telah menceritakan kepada kami ['Abdullah bin Dinar] berkata, aku mendengar [Ibnu'Umar radliallahu 'anhuma] berkata; Ada seorang laki-laki yang tertipu dalam berjual beli, maka Nabi shallallahu 'alaihi wasallam berkata, kepadanya: \"Jika kamu berjual beli katakanlah tidak boleh ada (penipuan dalam jual beli) \". Kemudian orang itu mengatakannya."},"2238":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَعْتَقَ عَبْدًا لَهُ لَيْسَ لَهُ مَالٌ غَيْرُهُ فَرَدَّهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَابْتَاعَهُ مِنْهُ نُعَيْمُ بْنُ النَّحَّامِ","id":"Telah menceritakan kepada kami ['Ashim bin 'Ali] telah menceritakan kepada kami [Ibnu Abi Dza'bi] dari [Muhammad bin Al Munkadir] dari [Jabir radliallahu 'anhuma] bahwa ada seseorang membebaskan budak miliknya padahal tidak ada harta baginya selain budak itu. Maka Nabi shallallahu 'alaihi wasallam mengembalikan kepadanya lalu di beli oleh Nu'aim bin An-Nahham. "},"2239":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ وَهُوَ فِيهَا فَاجِرٌ لِيَقْتَطِعَ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُقَالَ فَقَالَ الْأَشْعَثُ فِيَّ وَاللَّهِ كَانَ ذَلِكَ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ فَقَالَ لِلْيَهُودِيِّ احْلِفْ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفَ وَيَذْهَبَ بِمَالِي فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari ['Abdullah radliallahu 'anhu] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah yang dengan sumpahnya itu dia durhaka dan bermaksud mengambil harta seorang Muslim, maka dia kelak akan berjumpa dengan Allah sedang Allah murka kepadanya\". 'Abdullah berkata, [Al Asy'ats] berkata: \"Demi Allah, ayat itu turun tentang aku, yang dahulu antara aku dan seorang Yahudi ada tanah yang diperebutkan lalu dia mengalahkan aku. Kemudian aku adukan hal itu kepada Nabi shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam berkata, kepadaku: \"Apakah kamu punya bukti?\" Aku jawab: \"Tidak\". Lalu Beliau berkata, kepada orang Yahudi itu: \"Bersumpahlah\". Dia berkata,, aku katakan: \"Wahai Rasulullah, dia bersumpah sementara dia mengambil hartaku?\" Maka turunlah firman Allah QS Alu 'Imran ayat 77 yang artinya (\"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit…\") hingga akhir ayat."},"2240":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ كَعْبٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ تَقَاضَى ابْنَ أَبِي حَدْرَدٍ دَيْنًا كَانَ لَهُ عَلَيْهِ فِي الْمَسْجِدِ فَارْتَفَعَتْ أَصْوَاتُهُمَا حَتَّى سَمِعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَيْهِمَا حَتَّى كَشَفَ سِجْفَ حُجْرَتِهِ فَنَادَى يَا كَعْبُ قَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ ضَعْ مِنْ دَيْنِكَ هَذَا فَأَوْمَأَ إِلَيْهِ أَيْ الشَّطْرَ قَالَ لَقَدْ فَعَلْتُ يَا رَسُولَ اللَّهِ قَالَ قُمْ فَاقْضِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami ['Utsman bin 'Umar] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy] dari ['Abdullah bin Ka'ab bin Malik] dari [Ka'ab radliallahu 'anhu] bahwa dia menagih hutang kepada Ibnu Abu Hadrad yang dia berhutang kepadanya di dalam masjid hingga suara keduanya meninggi yang akhirnya didengar oleh Rasulullah shallallahu 'alaihi wasallam. Saat itu Beliau shallallahu 'alaihi wasallam berada di rumah. Maka Beliau shallallahu 'alaihi wasallam keluar menemui keduanya sambil menyingkap kain gorden kamar Beliau seraya memanggil: \"Wahai Ka'ab!\". Ka'ab bin Malik menjawab: \"Ya, Rasulullah\". Beliau berkata: \"Mintalah dulu dari hutangmu segini\". Beliau memberi isyarat kepadanya yang maksudnya setengahnya. Dia (Ka'ab) berkata: \"Sudah aku lakukan wahai Rasulullah\". Maka Beliau shallallahu 'alaihi wasallam berkata, (kepada Ibnu Abu Hadrad): \"Kalau begitu tunaikanlah\""},"2241":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَنَّهُ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَؤُهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا وَكِدْتُ أَنْ أَعْجَلَ عَلَيْهِ ثُمَّ أَمْهَلْتُهُ حَتَّى انْصَرَفَ ثُمَّ لَبَّبْتُهُ بِرِدَائِهِ فَجِئْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ عَلَى غَيْرِ مَا أَقْرَأْتَنِيهَا فَقَالَ لِي أَرْسِلْهُ ثُمَّ قَالَ لَهُ اقْرَأْ فَقَرَأَ قَالَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِي اقْرَأْ فَقَرَأْتُ فَقَالَ هَكَذَا أُنْزِلَتْ إِنَّ الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مِنْهُ مَا تَيَسَّرَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Abdurrahman bin 'Abdul Qariy] bahwa dia berkata, aku mendengar ['Umar bin Al Khaththob radliallahu 'anhu] berkata, aku mendengar Hisyam bin Hakim bin Hizam membaca surah Al Furqan dengan cara yang berbeda dari yang aku baca sebagaimana Rasulullah shallallahu 'alaihi wasallam membacakannya kepadaku dan hampir saja aku mau bertindak terhadapnya namun aku biarkan sejenak hingga dia selesai membaca. Setelah itu aku ikat dia dengan kainku lalu aku giring dia menghadap Rasulullah shallallahu 'alaihi wasallam dan aku katakan: \"Aku mendengar dia membaca Al Qur'an tidak sama dengan aku sebagaimana anda membacakannya kepadaku\". Maka Beliau berkata, kepadaku: \"Bawalah dia kemari\". Kemudian Beliau berkata, kepadanya: \"Bacalah\". Maka dia membaca. Beliau shallallahu 'alaihi wasallam kemudian bersabda: \"Begitulah memang yang diturunkan\". Kemudian Beliau berkata kepadaku: \"Bacalah\". Maka aku membaca. Beliau shallallahu 'alaihi wasallam bersabda: \"Begitulah memang yang diturunkan. Sesungguhnya Al Qur'an diturunkan dengan tujuh huruf, maka bacalah oleh kalian mana yang mudah\". "},"2242":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ هَمَمْتُ أَنْ آمُرَ بِالصَّلَاةِ فَتُقَامَ ثُمَّ أُخَالِفَ إِلَى مَنَازِلِ قَوْمٍ لَا يَشْهَدُونَ الصَّلَاةَ فَأُحَرِّقَ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Abi 'Adiy] dari [Syu'bah] dari [Sa'ad bin Ibrahim] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh aku bertekad untuk memerintahkan shalat agar ditegakkan, lalu akan aku datangi rumah-rumah orang-orang yang tidak ikut shalat berjama'ah lalu aku akan bakar rumah-rumah mereka\"."},"2243":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ عَبْدَ بْنَ زَمْعَةَ وَسَعْدَ بْنَ أَبِي وَقَّاصٍ اخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ابْنِ أَمَةِ زَمْعَةَ فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ أَوْصَانِي أَخِي إِذَا قَدِمْتُ أَنْ أَنْظُرَ ابْنَ أَمَةِ زَمْعَةَ فَأَقْبِضَهُ فَإِنَّهُ ابْنِي وَقَالَ عَبْدُ بْنُ زَمْعَةَ أَخِي وَابْنُ أَمَةِ أَبِي وُلِدَ عَلَى فِرَاشِ أَبِي فَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَبَهًا بَيِّنًا بِعُتْبَةَ فَقَالَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ الْوَلَدُ لِلْفِرَاشِ وَاحْتَجِبِي مِنْهُ يَا سَوْدَةُ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhriy] dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa 'Abdu bin Zam'ah dan Sa'ad bin Abi Waqash mengadu kepada Nabi shallallahu 'alaihi wasallam tentang anak budak wanita Zam'ah. Sa'ad berkata: \"Wahai Rasulullah, saudaraku berwasiat kepadaku apabila aku datang dan bertemu dengan anak hamba sahaya Zam'ah supaya aku mengambilnya karena dia adalah anakku\". Dan berkata 'Abdu bin Zam'ah: \"Saudaraku dan anak dari hamba sahaya bapakku lahir diatas tempat tidur bapakku\". Nabi shallallahu 'alaihi wasallam melihat tanda kemiripan dengan jelas ada pada 'Utbah namun Beliau berkata: \"Anak itu milikmu wahai 'Abdu bin Zam'ah. Anak itu berasal dari tempat tidur (perkawinan) sedangkan untuk pezina baginya batu (rajam). Jauhkanlah dia dariku, wahai Saudah \". "},"2244":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا قِبَلَ نَجْدٍ فَجَاءَتْ بِرَجُلٍ مِنْ بَنِي حَنِيفَةَ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ سَيِّدُ أَهْلِ الْيَمَامَةِ فَرَبَطُوهُ بِسَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ فَخَرَجَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا عِنْدَكَ يَا ثُمَامَةُ قَالَ عِنْدِي يَا مُحَمَّدُ خَيْرٌ فَذَكَرَ الْحَدِيثَ قَالَ أَطْلِقُوا ثُمَامَةَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam mengirim pasukan berkuda untuk mendatangi Nejed lalu pasukan itu kembali dengan membawa seseorang dari suku Banu Hanifah yang namanya Tsumamah bin Utsal, pimpinan penduduk Yamamah lalu orang ini diikat di salah satu tiang masjid. Kemudian Rasulullah shallallahu 'alaihi wasallam keluar menemuinya lalu berkata: \"Apa yang kamu miliki wahai Tsumamah? '. Dia menjawab: \"Aku punya harta wahai Muhammad\". Maka (Abu Hurairah) menceritakan hadits yang panjang. Akhirnya Beliau shallallahu 'alaihi wasallam bersabda: \"Bebaskanlah Tsumamah\". "},"2245":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا قِبَلَ نَجْدٍ فَجَاءَتْ بِرَجُلٍ مِنْ بَنِي حَنِيفَةَ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ فَرَبَطُوهُ بِسَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku [Sa'id bin Abu Sa'id] bahwasanya dia mendengar [Abu Hurairah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam pernah mengirim pasukan berkuda mendatangi Nejed, lalu pasukan itu kembali dengan membawa seseorang dari suku Banu Hanifah yang namanya Tsumamah bin Utsal, lalu orang ini diikat di salah satu tiang masjid."},"2246":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ وَقَالَ غَيْرُهُ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ الْأَنْصَارِيِّ عَنْ كَعْبِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ كَانَ لَهُ عَلَى عَبْدِ اللَّهِ بْنِ أَبِي حَدْرَدٍ الْأَسْلَمِيِّ دَيْنٌ فَلَقِيَهُ فَلَزِمَهُ فَتَكَلَّمَا حَتَّى ارْتَفَعَتْ أَصْوَاتُهُمَا فَمَرَّ بِهِمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا كَعْبُ وَأَشَارَ بِيَدِهِ كَأَنَّهُ يَقُولُ النِّصْفَ فَأَخَذَ نِصْفَ مَا عَلَيْهِ وَتَرَكَ نِصْفًا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] telah mengabarkan kepadaku [Ja'far bin Rabi'ah] dan berkata, yang lain telah menceritakan kepadaku [Al Laits] berkata, telah menceritakan kepadaku [Ja'far bin Rabi'ah] dari ['Abdurrahman bin Hurmuz] dari ['Abdullah bin Ka'ab bin Malik Al Anshariy] dari [Ka'ab bin Malik radliallahu 'anhu] bahwa dia mempunyai piutang kepada Ibnu Abu Hadrad Al Aslamiy, lalu dia datang menemuinya untuk menagihnya kemudian terjadi pembicaraan hingga suara keduanya meninggi. Kemudian Rasulullah shallallahu 'alaihi wasallam lewat di hadapan keduanya lalu berkata: \"Wahai Ka'ab!\". Beliau memberi isyarat dengan tangan Beliau seakan Beliau berkata setengahnya. Maka Ka'ab mengambil setengahnya (dari Ibnu Abu Hadrad) dan membiarkan setengahnya lagi\"."},"2247":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا وَهْبُ بْنُ جَرِيرِ بْنِ حَازِمٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَرَاهِمُ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ فَقُلْتُ لَا وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يَبْعَثَكَ قَالَ فَدَعْنِي حَتَّى أَمُوتَ ثُمَّ أُبْعَثَ فَأُوتَى مَالًا وَوَلَدًا ثُمَّ أَقْضِيَكَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }الْآيَةَ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Wahb bin Jarir bin Hazim] telah mengabarkan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Adh Dhuha] dari [Masruq] dari [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan aku punya uang dirham yang ada pada Al 'Ash bin Wa'il lalu aku menemui dia untuk menagih agar dia membayarnya. Dia berkata: \"Aku tidak akan membayarnya kepadamu kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Demi Allah, aku tidak akan kufur kepada Muhammad shallallahu 'alaihi wasallam sampai Allah mematikan kamu lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah sampai aku mati lalu dibangkitkan dan disana aku akan mendapatkan harta dan anak lalu aku akan bayar hutang kepadamu\". Maka Allah Ta'ala menurunkan QS Maryam ayat yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan \"pasti aku akan diberi harta dan anak\" (QS. Maryam 77)."},"2248":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ و حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ سَمِعْتُ سُوَيْدَ بْنَ غَفَلَةَ قَالَ لَقِيتُ أُبَيَّ بْنَ كَعْبٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَأَخَذْتُ صُرَّةً مِائَةَ دِينَارٍ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا فَلَمْ أَجِدْ مَنْ يَعْرِفُهَا ثُمَّ أَتَيْتُهُ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا فَلَمْ أَجِدْ ثُمَّ أَتَيْتُهُ ثَلَاثًا فَقَالَ احْفَظْ وِعَاءَهَا وَعَدَدَهَا وَوِكَاءَهَا فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَاسْتَمْتِعْ بِهَا فَاسْتَمْتَعْتُ فَلَقِيتُهُ بَعْدُ بِمَكَّةَ فَقَالَ لَا أَدْرِي ثَلَاثَةَ أَحْوَالٍ أَوْ حَوْلًا وَاحِدًا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dan diriwayatkan pula, telah menceritakan kepadaku [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Salamah] aku mendengar [Suwaid bin Ghoflah] berkata; \"Aku bertemu dengan [Ubay bin Ka'ab] radliallahu 'anhu lalu dia berkata; Aku menemukan bungkusan berisi uang seratus dinar, lalu aku temui Nabi shallallahu 'alaihi wasallam, maka Beliau berkata: \"Umumkanlah (agar diketahui orang) selama satu tahun\". Maka aku lakukan selama setahun namun tidak ada orang yang mengakuinya sebagai pemiliknya. Kemudian aku datangi lagi Beliau dan Beliau berkata: \"Umumkanlah selama satu tahun\". Maka aku lakukan selama setahun lagi namun tidak ada orang yang mengakuinya. Kemudian aku datangi lagi Beliau untuk ketiga kalinya dan Beliau berkata: \"Peganglah bungkusan dan jumlah isinya, nanti bila ada yang datang sebagai pemiliknya berikanlah namun bila tidak ada yang datang maka nikmatilah. Maka aku nikmati uang itu. (Syu'bah) berkata; \"Setelah beberapa tahun ketika berada di Makkah aku menemui dia (Salamah), maka dia berkata; \"Aku tidak tahu apakah selama tiga tahun atau satu tahun saja\"."},"2249":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ رَبِيعَةَ حَدَّثَنِي يَزِيدُ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ أَعْرَابِيٌّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَمَّا يَلْتَقِطُهُ فَقَالَ عَرِّفْهَا سَنَةً ثُمَّ احْفَظْ عِفَاصَهَا وَوِكَاءَهَا فَإِنْ جَاءَ أَحَدٌ يُخْبِرُكَ بِهَا وَإِلَّا فَاسْتَنْفِقْهَا قَالَ يَا رَسُولَ اللَّهِ فَضَالَّةُ الْغَنَمِ قَالَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ ضَالَّةُ الْإِبِلِ فَتَمَعَّرَ وَجْهُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا لَكَ وَلَهَا مَعَهَا حِذَاؤُهَا وَسِقَاؤُهَا تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ","id":"Telah menceritakan kepada kami ['Amru bin 'Abbas] telah menceritakan kepada kami ['Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Rabi'ah] telah menceritakan kepadaku [Yazid, maula Al Munba'its] dari [Zaid bin Khalid Al Juhaniy radliallahu 'anhu] berkata; \"Datang seorang laki-laki Arab Baduy kepada Rasulullah shallallahu 'alaihi wasallam lalu bertanya kepada Beliau tentang barang yang ditemuinya. Maka Beliau bersabda: \"Kamu umumkan selama satu tahun kemudian jagalah bungkus dan isinya. Jika datang seseorang yang mengabarkan kepadamu tentang barang itu maka berikanlah namun bila tidak maka belanjakanlah (manfaatkanlah) \". Orang itu bertanya lagi tentang hukum bila menemukan kambing. Maka Beliau menjawab: \"Itu untuk kamu atau saudaramu atau serigala\". Lalu orang itu bertanya lagi tentang menemukan unta. Maka wajah Nabi shallallahu 'alaihi wasallam berubah karena marah seraya berkata: \"Bagaimana kamu ini, padahal unta itu selalu membawa sepatunya dan tempat airnya sehingga ia bisa hilir mudik mencari air dan makan rerumputan hingga pemiliknya \"."},"2250":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ أَنَّهُ سَمِعَ زَيْدَ بْنَ خَالِدٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ فَزَعَمَ أَنَّهُ قَالَ اعْرِفْ عِفَاصَهَا وَوِكَاءَهَا ثُمَّ عَرِّفْهَا سَنَةًيَقُولُ يَزِيدُ إِنْ لَمْ تُعْرَفْ اسْتَنْفَقَ بِهَا صَاحِبُهَا وَكَانَتْ وَدِيعَةً عِنْدَهُ قَالَ يَحْيَى فَهَذَا الَّذِي لَا أَدْرِي أَفِي حَدِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ أَمْ شَيْءٌ مِنْ عِنْدِهِ ثُمَّ قَالَ كَيْفَ تَرَى فِي ضَالَّةِ الْغَنَمِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْهَا فَإِنَّمَا هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ يَزِيدُ وَهِيَ تُعَرَّفُ أَيْضًا ثُمَّ قَالَ كَيْفَ تَرَى فِي ضَالَّةِ الْإِبِلِ قَالَ فَقَالَ دَعْهَا فَإِنَّ مَعَهَا حِذَاءَهَا وَسِقَاءَهَا تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ حَتَّى يَجِدَهَا رَبُّهَا","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepadaku [Sulaiman bin Bilal] dari [Yahya] dari [Yazid, maula Al Munba'its] bahwa dia mendengar [Zaid bin Khalid radliallahu 'anhu] berkata; \"Nabi shallallahu 'alaihi wasallam ditanya tentang barang temuan\". Maka Beliau bersabda: \"Kamu kenali tutup bungkus dan talinya kemudian umumkan selama satu tahun\". Yazid berkata: \"Dan jika tidak ada yang mengakuinya maka dapat digunakan oleh penemunya karena itu berarti titipan Allah baginya\". Yahya berkata: \"Inilah yang aku tidak tahu apakah kalimat ini termasuk bagian dari hadits yang disabdakan Rasulullah shallallahu 'alaihi wasallam atau hanya perkataan dari Yazid. Kemudian orang itu bertanya lagi: \"Bagaimana tentang menemukan kambing?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Ambillah karena kambing itu untuk kamu atau saudaramu atau serigala\". Yazid berkata: \"Untuk kambing juga diumumkan dahulu\". Kemudia orang itu bertanya lagi: \"Bagaimana tentang menemukan unta. Yazid berkata; maka Beliau menjawab: \"Biarkanlah unta itu, karena ia selalu nampak sepatunya dan perutnya (yang terisi air) sehingga ia bisa hilir mudik mencari air dan makan rerumputan hingga ditemukan oleh pemiliknya\"."},"2251":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ اللُّقَطَةِ فَقَالَ اعْرِفْ عِفَاصَهَا وَوِكَاءَهَا ثُمَّ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَشَأْنَكَ بِهَا قَالَ فَضَالَّةُ الْغَنَمِ قَالَ هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ فَضَالَّةُ الْإِبِلِ قَالَ مَا لَكَ وَلَهَا مَعَهَا سِقَاؤُهَا وَحِذَاؤُهَا تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ حَتَّى يَلْقَاهَا رَبُّهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Rabi'ah bin Abi 'Abdurrahman] dari [Yazid, maula Al Munba'its] dari [Zaid bin Khalid Al Juhaniy radliallahu 'anhu] berkata; \"Datang seorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam lalu bertanya kepada Beliau tentang barang temuan. Maka Beliau bersabda: \"Kamu kenali tutup bungkus dan talinya kemudian umumkan selama satu tahun dan jika datang pemiliknya maka berikanlah namun bila tidak maka menjadi kewenanganmu dengan barang tersebut\". Orang itu bertanya lagi tentang hukum bila menemukan kambing. Maka Beliau menjawab: \"Itu untuk kamu atau saudaramu atau serigala\". Lalu orang itu bertanya lagi tentang menemukan unta. Maka Beliau menjawab: \"Bagaimana kamu ini, padahal unta itu ia mempunyai kantung air (yang terisi air) dan sepatunya sehingga ia bisa hilir mudik mencari air dan makan rerumputan hingga pemiliknya menemukannya\"."},"2252":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ ��ُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ طَلْحَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَمْرَةٍ فِي الطَّرِيقِ قَالَ لَوْلَا أَنِّي أَخَافُ أَنْ تَكُونَ مِنْ الصَّدَقَةِ لَأَكَلْتُهَاوَقَالَ يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنِي مَنْصُورٌ وَقَالَ زَائِدَةُ عَنْ مَنْصُورٍ عَنْ طَلْحَةَ حَدَّثَنَا أَنَسٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Tholhah] dari [Anas radliallahu 'anhu] berkata: Nabi shallallahu 'alaihi wasallam berjalan melewati buah-buah kurma yang jatuh di jalan, lalu Beliau berkata: \"Seandainya aku tidak takut bahwa pada kurma-kurma ini ada kewajiban shadaqah (zakat) tentu aku sudah memakannya\". Dan berkata, [Yahya] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Manshur] dan berkata, [Za'idah] dari [Manshur] dari [Tholhah] telah menceritakan kepada kami [Anas]."},"2253":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّ��ٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي لَأَنْقَلِبُ إِلَى أَهْلِي فَأَجِدُ التَّمْرَةَ سَاقِطَةً عَلَى فِرَاشِي فَأَرْفَعُهَا لِآكُلَهَا ثُمَّ أَخْشَى أَنْ تَكُونَ صَدَقَةً فَأُلْقِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam berkata: \"Ketika aku pulang kepada keluargaku aku menemukan buah-buah kurma berserakan di tempat tidurku maka aku ambil untuk aku makan kemudian aku takut kalau kurma itu sebagai zakat hingga akhirnya aku biarkan\"."},"2254":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا فَتَحَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قَامَ فِي النَّاسِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ اللَّهَ حَبَسَ عَنْ مَكَّةَ الْفِيلَ وَسَلَّطَ عَلَيْهَا رَسُولَهُ وَالْمُؤْمِنِينَ فَإِنَّهَا لَا تَحِلُّ لِأَحَدٍ كَانَ قَبْلِي وَإِنَّهَا أُحِلَّتْ لِي سَاعَةً مِنْ نَهَارٍ وَإِنَّهَا لَا تَحِلُّ لِأَحَدٍ بَعْدِي فَلَا يُنَفَّرُ صَيْدُهَا وَلَا يُخْتَلَى شَوْكُهَا وَلَا تَحِلُّ سَاقِطَتُهَا إِلَّا لِمُنْشِدٍ وَمَنْ قُتِلَ لَهُ قَتِيلٌ فَهُوَ بِخَيْرِ النَّظَرَيْنِ إِمَّا أَنْ يُفْدَى وَإِمَّا أَنْ يُقِيدَ فَقَالَ الْعَبَّاسُ إِلَّا الْإِذْخِرَ فَإِنَّا نَجْعَلُهُ لِقُبُورِنَا وَبُيُوتِنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الْإِذْخِرَ فَقَامَ أَبُو شَاهٍ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ فَقَالَ اكْتُبُوا لِي يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْتُبُوا لِأَبِي شَاهٍ قُلْتُ لِلْأَوْزَاعِيِّ مَا قَوْلُهُ اكْتُبُوا لِي يَا رَسُولَ اللَّهِ قَالَ هَذِهِ الْخُطْبَةَ الَّتِي سَمِعَهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Awza'iy] berkata, telah menceritakan kepadaku [Yahya bin Abi Katsir] berkata, telah menceritakan kepadaku [Abu Salamah bin 'Abdurrahman] berkata, telah menceritakan kapadaku [Abu Hurairah radliallahu 'anhu] berkata; Ketika Allah subhanahu wata'ala membukakan kemenangan bagi RasulNya shallallahu 'alaihi wasallam atas Kota Makkah, Beliau berdiri di hadapan manusia, maka Beliau memuji Allah dan mensucikanNya kemudian bersabda: \"Sesungguhnya Allah telah melarang menawan gajah di Makkah ini dan menyerahkan urusannya kepada RasulNya dan Kaum Mu'minin, karena di tanah Makkah ini tidaklah dihalalkan bagi seorangpun sebelumku dan sesungguhnya pernah dihalalkan buatku pada suatu masa di suatu hari dan juga tidak dihalalkan bagi seseorang setelah aku. Maka tidak boleh diburu binatang buruannya, tidak boleh dipotong durinya, dan tidak boleh diambil barang temuan disana kecuali untuk diumumkan dan dicari pemiliknya. Barangsiapa yang dibunuh maka keluarga korban memiliki dua pilihan apakah dia akan meminta tebusan uang atau meminta balasan dari keluarga korban\". Maka berkatalah Al 'Abbas: \"Kecuali pohon Idzhir, karena pohon itu kami gunakan sebagai wewangian di kuburan kami dan di rumah kami\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda; \"Ya, kecuali pohon Idzhir\". Lalu berdiri Abu Syah, seorang penduduk Yaman dan berkata: \"Wahai Rasulullah, tuliskanlah buatku? Rasulullah shallallahu 'alaihi wasallam berkata: \"Tuliskanlah buat Abu Syah\". Berkata, Al Walid bin Muslim; Aku bertanya kepada Al Awza'iy: \"Apa yang ia maksud dengan meminta tuliskanlah buatku wahai Rasulullah?\" Dia berkata: \"Isi khathbah tadi yang dia dengar dari Rasulullah shallallahu 'alaihi wasallam \"."},"2255":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحْلُبَنَّ أَحَدٌ مَاشِيَةَ امْرِئٍ بِغَيْرِ إِذْنِهِ أَيُحِبُّ أَحَدُكُمْ أَنْ تُؤْتَى مَشْرُبَتُهُ فَتُكْسَرَ خِزَانَتُهُ فَيُنْتَقَلَ طَعَامُهُ فَإِنَّمَا تَخْزُنُ لَهُمْ ضُرُوعُ مَوَاشِيهِمْ أَطْعِمَاتِهِمْ فَلَا يَحْلُبَنَّ أَحَدٌ مَاشِيَةَ أَحَدٍ إِلَّا بِإِذْنِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang memeras susu ternak orang lain tanpa seizinnya. Apakah seorang dari kalian suka bila rumahnya didatangi lalu dirusak pintunya kemudian simpanan makanannya diambil. Karena sesungguhnya puting susu ternak mereka adalah makanan simpanan mereka, maka janganlah seseorang memeras susu ternak orang lain kecuali dengan izinnya\"."},"2256":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ قَالَ عَرِّفْهَا سَنَةً ثُمَّ اعْرِفْ وِكَاءَهَا وَعِفَاصَهَا ثُمَّ اسْتَنْفِقْ بِهَا فَإِنْ جَاءَ رَبُّهَا فَأَدِّهَا إِلَيْهِ قَالُوا يَا رَسُولَ اللَّهِ فَضَالَّةُ الْغَنَمِ قَالَ خُذْهَا فَإِنَّمَا هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ قَالَ يَا رَسُولَ اللَّهِ فَضَالَّةُ الْإِبِلِ قَالَ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى احْمَرَّتْ وَجْنَتَاهُ أَوْ احْمَرَّ وَجْهُهُ ثُمَّ قَالَ مَا لَكَ وَلَهَا مَعَهَا حِذَاؤُهَا وَسِقَاؤُهَا حَتَّى يَلْقَاهَا رَبُّهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Rabi'ah bin Abi 'Abdurrahman] dari [Yazid, maula Al Munba'its] dari [Zaid bin Khalid Al Juhaniy radliallahu 'anhu] berkata; \"Ada seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang barang temuan. Maka Beliau bersabda: \"Kamu umumkan selama satu tahun kemudian kamu pergunakan. Jika datang pemiliknya maka berikanlah kepadanya\". Mereka bertanya: \"Bagaimana tentang hukum bila menemukan kambing. Maka Beliau menjawab: \"Ambillah karena dia untuk kamu atau saudaramu atau serigala\". Lalu orang itu bertanya lagi tentang menemukan unta. Maka Rasulullah shallallahu 'alaihi wasallam marah hingga memerah pipi atau wajah Beliau kemudian berkata: \"Bagaimana kamu ini, padahal unta itu selalu bersama sepatunya dan perutnya (yang terisi air) hingga pemiliknya bisa menemukannya\"."},"2257":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ سُوَيْدَ بْنَ غَفَلَةَ قَالَ كُنْتُ مَعَ سَلْمَانَ بْنِ رَبِيعَةَ وَزَيْدِ بْنِ صُوحَانَ فِي غَزَاةٍ فَوَجَدْتُ سَوْطًا فَقَالَا لِي أَلْقِهِ قُلْتُ لَا وَلَكِنْ إِنْ وَجَدْتُ صَاحِبَهُ وَإِلَّا اسْتَمْتَعْتُ بِهِ فَلَمَّا رَجَعْنَا حَجَجْنَا فَمَرَرْتُ بِالْمَدِينَةِ فَسَأَلْتُ أُبَيَّ بْنَ كَعْبٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَوَجَدْتُ صُرَّةً عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا مِائَةُ دِينَارٍ فَأَتَيْتُ بِهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ الرَّابِعَةَ فَقَالَ اعْرِفْ عِدَّتَهَا وَوِكَاءَهَا وَوِعَاءَهَا فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا اسْتَمْتِعْ بِهَاحَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ سَلَمَةَ بِهَذَا قَالَ فَلَقِيتُهُ بَعْدُ بِمَكَّةَ فَقَالَ لَا أَدْرِي أَثَلَاثَةَ أَحْوَالٍ أَوْ حَوْلًا وَاحِدًا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] berkata, aku mendengar [Suwaid bin Ghoflah] berkata; \"Aku pernah bersama dengan Salman bin Rabi'ah dan Zaid bin Shuhan dalam suatu peperangan kemudian aku menemukan satu cemeti lalu keduanya berkata, kepadaku: \"Buanglah\". Aku katakan: \"Tidak, tapi aku akan mencari pemiliknya. Bila tidak ketemu maka aku akan manfaatkan\". Ketika kami kembali kami masih berselisih. Ketika aku berjalan di Madinah aku bertanya kepada [Ubay bin Ka'ab] radliallahu 'anhu lalu dia berkata; Di zaman Nabi shallallahu 'alaihi wasallam aku pernah menemukan bungkusan berisi uang seratus dinar lalu aku menemui Nabi shallallahu 'alaihi wasallam dengan membawa barang tersebut, maka Beliau berkata: \"Umumkanlah (agar diketahui orang) selama satu tahun\". Maka aku lakukan selama setahun. Kemudian aku datangi lagi Beliau dan Beliau berkata: \"Umumkanlah selama satu tahun\". Maka aku lakukan selama setahun lagi. Kemudian aku datangi lagi Beliau dan Beliau berkata: \"Umumkanlah selama satu tahun\". Maka aku lakukan selama setahun lagi. Kemudian aku temui Beliau untuk yag keempat kali lalu Beliau berkata:: \"Kenalilah jumlah isinya dan bungkusan serta penutupnya, nanti bila ada yang datang sebagai pemiliknya berikanlah namun bila tidak ada yang datang maka nikmatilah\". Telah menceritakan kepada kami ['Abdan] berkata, telah menceritakan kepadaku [bapakku] dari [Syu'bah] dari [Salamah] dengan sanad hadits seperti ini, dia berkata: \"Maka kemudian aku (Syu'bah) temui dia (Salamah) setelah beberapa lamanya di Makkah lalu dia berkata; \"Aku tidak tahu apakah selama tiga tahun atau satu tahun saja\"."},"2258":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ رَبِيعَةَ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ أَعْرَابِيًّا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اللُّقَطَةِ قَالَ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ أَحَدٌ يُخْبِرُكَ بِعِفَاصِهَا وَوِكَائِهَا وَإِلَّا فَاسْتَنْفِقْ بِهَا وَسَأَلَهُ عَنْ ضَالَّةِ الْإِبِلِ فَتَمَعَّرَ وَجْهُهُ وَقَالَ مَا لَكَ وَلَهَا مَعَهَا سِقَاؤُهَا وَحِذَاؤُهَا تَرِدُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ دَعْهَا حَتَّى يَجِدَهَا رَبُّهَا وَسَأَلَهُ عَنْ ضَالَّةِ الْغَنَمِ فَقَالَ هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Rabi'ah] dari [Yazid, maula Al Munba'its] dari [Zaid bin Khalid radliallahu 'anhu]; \"Ada seorang Arab Baduy bertanya kepada Nabi shallallahu 'alaihi wasallam tentang barang temuan. Maka Beliau bersabda: \"Kamu umumkan selama satu tahun. Jika datang pemiliknya mengabarkan kepadamu tentang ciri tutup bungkusnya dan tali pengikatnya maka berikanlah kepadanya. Jika tidak maka pergunakanlah\". Lalu orang itu bertanya tentang hukum bila menemukan unta. Maka wajah Beliau berubah lalu berkata,.: \"Bagaimana kamu ini, padahal unta itu selalu bersamanya perutnya (yang terirsi air) dan sepatunya sehingga ia bisa hilir mudik mencari air dan memakan rerumputan. Biarkanlah dia hingga pemiliknya datang menemukannya\". Lalu orang itu bertanya lagi tentang menemukan kambing. Maka Beliau menjawab: \"Kambing itu untuk kamu atau saudaramu atau serigala\"."},"2259":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ أَخْبَرَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ قَالَ أَخْبَرَنِي الْبَرَاءُ عَنْ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ عَنْ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَانْطَلَقْتُ فَإِذَا أَنَا بِرَاعِي غَنَمٍ يَسُوقُ غَنَمَهُ فَقُلْتُ لِمَنْ أَنْتَ قَالَ لِرَجُلٍ مِنْ قُرَيْشٍ فَسَمَّاهُ فَعَرَفْتُهُ فَقُلْتُ هَلْ فِي غَنَمِكَ مِنْ لَبَنٍ فَقَالَ نَعَمْ فَقُلْتُ هَلْ أَنْتَ حَالِبٌ لِي قَالَ نَعَمْ فَأَمَرْتُهُ فَاعْتَقَلَ شَاةً مِنْ غَنَمِهِ ثُمَّ أَمَرْتُهُ أَنْ يَنْفُضَ ضَرْعَهَا مِنْ الْغُبَارِ ثُمَّ أَمَرْتُهُ أَنْ يَنْفُضَ كَفَّيْهِ فَقَالَ هَكَذَا ضَرَبَ إِحْدَى كَفَّيْهِ بِالْأُخْرَى فَحَلَبَ كُثْبَةً مِنْ لَبَنٍ وَقَدْ جَعَلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِدَاوَةً عَلَى فَمِهَا خِرْقَةٌ فَصَبَبْتُ عَلَى اللَّبَنِ حَتَّى بَرَدَ أَسْفَلُهُ فَانْتَهَيْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ اشْرَبْ يَا رَسُولَ اللَّهِ فَشَرِبَ حَتَّى رَضِيتُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [An-Nadhar] telah mengabarkan kepada kami [Isra'il] dari [Abu Ishaq] berkata, telah menceritakan kepadaku [Al Bara'] dari [Abu Bakar radliallahu 'anhuma]. Dan diriwayatkan pula, telah menceritakan kepada kami ['Abdullah bin Raja'] telah menceritakan kepada kami [Isra'il] dari [Abu Ishaq] dari [Al Bara'] dari [Abu Bakar] radliallahu 'anhuma berkata: \"Pada suatu hari aku pergi kemudian mendapatkan seorang pengembala kambing sedang mengembalakan ternaknya lalu aku berkata: \"Kamu milik siapa? '. Dia menjawab: \"Milik seorang dari suku Quraisy\". Lalu dia menyebutkan namanya yang ternyata aku mengenalnya. Lalu aku katakan: \"Apakah kambingmu ini memiliki air susu?\" Dia menjawab: \"Ya ada\". Aku katakan: \"Apakah kamu mau memeraskan susunya untukku?\" Dia menjawab: \"Ya mau\". Maka aku memerintahkannya untuk mengambil seekor dari kambingnya yang ada, lalu aku suruh dia agar memoleskan sedikit tanah pada putting susu kambingya lalu aku suruh dia untuk menadahkan dengan kedua telapak tangannya. Dia berkata: \"Begini caranya\". Dia merapatkan kedua telapak tangannya satu sama lain lalu diperaslah sedikit dari susunya. Dan aku sudah menyiapkan cawan gelas yang diujungnya ada kain lalu aku usapkan pada susu hingga bawah gelas itu terasa dingin lalu aku menghampiri Nabi shallallahu 'alaihi wasallam lalu aku katakan: \"Minumlah wahai Rasulullah\". Maka Beliau meminumnya sehingga aku menjadi ridha karenanya\"."},"2260":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي الْمُتَوَكِّلِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا خَلَصَ الْمُؤْمِنُونَ مِنْ النَّارِ حُبِسُوا بِقَنْطَرَةٍ بَيْنَ الْجَنَّةِ وَالنَّارِ فَيَتَقَاصُّونَ مَظَالِمَ كَانَتْ بَيْنَهُمْ فِي الدُّنْيَا حَتَّى إِذَا نُقُّوا وَهُذِّبُوا أُذِنَ لَهُمْ بِدُخُولِ الْجَنَّةِ فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَأَحَدُهُمْ بِمَسْكَنِهِ فِي الْجَنَّةِ أَدَلُّ بِمَنْزِلِهِ كَانَ فِي الدُّنْيَاوَقَالَ يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ حَدَّثَنَا أَبُو الْمُتَوَكِّلِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Qatadah] dari [Abu Al Mutawakkil An-Naajiy] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika orang-orang beriman telah melewati neraka, mereka akan ditahan di suatu jembatan yang disebut Qanthorah yang terletak antara surga dan neraka, lalu disana mereka akan diqishas (dibalas) atas kezhalimin yang terjadi sesama mereka di dunia, sehingga apabila telah tidak ada lagi dosa barulah mereka diizinkan untuk memasuki surga. Dan demi Dzat yang jiwaku berada di tangaNya, sungguh seorang dari mereka berada di tempat tinggalnya di surga lebih aku kenal dari pada rumah mereka di dunia\". Dan berkata, [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] dari [Qatadah] telah menceritakan kepada kami [Abu Al Mutawakkil]."},"2261":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ قَالَ أَخْبَرَنِي قَتَادَةُ عَنْ صَفْوَانَ بْنِ مُحْرِزٍ الْمَازِنِيِّ قَالَ بَيْنَمَا أَنَا أَمْشِي مَعَ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاآخِذٌ بِيَدِهِ إِذْ عَرَضَ رَجُلٌ فَقَالَ كَيْفَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي النَّجْوَى فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يُدْنِي الْمُؤْمِنَ فَيَضَعُ عَلَيْهِ كَنَفَهُ وَيَسْتُرُهُ فَيَقُولُ أَتَعْرِفُ ذَنْبَ كَذَا أَتَعْرِفُ ذَنْبَ كَذَا فَيَقُولُ نَعَمْ أَيْ رَبِّ حَتَّى إِذَا قَرَّرَهُ بِذُنُوبِهِ وَرَأَى فِي نَفْسِهِ أَنَّهُ هَلَكَ قَالَ سَتَرْتُهَا عَلَيْكَ فِي الدُّنْيَا وَأَنَا أَغْفِرُهَا لَكَ الْيَوْمَ فَيُعْطَى كِتَابَ حَسَنَاتِهِ وَأَمَّا الْكَافِرُ وَالْمُنَافِقُونَ فَيَقُولُ الْأَشْهَادُ{ هَؤُلَاءِ الَّذِينَ كَذَبُوا عَلَى رَبِّهِمْ أَلَا لَعْنَةُ اللَّهِ عَلَى الظَّالِمِينَ }","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepadaku [Qatadah] dari [Shafwan bin Muhriz Al Maziniy] berkata; Ketika aku sedang berjalan bersama [Ibnu'Umar] radliallahu 'anhuma, ada seorang yang memegang tangannya ketika menyodorkannya lalu berkata: \"Bagaimana kamu mendengar Rasulullah shallallahu 'alaihi wasallam berkata tentang An-Najwaa (pembicaraan rahasia antara Allah dengan hambaNya pada hari Qiyamat)?\" Maka dia berkata: \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesunggunnya Allah ketika orang beriman didekatkan lalu bagian sisi badannya diletakkan kemudian ditutup, Allah berfirman: \"Apakah kamu mengenal dosamu yang begini?, apakah kamu mengenal dosamu yang begini?\" Orang beriman itu berkata: \"Ya, Tuhanku\". Hingga ketika sudah diakui dosa-dosanya dan dia melihat bahwa dirinya akan celaka, Allah berfirman: \"Aku telah merahasiakannya bagimu di dunia dan Aku mengampuninya buatmu hari ini\". Maka orang beriman itu diberikan kitab catatan kebaikannya. Adapun orang kafir dan munafiqin, Allah berfirman: Dan para saksi akan berkata: itulah orang-orang yang mendustakan Tuhan mereka. Maka laknat Allah untuk orang-orang yang zhalim\"."},"2262":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَنَّ سَالِمًا أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يُسْلِمُهُ وَمَنْ كَانَ فِي حَاجَةِ أَخِيهِ كَانَ اللَّهُ فِي حَاجَتِهِ وَمَنْ فَرَّجَ عَنْ مُسْلِمٍ كُرْبَةً فَرَّجَ اللَّهُ عَنْهُ كُرْبَةً مِنْ كُرُبَاتِ يَوْمِ الْقِيَامَةِ وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللَّهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] bahwa [Salim] mengabarkannya bahwa ['Abdullah bin 'Umar radliallahu 'anhuma] mengabarkannya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim adalah saudara bagi muslim lainnya, dia tidak menzhaliminya dan tidak membiarkannya untuk disakiti. Siapa yang membantu kebutuhan saudaranya maka Allah akan membantu kebutuhannya. Siapa yang menghilangkan satu kesusahan seorang muslim, maka Allah menghilangkan satu kesusahan baginya dari kesusahan-kesusahan hari qiyamat. Dan siapa yang menutupi (aib) seorang muslim maka Allah akan menutup aibnya pada hari qiyamat\". "},"2263":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ أَنَسٍ وَحُمَيْدٌ الطَّوِيلُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصُرْ أَخَاكَ ظَالِمًا أَوْ مَظْلُومًا","id":"Telah menceritakan kepada kami ['Utsman bin Abi Syaibah] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami ['Ubaidullah bin Abi Bakar bin Anas] dan [Humaid Ath-Thowil] dia mendengar [Anas bin Malik radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tolonglah saudaramu yang berbuat zhalim (aniaya) dan yang dizhalimi\"."},"2264":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصُرْ أَخَاكَ ظَالِمًا أَوْ مَظْلُومًا قَالُوا يَا رَسُولَ اللَّهِ هَذَا نَنْصُرُهُ مَظْلُومًا فَكَيْفَ نَنْصُرُهُ ظَالِمًا قَالَ تَأْخُذُ فَوْقَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mu'tamir] dari [Humaid] dari [Anas radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tolonglah saudaramu yang berbuat zhalim (aniaya) dan yang dizhalimi\". Mereka bertanya: \"Wahai Rasulullah, jelas kami faham menolong orang yang dizhalimi tapi bagaimana kami harus menolong orang yang berbuat zhalim?\" Beliau bersabda: \"Pegang tangannya (agar tidak berbuat zhalim) \"."},"2265":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ سُوَيْدٍ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ فَذَكَرَ عِيَادَةَ الْمَرِيضِ وَاتِّبَاعَ الْجَنَائِزِ وَتَشْمِيتَ الْعَاطِسِ وَرَدَّ السَّلَامِ وَنَصْرَ الْمَظْلُومِ وَإِجَابَةَ الدَّاعِي وَإِبْرَارَ الْمُقْسِمِ","id":"Telah menceritakan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats bin Sulaim] berkata, aku mendengar [Mu'awiyah bin Suwaid] aku mendengar [Al Bara' bin 'Azib radliallahu 'anhuma] berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkan kami tujuh perkara dan melarang kami dari tujuh perkara pula\". Maka Beliau menyebutkan: \"Menjenguk orang sakit, mengiringi jenazah, mendoakan orang yang bersin, membalas salam, menolong orang yang dizholimi, memunuhi undangan dan berbuat adil dalam pembagian\". "},"2266":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًا وَشَبَّكَ بَيْنَ أَصَ��بِعِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Alaa'] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Orang beriman terhadap orang beriman lainnya bagaikan satu bangunan yang satu sama lain saling menguatkan\". Dan Beliau mendemontrasikannya dengan cara mengepalkan jari jemari Beliau."},"2267":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عَبْدُ الْعَزِيزِ الْمَاجِشُونُ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الظُّلْمُ ظُلُمَاتٌ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Ahmad binYunus] telah menceritakan kepada kami ['Abdul 'Aziz Al Majisyun] telah mengabarkan kepada kami ['Abdullah bin DInar] dari ['Abdullah bin 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam: \"Kezhaliman adalah mendatangkan kegelapan hari qiyamat\"."},"2268":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَاقَ الْمَكِّيُّ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذًا إِلَى الْيَمَنِ فَقَالَ اتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّهَا لَيْسَ بَيْنَهَا وَبَيْنَ اللَّهِ حِجَابٌ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Zakariyya' bin Ishaq Al Makkiy] dari [Yahya bin 'Abdullah bin Shaifiy] dari [Abu Ma'bad, maula Ibnu 'Abbas] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam mengutus Mu'adz ke negeri Yaman lalu bersabda: \"Berhati-hatilah kamu terhadap do'anya orang yang dizhalimi karena antara do'anya dan Allah tidak ada penghalangnya\" "},"2269":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ مَظْلَمَةٌ لِأَخِيهِ مِنْ عِرْضِهِ أَوْ شَيْءٍ فَلْيَتَحَلَّلْهُ مِنْهُ الْيَوْمَ قَبْلَ أَنْ لَا يَكُونَ دِينَارٌ وَلَا دِرْهَمٌ إِنْ كَانَ لَهُ عَمَلٌ صَالِحٌ أُخِذَ مِنْهُ بِقَدْرِ مَظْلَمَتِهِ وَإِنْ لَمْ تَكُنْ لَهُ حَسَنَاتٌ أُخِذَ مِنْ سَيِّئَاتِ صَاحِبِهِ فَحُمِلَ عَلَيْهِقَالَ أَبُو عَبْد اللَّهِ قَالَ إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ إِنَّمَا سُمِّيَ الْمَقْبُرِيَّ لِأَنَّهُ كَانَ نَزَلَ نَاحِيَةَ الْمَقَابِرِ قَالَ أَبُو عَبْد اللَّهِ وَسَعِيدٌ الْمَقْبُرِيُّ هُوَ مَوْلَى بَنِي لَيْثٍ وَهُوَ سَعِيدُ بْنُ أَبِي سَعِيدٍ وَاسْمُ أَبِي سَعِيدٍ كَيْسَانُ","id":"Telah menceritakan kepada kami [Adam bin Abi Iyas] telah menceritakan kepada kami [Ibnu Abi Dza'bi] telah menceritakan kepada kami [Sa'id Al Maqburiy] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang pernah berbuat aniaya (zhalim) terhadap kehormatan saudaranya atau sesuatu apapun hendaklah dia meminta kehalalannya (maaf) pada hari ini (di dunia) sebelum datang hari yang ketika itu tidak bermanfaat dinar dan dirham. Jika dia tidak lakukan, maka (nanti pada hari qiyamat) bila dia memiliki amal shalih akan diambil darinya sebanyak kezholimannya. Apabila dia tidak memiliki kebaikan lagi maka keburukan saudaranya yang dizholiminya itu akan diambil lalu ditimpakan kepadanya\". Berkata, Abu 'Abdullah Al Bukhariy berkata, Isma'il bin Abi Uwais: \"Sa'id dipangil namanya dengan Al Maqburiy karena dia pernah tinggal di pinggiran maqabir (kuburan). Berkata, Abu 'Abdullah Al Bukhariy: Dan Sa'id Al Maqburiy adalah maula Bani Laits yang nama aslinya adalah Sa'id bin Abi Sa'id sedangkan nama Abu Sa'id adalah Kaisan\". "},"2270":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَافِي هَذِهِ الْآيَةِ{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ الرَّجُلُ تَكُونُ عِنْدَهُ الْمَرْأَةُ لَيْسَ بِمُسْتَكْثِرٍ مِنْهَا يُرِيدُ أَنْ يُفَارِقَهَا فَتَقُولُ أَجْعَلُكَ مِنْ شَأْنِي فِي حِلٍّ فَنَزَلَتْ هَذِهِ الْآيَةُ فِي ذَلِكَ","id":"Telah menceritakan kepada kami [Muhamamad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] tentang ayat ini QS An-Nisaa: 128): (\"Apabila seorang isteri takut suaminya akan berbuat nusyuz (tidak mau menggaulinya) atau berlaku kasar terhadapnya\"), dia ('Aisyah radliallahu 'anha) berkata: \"Yaitu jika seorang suami yang memiliki isteri namun dia tidak lagi mencintai dan menggaulinya serta berkehendak untuk menceraikanya lalu isterinya berkata, \"aku persilakan kamu meninggalkan aku namun jangan ceraikan aku\", maka turunlah ayat ini\". "},"2271":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي حَازِمِ بْنِ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِشَرَابٍ فَشَرِبَ مِنْهُ وَعَنْ يَمِينِهِ غُلَامٌ وَعَنْ يَسَارِهِ الْأَشْيَاخُ فَقَالَ لِلْغُلَامِ أَتَأْذَنُ لِي أَنْ أُعْطِيَ هَؤُلَاءِ فَقَالَ الْغُلَامُ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ لَا أُوثِرُ بِنَصِيبِي مِنْكَ أَحَدًا قَالَ فَتَلَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَدِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Hazim bin Dinar] dari [Sahal bin Sa'ad As-Sa'idiy radliallahu 'anhu] bahwa kepada Rasulullah shallallahu 'alaihi wasallam disuguhkan minuman, lalu Beliau meminumnya sementara disamping kanan Beliau ada seorang anak kecil sedangkan di sebelah kiri Beliau ada para orang-orang tua. Maka Beliau berkata, kepada anak kecil itu: \"Apakah kamu mengizinkan aku untuk memberi minuman ini kepada mereka?\" Anak kecil itu berkata: \"Demi Allah, tidak wahai Rasulullah, aku tidak akan mendahulukan seorangpun daripadaku selain anda\". Maka Beliau memberikan kepadanya."},"2272":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي طَلْحَةُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَمْرِو بْنِ سَهْلٍ أَخْبَرَهُ أَنَّ سَعِيدَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ظَلَمَ مِنْ الْأَرْضِ شَيْئًا طُوِّقَهُ مِنْ سَبْعِ أَرَضِينَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepadaku [Tholhah bin 'Abdullah] bahwa ['Abdurrahman bin 'Amru bin Sahal] mengabarkan kepadanya bahwa [Sa'id bin Zaid radliallahu 'anhu] berkata, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang pernah berbuat aniaya terhadap sebidang tanah (di muka bumi ini) maka nanti dia akan dibebani (dikalungkan pada lehernya) tanah dari tujuh bumi\"."},"2273":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا حُسَيْنٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ أَنَّهُ كَانَتْ بَيْنَهُ وَبَيْنَ أُنَاسٍ خُصُومَةٌ فَذَكَرَ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَتْيَا أَبَا سَلَمَةَ اجْتَنِبْ الْأَرْضَ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ظَلَمَ قِيدَ شِبْرٍ مِنْ الْأَرْضِ طُوِّقَهُ مِنْ سَبْعِ أَرَضِينَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Husain] dari [Yahya bin Abi Katsir] berkata, telah menceritakan kepadaku [Muhammad bin Ibrahim] bahwa [Abu Salamah] menceritakan kepadanya bahwa dia pernah bertengkar dengan seseorang lalu diceritakan hal ini kepada 'Aisyah radliallahu 'anha, maka ['Aisyah radliallahu 'anha] berkata: \"Wahai Abu Salamah hindarkanlah bertengkar dalam urusan tanah karena Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Siapa yang pernah berbuat aniaya sejengkal saja (dalam perkara tanah) maka nanti dia akan dibebani (dikalungkan pada lehernya) tanah dari tujuh petala bumi\"."},"2274":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَخَذَ مِنْ الْأَرْضِ شَيْئًا بِغَيْرِ حَقِّهِ خُسِفَ بِهِ يَوْمَ الْقِيَامَةِ إِلَى سَبْعِ أَرَضِينَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami ['Abdullah bin Al Mubarak] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Salim] dari [bapaknya] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengambil sesuatu (sebidang tanah) dari bumi yang bukan haknya maka pada hari qiyamat nanti dia akan dibenamkan sampai tujuh bumi\"."},"2275":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ جَبَلَةَ كُنَّا بِالْمَدِينَةِ فِي بَعْضِ أَهْلِ الْعِرَاقِ فَأَصَابَنَا سَنَةٌ فَكَانَ ابْنُ الزُّبَيْرِ يَرْزُقُنَا التَّمْرَ فَكَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَمُرُّ بِنَا فَيَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْإِقْرَانِ إِلَّا أَنْ يَسْتَأْذِنَ الرَّجُلُ مِنْكُمْ أَخَاهُ","id":"Telah menceritakan kepada kami [Hafzh bin 'Umar] telah menceritakan kepada kami [Syu'bah] dari [Jabalah]; Kami pernah tinggal di Madinah bersama orang-orang dari penduduk 'Iraq selama setahun yang Ibnu Az Zubair memberi kami rezeki berupa kurma. Suatu hari [Ibnu 'Umar] radliallahu 'anhuma berjalan melewati kami lalu dia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang qiran (mengambil dua dua kurma sekaligus ketika memakannya) kecuali bila seseorang dari kalian meminta izin kepada saudaranya\"."},"2276":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ يُقَالُ لَهُ أَبُو شُعَيْبٍ كَانَ لَهُ غُلَامٌ لَحَّامٌ فَقَالَ لَهُ أَبُو شُعَيْبٍ اصْنَعْ لِي طَعَامَ خَمْسَةٍ لَعَلِّي أَدْعُو النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَامِسَ خَمْسَةٍ وَأَبْصَرَ فِي وَجْهِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُوعَ فَدَعَاهُ فَتَبِعَهُمْ رَجُلٌ لَمْ يُدْعَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا قَدْ اتَّبَعَنَا أَتَأْذَنُ لَهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Abu Wa'il] dari [Abu Mas'ud]: \"Ada seorang Kaum Anshar yang biasa dipanggil dengan Abu Syu'aib memiliki pembantu sebagai tukang potong hewan (jagal). Berkata Abu Syu'aib kepadanya: \"Buatkan aku makanan untuk lima orang, karena aku ingin mengundang Nabi shallallahu 'alaihi wasallam sebagai tamu kelimaku\". Dia melihat rasa lapar dari raut muka Beliau\". Lalu ia mengundang Beliau namun ada seseorang yang tidak diundang ikut bersama mereka, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang ini mengikuti kami, apakah kamu mengizinkannya?\" Dia menjawab: \"Iya\"."},"2277":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَبْغَضَ الرِّجَالِ إِلَى اللَّهِ الْأَلَدُّ الْخَصِمُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abi Mulaikah] dari ['Aisyah radliallahu 'anha] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang paling dimurkai Allah adalah penantang yang paling keras\"."},"2278":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ زَيْنَبَ بِنْتَ أُمِّ سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّهَا أُمَّ سَلَمَةَ رَضِيَ اللَّهُ عَنْه��ا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَمِعَ خُصُومَةً بِبَابِ حُجْرَتِهِ فَخَرَجَ إِلَيْهِمْ فَقَالَ إِنَّمَا أَنَا بَشَرٌ وَإِنَّهُ يَأْتِينِي الْخَصْمُ فَلَعَلَّ بَعْضَكُمْ أَنْ يَكُونَ أَبْلَغَ مِنْ بَعْضٍ فَأَحْسِبُ أَنَّهُ صَدَقَ فَأَقْضِيَ لَهُ بِذَلِكَ فَمَنْ قَضَيْتُ لَهُ بِحَقِّ مُسْلِمٍ فَإِنَّمَا هِيَ قِطْعَةٌ مِنْ النَّارِ فَلْيَأْخُذْهَا أَوْ فَلْيَتْرُكْهَا","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepadaku [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku ['Urwah bin Az Zubair] bahwa [Zainab bunti Ummu Salamah] mengabarkan kepadanya bahwa ibunya, [Ummu Salamah radliallahu 'anhah], isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya dari Rasulullah shallallahu 'alaihi wasallam bahwa Beliau mendengar dari balik pintu rumah Beliau ada pertengkaran lalu Beliau keluar menemui mereka kemudian bersabda: \"Aku ini hanyalah manusia biasa dan sesungguhnya pertangkaran seringkali dilaporkan kepadaku. Dan bisa salah seorang diantara kalian lebih pandai bersilat lidah daripada lainnya, lalu aku menganggap dia benar kemudian aku berikan kepadanya sesuai pengakuannya itu. Maka siapa yang aku putuskan menang dengan mencederai hak seorang muslim, berarti itu adalah potongan dari api neraka. Karena itu hendaklah dia ambil atau ditinggalkannya\"."},"2279":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا أَوْ كَانَتْ فِيهِ خَصْلَةٌ مِنْ أَرْبَعَةٍ كَانَتْ فِيهِ خَصْلَةٌ مِنْ النِّفَاقِ حَتَّى يَدَعَهَا إِذَا حَدَّثَ كَذَبَ وَإِذَا وَعَدَ أَخْلَفَ وَإِذَا عَاهَدَ غَدَرَ وَإِذَا خَاصَمَ فَجَرَ","id":"Telah menceritakan kepada kami [Bisyir bin Khalid] telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abdullah bin Murrah] dari [Masruq] dari ['Abdullah bin 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ada empat hal yang bila ada pada seseorang berarti dia adalah munafiq atau siapa yang memiliki empat kebiasaan (tabi'at) berarti itu tabiat munafiq sampai dia meninggalkannya, yaitu jika berbicara dusta, jika berjanji ingkar, jika membuat kesepakatan khiyanat dan jika bertengkar (ada perselisihan) maka dia curang\". "},"2280":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْجَاءَتْ هِنْدُ بِنْتُ عُتْبَةَ بْنِ رَبِيعَةَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ مِسِّيكٌ فَهَلْ عَلَيَّ حَرَجٌ أَنْ أُطْعِمَ مِنْ الَّذِي لَهُ عِيَالَنَا فَقَالَ لَا حَرَجَ عَلَيْكِ أَنْ تُطْعِمِيهِمْ بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] telah menceritakan kepadaku ['Urwah] dari ['Aisyah radliallahu 'anha] berkata; Hindun binti 'Utbah datang menemui Rasulullah shallallahu 'alaihi wasallam lalu berkata: \"Abu Sufyan adalah seorang yang kikir, apakah aku berdosa bila aku ambil dari hartanya untuk memberi makan keluarga kami? '. Maka Beliau bersabda: \"Tidak dosa atasmu jika kamu beri makan mereka dengan cara yang ma'ruf (wajar)."},"2281":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي يَزِيدُ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقُلْنَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ تَبْعَثُنَا فَنَنْزِلُ بِقَوْمٍ لَا يَقْرُونَا فَمَا تَرَى فِيهِ فَقَالَ لَنَا إِنْ نَزَلْتُمْ بِقَوْمٍ فَأُمِرَ لَكُمْ بِمَا يَنْبَغِي لِلضَّيْفِ فَاقْبَلُوا فَإِنْ لَمْ يَفْعَلُوا فَخُذُوا مِنْهُمْ حَقَّ الضَّيْفِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku [Yazid] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] berkata; Kami bertanya kepada Nabi shallallahu 'alaihi wasallam: Bila anda mengutus kami dalam suatu perjalanan lalu kami singgah di suatu kaum (kampung) namun mereka tidak melayani kami (memberikan hak tamu) apa pendapat anda dalam masalah ini?\" Maka Beliau bersabda: \"Bagi kita, bila kalian singgah di suatu kaum diperintahkan bagi kalian untuk mendapatkan apa yang seharusnya didapat sebagai tamu, maka mintalah kepada mereka. Bila mereka tidak menunaikannya ambillah dari mereka sebatas hak tamu\"."},"2282":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ حَدَّثَنِي مَالِكٌ وَأَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُمْقَالَ حِينَ تَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْأَنْصَارَ اجْتَمَعُوا فِي سَقِيفَةِ بَنِي سَاعِدَةَ فَقُلْتُ لِأَبِي بَكْرٍ انْطَلِقْ بِنَا فَجِئْنَاهُمْ فِي سَقِيفَةِ بَنِي سَاعِدَةَ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] berkata, telah menceritakan kepadaku [Ibnu Wahb] berkata, telah menceritakan kepadaku [Malik] telah menceritakan kapadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kapadaku ['Ubaidullah bin 'Abdullah bin 'Utbah] bahwa [Ibnu 'Abbas] mengabarkan kepadanya dari ['Umar] radliallahu 'anhum berkata: \"Ketika Allah subhanahu wata'ala mewafatkan nabiNya shallallahu 'alaihi wasallam, orang-orang Anshar berkumpul di aula pertemuan Bani Sa'idah. Maka aku katakan kepada Abu Bakar; \"Mari kita kesana\". Maka kami pun mendatangi mereka di aula pertemuan Bani Sa'idah itu\"."},"2283":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْنَعْ جَارٌ جَارَهُ أَنْ يَغْرِزَ خَشَبَهُ فِي جِدَارِهِثُمَّ يَقُولُ أَبُو هُرَيْرَةَ مَا لِي أَرَاكُمْ عَنْهَا مُعْرِضِينَ وَاللَّهِ لَأَرْمِيَنَّ بِهَا بَيْنَ أَكْتَافِكُمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang melarang tetangganya untuk menyandarkan kayunya di dinding rumahnya\". Kemudian Abu Hurairah radliallahu 'anhu berkata: \"Jangan sampai aku lihat kalian menolak ketentuan hukum ini. Demi Allah, kalau sampai terjadi, akan aku lempar kayu-kayu itu menimpa samping kalian\"."},"2284":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَبُو يَحْيَى أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُكُنْتُ سَاقِيَ الْقَوْمِ فِي مَنْزِلِ أَبِي طَلْحَةَ وَكَانَ خَمْرُهُمْ يَوْمَئِذٍ الْفَضِيخَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنَادِيًا يُنَادِي أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ قَالَ فَقَالَ لِي أَبُو طَلْحَةَ اخْرُجْ فَأَهْرِقْهَا فَخَرَجْتُ فَهَرَقْتُهَا فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ فَقَالَ بَعْضُ الْقَوْمِ قَدْ قُتِلَ قَوْمٌ وَهِيَ فِي بُطُونِهِمْ فَأَنْزَلَ اللَّهُ{ لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdur Rahim Abu Yahya] telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Tsabit] dari [Anas radliallahu 'anhu]: \"Aku pernah menjamu suatu kaum dengan minuman di rumah Abu Tholhah. Saat itu khamar (arak, minuman keras) mereka adalah Al Fadhikh (arak terbuat dari buah kurma). Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan seorang penyeru untuk menyerukan bahwa khamar telah diharamkan\". Anas berkata: \"Maka Abu Tholhah berkata, kepadaku: \"Keluar dan tumpahkanlah\". Maka aku keluar lalu aku tumpahkan. Maka khamar mengalirdi jalan-jalan kota Madinah. Kemudian sebagian kaum berkata; \"Telah wafat sebagian orang sedangkan di perut mereka masih ada khamar, maka Allah subhanahu wata'ala menurunkan firmanNya (QS Alu 'Imran ayat 93 yang artinya): (Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang saleh karena memakan makanan yang telah mereka makan dahulu…) "},"2285":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا أَبُو عُمَرَ حَفْصُ بْنُ مَيْسَرَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالْجُلُوسَ عَلَى الطُّرُقَاتِ فَقَالُوا مَا لَنَا بُدٌّ إِنَّمَا هِيَ مَجَالِسُنَا نَتَحَدَّثُ فِيهَا قَالَ فَإِذَا أَبَيْتُمْ إِلَّا الْمَجَالِسَ فَأَعْطُوا الطَّرِيقَ حَقَّهَا قَالُوا وَمَا حَقُّ الطَّرِيقِ قَالَ غَضُّ الْبَصَرِ وَكَفُّ الْأَذَى وَرَدُّ السَّلَامِ وَأَمْرٌ بِالْمَعْرُوفِ وَنَهْيٌ عَنْ الْمُنْكَرِ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Abu 'Umar Hafsh bin Maisarah] dari [Zaid bin Aslam] dari ['Atha' bin Yasar] dari [Abu Sa'id AL Khudriy radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian duduk duduk di pinggir jalan\". Mereka bertanya: \"Itu kebiasaan kami yang sudah biasa kami lakukan karena itu menjadi majelis tempat kami bercengkrama\". Beliau bersabda: \"Jika kalian tidak mau meninggalkan majelis seperti itu maka tunaikanlah hak jalan tersebut\". Mereka bertanya: \"Apa hak jalan itu?\" Beliau menjawab: \"Menundukkan pandangan, menyingkirkan halangan, menjawab salam dan amar ma'ruf nahiy munkar\". "},"2286":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا رَجُلٌ بِطَرِيقٍ اشْتَدَّ عَلَيْهِ الْعَطَشُ فَوَجَدَ بِئْرًا فَنَزَلَ فِيهَا فَشَرِبَ ثُمَّ خَرَجَ فَإِذَا كَلْبٌ يَلْهَثُ يَأْكُلُ الثَّرَى مِنْ الْعَطَشِ فَقَالَ الرَّجُلُ لَقَدْ بَلَغَ هَذَا الْكَلْبَ مِنْ الْعَطَشِ مِثْلُ الَّذِي كَانَ بَلَغَ مِنِّي فَنَزَلَ الْبِئْرَ فَمَلَا خُفَّهُ مَاءً فَسَقَى الْكَلْبَ فَشَكَرَ اللَّهُ لَهُ فَغَفَرَ لَهُ قَالُوا يَا رَسُولَ اللَّه وَإِنَّ لَنَا فِي الْبَهَائِمِ لَأَجْرًا فَقَالَ فِي كُلِّ ذَاتِ كَبِدٍ رَطْبَةٍ أَجْرٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Sumayya, maula Abu Bakar] dari [Abu Shalih As-Samman] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Ada seorang laki-laki yang sedang berjalan, lalu dia merasakan kehausan yang sangat. Kemudian dia dapatkan sebuah sumur lalu dia turun ke sumur itu lalu minum dari air sumur tersebut. Kemudian dia keluar ternyata didapatkannya seekor anjing yang sedang menjulurkan lidahnya menjilat-jilat tanah karena kehausan. Orang itu berkata: \"Anjing ini sedang kehausan seperti yang aku alami tadi\". Maka dia (turun kembali ke dalam sumur) dan diisinya sepatunya dengan air dan sambil menggigit sepatunya dengan mulutnya dia naik keatas lalu memberi anjing itu minum. Kemudian dia bersyukur kepada Allah maka Allah mengampuninya\". Mereka bertanya: \"Wahai Rasulullah, apakah kita akan dapat pahala dengan berbuat baik kepada hewan?\" Beliau shallallahu 'alaihi wasallam menjawab: \"Terhadap setiap makhluq bernyawa diberi pahala\". "},"2287":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَشْرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أُطُمٍ مِنْ آطَامِ الْمَدِينَةِ ثُمَّ قَالَ هَلْ تَرَوْنَ مَا أَرَى إِنِّي أَرَى مَوَاقِعَ الْفِتَنِ خِلَالَ بُيُوتِكُمْ كَمَوَاقِعِ الْقَطْرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhriy] dari ['Urwah] aku mendengar ['Usamah radliallahu 'anhu] berkata; \"Nabi shallallahu 'alaihi wasallam naik ke atas salah satu dari benteng-benteng Madinah lalu bersabda: \"Apakah kalian melihat sebagaimana aku melihat? Sungguh aku melihat tempat-tempat terjadinya fitnah di sela-sela rumah kalian seperti tempat jatuhnya tetesan (air hujan) \". "},"2288":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمْ أَزَلْ حَرِيصًا عَلَى أَنْ أَسْأَلَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }فَحَجَجْتُ مَعَه فَعَدَلَ وَعَدَلْتُ مَعَهُ بِالْإِدَاوَةِ فَتَبَرَّزَ حَتَّى جَاءَ فَسَكَبْتُ عَلَى يَدَيْهِ مِنْ الْإِدَاوَةِ فَتَوَضَّأَ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ الْمَرْأَتَانِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَانِ قَالَ اللَّهُ عَزَّ وَجَلَّ لَهُمَا{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }فَقَالَ وَا عَجَبِي لَكَ يَا ابْنَ عَبَّاسٍ عَائِشَةُ وَحَفْصَةُ ثُمَّ اسْتَقْبَلَ عُمَرُ الْحَدِيثَ يَسُوقُهُ فَقَالَ إِنِّي كُنْتُ وَجَارٌ لِي مِنْ الْأَنْصَارِ فِي بَنِي أُمَيَّةَ بْنِ زَيْدٍ وَهِيَ مِنْ عَوَالِي الْمَدِينَةِ وَكُنَّا نَتَنَاوَبُ النُّزُولَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْزِلُ يَوْمًا وَأَنْزِلُ يَوْمًا فَإِذَا نَزَلْتُ جِئْتُهُ مِنْ خَبَرِ ذَلِكَ الْيَوْمِ مِنْ الْأَمْرِ وَغَيْرِهِ وَإِذَا نَزَلَ فَعَلَ مِثْلَهُ وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا عَلَى الْأَنْصَارِ إِذَا هُمْ قَوْمٌ تَغْلِبُهُمْ نِسَاؤُهُمْ فَطَفِقَ نِسَاؤُنَا يَأْخُذْنَ مِنْ أَدَبِ نِسَاءِ الْأَنْصَارِ فَصِحْتُ عَلَى امْرَأَتِي فَرَاجَعَتْنِي فَأَنْكَرْتُ أَنْ تُرَاجِعَنِي فَقَالَتْ وَلِمَ تُنْكِرُ أَنْ أُرَاجِعَكَ فَوَاللَّهِ إِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ليُرَاجِعْنَهُ وَإِنَّ إِحْدَاهُنَّ لَتَهْجُرُهُ الْيَوْمَ حَتَّى اللَّيْلِ فَأَفْزَعَنِي فَقُلْتُ خَابَتْ مَنْ فَعَلَ مِنْهُنَّ بِعَظِيمٍ ثُمَّ جَمَعْتُ عَلَيَّ ثِيَابِي فَدَخَلْتُ عَلَى حَفْصَةَ فَقُلْتُ أَيْ حَفْصَةُ أَتُغَاضِبُ إِحْدَاكُنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَوْمَ حَتَّى اللَّيْلِ فَقَالَتْ نَعَمْ فَقُلْتُ خَابَتْ وَخَسِرَتْ أَفَتَأْمَنُ أَنْ يَغْضَبَ اللَّهُ لِغَضَبِ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَهْلِكِينَ لَا تَسْتَكْثِرِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تُرَاجِعِيهِ فِي شَيْءٍ وَلَا تَهْجُرِيهِ وَاسْأَلِينِي مَا بَدَا لَكِ وَلَا يَغُرَّنَّكِ أَنْ كَانَتْ جَارَتُكَ هِيَ أَوْضَأَ مِنْكِ وَأَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عَائِشَةَ وَكُنَّا تَحَدَّثْنَا أَنَّ غَسَّانَ تُنْعِلُ النِّعَالَ لِغَزْوِنَا فَنَزَلَ صَاحِبِي يَوْمَ نَوْبَتِهِ فَرَجَعَ عِشَاءً فَضَرَبَ بَابِي ضَرْبًا شَدِيدًا وَقَالَ أَنَائِمٌ هُوَ فَفَزِعْتُ فَخَرَجْتُ إِلَيْهِ وَقَالَ حَدَثَ أَمْرٌ عَظِيمٌ قُلْتُ مَا هُوَ أَجَاءَتْ غَسَّانُ قَالَ لَا بَلْ أَعْظَمُ مِنْهُ وَأَطْوَلُ طَلَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ قَالَ قَدْ خَابَتْ حَفْصَةُ وَخَسِرَتْ كُنْتُ أَظُنُّ أَنَّ هَذَا يُوشِكُ أَنْ يَكُونَ فَجَمَعْتُ عَلَيَّ ثِيَابِي فَصَلَّيْتُ صَلَاةَ الْفَجْرِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ مَشْرُبَةً لَهُ فَاعْتَزَلَ فِيهَا فَدَخَلْتُ عَلَى حَفْصَةَ فَإِذَا هِيَ تَبْكِي قُلْتُ مَا يُبْكِيكِ أَوَلَمْ أَكُنْ حَذَّرْتُكِ أَطَلَّقَكُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَا أَدْرِي هُوَ ذَا فِي الْمَشْرُبَةِ فَخَرَجْتُ فَجِئْتُ الْمِنْبَرَ فَإِذَا حَوْلَهُ رَهْطٌ يَبْكِي بَعْضُهُمْ فَجَلَسْتُ مَعَهُمْ قَلِيلًا ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ الْمَشْرُبَةَ الَّتِي هُوَ فِيهَا فَقُلْتُ لِغُلَامٍ لَهُ أَسْوَدَ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ فَكَلَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ خَرَجَ فَقَالَ ذَكَرْتُكَ لَهُ فَصَمَتَ فَانْصَرَفْتُ حَتَّى جَلَسْتُ مَعَ الرَّهْطِ الَّذِينَ عِنْدَ الْمِنْبَرِ ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ فَذَكَرَ مِثْلَهُ فَجَلَسْتُ مَعَ الرَّهْطِ الَّذِينَ عِنْدَ الْمِنْبَرِ ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ الْغُلَامَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ فَذَكَرَ مِثْلَهُ فَلَمَّا وَلَّيْتُ مُنْصَرِفًا فَإِذَا الْغُلَامُ يَدْعُونِي قَالَ أَذِنَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلْتُ عَلَيْهِ فَإِذَا هُوَ مُضْطَجِعٌ عَلَى رِمَالِ حَصِيرٍ لَيْسَ بَيْنَهُ وَبَيْنَهُ فِرَاشٌ قَدْ أَثَّرَ الرِّمَالُ بِجَنْبِهِ مُتَّكِئٌ عَلَى وِسَادَةٍ مِنْ أَدَمٍ حَشْوُهَا لِيفٌ فَسَلَّمْتُ عَلَيْهِ ثُمَّ قُلْتُ وَأَنَا قَائِمٌ طَلَّقْتَ نِسَاءَكَ فَرَفَعَ بَصَرَهُ إِلَيَّ فَقَالَ لَا ثُمَّ قُلْتُ وَأَنَا قَائِمٌ أَسْتَأْنِسُ يَا رَسُولَ اللَّهِ لَوْ رَأَيْتَنِي وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا عَلَى قَوْمٍ تَغْلِبُهُمْ نِسَاؤُهُمْ فَذَكَرَهُ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قُلْتُ لَوْ رَأَيْتَنِي وَدَخَلْتُ عَلَى حَفْصَةَ فَقُلْتُ لَا يَغُرَّنَّكِ أَنْ كَانَتْ جَارَتُكِ هِيَ أَوْضَأَ مِنْكِ وَأَحَبَّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عَائِشَةَ فَتَبَسَّمَ أُخْرَى فَجَلَسْتُ حِينَ رَأَيْتُهُ تَبَسَّمَ ثُمَّ رَفَعْتُ بَصَرِي فِي بَيْتِهِ فَوَاللَّهِ مَا رَأَيْتُ فِيهِ شَيْئًا يَرُدُّ الْبَصَرَ غَيْرَ أَهَبَةٍ ثَلَاثَةٍ فَقُلْتُ ادْعُ اللَّهَ فَلْيُوَسِّعْ عَلَى أُمَّتِكَ فَإِنَّ فَارِسَ وَالرُّومَ وُسِّعَ عَلَيْهِمْ وَأُعْطُوا الدُّنْيَا وَهُمْ لَا يَعْبُدُونَ اللَّهَ وَكَانَ مُتَّكِئًا فَقَالَ أَوَفِي شَكٍّ أَنْتَ يَا ابْنَ الْخَطَّابِ أُولَئِكَ قَوْمٌ عُجِّلَتْ لَهُمْ طَيِّبَاتُهُمْ فِي الْحَيَاةِ الدُّنْيَا فَقُلْتُ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ لِي فَاعْتَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَجْلِ ذَلِكَ الْحَدِيثِ حِينَ أَفْشَتْهُ حَفْصَةُ إِلَى عَائِشَةَ وَكَانَ قَدْ قَالَ مَا أَنَا بِدَاخِلٍ عَلَيْهِنَّ شَهْرًا مِنْ شِدَّةِ مَوْجِدَتِهِ عَلَيْهِنَّ حِينَ عَاتَبَهُ اللَّهُ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ دَخَلَ عَلَى عَائِشَةَ فَبَدَأَ بِهَا فَقَالَتْ لَهُ عَائِشَةُ إِنَّكَ أَقْسَمْتَ أَنْ لَا تَدْخُلَ عَلَيْنَا شَهْرًا وَإِنَّا أَصْبَحْنَا لِتِسْعٍ وَعِشْرِينَ لَيْلَةً أَعُدُّهَا عَدًّا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ وَكَانَ ذَلِكَ الشَّهْرُ تِسْعًا وَعِشْرِينَ قَالَتْ عَائِشَةُ فَأُنْزِلَتْ آيَةُ التَّخْيِيرِ فَبَدَأَ بِي أَوَّلَ امْرَأَةٍ فَقَالَ إِنِّي ذَاكِرٌ لَكِ أَمْرًا وَلَا عَلَيْكِ أَنْ لَا تَعْجَلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ قَدْ أَعْلَمُ أَنَّ أَبَوَيَّ لَمْ يَكُونَا يَأْمُرَانِي بِفِرَاقِكَ ثُمَّ قَالَ إِنَّ اللَّهَ قَالَ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ إِلَى قَوْلِهِ عَظِيمًا }قُلْتُ أَفِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ ثُمَّ خَيَّرَ نِسَاءَهُ فَقُلْنَ مِثْلَ مَا قَالَتْ عَائِشَةُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku ['Ubaidullah bin 'Abdullah bin Abu Tsaur] dari ['Abdullah bin 'Abbas radliallahu 'anhuma] berkata: \"Aku selalu antusias untuk bertanya kepada ['Umar] tentang dua wanita diantara isteri-isteri Nabi shallallahu 'alaihi wasallam yang Allah berfirman kepada keduanya: (\"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan) …QS At-Tahrim 4). Maka aku kunjungi dia namun dia menghindar dan aku susul dia dengan membawa kantong terbuat dari kulit berisi air hingga dia datang, lalu aku tuangkan air dari kantong air tadi keatas kedua tangannya hingga dia berwudhu' lalu aku tanya: \"Wahai amirul mu'minin, siapakah dua wanita dari isteri Nabi shallallahu 'alaihi wasallam yang Allah berfirman kepadanya (\"Jika kamu berdua bertaubat kepada Allah, maka sesungguhnya hati kamu berdua telah condong (untuk menerima kebaikan) …), maka dia menjawab: \"Aku heran kepadamu wahai Ibnu 'Abbas!, dia adalah 'Aisyah dan Hafshah\". Kemudian 'Umar menyebutkan hadits, katanya: \"Aku dan tetanggaku dari Anshar berada di desa Banu Umayyah bin Zaid, termasuk suku kepercayaan di Madinah dan kami saling bergantian menemui Rasul shallallahu 'alaihi wasallam. Sehari aku yang menemui Beliau shallallahu 'alaihi wasallam, hari lain dia yang menemui Beliau shallallahu 'alaihi wasallam. Jika giliranku menemui Beliau, aku menanyakan seputar wahyu yang turun hari itu dan perkara lainnya. Dan jika giliran tetangguku itu, ia pun melakukan hal sama. Kami adalah kaum Quraisy yang bisa menundukkan para isteri, hingga ketika kami mendatangi Kaum Anshar, ternyata mereka adalah sebuah kaum yang ditundukkan oleh isteri-isteri mereka. Lalu isteri-isteri kami segera saja meniru kebiasaan wanita Anshar tersebut. Suatu hari aku nasehati isteriku tapi dia membantahku dan aku larang dia membantahku tapi dia berkata: \"Kenapa kamu melarang aku membantahmu? Demi Allah, sesungguhnya hari ini isteri-isteri Nabi Shallallahu 'alaihiwasallam telah membantah Beliau bahkan seorang dari mereka tidak berbicara kepada Beliau hingga malam hari\". Aku kaget mendengar itu lalu aku katakan: \"Sangat celakalah diantara kalian orang yang berbuat hal seperti ini\". Kemudian aku bergegas untuk menemui Hafshah lalu aku bertanya: \"Wahai Hafshah, apakah salah seorang dari kalian hari ini telah membantah Rasulullah shallallahu 'alaihi wasallam hingga malam hari?\" Dia menjawab: \"Iya\". Aku katakan: \"Celaka dan rugilah. Apakah kalian merasa aman dari murka Allah disebabkan RasulNya shallallahu 'alaihi wasallam marah lalu kalian menjadi binasa? Janganlah kalian menuntut terlalu banyak kepada Rasulullah shallallahu 'alaihi wasallam dan jangan kalian membantahnya tentang suatu apapun dan jangan pula kalian menghindar untuk berbicara dengan Beliau. Mintalah kepadaku apa yang menjadi keperluanmu dan jangan kamu cemburu bila ada (isteri Nabi shallallahu 'alaihi wasallam), madu kamu, yang lebih cantik dan lebih dicintai oleh Rasulullah shallallahu 'alaihi wasallam \". Yang dimaksudkannya adalah 'Aisyah radliallahu 'anha. Suatu hari kami membicarakan suku Ghossan sebagai tukang sepatu yang biasanya menyiapkan sepatu kami untuk perang. Maka sahabatku pergi (menemui Rasulullah shallallahu 'alaihi wasallam) pada hari gilirannya lalu dia kembali pada waktu 'Isya dengan mengetuk rumahku dengan sangat keras seraya berkata: \"Apakah dia sudah tidur?\" Aku kaget lalu keluar menemuinya. Dia berkata: \"Telah terjadi masalah besar\". Aku bertanya: \"Masalah apa itu? Apakah suku Ghassan sudah datang?\" Dia menjawab: \"Bukan, bahkan urusannya lebih penting dan lebih panjang dari masalah itu. Rasulullah shallallahu 'alaihi wasallam telah menceraikan isteri-isteri Beliau. 'Umar berkata: \"Sungguh celaka dan rugilah Hafshah. Aku mengira hal ini tidak akan terjadi. Maka aku lipat pakaianku kemudian aku shalat Shubuh bersama Nabi shallallahu 'alaihi wasallam lalu Beliau memasuki bilik yang tinggi dan mengasingkan diri disana. Maka aku menemui Hafshah yang ternyata sedang menangis lalu aku bertanya: \"Apa yang membuatmu menangis, bukankah aku sudah peringatkan kamu? Apakah Rasulullah shallallahu 'alaihi wasallam telah menceraikan kalian?\" Dia menjawab: \"Aku tidak tahu, sekarang Beliau berada di tempat pengasingannya\". Maka aku keluar lalu mendatangi mimbar ternyata di sekelilingnya ada sejumlah orang (kurang dari sepuluh) yang sedang berkumpul diantaranya ada yang menangis. Maka aku duduk bersama mereka sebentar lalu aku sangat ingin mendatangi tempat pengasingan tempat Beliau berdiam disana. Aku katakan kepada Aswad, anak kecil pembantu Beliau: \"Mintakanlah izin untuk 'Umar?\" Maka dia masuk dan berbicara dengan Nabi shallallahu 'alaihi wasallam lalu keluar dan berkata: \"Aku sudah sampaikan tentang maksudmu namun Beliau diam saja\". Maka kemudian aku kembali dan berkumpul bersama orang-orang yang berada dekat mimbar. Sesaat kemudian timbul lagi keinginanku maka aku temui anak kecil itu lalu aku sampaikan maksudku seperti tadi dan diapun menjawab seperti tadi pula. Maka aku kembali duduk bersama orang-orang yang berada dekat mimbar. Ternyata timbul lagi keinginanku, maka aku datangi lagi anak kecil itu dan aku katakan: \"Mintakanlah izin untuk 'Umar?\" Maka dia menjawab seperti tadi pula. Ketika aku hendak kembali, anak kecil itu memanggilku dan berkata: \"Rasulullah shallallahu 'alaihi wasallam mengizinkan kamu masuk\". Maka aku masuk menemui Beliau yang ketika itu Beliau sedang berbaring diatas pasir sebagai kasurnya, dan tidak ada kasur yang menengahi antara pasir dan beliau sehingga pasir itu membekas pada sisi badan Beliau, Beliau bersandar diatas bantal yang terbuat dari kulit yang isinya sabut. Aku memberi salam kepada Beliau lalu aku berkata dalam posisi tetap berdiri: \"Apakah anda telah menceraikan isteri-isteri anda\". Maka Beliau memandang ke arahku lalu berkata: \"Tidak\". Kemudian aku katakan: \"Apakah anda merasa tidak enak karena melihat aku?\" Kami ini adalah orang Quraisy yang biasa menundukkan isteri-isteri. Ketika kami datang disini bertemu dengan Kaum yang mereka ditundukkan oleh isteri-isteri mereka\". Maka 'Umar menceritakan. Lalu Nabi shallallahu 'alaihi wasallam tersenyum. Kemudian aku katakan: \"Bagaimana seandainya anda melihatku menemui Hafshah dan aku katakan kepadanya: \"Jangan kamu cemburu bila ada (isteri Nabi shallallahu 'alaihi wasallam), madu kamu, yang lebih cantik dan lebih dicintai oleh Rasulullah shallallahu 'alaihi wasallam \". Yang dimaksudkan Umar adalah 'Aisyah radliallahu 'anha. Maka Beliau tersenyum lagi. Lalu aku duduk ketika melihat Beliau tersenyum lalu aku memandang ke rumah Beliau. Demi Allah, aku tidak melihat apapun disana, karena mataku bolak balik melihat tidak kurang dari tiga kali. Lalu aku katakan: \"Mintalah kepada Allah agar melapangkan dunia buat ummat anda karena bangsa Persia dan Ramawi saja dilapangkan dan diberikan dunia padahal mereka tidak menyembah Allah\". Saat itu Beliau sedang berbaring lalu berkata: \"Apakah kamu ragu wahai Ibnu Al Khaththob? Mereka itulah kaum yang telah disegerakan kebaikan mereka dalam kehidupan dunia ini\". Aku katakan: \"Wahai Rasulullah, mohonkanlah ampun buatku\". Ternyata disebabkan kalimatku seperti tadilah Rasulullah shallallahu 'alaihi wasallam mengasingkan diri ketika Hafshah menyampaikannya kepada 'Aisyah radliallahu 'anha. Sebelumnya Beliau telah berkata: Aku tidak akan tinggal bersama mereka selama satu bulan karena disebabkan kesalnya Beliau terhadap mereka setelah Allah menegur Beliau. Ketika telah berlalu masa selama dua puluh sembilan hari, yang pertama kali Beliau datangi adalah 'Aisyah. Maka 'Aisyah berkata, kepada Beliau: \"Anda sudah bersumpah untuk tidak mendatangi kami selama satu bulan, sedangkan hari ini kita baru melewati malam kedua puluh sembilan, aku sudah menghitungnya\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Bulan ini berjumlah dua puluh sembilan hari\". Pada bulan itu memang berjumlah dua puluh sembilan hari. Kemudian 'Aisyah radliallahu 'anha berkata: \"Maka turunlah ayat takhyiir (pilihan). Maka Beliau memulainya dari aku sebagai yang pertama dari isteri-isteri Beliau. Beliau berkata: \"Sesungguhnya aku mengingatkan kamu pada suatu urusan yaitu janganlah kamu tergesa-gesa hingga kamu meminta pendapat kedua orangtuamu\". 'Aisyah radliallahu 'anha berkata: \"Aku sudah mengetahui bahwa kedua orangtuaku tidaklah menyuruh aku untuk bercerai dari anda\" Kemudian Beliau berkata: \"Sesungguhnya Allah telah berfirman: (\"Wahai Nabi, katakanlah kepada isteri-isterimu … hingga sampai pada firmanNya … pahala yang besar) QS Al Ahzab: 28 -29). Aisyah radliallahu 'anha berkata: \"Apakah begitu kedua orangtuaku memerintahkannya? Sungguh aku lebih memilih Allah, RasulNya dan kehidupan akhirat\". Kemudian para isteri Beliau memilih hal yang sama lalu mereka berkata, seperti yang diucapkan 'Aisyah radliallahu 'anha."},"2289":{"ar":"حَدَّثَنَا ابْنُ سَلَامٍ حَدَّثَنَا الْفَزَارِيُّ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَآلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نِسَائِهِ شَهْرًا وَكَانَتْ انْفَكَّتْ قَدَمُهُ فَجَلَسَ فِي عُلِّيَّةٍ لَهُ فَجَاءَ عُمَرُ فَقَالَ أَطَلَّقْتَ نِسَاءَكَ قَالَ لَا وَلَكِنِّي آلَيْتُ مِنْهُنَّ شَهْرًا فَمَكَثَ تِسْعًا وَعِشْرِينَ ثُمَّ نَزَلَ فَدَخَلَ عَلَى نِسَائِهِ","id":"Telah menceritakan kepada kami [Ibnu Salam] telah menceritakan kepada kami [Al Fazariy] dari [Humaid Ath Thawil] dari [Anas radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam meninggalkan isteri-isteri Beliau selama satu bulan dan melepaskan kedua kaki Beliau (tidak turun) lalu tinggal di ruangan khusu Beliau (tempat pengasingan). Lalu datang 'Umar seraya berkata: \"Apakah anda telah menceraikan isteri-isri anda?\" Beliau menjawab: \"Tidak, tetapi aku berpaling dari mereka selama satu bulan\". Beliau berdiam disana selama dua puluh sembilah hari kemudian turun dan menemui isteri-isteri Beliau."},"2290":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا أَبُو عَقِيلٍ حَدَّثَنَا أَبُو الْمُتَوَكِّلِ النَّاجِيُّ قَالَ أَتَيْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْجِدَ فَدَخَلْتُ إِلَيْهِ وَعَقَلْتُ الْجَمَلَ فِي نَاحِيَةِ الْبَلَاطِ فَقُلْتُ هَذَا جَمَلُكَ فَخَرَجَ فَجَعَلَ يُطِيفُ بِالْجَمَلِ قَالَ الثَّمَنُ وَالْجَمَلُ لَكَ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Abu 'Aqil] telah menceritakan kepada kami [Abu Al Mutawakkil An-Najiy] berkata; Aku menemui [Jabir bin 'Abdullah radliallahu 'anhuma] yang berkata: \"Nabi shallallahu 'alaihi wasallam memasuki masjid lalu aku ikut masuk menemui Beliau sementara unta aku ikat pada batu di depan masjid lalu aku katakan: \"Ini unta anda\". Maka Beliau keluar lalu mendekati unta kemudian bersabda: 'Unta dan uang jualnya buat kamu\". "},"2291":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُ قَالَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ لَقَدْ أَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dari [Syu'bah] dari [Manshur] dari [Abu Wa'il] dari [Hudzaifah radliallahu 'anhu] berkata: \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam \" atau katanya \"Sungguh aku pernah melihat Nabi shallallahu 'alaihi wasallam kencing di tempat pembuangan kotoran sambil berdiri\"."},"2292":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَجُلٌ يَمْشِي بِطَرِيقٍ وَجَدَ غُصْنَ شَوْكٍ عَلَى الطَّرِيقِ فَأَخَذَهُ فَشَكَرَ اللَّهُ لَهُ فَغَفَرَ لَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada seorang laki-laki yang sedang berjalan lalu menemuklan potongan duri di jalan lalu diambilnya. Kemudian dia bersyukur kepada Allah maka Allah mengampuninya\". "},"2293":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ الزُّبَيْرِ بْنِ خِرِّيتٍ عَنْ عِكْرِمَةَ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَشَاجَرُوا فِي الطَّرِيقِ بِسَبْعَةِ أَذْرُعٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Jarir bin Hazim] dari [Az Zubair bin Khirrit] dari ['Ikrimah] aku mendengar [Abu Hurairah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam telah menetapkan jika kalian berselisih tentang jalan supaya membaginya sepanjang tujuh hasta\"."},"2294":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَدِيُّ بْنُ ثَابِتٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ الْأَنْصَارِيَّ وَهُوَ جَدُّهُ أَبُو أُمِّهِ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النُّهْبَى وَالْمُثْلَةِ","id":"Telah menceritakan kepada kami [Adam bin Abi Iyas] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Adiy bin Tsabit] aku mendengar ['Abdullah bin Yazid AL Anshariy] dan 'Abdullah ini adalah kakeknya 'Adiy dari pihak ibunya, berkata: \"Nabi shallallahu 'alaihi wasallam telah melarang merampas harta orang dan membuat gambar\"."},"2295":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ حَدَّثَنَا عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُ وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَنْتَهِبُ نُهْبَةً يَرْفَعُ النَّاسُ إِلَيْهِ فِيهَا أَبْصَارَهُمْ حِينَ يَنْتَهِبُهَا وَهُوَ مُؤْمِنٌوَعَنْ سَعِيدٍ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا النُّهْبَةَ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, telah menceritakan kepadaku [Al Laits] telah menceritakan kepada kami ['Uqail] dari [Ibnu Syihab] dari [Abu Bakar bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang pezina tidak sempurna imannya ketika sedang berzina, dan seorang peminum khamar tidak sempurna imannya ketika sedang minum-minum dan seorang pencuri idak sempurna imannya ketika sedang mencuri dan seorang yang merampas hak orang agar pandangan manusia tertuju kepadanya tidak sempurna imannya ketika dia merampasnya\". Dan dari [Sa'id] dan [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini juga kecuali tentang An-Nublah (merampas hak orang)."},"2296":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَنْزِلَ فِيكُمْ ابْنُ مَرْيَمَ حَكَمًا مُقْسِطًا فَيَكْسِرَ الصَّلِيبَ وَيَقْتُلَ الْخِنْزِيرَ وَيَضَعَ الْجِزْيَةَ وَيَفِيضَ الْمَالُ حَتَّى لَا يَقْبَلَهُ أَحَدٌ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhriy] berkata, telah menceritakan kepadaku [Sa'id bin Al Musayyab] dia mendengar [Abu Hurairah radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan terjadi qiyamat hingga Isa bin Maryam turun sebagai hakim yang adil yang dia menghancurkan salib, membunuh babi, membebaskan jizyah dan harta melimpa ruah sampai tidak ada seorang pun yang mau menerimanya\"."},"2297":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نِيرَانًا تُوقَدُ يَوْمَ خَيْبَرَ قَالَ عَلَى مَا تُوقَدُ هَذِهِ النِّيرَانُ قَالُوا عَلَى الْحُمُرِ الْإِنْسِيَّةِ قَالَ اكْسِرُوهَا وَأَهْرِقُوهَا قَالُوا أَلَا نُهَرِيقُهَا وَنَغْسِلُهَا قَالَ اغْسِلُواقَالَ أَبُو عَبْد اللَّهِ كَانَ ابْنُ أَبِي أُوَيْسٍ يَقُولُ الْحُمُرِ الْأَنْسِيَّةِ بِنَصْبِ الْأَلِفِ وَالنُّونِ","id":"Telah menceritakan kepada kami [Abu 'Ashim Adh-Dhohhak bin Makhlad] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa' radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam melihat api yang dinyalakan pada perang Khaibar. Beliau bertanya: \"Untuk apa api itu dinyalakan?\" Mereka menjawab: \"Untuk daging keledai piaraan manusia\". Beliau berkata: \"Hancurkan dan bakarlah\". Mereka bertanya: \"Apakah kita bakar lalu kita cuci (bersihkan)?\" Beliau berkata: \"Bersihkanlah\". Berkata, Abu 'Abdullah Al Bukhariy: Ibnu Abu Uwais berkata, Al Humur Al Insiyah dengan huruf alif dan nun manshub. "},"2298":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَحَوْلَ الْكَعْبَةِ ثَلَاثُ مِائَةٍ وَسِتُّونَ نُصُبًا فَجَعَلَ يَطْعُنُهَا بِعُودٍ فِي يَدِهِ وَجَعَلَ يَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ }الْآيَةَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnu Abi Najih] dari [Mujahid] dari [Abu Ma'mar] dari ['Abdullah bin Mas'ud radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam masuk ke Ka'bah saat yang ketika itu berisi tiga ratus enam puluh patung, lalu Beliau menusuk dan menghancurkannya dengan menggunakan tongkat yang ada di tangan Beliau seraya berkata: \"Telah datang kebenaran dan sirnalah kebathilan\", QS Al Isra' ayat 81."},"2299":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا كَانَتْ اتَّخَذَتْ عَلَى سَهْوَةٍ لَهَا سِتْرًا فِيهِ تَمَاثِيلُ فَهَتَكَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاتَّخَذَتْ مِنْهُ نُمْرُقَتَيْنِ فَكَانَتَا فِي الْبَيْتِ يَجْلِسُ عَلَيْهِمَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Anas bin 'Iyadh] dari ['Ubaidullah bin 'Umar] dari ['Abdurrahman bin Al Qasim] dari [bapaknya, Al Qasim] dari ['Aisyah radliallahu 'anha] bahwa dia tanpa sengaja memiliki tabir yang padanya ada gambar. Maka Nabi shallallahu 'alaihi wasallam merobeknya. Kemudian dia ('Aisyah) mengambil dan membuatnya menjadi dua bantal yang dipakai dirumah sebagai alas duduk Beliau. "},"2300":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي أَبُو الْأَسْوَدِ عَنْ عِكْرِمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id, dia adalah anak dari Abu Ayyub] berkata, telah menceritakan kepadaku [Abu Al Aswad] dari ['Ikrimah] dari ['Abdullah bin 'Amru radliallahu 'anhuma] berkata, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang terbunuh karena membela hartanya maka dia syahid\"."},"2301":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَ بَعْضِ نِسَائِهِ فَأَرْسَلَتْ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ مَعَ خَادِمٍ بِقَصْعَةٍ فِيهَا طَعَامٌ فَضَرَبَتْ بِيَدِهَا فَكَسَرَتْ الْقَصْعَةَ فَضَمَّهَا وَجَعَلَ فِيهَا الطَّعَامَ وَقَالَ كُلُوا وَحَبَسَ الرَّسُولَ وَالْقَصْعَةَ حَتَّى فَرَغُوا فَدَفَعَ الْقَصْعَةَ الصَّحِيحَةَ وَحَبَسَ الْمَكْسُورَةَوَقَالَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا حُمَيْدٌ حَدَّثَنَا أَنَسٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Humaid] dari [Anas radliallahu 'anhu] bahwa ketika Nabi shallallahu 'alaihi wasallam sedang bersama sebagian isteri-isteri Beliau datang salah seorang Ummahatul Mu'minin bersama seorang pembantu membawa nampan besar berisi makanan lalu nampan itu dipukul oleh saorang isteri Beliau tersebut hingga pecah. Maka Beliau membereskan nampan pecah tersebut lalu meletakkan kembali makanan tersebut kedalam nampan kemudian berkata: \"Makanlah\". Lalu Beliau membiarkan pembantu dan nampan itu hingga mereka selesai makan kemudian datng mengganti nampan dengan nampan yang baru lalu membawa masuk nampan yang pecah\". Dan [Ibnu Abi Maryam] berkata, telah mengabarkan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Humaid] telah menceritakan kepada kami [Anas] dari Nabi shallallahu 'alaihi wasallam. "},"2302":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ رَجُلٌ فِي بَنِي إِسْرَائِيلَ يُقَالُ لَهُ جُرَيْجٌ يُصَلِّي فَجَاءَتْهُ أُمُّهُ فَدَعَتْهُ فَأَبَى أَنْ يُجِيبَهَا فَقَالَ أُجِيبُهَا أَوْ أُصَلِّي ثُمَّ أَتَتْهُ فَقَالَتْ اللَّهُمَّ لَا تُمِتْهُ حَتَّى تُرِيَهُ وُجُوهَ الْمُومِسَاتِ وَكَانَ جُرَيْجٌ فِي صَوْمَعَتِهِ فَقَالَتْ امْرَأَةٌ لَأَفْتِنَنَّ جُرَيْجًا فَتَعَرَّضَتْ لَهُ فَكَلَّمَتْهُ فَأَبَى فَأَتَتْ رَاعِيًا فَأَمْكَنَتْهُ مِنْ نَفْسِهَا فَوَلَدَتْ غُلَامًا فَقَالَتْ هُوَ مِنْ جُرَيْجٍ فَأَتَوْهُ وَكَسَرُوا صَوْمَعَتَهُ فَأَنْزَلُوهُ وَسَبُّوهُ فَتَوَضَّأَ وَصَلَّى ثُمَّ أَتَى الْغُلَامَ فَقَالَ مَنْ أَبُوكَ يَا غُلَامُ قَالَ الرَّاعِي قَالُوا نَبْنِي صَوْمَعَتَكَ مِنْ ذَهَبٍ قَالَ لَا إِلَّا مِنْ طِينٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Jarir bin HAzim] dari [Muhammad bin Sirin] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada seorang laki-laki Bani Isra'il, yang dipanggil dengan nama Juraij, sedang melaksanakan shalat lalu ibunya datang memanggilnya, namun laki-laki itu enggan menjawabnya. Dia berkata: \"Apakah aku penuhi panggilannya atau aku teruskan shalat?\". Akhirnya ibunya itu mendekatinya seraya berkata: \"Ya Allah, janganlah Engkau matikan dia kecuali setelah dia memperoleh ujian\". Suatu hari Juraij sedang berada di biaranya lalu ada seorang wanita berkata,: \"Aku akan goda si Juraij\". Lalu wanita ini menawarkan dirinya tapi Juraij menolakmya. Kemudian wanita ini mendatangi seorang pengembala lalu wanita ini tinggal bersamanya hingga melahirkan seorang bayi. Lalu wanita itu berkata: \"Ini anaknya Juraij\". Maka orang-orang mendatangi Juraij dan menghancurkan biaranya dan memaksanya keluar lalu memaki-makinya. Juraij berwudhu' lalu shalat. Kemudian dia mendatangi bayi lalu bertanya: \"Siapakah bapakmu wahai anak?\". Bayi itu menjawab: \"Seorang pengembala\". Orang-orang berkata: \"Kami akan bangun biaramu terbuat dari emas\". Juraij berkata: \"Tidak, dari tanah saja\". "},"2303":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْثًا قِبَلَ السَّاحِلِ فَأَمَّرَ عَلَيْهِمْ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ وَهُمْ ثَلَاثُ مِائَةٍ وَأَنَا فِيهِمْ فَخَرَجْنَا حَتَّى إِذَا كُنَّا بِبَعْضِ الطَّرِيقِ فَنِيَ الزَّادُ فَأَمَرَ أَبُو عُبَيْدَةَ بِأَزْوَادِ ذَلِكَ الْجَيْشِ فَجُمِعَ ذَلِكَ كُلُّهُ فَكَانَ مِزْوَدَيْ تَمْرٍ فَكَانَ يُقَوِّتُنَا كُلَّ يَوْمٍ قَلِيلًا قَلِيلًا حَتَّى فَنِيَ فَلَمْ يَكُنْ يُصِيبُنَا إِلَّا تَمْرَةٌ تَمْرَةٌ فَقُلْتُ وَمَا تُغْنِي تَمْرَةٌ فَقَالَ لَقَدْ وَجَدْنَا فَقْدَهَا حِينَ فَنِيَتْ قَالَ ثُمَّ انْتَهَيْنَا إِلَى الْبَحْرِ فَإِذَا حُوتٌ مِثْلُ الظَّرِبِ فَأَكَلَ مِنْهُ ذَلِكَ الْجَيْشُ ثَمَانِيَ عَشْرَةَ لَيْلَةً ثُمَّ أَمَرَ أَبُو عُبَيْدَةَ بِضِلَعَيْنِ مِنْ أَضْلَاعِهِ فَنُصِبَا ثُمَّ أَمَرَ بِرَاحِلَةٍ فَرُحِلَتْ ثُمَّ مَرَّتْ تَحْتَهُمَا فَلَمْ تُصِبْهُمَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Wahb bin Kaisan] dari [Jabir bin 'Abdullah radliallahu 'anhuma] bahwa dia berkata; Rasulullah shallallahu 'alaihi wasallam mengutus pasukan menuju pantai dengan menunjuk Abu 'Ubaidah sebagai pemimpin mereka yang berjumlah tiga ratus orang dan aku termasuk dalam pasukan itu. Maka kami keluar hingga ketika kami sampai di tengah perjalanan bekal kami habis. Maka Abu 'Ubaidah memerintahkan agar semua anggota pasukan mengumpulkan bekal yang masih tersisa dan akhirnya terkumpul kurma dalam kantong yang bisa menguatkan kami, setiap hari kami makan sedikit sedikit sampai kurma itu habis dan tidak tersisa kecuali masing-masing kami dapat satu butir satu butir. Aku (Wahbbin Kaisan) bertanya: \"Apakah satu butir kurma mencukupi?\". Dia (Jabir bin 'Abdullah) berkata: \"Kami dapatkan penggantinya ketika sudah habis\". Jabir berkata: \"Kemudian kami sampai di laut, kami mendapatkan seekor ikan hiu sebesar bukit. Akhirnya pasukan memakan ikan hiu tersebut selama delapan belas malam lalu Abu 'Ubaidah memerintahkan untuk mengambil dua tulang rusuk ikan hiu tersebut lalu memerintahkan salah seorang dari pasukan berjalan di bawahnya maka orang itu dapat melaluinya dengan tanpa mengenainya (karena besarnya ikan hiu tersebut). "},"2304":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مَرْحُومٍ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ رَضِيَ اللَّهُ عَنْهُ قَالَخَفَّتْ أَزْوَادُ الْقَوْمِ وَأَمْلَقُوا فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَحْرِ إِبِلِهِمْ فَأَذِنَ لَهُمْ فَلَقِيَهُمْ عُمَرُ فَأَخْبَرُوهُ فَقَالَ مَا بَقَاؤُكُمْ بَعْدَ إِبِلِكُمْ فَدَخَلَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا بَقَاؤُهُمْ بَعْدَ إِبِلِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ��َادِ فِي النَّاسِ فَيَأْتُونَ بِفَضْلِ أَزْوَادِهِمْ فَبُسِطَ لِذَلِكَ نِطَعٌ وَجَعَلُوهُ عَلَى النِّطَعِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا وَبَرَّكَ عَلَيْهِ ثُمَّ دَعَاهُمْ بِأَوْعِيَتِهِمْ فَاحْتَثَى النَّاسُ حَتَّى فَرَغُوا ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami [Bisyir bin Marhum] telah menceritakan kepada kami [Hatim bin Isma'il] dari [YAzid bin Abu 'Ubaid] dari [Salamah radliallahu 'anhu] berkata: \"Perbekalan kaum menipis dan mereka kekurangan air dan makanan, lalu mereka mendatangi Nabi shallallahu 'alaihi wasallam meminta ijin untuk menyembelih unta mereka, Beliau pun mengijinkannya. Lalu 'Umar datang menemui mereka dan mereka mengabari hal itu padanya, lalu ia berkata; \"Apakah kalian akan dapat hidup setelah unta kalian habis, ia pun menemui Nabi shallallahu 'alaihi wasallam lalu berkata: \"Wahai Rasulullah, apakah mereka dapat bertahan hidup setelah mereka menyembelih unta mereka?\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Panggillah orang-orang agar mereka membawa sisa-sisa bekal mereka kemari\". Maka dihamparkan lembaran kulit lalu bekal bekal mereka diletakkan diatasnya. Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri dan berdo'a serta memohon berkah untuknya, lalu Beliau perintahkan mereka membawa bejana mereka masing-masing. Maka orang-orang pun mengambil bagiannya hingga mereka mendapatkan semua, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku bersaksi bahwa tidak ada Ilah yang berhak disembah kecuali Allah dan aku adalah Rasululloh\"."},"2305":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا أَبُو النَّجَاشِيِّ قَالَ سَمِعْتُ رَافِعَ بْنَ خَدِيجٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ فَنَنْحَرُ جَزُورًا فَتُقْسَمُ عَشْرَ قِسَمٍ فَنَأْكُلُ لَحْمًا نَضِيجًا قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Muhammad boin Yusuf] telah menceritakan kepada kami [Al Awza'iy] telah menceritakan kepada kami [Abu An-Najasyiy] berkata, aku mendengar [Rafi' bin Khadij radliallahu 'anhu] berkata: \"Kami shalat 'Ashar bersama Nabi shallallahu 'alaihi wasallam lalu kami menyembelih seekor hewan sembelihan lalu dibagi menjadi sepuluh bagian kemudian kami makan daging yang dimasak sebelum terbenam matahari\". "},"2306":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا حَمَّادُ بْنُ أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْأَشْعَرِيِّينَ إِذَا أَرْمَلُوا فِي الْغَزْوِ أَوْ قَلَّ طَعَامُ عِيَالِهِمْ بِالْمَدِينَةِ جَمَعُوا مَا كَانَ عِنْدَهُمْ فِي ثَوْبٍ وَاحِدٍ ثُمَّ اقْتَسَمُوهُ بَيْنَهُمْ فِي إِنَاءٍ وَاحِدٍ بِالسَّوِيَّةِ فَهُمْ مِنِّي وَأَنَا مِنْهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Alaa'] telah menceritakan kepada kami [Hammad bin Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang-orang Asya'ariy jika mereka berperang atau harta kebutuhan keluarga mereka di Madinah menipis maka mereka mengumpulkan apa saja milik mereka pada satu kain lalu mereka membagi rata diantara mereka pada tiap masing-masing, maka mereka adalah bagian dariku dan aku adalah bagian dari mereka\"."},"2307":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُثَنَّى قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي ثُمَامَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَنَسٍ أَنَّ أَنَسًا حَدَّثَهُأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ كَتَبَ لَهُ فَرِيضَةَ الصَّدَقَةِ الَّتِي فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَمَا كَانَ مِنْ خَلِيطَيْنِ فَإِنَّهُمَا يَتَرَاجَعَانِ بَيْنَهُمَا بِالسَّوِيَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Al Mutsannaa] berkata, telah menceritakan kepadaku [bapakku] berkata, telah menceritakan kepadaku [Tsumamah bin 'Abdullah bin Anas] bahwa [Anas] menceritakan kepadanya bahwa Abu Bakar radliallahu 'anhu menetapkan kewajiban shadaqah kepadanya sebagaimana Rasulullah shallallahu 'alaihi wasallam telah mewajibkannya. Dia berkata: \"Dan dua orang yang telah bercampur (hewan ternak keduanya) hendaklah keduanya berdamai dengan menanggung beban yang sama\"."},"2308":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحَكَمِ الْأَنْصَارِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعِ بْنِ خَدِيجٍ عَنْ جَدِّهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي الْحُلَيْفَةِ فَأَصَابَ النَّاسَ جُوعٌ فَأَصَابُوا إِبِلًا وَغَنَمًا قَالَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُخْرَيَاتِ الْقَوْمِ فَعَجِلُوا وَذَبَحُوا وَنَصَبُوا الْقُدُورَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقُدُورِ فَأُكْفِئَتْ ثُمَّ قَسَمَ فَعَدَلَ عَشَرَةً مِنْ الْغَنَمِ بِبَعِيرٍ فَنَدَّ مِنْهَا بَعِيرٌ فَطَلَبُوهُ فَأَعْيَاهُمْ وَكَانَ فِي الْقَوْمِ خَيْلٌ يَسِيرَةٌ فَأَهْوَى رَجُلٌ مِنْهُمْ بِسَهْمٍ فَحَبَسَهُ اللَّهُ ثُمَّ قَالَ إِنَّ لِهَذِهِ الْبَهَائِمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا فَقَالَ جَدِّي إِنَّا نَرْجُو أَوْ نَخَافُ الْعَدُوَّ غَدًا وَلَيْسَتْ مَعَنَا مُدًى أَفَنَذْبَحُ بِالْقَصَبِ قَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَلَيْهِ فَكُلُوهُ لَيْسَ السِّنَّ وَالظُّفُرَ وَسَأُحَدِّثُكُمْ عَنْ ذَلِكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ","id":"Telah menceritakan kepada kami ['Ali bin Al Hakam Al Anshariy] telah menceritakan kepada kami [Abu 'Awanah] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah bin Rafi' bin Khadij] dari [kakeknya] berkata; \"Kami bersama Nabi shallallahu 'alaihi wasallam di Dzul Hulaifah ketika sebagian orang terserang lapar lalu mereka mendapatkan (harta rampasan perang berupa) unta dan kambing. Saat itu Nabi shallallahu 'alaihi wasallam berada di belakang bersama rombongan yang lain. Orang-orang yang lapar itu segera saja menyembelih lalu mendapatkan daging sebanyak satu kuali. Maka Nabi shallallahu 'alaihi wasallam memerintahkan agar kuali tersebut ditumpahkan isinya. Kemudian Beliau membagi rata dimana bagian setiap sepuluh kambing sama dengan satu ekor unta. Namun ada seekor unta yang lari lalu mereka mencarinya hingga kelelahan. Sementara itu diantara mereka ada yang memiliki seekor kuda yang lincah lalu ia mencari unta tadi dan memburunya dengan panah hingga akhirnya Allah menakdirkannya dapat membunuh unta tersebut. Beliau bersabda: \"Sesungguhnya bintang seperti ini hukumnya sama dengan binatang liar. Maka apa saja yang kabur dari kalian (lalu didapatkannya,) perlakuklanlah seperti ini\". Kakekku berkata: \"Kita berharap atau khawatir bertemu musuh esok hari sedangkan kita tidak punya pisau, apakah kita boleh menyembelih dengan kayu?\". Beliau berkata: \"Setiap yang ditumpahkan darahnya dengan disebut nama Allah maka makanlah kecuali gigi dan kukunya, dan aku akan sampaikan tentang itu. Adapun gigi dia termasuk tulang sedangkan kuku merupakan pisaunya orang-orang Habsasyah\"."},"2309":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنَا جَبَلَةُ بْنُ سُحَيْمٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقْرُنَ الرَّجُلُ بَيْنَ التَّمْرَتَيْنِ جَمِيعًا حَتَّى يَسْتَأْذِنَ أَصْحَابَهُ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Jabalah bin Suhaim] berkata, aku mendengar [Ibnu 'Umar radliallahu 'anhuma] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang memakan dua butir kurma sekaligus sebelum dia meminta izin sahabat-sahabatnya (yang sedang makan bersama) \"."},"2310":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ جَبَلَةَ قَالَ كُنَّا بِالْمَدِينَةِ فَأَصَابَتْنَا سَنَةٌ فَكَانَ ابْنُ الزُّبَيْرِ يَرْزُقُنَا التَّمْرَ وَكَانَ ابْنُ عُمَرَيَمُرُّ بِنَا فَيَقُولُ لَا تَقْرُنُوا فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْإِقْرَانِ إِلَّا أَنْ يَسْتَأْذِنَ الرَّجُلُ مِنْكُمْ أَخَاهُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Jabalah] berkata; Ketika di Madinah saat kami tertimpa paceklik, Ibnu Az Zubair adalah orang yang memberi makan kami. Suatu saat [Ibnu 'Umar] lewat di hadapan kami, maka dia berkata: \"Janganlah kalian makan dua butir secara sekaligus, karena Nabi shallallahu 'alaihi wasallam telah melarang memakan dua butir kurma sekaligus kecuali bila seorang dari kalian meminta izin saudaranya terlebih dahulu\"."},"2311":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ شِقْصًا لَهُ مِنْ عَبْدٍ أَوْ شِرْكًا أَوْ قَالَ نَصِيبًا وَكَانَ لَهُ مَا يَبْلُغُ ثَمَنَهُ بِقِيمَةِ الْعَدْلِ فَهُوَ عَتِيقٌ وَإِلَّا فَقَدْ عَتَقَ مِنْهُ مَا عَتَقَقَالَ لَا أَدْرِي قَوْلُهُ عَتَقَ مِنْهُ مَا عَتَقَ قَوْلٌ مِنْ نَافِعٍ أَوْ فِي الْحَدِيثِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Imran bin Maisarah] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang membebaskan jatah kepemilikan, atau bagian kepemilikan dari budaknya\" atau Beliau bersabda dengan redaksi 'hak kepemilikan', lantas ia mempunyai harta yang bisa membebaskan budak itu secara penuh sesuai harga yang rata-rata, maka budak itu menjadi merdeka\". (Ayyub) berkata: \"Aku tidak tahu apakah ucapan itu dari Nafi' atau termasuk hadits yang disabdakan Nabi shallallahu 'alaihi wasallam \". "},"2312":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ شَقِيصًا مِنْ مَمْلُوكِهِ فَعَلَيْهِ خَلَاصُهُ فِي مَالِهِ فَإِنْ لَمْ يَكُنْ لَهُ مَالٌ قُوِّمَ الْمَمْلُوكُ قِيمَةَ عَدْلٍ ثُمَّ اسْتُسْعِيَ غَيْرَ مَشْقُوقٍ عَلَيْهِ","id":"Telah menceritakan kepada kami [Bisyir bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Sa'id bin Abi 'Urwah] dari [Qatadah] dari [An-Nadhar bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membebaskan hak kepemilikan budaknya, maka dia masih berkewajiban membebaskan budak tersebut secara penuh. Bila dia tidak memiliki harta, maka budak itu ditaksir harganya secara normal, lantas budak diusahakan untuk dibebaskan secara penuh dengan tanpa membebani dia saja. "},"2313":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ قَالَ سَمِعْتُ عَامِرًا يَقُولُ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْقَائِمِ عَلَى حُدُودِ اللَّهِ وَالْوَاقِعِ فِيهَا كَمَثَلِ قَوْمٍ اسْتَهَمُوا عَلَى سَفِينَةٍ فَأَصَابَ بَعْضُهُمْ أَعْلَاهَا وَبَعْضُهُمْ أَسْفَلَهَا فَكَانَ الَّذِينَ فِي أَسْفَلِهَا إِذَا اسْتَقَوْا مِنْ الْمَاءِ مَرُّوا عَلَى مَنْ فَوْقَهُمْ فَقَالُوا لَوْ أَنَّا خَرَقْنَا فِي نَصِيبِنَا خَرْقًا وَلَمْ نُؤْذِ مَنْ فَوْقَنَا فَإِنْ يَتْرُكُوهُمْ وَمَا أَرَادُوا هَلَكُوا جَمِيعًا وَإِنْ أَخَذُوا عَلَى أَيْدِيهِمْ نَجَوْا وَنَجَوْا جَمِيعًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariyya'] berkata, aku mendengar ['Amir] berkata, aku mendengar [An-Nu'man bin Basyir radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang yang menegakkan hukum Allah dan orang yang diam terhadapnya seperti sekelompok orang yang berlayar dengan sebuah kapal lalu sebagian dari mereka ada yang mendapat tempat di atas dan sebagian lagi di bagian bawah perahu. Lalu orang yang berada di bawah perahu bila mereka mencari air untuk minum mereka harus melewati orang-orang yang berada di bagian atas seraya berkata; \"Seandainya boleh kami lubangi saja perahu ini untuk mendapatkan bagian kami sehingga kami tidak mengganggu orang yang berada di atas kami\". Bila orang yang berada di atas membiarkan saja apa yang diinginkan orang-orang yang di bawah itu maka mereka akan binasa semuanya. Namun bila mereka mencegah dengan tangan mereka maka mereka akan selamat semuanya\". "},"2314":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْعَامِرِيُّ الْأُوَيْسِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّهُسَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ قَوْلِ اللَّهِ تَعَالَى{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا إِلَى وَرُبَاعَ }فَقَالَتْ يَا ابْنَ أُخْتِي هِيَ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا تُشَارِكُهُ فِي مَالِهِ فَيُعْجِبُهُ مَالُهَا وَجَمَالُهَا فَيُرِيدُ وَلِيُّهَا أَنْ يَتَزَوَّجَهَا بِغَيْرِ أَنْ يُقْسِطَ فِي صَدَاقِهَا فَيُعْطِيهَا مِثْلَ مَا يُعْطِيهَا غَيْرُهُ فَنُهُوا أَنْ يُنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ وَيَبْلُغُوا بِهِنَّ أَعْلَى سُنَّتِهِنَّ مِنْ الصَّدَاقِ وَأُمِرُوا أَنْ يَنْكِحُوا مَا طَابَ لَهُمْ مِنْ النِّسَاءِ سِوَاهُنَّ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ ثُمَّ إِنَّ النَّاسَ اسْتَفْتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذِهِ الْآيَةِ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ إِلَى قَوْلِهِ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }وَالَّذِي ذَكَرَ اللَّهُ أَنَّهُ يُتْلَى عَلَيْكُمْ فِي الْكِتَابِ الْآيَةُ الْأُولَى الَّتِي قَالَ فِيهَا{ وَإِنْ خِفْتُمْ أَنْ لَا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ عَائِشَةُ وَقَوْلُ اللَّهِ فِي الْآيَةِ الْأُخْرَى{ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }يَعْنِي هِيَ رَغْبَةُ أَحَدِكُمْ لِيَتِيمَتِهِ الَّتِي تَكُونُ فِي حَجْرِهِ حِينَ تَكُونُ قَلِيلَةَ الْمَالِ وَالْجَمَالِ فَنُهُوا أَنْ يَنْكِحُوا مَا رَغِبُوا فِي مَالِهَا وَجَمَالِهَا مِنْ يَتَامَى النِّسَاءِ إِلَّا بِالْقِسْطِ مِنْ أَجْلِ رَغْبَتِهِمْ عَنْهُنَّ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah Al 'Amiriy Al Uwaisiy] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] telah menceritakan kepadaku ['Urwah] bahwa dia bertanya kepada ['Aisyah radliallahu 'anha]. Dan [Al Laits] berkata, telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] be telah menceritakan kapadaku ['Urwah bin Az Zubair] bahwa dia bertanya kepada ['Aisyah radliallahu 'anha] tentang firman Allah yang artinya: (\"Jika kamu khawatir tidak dapat berlaku adil …. seterusnya hingga …empat-empat\". (QS. An-Nisaa ayat 3), maka ia menjawab: \"Wahai anak saudariku, yang dimaksud ayat itu adalah seorang anak perempuan yatim yang berada pada asuhan walinya, hartanya ada pada walinya, dan walinya ingin memiliki harta itu dan menikahinya namun ia tidak bisa berbuat adil dalam memberikan maharnya, yaitu memberi seperti ia memberikan untuk yang lainnya, maka mereka dilarang untuk menikahinya kecuali jika mereka bisa berbuat adil pada mereka, dan mereka memberikan mahar terbaik kepadanya, mereka diperintahkan untuk menikahi wanita-wanita yang baik untuk mereka selain anak-anak yatim itu\". 'Urwah berkata, lalu 'Aisyah berkata, kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah turunnya ayat ini; wayastaftuunaka finnisaa' (dan mereka meminta fatwa kepadamu tentang para wanita) hingga firmanNya; watarghobuuna antankihuuhunna (dan kalian ingin menikahi mereka) dan yang disebutkan Allah pada firmanNya bahwa; yutla 'alaikum fil kitab (telah disebutkan untuk kalian di dalam Al Quran) ayat pertama yang Allah berfirman didalamnya ada kalimat; wa in khiftum allaa tuqsituu fil yataamaa fankihuu maa thaoba lakum minan nisaa' (jika kalian tidak bisa berbuat adil kepada anak-anak yatim, maka nikahilah wanita-wanita yang baik untuk kalian), 'Aisyah berkata, dan firman Allah pada ayat yang lain; watarghobuuna an tankihuuhunna (dan kalian ingin untuk menikahi mereka) yaitu keinginan kalian untuk menikahi anak perempuan yatim yang kalian asuh ketika ia sedikit hartanya dan kurang menarik wajahya, maka mereka dilarang untuk menikahi mereka karena semata hartanya dan kecantikannya dari anak-anak perempuan yatim kecuali dengan adil disebabkan ketidak tertarikan mereka kepada perempuan yatim itu\"."},"2315":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَإِنَّمَا جَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشُّفْعَةَ فِي كُلِّ مَا لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَصُرِّفَتْ الطُّرُقُ فَلَا شُفْعَةَ","id":"Telah menceritakan kepada saya ['Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari [Abu Salamah] dari [Jabir bin 'Abdullah radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam telah menetapkan Asy-Syuf'ah pada setiap tanah yang belum dibagi. Apabila sudah terdapat batasan-batasan dan jalan yang terpisah maka tidak ada syuf'ah lagi\". "},"2316":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالشُّفْعَةِ فِي كُلِّ مَا لَمْ يُقْسَمْ فَإِذَا وَقَعَتْ الْحُدُودُ وَصُرِّفَتْ الطُّرُقُ فَلَا شُفْعَةَ","id":"Telah menceritakan kepada saya [Musaddad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhriy] dari [Abu Salamah] dari [Jabir bin 'Abdullah radliallahu 'anhuma]; Nabi shallallahu 'alaihi wasallam telah menetapkan Asy-Syuf'ah pada setiap tanah yang belum dibagi. Apabila sudah terdapat batasan-batasan dan jalan yang terpisah maka tidak ada syuf'ah lagi\". "},"2317":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عُثْمَانَ يَعْنِي ابْنَ الْأَسْوَدِ قَالَ أَخْبَرَنِي سُلَيْمَانُ بْنُ أَبِي مُسْلِمٍ قَالَ سَأَلْتُ أَبَا الْمِنْهَالِ عَنْ الصَّرْفِ يَدًا بِيَدٍ فَقَالَ اشْتَرَيْتُ أَنَا وَشَرِيكٌ لِي شَيْئًا يَدًا بِيَدٍ وَنَسِيئَةً فَجَاءَنَا الْبَرَاءُ بْنُ عَازِبٍفَسَأَلْنَاهُ فَقَالَ فَعَلْتُ أَنَا وَشَرِيكِي زَيْدُ بْنُ أَرْقَمَ وَسَأَلْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ مَا كَانَ يَدًا بِيَدٍ فَخُذُوهُ وَمَا كَانَ نَسِيئَةً فَذَرُوهُ","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] telah menceritakan kepada kami [Abu 'Ashim] dari ['Utsman, yakni Ibnu Al Aswad] berkata, telah menceritakan kepadaku [Sulaiman bin Abi Muslim] berkata, aku bertanya kepada [Al Minhal] tentang tentang pertukaran uang secara langsung. Maka dia berkata: \"Dahulu aku dan temanku membeli sesuatu secara langsung dan dengan tempo lalu datang kepada kami [Al Bara' bin 'Azib] lalu kami tanyakan kepadanya tentang masalah itu maka dia berkata: \"Dulu aku dan temanku Zaid bin Arqam pernah menanyakan hal itu kepada Nabi shallallahu 'alaihi wasallam maka Beliau bersabda: \"Jika transaksi langsung diatas tangan (pembayaran secara cash, kontan) ambillah, namun bila tunda (tempo) maka tinggalkanlah\"."},"2318":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَأَعْطَى رَسُولُ اللّ��هِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ الْيَهُودَ أَنْ يَعْمَلُوهَا وَيَزْرَعُوهَا وَلَهُمْ شَطْرُ مَا يَخْرُجُ مِنْهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah bin Asma'] dari [Nafi'] dari ['Abdullah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam memberikan tanah Khaibar kepada orang Yahudi agar dimanfaatkan dan dijadikan ladang pertanian dan mereka mendapat bagian dari separuh hasilnya. "},"2319":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ غَنَمًا يَقْسِمُهَا عَلَى صَحَابَتِهِ ضَحَايَا فَبَقِيَ عَتُودٌ فَذَكَرَهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِّ بِهِ أَنْتَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [YAzid bin Abi Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan kepadanya seekor kambing yang Beliau bagikan untuk para sahabat Beliau sebagai hewan qurban dan tersisa anak kambing yang sudah bisa berdiri sendiri. Kemudian diceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam maka Beliau bersabda: \"Ambillah buatmu\"."},"2320":{"ar":"حَدَّثَنَا أَصْبَغُ بْنُ الْفَرَجِ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي سَعِيدٌ عَنْ زُهْرَةَ بْنِ مَعْبَدٍ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ هِشَامٍ وَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَهَبَتْ بِهِ أُمُّهُ زَيْنَبُ بِنْتُ حُمَيْدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْيَا رَسُولَ اللَّهِ بَايِعْهُ فَقَالَ هُوَ صَغِيرٌ فَمَسَحَ رَأْسَهُ وَدَعَا لَهُ وَعَنْ زُهْرَةَ بْنِ مَعْبَدٍ أَنَّهُ كَانَ يَخْرُجُ بِهِ جَدُّهُ عَبْدُ اللَّهِ بْنُ هِشَامٍ إِلَى السُّوقِ فَيَشْتَرِي الطَّعَامَ فَيَلْقَاهُ ابْنُ عُمَرَ وَابْنُ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُمَا فَيَقُولَانِ لَهُ أَشْرِكْنَا فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ دَعَا لَكَ بِالْبَرَكَةِ فَيَشْرَكُهُمْ فَرُبَّمَا أَصَابَ الرَّاحِلَةَ كَمَا هِيَ فَيَبْعَثُ بِهَا إِلَى الْمَنْزِلِ","id":"Telah menceritakan kepada kami [Ashbagh bin Al Faraj] berkata, telah menceritakan kepadaku ['Abdullah bin Wahb] berkata, telah menceritakan kepadaku [Sa'id] dari [Zuhrah bin Ma'bad] dari [kakeknya, 'Abdullah bin Hisyam] dimana dia semasa hidupnya pernah bersama Nabi shallallahu 'alaihi wasallam. Suatu hari ibunya Zainab binti Humaid menemui Rasulullah shallallahu 'alaihi wasallam lalu berkata: \"Wahai Rasulullah, bai'atlah dia?\". Maka Beliau berkata: \"Dia masih kecil\". Lalu Beliau mengusap kepalanya serta mendo'akannya. Dan dari [Zuhrah bin Ma'bad] bahwa dia pernah pergi bersama kakeknya ['Abdullah bin Hisyam] ke pasar untuk membeli makanan lalu di sana dia bertemu dengan [Ibnu 'Umar] dan [Ibnu Az Zubair] radliallahu 'anhuma, lalu keduanya berkata kepadanya: \"Sertakanlah kami karena Nabi shallallahu 'alaihi wasallam telah mendo'akan keberkahan untukmu. Maka akhirnya dia menyertakan mereka. Apabila dia menempuh perjalanan dia diminta untuk singgah di tempat tinggal."},"2321":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ شِرْكًا لَهُ فِي مَمْلُوكٍ وَجَبَ عَلَيْهِ أَنْ يُعْتِقَ كُلَّهُ إِنْ كَانَ لَهُ مَالٌ قَدْرَ ثَمَنِهِ يُقَامُ قِيمَةَ عَدْلٍ وَيُعْطَى شُرَكَاؤُهُ حِصَّتَهُمْ وَيُخَلَّى سَبِيلُ الْمُعْتَقِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Juwairiyah bin Asma'] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membebaskan hak kepemilikan seorang budak, maka ia berkewajiban untuk membebaskan seluruhnya. Seandainya dia memiliki harta sebanyak harga budaknya, maka budaknya ditaksir dengan harga normal dan teman yang memiliki hak berserikat itu diberikan hak bagiannya dan budak dibebaskan\"."},"2322":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ شِقْصًا لَهُ فِي عَبْدٍ أُعْتِقَ كُلُّهُ إِنْ كَانَ لَهُ مَالٌ وَإِلَّا يُسْتَسْعَ غَيْرَ مَشْقُوقٍ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Jarir bin HAzim] dari [Qatadah] dari [An-Nadhar bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membebaskan bagiannya dari budak yang dimiliki secara berserikat, maka wajib baginya untuk membebaskan seluruhnya seandainya dia memiliki harta sebanyak harga budaknya, dan jika tidak, maka si budak wajib tetap berusaha untuk membebaskan sisa status kebudakannya dengan tidak menyusahkan orang yang telah memerdekkan sebagiannya.\""},"2323":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ وَعَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ قَالَاقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ صُبْحَ رَابِعَةٍ مِنْ ذِي الْحِجَّةِ مُهِلِّينَ بِالْحَجِّ لَا يَخْلِطُهُمْ شَيْءٌ فَلَمَّا قَدِمْنَا أَمَرَنَا فَجَعَلْنَاهَا عُمْرَةً وَأَنْ نَحِلَّ إِلَى نِسَائِنَا فَفَشَتْ فِي ذَلِكَ الْقَالَةُ قَالَ عَطَاءٌ فَقَالَ جَابِرٌ فَيَرُوحُ أَحَدُنَا إِلَى مِنًى وَذَكَرُهُ يَقْطُرُ مَنِيًّا فَقَالَ جَابِرٌ بِكَفِّهِ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ خَطِيبًا فَقَالَ بَلَغَنِي أَنَّ أَقْوَامًا يَقُولُونَ كَذَا وَكَذَا وَاللَّهِ لَأَنَا أَبَرُّ وَأَتْقَى لِلَّهِ مِنْهُمْ وَلَوْ أَنِّي اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا أَهْدَيْتُ وَلَوْلَا أَنَّ مَعِي الْهَدْيَ لأَحْلَلْتُ فَقَامَ سُرَاقَةُ بْنُ مَالِكِ بْنِ جُعْشُمٍ فَقَالَ يَا رَسُولَ اللَّهِ هِيَ لَنَا أَوْ لِلْأَبَدِ فَقَالَ لَا بَلْ لِلْأَبَدِ قَالَ وَجَاءَ عَلِيُّ بْنُ أَبِي طَالِبٍ فَقَالَ أَحَدُهُمَا يَقُولُ لَبَّيْكَ بِمَا أَهَلَّ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ وَقَالَ الْآخَرُ لَبَّيْكَ بِحَجَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقِيمَ عَلَى إِحْرَامِهِ وَأَشْرَكَهُ فِي الْهَدْيِ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] telah mengabarkan kepada kami ['Abdul Malik bin Juraij] dari ['Atha'] dari [Jabir] dan [Thowus] serta [Ibnu 'Abbas] radliallahu 'anhuma, keduanya berkata; Nabi shallallahu 'alaihi wasallam dan para shahabat Beliau berangkat pada waktu pagi tanggal empat belas Dzul Hijjah untuk melaksanakan hajji dan tidak ada sesuatupun yang menghalangi mereka. Ketika kami telah sampai, Beliau memerintahkan kami untuk menjadikannya sebagai niat 'umrah lalu kami boleh mencampuri isteri-isteri kami. Kemudian sabda Beliau tersebut tersebar. 'Atha' berkata; Maka Jabir berkata: \"Lalu ada seorang diantara kami yang pergi menuju Mina kemudian dia menceritakan bahwa dia mengeluarkan air mani\". Jabir berkata, agar orang itu merahasiakan kejadiannya. Namun kemudian peristiwa itu sampai juga kepada Nabi shallallahu 'alaihi wasallam lalu Beliau berdiri menyampaikan khatbah kepada kami, sabda Beliau: \"Telah sampai kepadaku berita bahwa ada sebagian orang yang berkata, begini begini. Demi Allah, akulah orang yang paling baik dan paling taqwa kepada Allah diantara mereka. Seandainya aku bisa mengulang kembali urusanku yang telah kulakukan niscaya aku tidak membawa sembelihan, dan seandainya aku tidak membawa hewan sembelihan (Al hadyu) tentu aku akan bertahallul\". Maka Suraqah bin Malik bin Ju'tsum berkata: \"Wahai Rasulullah, ketentuan itu berlaku khusus untuk kami saja atau untuk selamanya?\" Beliau bersabda: \"Tidak, tapi untuk selamanya\". Jabir berkata: \"Kemudian datang 'Ali bin Abu Tholib\". Lalu seorang dari keduanya berkata; 'Ali berkata: \"Labbaik, aku berniat hajji sebagaimana Rasulullah shallallahu 'alaihi wasallam bertalbiyah (berniat hajji). Dan dia berkata: Berkata, yang lain: \"Labbaik, aku berniat hajji seperti hajjinya Rasulullah shallallahu 'alaihi wasallam.\" Maka Nabi shallallahu 'alaihi wasallam memerintahkan untuk mengenakan ihramnya dan mengambil bagian pada hewan sembelihannya. "},"2324":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي الْحُلَيْفَةِ مِنْ تِهَامَةَ فَأَصَبْنَا غَنَمًا وَإِبِلًا فَعَجِلَ الْقَوْمُ فَأَغْلَوْا بِهَا الْقُدُورَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهَا فَأُكْفِئَتْ ثُمَّ عَدَلَ عَشْرًا مِنْ الْغَنَمِ بِجَزُورٍ ثُمَّ إِنَّ بَعِيرًا نَدَّ وَلَيْسَ فِي الْقَوْمِ إِلَّا خَيْلٌ يَسِيرَةٌ فَرَمَاهُ رَجُلٌ فَحَبَسَهُ بِسَهْمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْبَهَائِمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا قَالَ قَالَ جَدِّي يَا رَسُولَ اللَّهِ إِنَّا نَرْجُو أَوْ نَخَافُ أَنْ نَلْقَى الْعَدُوَّ غَدًا وَلَيْسَ مَعَنَا مُدًى فَنَذْبَحُ بِالْقَصَبِ فَقَالَ اعْجَلْ أَوْ أَرْنِي مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَلَيْهِ فَكُلُوا لَيْسَ السِّنَّ وَالظُّفُرَ وَسَأُحَدِّثُكُمْ عَنْ ذَلِكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Waki'] dari [Sufyan] dari [bapaknya] dari ['Abayah bin Rifa'ah] dari [kakeknya, Rafi' bin Khadij radliallahu 'anhu] berkata; \"Kami bersama Nabi shallallahu 'alaihi wasallam tiba di Dzul Hulaifah dari Tihamah lalu kami mendapatkan kambing dan unta (sebagai harta rampasan perang). Tiba-tiba rombongan menyembelih hewan-hewan tersebut hingga memenuhi kuali besar. Kemudian Rasulullah shallallahu 'alaihi wasallam datang dan memerintahkan agar kuali tersebut ditumpahkan isinya. Kemudian Beliau membagi rata yang bagian setiap sepuluh kambing sama dengan satu ekor unta. Namun ada seekor unta yang lari sementara dalam rambongan itu tidak ada kuda kecuali seekor yang sangat lincah, lalu dengan kuda itu ada seorang yang mengejar sapi yang kabur tersebut hingga dapat membunuhnyadengan tombaknya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya binatang seperti ini hukumnya sama dengan binatang liar. Maka siapa yang dapat membunuhnya maka perlakuklanlah seperti ini\". Dia berkata; Kakekku berkata: \"Kami berharap atau khawatir bertemu musuh esok hari sedangkan kita tidak punya pisau, apakah kita boleh menyembelih dengan kayu?\". Beliau berkata: \"Ya, atau bawalah kepadaku, sesungguhnya setiap yang ditumpahkan darahnya dengan disebut nama Allah maka makanlah kecuali gigi dan kukunya, dan aku akan sampaikan tentang itu. Adapun gigi dia termasuk tulang sedangkan kuku merupakan pisaunya orang-orang Habasyah\"."},"2325":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَوَلَقَدْ رَهَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِرْعَهُ بِشَعِيرٍ وَمَشَيْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخُبْزِ شَعِيرٍ وَإِهَالَةٍ سَنِخَةٍ وَلَقَدْ سَمِعْتُهُ يَقُولُ مَا أَصْبَحَ لِآلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا صَاعٌ وَلَا أَمْسَى وَإِنَّهُمْ لَتِسْعَةُ أَبْيَاتٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas radliallahu 'anhu] berkata; Sungguh Nabi shallallahu 'alaihi wasallam telah menggadaikan baju besi Beliau untuk mendapatkan gandum dan aku pernah di sore hari menenmui Nabi shallallahu 'alaihi wasallam dengan membawa rati terbuat gandum dengan sayur yang telah basi dan aku pernah mendengar Beliau bersabda: \"Keluarga Muhammad tidak pernah menemui pagi dengan menyisakan makanan kecuali satu sha' begitu juga pada sore hari\". Padahal mereka ada sembilan rumah. "},"2326":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ قَالَ تَذَاكَرْنَا عِنْدَ إِبْرَاهِيمَ الرَّهْنَ وَالْقَبِيلَ فِي السَّلَفِ فَقَالَ إِبْرَاهِيمُ حَدَّثَنَا الْأَسْوَدُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى مِنْ يَهُودِيٍّ طَعَامًا إِلَى أَجَلٍ وَرَهَنَهُ دِرْعَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Al A'masy] berkata; kami menceritakan di hadapan Ibrahim tentang masalah gadai dan pembayaran tunda dalam jual beli. Maka [Ibrahim] berkata; telah menceritakan kepada kami [Al Aswad] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam pernah membeli makanan dari orang Yahudi dengan pembayaran tunda sampai waktu yang ditentukan, yang Beliau menggadaikan (menjaminkan) baju besi Beliau.\" "},"2327":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لِكَعْبِ بْنِ الْأَشْرَفِ فَإِنَّهُ قَدْ آذَى اللَّهَ وَرَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُحَمَّدُ بْنُ مَسْلَمَةَ أَنَا فَأَتَاهُ فَقَالَ أَرَدْنَا أَنْ تُسْلِفَنَا وَسْقًا أَوْ وَسْقَيْنِ فَقَالَ ارْهَنُونِي نِسَاءَكُمْ قَالُوا كَيْفَ نَرْهَنُكَ نِسَاءَنَا وَأَنْتَ أَجْمَلُ الْعَرَبِ قَالَ فَارْهَنُونِي أَبْنَاءَكُمْ قَالُوا كَيْفَ نَرْهَنُ أَبْنَاءَنَا فَيُسَبُّ أَحَدُهُمْ فَيُقَالُ رُهِنَ بِوَسْقٍ أَوْ وَسْقَيْنِ هَذَا عَارٌ عَلَيْنَا وَلَكِنَّا نَرْهَنُكَ اللَّأْمَةَ قَالَ سُفْيَانُ يَعْنِي السِّلَاحَ فَوَعَدَهُ أَنْ يَأْتِيَهُ فَقَتَلُوهُ ثُمَّ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرُوهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata, ['Amru] aku mendengar [Jabir bin 'Abdullah radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersedia untuk (membunuh) Ka'ab bin Al Asyraf karena dia telah menghina Allah dan Rasul-Nya shallallahu 'alaihi wasallam?. Lalu Muhammad Bin Maslamah berkata: \"Aku bersedia\". Kemudian Muhammad bin Maslamah menemui Ka'ab bin Al Asyraf, lalu berkata: \"Kami ingin engkau agar meminjamiku satu atau dua wasaq kurma\". Dia (Ka'ab) menjawab: \"Gadaikan dulu isteri-isteri kalian\". Para sahabat Maslamah menjawab: \"Bagaimana mungkin kami menggadaikan isteri-isteri kami sedangkan engkau orang arab yang paling tampan?\". Dia berkata: \"Kalau begitu gadaikan anak-anak kalian.\" Mereka berkata: \"Bagaimana kami menggadaikan anak-anak kami, padahal nantinya mereka mendapat cemoohan: \"Duh, anaknya digadaikan hanyalah untuk sekedar menadapat satu atau dua wasaq, itu adalah celaan bagi kami, namun kami akan menggadaikan kamu dengan lakmah\". Sufyan berkata: \"Maksud lakmah adalah pedang\". Maka Maslamah berjanji kepadanya untuk menemuinya, lalu mereka membunuhnya kemudian mereka temui Nabi shallallahu 'alaihi wasallam lalu mereka kabarkan kejadiannya."},"2328":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ الرَّهْنُ يُرْكَبُ بِنَفَقَتِهِ وَيُشْرَبُ لَبَنُ الدَّرِّ إِذَا كَانَ مَرْهُونًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya'] dari ['Amir] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sesuatu (hewan) yang digadaikan boleh dikendarai untuk dimanfaatkan, begitu juga susu hewan boleh diminum bila digadaikan\"."},"2329":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا زَكَرِيَّاءُ عَنْ الشَّعْبِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّهْنُ يُرْكَبُ بِنَفَقَتِهِ إِذَا كَانَ مَرْهُونًا وَلَبَنُ الدَّرِّ يُشْرَبُ بِنَفَقَتِهِ إِذَا كَانَ مَرْهُونًا وَعَلَى الَّذِي يَرْكَبُ وَيَشْرَبُ النَّفَقَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Zakariya'] dari [Asy-Sya'biy] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Hewan) boleh dikendarai jika digadaikan dengan pembayaran tertentu, susu hewan juga boleh diminum bila digadaikan dengan pembayaran tertentu, dan terhadap orangyang mengendarai dan meminum susunya wajib membayar\"."},"2330":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاشْتَرَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ يَهُودِيٍّ طَعَامًا وَرَهَنَهُ دِرْعَهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata: Rasulullah shallallahu 'alaihi wasallam pernah membeli makanan dari orang Yahudi dengan menggadaikan (menjaminkan) baju besi Beliau\" "},"2331":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ كَتَبْتُ إِلَى ابْنِ عَبَّاسٍ فَكَتَبَ إِلَيَّإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ الْيَمِينَ عَلَى الْمُدَّعَى عَلَيْهِ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Nafi' bin 'Umar] dari [Ibnu Abi Mulaikah] berkata; \"Aku menulis surat kepada [Ibnu 'Abbas] lalu dia membalasnya dengan menjelaskan bahwa Nabi shallallahu 'alaihi wasallam telah menetapkan bahwa sumpah wajib bagi siapa yang tertuduh\"."},"2332":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالًا وَهُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا فَقَرَأَ إِلَى عَذَابٌ أَلِيمٌ }ثُمَّ إِنَّ الْأَشْعَثَ بْنَ قَيْسٍ خَرَجَ إِلَيْنَا فَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ قَالَ فَحَدَّثْنَاهُ قَالَ فَقَالَ صَدَقَ لَفِيَّ وَاللَّهِ أُنْزِلَتْ كَانَتْ بَيْنِي وَبَيْنَ رَجُلٍ خُصُومَةٌ فِي بِئْرٍ فَاخْتَصَمْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ شَاهِدَاكَ أَوْ يَمِينُهُ قُلْتُ إِنَّهُ إِذًا يَحْلِفُ وَلَا يُبَالِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالًا وَهُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ ثُمَّ اقْتَرَأَ هَذِهِ الْآيَةَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا إِلَى وَلَهُمْ عَذَابٌ أَلِيمٌ }","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] berkata, ['Abdullah radliallahu 'anhu] berkata: \"Siapa yang bersumpah yang dengan sumpahnya itu dia bermaksud mengambil harta orang maka dia seorang durhaka yang akan berjumpa dengan Allah dimana Allah murka kepadanya\". Maka Allah menurunkan ayatnya sebagai pembenaran QS Alu 'Imran ayat 77 yang artinya (\"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit…lalu dia membaca hingga ayat berbunyi …siksa yang pedih\"). Kemudian bahwa [Al Asyats bin Qais] keluar bersama kami lalu berkata: \"Apa yang dibicarakan dengan kalian oleh Abu 'Abdurrahman?\". Dia berkata: \"Maka kami ceritakan kepadanya\". Maka dia berkata: \"Dia benar. Sungguh demi Allah, ayat itu turun berkenaan antara aku dengan sesoerang yang sedang berselisih tentang sumur lalu kami mengadukannya kepada Rasulullah shallallahu 'alaihi wasallam maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Kamu hadirkan dua saksi atau bersumpah?\". Aku katakan: \"Biarlah dia bersumpah dan aku tidak peduli\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah yang dengan sumpahnya itu dia bermaksud mengambil harta orang maka dia telah berbuat kedurhakaan dan akan berjumpa dengan Allah dimana Allah murka kepadanya\". Maka turunlah firman Allah sebagai pembenaran atas kejadian itu kemudian bacalah ayat ini: (\"Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit… hingga ayat…siksa yang pedih\"). "},"2333":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عَاصِمُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي وَاقِدُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ مَرْجَانَةَ صَاحِبُ عَلِيِّ بْنِ حُسَيْنٍ قَالَ قَالَ لِي أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ أَعْتَقَ امْرَأً مُسْلِمًا اسْتَنْقَذَ اللَّهُ بِكُلِّ عُضْوٍ مِنْهُ عُضْوًا مِنْهُ مِنْ النَّارِ قَالَ سَعِيدُ بْنُ مَرْجَانَةَ فَانْطَلَقْتُ بِهِ إِلَى عَلِيِّ بْنِ حُسَيْنٍ فَعَمَدَ عَلِيُّ بْنُ حُسَيْنٍ رَضِيَ اللَّهُ عَنْهُمَا إِلَى عَبْدٍ لَهُ قَدْ أَعْطَاهُ بِهِ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَشَرَةَ آلَافِ دِرْهَمٍ أَوْ أَلْفَ دِينَارٍ فَأَعْتَقَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami ['Ashim bin Muhammad] berkata, telah menceritakan kepadaku [Waqid bin Muhammad] berkata, telah menceritakan kepadaku [Sa'id bin Marjanah], sahabat 'Ali bin Husain berkata; [Abu Hurairah radliallahu 'anhu] berkata, kepadaku bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa saja orang yang membebaskan seorang muslim maka Allah akan menyelamatkan anggota tubuhnya dari api neraka dari setiap anggota tubuh yang dimerdekakannya\". Sa'id bin Marjanah berkata; Lalu aku pergi dengan membawa hadits ini menemui 'Ali bin Husain radliallahu 'anhuma, maka dia segera menemui budak miliknya yang dulu dia beli dari 'Abdullah bin Ja'far seharga sepuluh ribu dirham atau seribu dinar lalu dia membebaskan budak itu."},"2334":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ أَبِي مُرَاوِحٍ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْعَمَلِ أَفْضَلُ قَالَ إِيمَانٌ بِاللَّهِ وَجِهَادٌ فِي سَبِيلِهِ قُلْتُ فَأَيُّ الرِّقَابِ أَفْضَلُ قَالَ أَعْلَاهَا ثَمَنًا وَأَنْفَسُهَا عِنْدَ أَهْلِهَا قُلْتُ فَإِنْ لَمْ أَفْعَلْ قَالَ تُعِينُ ضَايِعًا أَوْ تَصْنَعُ لِأَخْرَقَ قَالَ فَإِنْ لَمْ أَفْعَلْ قَالَ تَدَعُ النَّاسَ مِنْ الشَّرِّ فَإِنَّهَا صَدَقَةٌ تَصَدَّقُ بِهَا عَلَى نَفْسِكَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Hisyam bin 'Urwah] dari [bapaknya] dari [Abu Murawih] dari [Abu Dzar radliallahu 'anhu] berkata; Aku bertanya kepada Nabi shallallahu 'alaihi wasallam, amal apakah yang paling utama?\". Beliau menjawab: \"Iman kepada Allah dan jihad di jalan-Nya\". Kemudian aku bertanya lagi: \"Pembebasan budak manakah yang paling utama?\". Beliau menjawab: \"Yang paling tinggi harganya dan yang paling berharga hati tuannya\". Aku katakan: \"Bagaimana kalau aku tidak dapat mengerjakannya?\". Beliau berkata: \"Kamu membantu orang yang telantar atau orang bodoh yang tak mempunyai ketrampilan \". Aku katakan lagi:: \"Bagaimana kalau aku tidak dapat mengerjakannya?\". Beliau berkata: \"Kamu hindari manusia dari keburukan karena yang demikian berarti shadaqah yang kamu lakukan untuk dirimu sendiri\". "},"2335":{"ar":"حَدَّثَنَا مُوسَى بْنُ مَسْعُودٍ حَدَّثَنَا زَائِدَةُ بْنُ قُدَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعَتَاقَةِ فِي كُسُوفِ الشَّمْسِتَابَعَهُ عَلِيٌّ عَنْ الدَّرَاوَرْدِيِّ عَنْ هِشَامٍ","id":"Telah menceritakan kepada kami [Musa bin Mas'ud] telah menceritakan kepada kami [Za'idah bin Qudamah] dari [Hisyam bin 'Urwah] dari [Fathimah binti Al Mundzir] dari [Asma' binti Abu Bakar radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam memerintahkan untuk membebaskan budak ketika terjadi gerhana matahari\". Hadits ini dikuatkan pula oleh ['Ali] dari [Ad-Darawardiy] dari [Hisyam]."},"2336":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا عَثَّامٌ حَدَّثَنَا هِشَامٌ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْكُنَّا نُؤْمَرُ عِنْدَ الْخُسُوفِ بِالْعَتَاقَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar] telah menceritakan kepada kami ['Atstsam] telah menceritakan kepada kami [Hisyam] dari [Fathimah binti Al Mundzir] dari [Asma' binti Abu Bakar radliallahu 'anhuma] berkata: \"Kami diperintahkan untuk membebaskan budak ketika terjadi gerhana matahari\"."},"2337":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ سَالِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ عَبْدًا بَيْنَ اثْنَيْنِ فَإِنْ كَانَ مُوسِرًا قُوِّمَ عَلَيْهِ ثُمَّ يُعْتَقُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Salim] dari [bapaknya] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membebaskan seorang budak yang dimiliki dua orang secara berserikat, maka apabila ada kelapangan hendaklah budak itu ditaksir harganya secara adil lantas dibebankan kepadanya, lantas di budak dibebaskan\". "},"2338":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ شِرْكًا لَهُ فِي عَبْدٍ فَكَانَ لَهُ مَالٌ يَبْلُغُ ثَمَنَ الْعَبْدِ قُوِّمَ الْعَبْدُ عَلَيْهِ قِيمَةَ عَدْلٍ فَأَعْطَى شُرَكَاءَهُ حِصَصَهُمْ وَعَتَقَ عَلَيْهِ الْعَبْدُ وَإِلَّا فَقَدْ عَتَقَ مِنْهُ مَا عَتَقَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membebaskan hak kepemilikan budak yang dimiliki secara berserikat, dan ia mempunyai harta yang bisa mencapai total harga budak, hendaklah harga budak ditaksir secara adil dan dibebankan kepadanya, lantas ia membebaskan hak kepemilikan yang masih dimiliki serikatnya, dan ia bebaskan budak secara keseluruhan. Jika ia tidak mempunyai harta ini, berarti ia telah membebaskan hak kepemilikannyya.\" "},"2339":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ شِرْكًا لَهُ فِي مَمْلُوكٍ فَعَلَيْهِ عِتْقُهُ كُلُّهُ إِنْ كَانَ لَهُ مَالٌ يَبْلُغُ ثَمَنَهُ فَإِنْ لَمْ يَكُنْ لَهُ مَالٌ يُقَوَّمُ عَلَيْهِ قِيمَةَ عَدْلٍ فَأُعْتِقَ مِنْهُ مَا أَعْتَقَحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ عَنْ عُبَيْدِ اللَّهِ اخْتَصَرَهُ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] dari [Abu Umamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang membebaskan hak kepemilikan budak yang dimiliki secara berserikat, maka wajib baginya membebaskan semuanya jika dia memiliki uang sebanyak jumlah harga budaknya. Jika dia tidak memiliki harta, maka budak ditaksir secara adil, sehingga yang telah dibebaskannya telah bebas \". Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyir] dari ['Ubaidullah]: yang ia meringkasnya."},"2340":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ نَصِيبًا لَهُ فِي مَمْلُوكٍ أَوْ شِرْكًا لَهُ فِي عَبْدٍ وَكَانَ لَهُ مِنْ الْمَالِ مَا يَبْلُغُ قِيمَتَهُ بِقِيمَةِ الْعَدْلِ فَهُوَ عَتِيقٌ قَالَ نَافِعٌ وَإِلَّا فَقَدْ عَتَقَ مِنْهُ مَا عَتَقَ قَالَ أَيُّوبُ لَا أَدْرِي أَشَيْءٌ قَالَهُ نَافِعٌ أَوْ شَيْءٌ فِي الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membebaskan hak kepemlikian budak yang dimilki secara berserikat atau dengan redaksi 'Membebaskan bagiannya dalam budak yang dimilki secara berserikat, sedang dia memiliki harta sebanyak jumlah harga total budaknya secara adil, maka budak itu menjadi bebas\". Nafi' berkata: \"Bila dia tidak memiliki harta, maka berarti ia telah membebaskan hak kepemilikan budaknya\". Ayyub berkata: \"Aku tidak tahu apakah ini kalimat yang diucapkan oleh Nafi' atau termasuk bagian dari hadits yang disabdakan Nabi shallallahu 'alaihi wasallam."},"2341":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مِقْدَامٍ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ كَانَ يُفْتِي فِي الْعَبْدِ أَوْ الْأَمَةِ يَكُونُ بَيْنَ شُرَكَاءَ فَيُعْتِقُ أَحَدُهُمْ نَصِيبَهُ مِنْهُ يَقُولُ قَدْ وَجَبَ عَلَيْهِ عِتْقُهُ كُلِّهِ إِذَا كَانَ لِلَّذِي أَعْتَقَ مِنْ الْمَالِ مَا يَبْلُغُ يُقَوَّمُ مِنْ مَالِهِ قِيمَةَ الْعَدْلِ وَيُدْفَعُ إِلَى الشُّرَكَاءِ أَنْصِبَاؤُهُمْ وَيُخَلَّى سَبِيلُ الْمُعْتَقِ يُخْبِرُ ذَلِكَ ابْنُ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَرَوَاهُ اللَّيْثُ وَابْنُ أَبِي ذِئْبٍ وَابْنُ إِسْحَاقَ وَجُوَيْرِيَةُ وَيَحْيَى بْنُ سَعِيدٍ وَإِسْمَاعِيلُ بْنُ أُمَيَّةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَصَرًا","id":"Telah menceritakan kepada kami [Ahmad bin Miqdam] telah menceritakan kepada kami [Al Fudhail bin Sulaiman] telah menceritakan kepada kami [Musa bin 'Uqbah] telah menceritakan kepadaku [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa dia berfatwa tentang budak (laki-laki maupun wanita) yang dimiliki secara berserikat, lantas salah seorang dari mereka membebaskan hak kepemilikannya. Kata Ibn Umar, maka dia berkewajiban membebaskan budak itu secara total jika dia memiliki uang yang dapat membebaskannya, Jika yang membebaskan tersebut mempunyai harta, maka hartanya ditaksir secara adil lantas dibayarkan kepada sekutu yang memiliki hak kepemilkan budaknya, lantas sang budak dibebaskan\". Ibnu 'Umar radliallahu 'anhuma memberitahukan yang demikian berdasarkan yang didapatnya dari Nabi shallallahu 'alaihi wasallam. Dan [Al Laits], [Ibnu Abi Dza'bi], [Ibnu Ishaq], [Juwairiyah], [Yahya bin Sa'id] dan [Isma'il boin Umayyah] meriwayatkan dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam secara ringkas."},"2342":{"ar":"حَدَّثَنَا أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ سَمِعْتُ قَتَادَةَ قَالَ حَدَّثَنِي النَّضْرُ بْنُ أَنَسِ بْنِ مَالِكٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ شَقِيصًا مِنْ عَبْدٍ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَمَنْ أَعْتَقَ نَصِيبًا أَوْ شَقِيصًا فِي مَمْلُوكٍ فَخَلَاصُهُ عَلَيْهِ فِي مَالِهِ إِنْ كَانَ لَهُ مَالٌ وَإِلَّا قُوِّمَ عَلَيْهِ فَاسْتُسْعِيَ بِهِ غَيْرَ مَشْقُوقٍ عَلَيْهِتَابَعَهُ حَجَّاجُ بْنُ حَجَّاجٍ وَأَبَانُ وَمُوسَى بْنُ خَلَفٍ عَنْ قَتَادَةَ اخْتَصَرَهُ شُعْبَةُ","id":"Telah menceritakan kepada kami [Ahmad bin Abi Raja'] telah menceritakan kepada kami [Yahya bin Abu Adam] telah menceritakan kepada kami [Jarir bin HAzim] aku mendengar [Qatadah] berkata, telah menceritakan kepadaku [An-Nadhar bin Anas bin Malik] dari [Basyir bin Nahik] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membebaskan hak kepemilikan budak\". Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [YAzid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [An-Nadhar bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Siapa yang membebaskan bagian atau hak kepemilikan budak yang dimilki secara berserikat, maka pembebasan total budak itu menjadi kewajibannya jika ia mempunyai harta. Jikalah tidak, maka harga budak tersebut ditaksir secara adil, lantas budak diusahakan untuk dibebaskan dengan tanpa membebani orang yang telah membebaskan hak kepemilikannya. Hadis ini diperkuat oleh [Hajjaj bin Hajjaj] dan [Abban] dan [Musa bin Khalaf] dari [Qatadah] yang diringkas oleh [Syu'bah]."},"2343":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مِسْعَرٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَجَاوَزَ لِي عَنْ أُمَّتِي مَا وَسْوَسَتْ بِهِ صُدُورُهَا مَا لَمْ تَعْمَلْ أَوْ تَكَلَّمْ","id":"Telah menceritakan kepada kami [Al Humaidiy] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Mis'ar] dari [Qatadah] dari [Zurarah bin Awfaa] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Allah memberi kelonggaran kepadaku tentang ummatku, mereka tidak dianggap melakukan dosa dari apa yang dibisikkan dalam dadanya (hatinya) selama tidak dikerjakan atau diucapkannya\"."},"2344":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُفْيَانَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ اللَّيْثِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَعْمَالُ بِالنِّيَّةِ وَلِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Sufyan] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Ibrahim At-Taymiy] dari ['Alqamah bin Waqash Al Laitsiy] berkata; aku mendengar dari ['Umar bin Al Khaththab radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Hanyasanya amal dihitung karena niat, dan setiap orang akan mendapatkan apa yang diniatkannya. Maka siapa yang berhijrah kepada Allah dan RasulNya maka hijrahnya itu kepada Allah dan RasulNya dan siapa yang hijrah untuk dunia yang ingin didapatkannya atau kepada wanita yang ingin dikawininya maka hijrahnya sekedar mendapat tujuan hijrahnya.\""},"2345":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ عَنْ مُحَمَّدِ بْنِ بِشْرٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّهُ لَمَّا أَقْبَلَ يُرِيدُ الْإِسْلَامَ وَمَعَهُ غُلَامُهُ ضَلَّ كُلُّ وَاحِدٍ مِنْهُمَا مِنْ صَاحِبِهِ فَأَقْبَلَ بَعْدَ ذَلِكَ وَأَبُو هُرَيْرَةَ جَالِسٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ هَذَا غُلَامُكَ قَدْ أَتَاكَ فَقَالَ أَمَا إِنِّي أُشْهِدُكَ أَنَّهُ حُرٌّ قَالَ فَهُوَ حِينَ يَقُولُ يَا لَيْلَةً مِنْ طُولِهَا وَعَنَائِهَاعَلَى أَنَّهَا مِنْ دَارَةِ الْكُفْرِ نَجَّتِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Mumair] dari [Muhammad bin Bisyir] dari [Isma'il] dari [Qais] dari [Abu Hurairah radliallahu 'anhu] bahwasanya ketika dia datang untuk memeluk Islam, dia datang bersama budak kecilnya (gulam), antara Abu Hurairah dan budak kecilnya tersebut, sama-sama terpisah dalam perjalanan karena suatu hal. Kemudian hari gulamnya datang ketika Abu Hurairah sedang duduk bersama Nabi shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Hurairah, ini gulammu datang menemuimu\". Maka dia berkata: \"Aku bersaksi kepada anda bahwa dia sekarang bebas\". Dia Qais) berkata: Ini terjadi ketika dia bersya'ir: Wahai malam dengan kelamaan dan kepayahannya # Dan menyelamatkan dari negeri kekufuran."},"2346":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا إِسْمَاعِيلُ عَنْ قَيْسٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا قَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ فِي الطَّرِيقِ يَا لَيْلَةً مِنْ طُولِهَا وَعَنَائِهَاعَلَى أَنَّهَا مِنْ دَارَةِ الْكُفْرِ نَجَّتِقَالَ وَأَبَقَ مِنِّي غُلَامٌ لِي فِي الطَّرِيقِ قَالَ فَلَمَّا قَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَايَعْتُهُ فَبَيْنَا أَنَا عِنْدَهُ إِذْ طَلَعَ الْغُلَامُ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ هَذَا غُلَامُكَ فَقُلْتُ هُوَ حُرٌّ لِوَجْهِ اللَّهِ فَأَعْتَقْتُهُقَالَ أَبُو عَبْد اللَّهِ لَمْ يَقُلْ أَبُو كُرَيْبٍ عَنْ أَبِي أُسَامَةَ حُرٌّ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Isma'il] dari [Qais] dari [Abu Hurairah radliallahu 'anhu] berkata; \"Ketika datang menemui Nabi shallallahu 'alaihi wasallam aku bersyair di sepanjang perjalanan: Wahai malam dengan kelamaan dan kepayahannya. Dan menyelamatkan dari negeri kekufuran. Dia berkata: \"Gulamku lalu melarikan diri dariku di jalan\". Dia berkata: \"Ketika aku menemui Nabi shallallahu 'alaihi wasallam, aku berbai'at Beliau. Ketika aku masih bersama Beliau tiba-tiba datang gulamku kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Wahai Abu Hurairah, ini gulammu datang menemuimu\". Aku katakan: \"Dia sekarang bebas demi mencari ridha Allah\". Maka dia aku bebaskan\". Berkata, Abu 'Abdullah Al Bukhariy: [Abu Kuraib] tidak mengatakan dari [Abu Usamah] ada kalimat bebas\". "},"2347":{"ar":"حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حُمَيْدٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ قَالَ لَمَّا أَقْبَلَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُوَمَعَهُ غُلَامُهُ وَهُوَ يَطْلُبُ الْإِسْلَامَ فَضَلَّ أَحَدُهُمَا صَاحِبَهُ بِهَذَا وَقَالَ أَمَا إِنِّي أُشْهِدُكَ أَنَّهُ لِلَّهِ","id":"Telah menceritakan kepada kami [Syihab bin 'Abbad] telah menceritakan kepada kami [Ibrahim Humaid] dari [Isma'il] dari [Qais] berkata; Ketika [Abu Hurairah radliallahu 'anhu] datang bersama budak kecilnya (gulam) untuk memeluk Islam satu sama lain diantara keduanya terpisah dari lainnya. Kemudian setelah itu dia berkata: \"Aku bersaksi kepada anda bahwa dia sekarang untuk Allah (bebas) \". "},"2348":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنَّ عُتْبَةَ بْنَ أَبِي وَقَّاصٍ عَهِدَ إِلَى أَخِيهِ سَعْدِ بْنِ أَبِي وَقَّاصٍ أَنْ يَقْبِضَ إِلَيْهِ ابْنَ وَلِيدَةِ زَمْعَةَ قَالَ عُتْبَةُ إِنَّهُ ابْنِي فَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْفَتْحِ أَخَذَ سَعْدٌ ابْنَ وَلِيدَةِ زَمْعَةَ فَأَقْبَلَ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَقْبَلَ مَعَهُ بِعَبْدِ بْنِ زَمْعَةَ فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ هَذَا ابْنُ أَخِي عَهِدَ إِلَيَّ أَنَّهُ ابْنُهُ فَقَالَ عَبْدُ بْنُ زَمْعَةَ يَا رَسُولَ اللَّهِ هَذَا أَخِي ابْنُ وَلِيدَةِ زَمْعَةَ وُلِدَ عَلَى فِرَاشِهِ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ابْنِ وَلِيدَةِ زَمْعَةَ فَإِذَا هُوَ أَشْبَهُ النَّاسِ بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ مِنْ أَجْلِ أَنَّهُ وُلِدَ عَلَى فِرَاشِ أَبِيهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجِبِي مِنْهُ يَا سَوْدَةُ بِنْتَ زَمْعَةَ مِمَّا رَأَى مِنْ شَبَهِهِ بِعُتْبَةَ وَكَانَتْ سَوْدَةُ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepadaku ['Urwah bin Az Zubair] bahwa ['Aisyah radliallahu 'anha] berkata; Bahwa 'Utbah bin Abu Waqash berjanji kepada saudaranya, Sa'ad bin Abi Waqash agar mengambil anak dari hamba sahaya Zam'ah untuknya. Maka 'Utbah berkata: \"Dia itu anakku\". Ketika Rasulullah shallallahu 'alaihi wasallam datang saat tahun penaklukan Makkah, Sa'ad mengambil anak dari hamba sahaya Zam'ah lalu membawanya ke hadapan Rasulullah shallallahu 'alaihi wasallam dan 'Abdu bin Zam'ah turut bersamanya. Sa'ad berkata: \"Wahai Rasulullah, dia ini anak saudaraku yang telah bersumpah kepadaku bahwa anak ini adalah anaknya. Kemudian 'Abdu bin Zam'ah berkata: Wahai Rasulullah, dia adalah saudaraku, anak dari hambasahaya milik Zam'ah yang dilahirkan di atas tempat tidurnya\". Lantas Rasulullah shallallahu 'alaihi wasallam memperhatikan anak hamba sahaya Zam'ah yang ternyata dia manusia yang paling mirip dengannya. Selanjutnya Rasulullah shallallahu 'alaihi wasallam berkata: \"Dia ini milikmu wahai 'Abdu bin Zam'ah karena dia dilahirkan diatas tempat tidur bapaknya\". Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berhijablah engkau daripadanya Saudah binti Zam'ah\". Ini beliau ucapkan setelah beliau melihat kemiripannya dengan 'Utbah. Saudah adalah isteri Nabi shallallahu 'alaihi wasallam."},"2349":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَعْتَقَ رَجُلٌ مِنَّا عَبْدًا لَهُ عَنْ دُبُرٍ فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِ فَبَاعَهُ قَالَ جَابِرٌ مَاتَ الْغُلَامُ عَامَ أَوَّلَ","id":"Telah menceritakan kepada kami [Adam bin Abi Iyas] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Amru bin DInar] aku mendengar [Jabir bin 'Abdullah radliallahu 'anhuma] berkata: \"Ada seorang laki-laki membebaskan seorang budak dengan cara mudabbar, lalu Nabi shallallahu 'alaihi wasallam memmanggilnya kemudian membelinya. Jabir berkata: \"Budak itu kemudian meningal dunia pada tahun itu juga\"."},"2350":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku ['Abdullah bin Dinar] aku mendengar [Ibnu Umar] berkata; Rasulullah shallallahu 'alaihi wasallam melarang membeli hak warisan budak dan juga menghibahkannya\"."},"2351":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاشْتَرَيْتُ بَرِيرَةَ فَاشْتَرَطَ أَهْلُهَا وَلَاءَهَا فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْتِقِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْطَى الْوَرِقَ فَأَعْتَقْتُهَا فَدَعَاهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَيَّرَهَا مِنْ زَوْجِهَا فَقَالَتْ لَوْ أَعْطَانِي كَذَا وَكَذَا مَا ثَبَتُّ عِنْدَهُ فَاخْتَارَتْ نَفْسَهَا","id":"Telah menceritakan kepada kami ['Utsman bin Abi Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata; Aku membeli seorang budak wanita bernama Barirah lalu tuannya mengajukan persyaratan (bahwa wala' tetap milik mereka), maka aku adukan hal itu kepada Nabi shallallahu 'alaihi wasallam, dan Beliau bersabda: \"Bebaskanlah dia karena perwalian bagi siapa yang memberikan perak (uang). Maka aku membebaskannya lalu Nabi shallallahu 'alaihi wasallam memanggilnya lalu memberi pilihan untuk tetap bersama suaminya atau tidak. Barirah berkata: seandainya suamiku memberi kepadaku ini dan itu, itu semuanya tidak menjadikanku tinggal bersamanya \". Lalu Barirah memilih untuk dirinya sendiri.  "},"2352":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ بْنِ عُقْبَةَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَنَسٌ رَضِيَ اللَّهُ عَنْهُأَنَّ رِجَالًا مِنْ الْأَنْصَارِ اسْتَأْذَنُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا ائْذَنْ لَنَا فَلْنَتْرُكْ لِابْنِ أُخْتِنَا عَبَّاسٍ فِدَاءَهُ فَقَالَ لَا تَدَعُونَ مِنْهُ دِرْهَمًا","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] telah menceritakan kepada kami [Isma'il bin Ibrahim bin 'Uqbah] dari [Musa bin 'Uqbah] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku [Anas radliallahu 'anhu] bahwa ada orang-orang dari kalangan Anshar meminta izin kepada Rasulullah shallallahu 'alaihi wasallam dan mereka berkata: \"izinkanlah kami untuk memberi tebusan atas anak saudara perempuan kami, yakni 'Abbas\". Maka Beliau bersabda: \"Janganlah kalian tinggalkan untuknya satu dirhampun\"."},"2353":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ أَخْبَرَنِي أَبِي أَنَّ حَكِيمَ بْنَ حِزَامٍ رَضِيَ اللَّهُ عَنْهُأَعْتَقَ فِي الْجَاهِلِيَّةِ مِائَةَ رَقَبَةٍ وَحَمَلَ عَلَى مِائَةِ بَعِيرٍ فَلَمَّا أَسْلَمَ حَمَلَ عَلَى مِائَةِ بَعِيرٍ وَأَعْتَقَ مِائَةَ رَقَبَةٍ قَالَ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ أَشْيَاءَ كُنْتُ أَصْنَعُهَا فِي الْجَاهِلِيَّةِ كُنْتُ أَتَحَنَّثُ بِهَا يَعْنِي أَتَبَرَّرُ بِهَا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمْتَ عَلَى مَا سَلَفَ لَكَ مِنْ خَيْرٍ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] telah menceritakan kepadaku [bapakku] bahwa [Hakim bin Hizam radliallahu 'anhu] pada zaman jahiliyah membebaskan seratus budak dan membawa tebusannya dengan seratus unta. Setelah dia masuk Islam dia membawa seratus unta untuk membebaskan seratus budak. Dia berkata; aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam, aku katakan: 'Wahai Rasulullah, bagaimana pendapat Anda tentang sesuatu perbuatan yang aku pernah mengerjakannya di zaman jahiliyah, aku pernah bertahannuts (mengasingkan diri) untuk mencari kebaikan\". Dia berkata; Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau kamu Islam, kamu akan mendapat dari kebaikan yang kamu lakukan dahulu\"."},"2354":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ ذَكَرَ عُرْوَةُ أَنَّ مَرْوَانَ وَالْمِسْوَرَ بْنَ مَخْرَمَةَأَخْبَرَاهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ حِينَ جَاءَهُ وَفْدُ هَوَازِنَ فَسَأَلُوهُ أَنْ يَرُدَّ إِلَيْهِمْ أَمْوَالَهُمْ وَسَبْيَهُمْ فَقَالَ إِنَّ مَعِي مَنْ تَرَوْنَ وَأَحَبُّ الْحَدِيثِ إِلَيَّ أَصْدَقُهُ فَاخْتَارُوا إِحْدَى الطَّائِفَتَيْنِ إِمَّا الْمَالَ وَإِمَّا السَّبْيَ وَقَدْ كُنْتُ اسْتَأْنَيْتُ بِهِمْ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتَظَرَهُمْ بِضْعَ عَشْرَةَ لَيْلَةً حِينَ قَفَلَ مِنْ الطَّائِفِ فَلَمَّا تَبَيَّنَ لَهُمْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ رَادٍّ إِلَيْهِمْ إِلَّا إِحْدَى الطَّائِفَتَيْنِ قَالُوا فَإِنَّا نَخْتَارُ سَبْيَنَا فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ إِخْوَانَكُمْ قَدْ جَاءُونَا تَائِبِينَ وَإِنِّي رَأَيْتُ أَنْ أَرُدَّ إِلَيْهِمْ سَبْيَهُمْ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يُطَيِّبَ ذَلِكَ فَلْيَفْعَلْ وَمَنْ أَحَبَّ أَنْ يَكُونَ عَلَى حَظِّهِ حَتَّى نُعْطِيَهُ إِيَّاهُ مِنْ أَوَّلِ مَا يُفِيءُ اللَّهُ عَلَيْنَا فَلْيَفْعَلْ فَقَالَ النَّاسُ طَيَّبْنَا لَكَ ذَلِكَ قَالَ إِنَّا لَا نَدْرِي مَنْ أَذِنَ مِنْكُمْ مِمَّنْ لَمْ يَأْذَنْ فَارْجِعُوا حَتَّى يَرْفَعَ إِلَيْنَا عُرَفَاؤُكُمْ أَمْرَكُمْ فَرَجَعَ النَّاسُ فَكَلَّمَهُمْ عُرَفَاؤُهُمْ ثُمَّ رَجَعُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرُوهُ أَنَّهُمْ طَيَّبُوا وَأَذِنُوا فَهَذَا الَّذِي بَلَغَنَا عَنْ سَبْيِ هَوَازِنَ وَقَالَ أَنَسٌ قَالَ عَبَّاسٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَادَيْتُ نَفْسِي وَفَادَيْتُ عَقِيلًا","id":"Telah menceritakan kepada kami [Ibnu Abi Maryam] berkata, telah menceritakan kepadaku [AL Laits] dari ['Uqail] dari [Ibnu Syihab]; ['Urwah] menceritakan bahwa [Marwan] dan [Al Miswar bin Makhramah] keduanya mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam berdiri ketika datang utusan HawAzin yang mereka meminta kepada Beliau agar beliau bersedia mengembalikan harta dan para tawanan (wanita dan anak-anak) mereka. Maka Beliau bersabda: \"Sesungguhnya bersama aku ada orang-orang yang kalian lihat dan ucapan yang paling aku sukai adalah yang paling jujur, silakan kalian pilih apakah harta atau tawanan. Sungguh aku akan menunggu mereka\". Kemudian Nabi shallallahu 'alaihi wasallam menunggu mereka sekitar sepuluh malam saat kembali dari Tho'if. Setelah jelas bagi mereka bahwa Nabi shallallahu 'alaihi wasallam tidak akan mengembalikan kepada mereka kecuali salah satu dari dua pilihan, mereka berkata: \"Baik kami memilih para tawanan\". Maka Nabi shallallahu 'alaihi wasallam berdiri di hadapan manusia lalu memuji Allah yang memang Dia yang paling berhak dipuji kemudian bersabda: \"Amma ba'du, sungguh saudara-saudara kalian telah datang kepada kita dengan bertobat dan aku memilih untuk membebaskan tawanan kepada mereka. Maka siapa yang suka berbuat baik (dengan mengikhlaskannya) silakan dan siapa yang suka mengambil haknya, kami akan berikan kepadanya haknya dari sejak awal Allah memberikan harta fa'i kepada kami, maka silakan dia lakukan\". Maka orang-orang berkata: \"Kami ikhlaskan semuanya untuk Anda\". Beliau berkata: \"Kami tidak tahu siapa dari kalian yang berwenang memberi izin dan siapa yang tidak. Untuk itu kembalilah kalian hingga orang-orang yang berwenang atas urusan kalian menyerahkannya kepada kami\". Maka orang-orang itu kembali lalu para pimpinan mereka mengadakan pembicaraan dengan mereka kemudian mereka kembali menghadap Nabi shallallahu 'alaihi wasallam dan mengabarkan bahwa mereka telah setuju dan mengizinkan\". Dan inilah riwayat yang sampai kepada kami tentang para tawanan suku HawAzin. Dan Anas berkata; 'Abbas berkata, kepada Nabi shallallahu 'alaihi wasallam: \"Kalau begitu aku tebus diriku dan aku tebus pula 'Aqil\"."},"2355":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا ابْنُ عَوْنٍ قَالَ كَتَبْتُ إِلَى نَافِعٍ فَكَتَبَ إِلَيَّإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَغَارَ عَلَى بَنِي الْمُصْطَلِقِ وَهُمْ غَارُّونَ وَأَنْعَامُهُمْ تُسْقَى عَلَى الْمَاءِ فَقَتَلَ مُقَاتِلَتَهُمْ وَسَبَى ذَرَارِيَّهُمْ وَأَصَابَ يَوْمَئِذٍ جُوَيْرِيَةَحَدَّثَنِي بِهِ عَبْدُ اللَّهِ بْنُ عُمَرَ وَكَانَ فِي ذَلِكَ الْجَيْشِ","id":"Telah menceritakan kepada kami ['Ali bin Al Hasan bin Syaqiq] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ibnu 'Aun] berkata; Aku menulis surat kepada [Nafi'] lalu dia membalasnya dan berkata: \"Sesungguhnya Nabi shallallahu 'alaihi wasallam pernah menyerang suku Bani Al Mushthaliq saat mereka sedang lalai sedangkan ternak-ternak mereka sedang minum air lalu Beliau membunuh prajurit suku tersebut dan menawan anak keturunan mereka dan pada saat itu Beliau mendapatkan Juwairiyah (sebagai tawanan) \". ['Abdullah bin 'Umar radliallahu 'anhuma] menceritakan kepadaku tentang riwayat ini dan saat itu dia termasuk salah seorang dari pasukan tersebut."},"2356":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ قَالَ رَأَيْتُ أَبَا سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ فَسَأَلْتُهُ فَقَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ بَنِي الْمُصْطَلِقِ فَأَصَبْنَا سَبْيًا مِنْ سَبْيِ الْعَرَبِ فَاشْتَهَيْنَا النِّسَاءَ فَاشْتَدَّتْ عَلَيْنَا الْعُزْبَةُ وَأَحْبَبْنَا الْعَزْلَ فَسَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا مَا مِنْ نَسَمَةٍ كَائِنَةٍ إِلَى يَوْمِ الْقِيَامَةِ إِلَّا وَهِيَ كَائِنَةٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Rabi'ah bin Abi 'Abdurrahman] dari [Muhammad bin Yahya] dari [Ibnu Muhairiz] berkata; Aku melihat [Abu Sa'id Al Khudriy radliallahu 'anhu] lalu aku bertanya kepadanya tentang sesuatu, maka dia berkata: \"Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam pada perang Bani Al Mushtaholiq lalu kami mendapatkan tawanan dari keturunan 'Arab lalu kami tertarik dengan para wanita, namun pada saat yang sama kami juga masih ingin membujang dan menyukai melakukan 'Azal (senggama terputus, coitus interuptus). Lalu kami tanyakan hal ini kepada Rasulullah shallallahu 'alaihi wasallam, maka Beliau bersabda: \" Tidak sebaiknyakah kalian tidak melakukannya, sebab tidak ada satu nyawapun yang telah Allah tetapkan akan muncul (jadi) hingga hari qiyamat kecuali dia pasti akan terjadi.\""},"2357":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ لَا أَزَالُ أُحِبُّ بَنِي تَمِيمٍ و حَدَّثَنِي ابْنُ سَلَامٍ أَخْبَرَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ الْمُغِيرَةِ عَنْ الْحَارِثِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ وَعَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَمَا زِلْتُ أُحِبُّ بَنِي تَمِيمٍ مُنْذُ ثَلَاثٍ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِيهِمْ سَمِعْتُهُ يَقُولُ هُمْ أَشَدُّ أُمَّتِي عَلَى الدَّجَّالِ قَالَ وَجَاءَتْ صَدَقَاتُهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ صَدَقَاتُ قَوْمِنَا وَكَانَتْ سَبِيَّةٌ مِنْهُمْ عِنْدَ عَائِشَةَ فَقَالَ أَعْتِقِيهَا فَإِنَّهَا مِنْ وَلَدِ إِسْمَاعِيلَ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Senantiasa aku mencintai Bani Tamim\". Dan telah menceritakan kepadaku [Ibnu Salam] telah mengabarkan kepada kami [Jarir bin 'Abdul Hamid] dari [Al Mughirah] dari [Al Harits] dari [Abu Zur'ah] dari [Abu Hurairah radliallahu 'anhu]. Dan dari ['Umarah] dari [Abu Zur'ah] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Senantiasa aku mencintai Bani Tamim sejak aku mendengar tiga perkara yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam dimana Beliau berkata, tentang mereka yang aku medengarnya, Beliau berkata: \"Mereka adalah ummatku yang paling keras perlawanannya terhada Ad-Dajjal\". Dia berkata: \"Ketika datang zakat-zakat dari mereka, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Inilah zakatnya kaum kita\". Dan ketika diantara tawanan mereka ada yang diambil oleh 'Aisyah, Beliau bersabda: \"Bebaskanlah, karena dia dari keturunan Nabi Isma'il\"."},"2358":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ سَمِعَ مُحَمَّدَ بْنَ فُضَيْلٍ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ جَارِيَةٌ فَعَالَهَا فَأَحْسَنَ إِلَيْهَا ثُمَّ أَعْتَقَهَا وَتَزَوَّجَهَا كَانَ لَهُ أَجْرَانِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dia mendengar [Muhammad bin Fudhail] dari [Mutharrif] dari [Asy-Sya'biy] dari [Abu Burdah] dari [Abu Musa radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang memiliki budak wanita lalu memberikan hak-haknya dan bersikap baik kepadanya kemudian dia bebaskan lalu dinikahinya maka baginya mendapat dua pahala\"."},"2359":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا وَاصِلٌ الْأَحْدَبُ قَالَ سَمِعْتُ الْمَعْرُورَ بْنَ سُويْدٍ قَالَ رَأَيْتُ أَبَا ذَرٍّ الْغِفَارِيَّ رَضِيَ اللَّهُ عَنْهُوَعَلَيْهِ حُلَّةٌ وَعَلَى غُلَامِهِ حُلَّةٌ فَسَأَلْنَاهُ عَنْ ذَلِكَ فَقَالَ إِنِّي سَابَبْتُ رَجُلًا فَشَكَانِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعَيَّرْتَهُ بِأُمِّهِ ثُمَّ قَالَ إِنَّ إِخْوَانَكُمْ خَوَلُكُمْ جَعَلَهُمْ اللَّهُ تَحْتَ أَيْدِيكُمْ فَمَنْ كَانَ أَخُوهُ تَحْتَ يَدِهِ فَلْيُطْعِمْهُ مِمَّا يَأْكُلُ وَلْيُلْبِسْهُ مِمَّا يَلْبَسُ وَلَا تُكَلِّفُوهُمْ مَا يَغْلِبُهُمْ فَإِنْ كَلَّفْتُمُوهُمْ مَا يَغْلِبُهُمْ فَأَعِينُوهُمْ","id":"Telah menceritakan kepada kami [Adam bin Abi Iyas] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Washil AL Ahdab] berkata, aku mendengar [Al Ma'rur bin Suwaid] berkata; Aku pernah melihat [Abu Dzar Al Ghifari] radliallahu 'anhu yang ketika itu dia memakai pakaian yang sama (seragam) dengan budak kecilnya, kami pun bertanya kepadanya tentang masalahnya itu. Maka dia berkata: \"Aku pernah menawan seorang laki-laki lalu hal ini aku adukan kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam berkata kepadaku: \"Apakah kamu menjelek-jelekkkannya karena ibunya?\" Beliau bersabda: \"Sesungguhnya saudara-saudara kalian adalah tanggungan kalian, Allah menjadikan mereka dibawah tangan kalian, maka siapa yang saudaranya berada di tangannya hendaklah dia memberi makan dari apa yang dia makan dan memberi pakaian dari pakaian yang ia pakai dan janganlah kalian membebani mereka dengan apa yang mereka tidak sanggup. Jika kalian membebani mereka denagn apa yang mereka tidak sanggup maka bantulah mereka\". "},"2360":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَبْدُ إِذَا نَصَحَ سَيِّدَهُ وَأَحْسَنَ عِبَادَةَ رَبِّهِ كَانَ لَهُ أَجْرُهُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang hamba jika setia kepada tuannya dan beribadah dengan baik kepada Tuhannya maka baginya mendapat dua pahala\"."},"2361":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ صَالِحٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ كَانَتْ لَهُ جَارِيَةٌ فَأَدَّبَهَا فَأَحْسَنَ تَأْدِيبَهَا وَأَعْتَقَهَا وَتَزَوَّجَهَا فَلَهُ أَجْرَانِ وَأَيُّمَا عَبْدٍ أَدَّى حَقَّ اللَّهِ وَحَقَّ مَوَالِيهِ فَلَهُ أَجْرَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Shalih] dari [Asy-Sya'biy] dari [Abu Burdah] dari [Abu Musa Al Asy'ariy radliallahu 'anhu] berkata, Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa saja dari seseorang yang memiliki seorang budak wanita lalu dididiknya dengan sebaik-baik pendidikan, kemudian dibebaskannya lalu dinikahinya maka baginya mendapat dua pahala, dan siapa saja dari seorang hamba yang menunaikan hak Allah dan hak tuannya maka baginya mendapat dua pahala.\""},"2362":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبْدِ الْمَمْلُوكِ الصَّالِحِ أَجْرَانِ وَالَّذِي نَفْسِي بِيَدِهِ لَوْلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ وَالْحَجُّ وَبِرُّ أُمِّي لَأَحْبَبْتُ أَنْ أَمُوتَ وَأَنَا مَمْلُوكٌ","id":"Telah menceritakan kepada kami [Bisyir bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy]; aku mendengar [Sa'id bin Al Musayyab] berkata; [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Untuk hamba sahaya yang shalih baginya dua pahala. Demi Dzat yang jiwaku berada di tangan-Nya, kalaulah bukan karena (keutamaan) jihad fii sabiilillah, hajji dan berbuat baik kepada ibuku tentu aku lebih meyukai mati sedangkan aku sebagai seorang budak\". "},"2363":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْأَعْمَشِ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ مَا لِأَحَدِهِمْ يُحْسِنُ عِبَادَةَ رَبِّهِ وَيَنْصَحُ لِسَيِّدِهِ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Abu Usamah] dari [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] berkata, Nabi shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik harta yang dimiliki seseorang adalah beribadah kepada Tuhannya dengan baik dan setia kepada tuanya\". "},"2364":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَصَحَ الْعَبْدُ سَيِّدَهُ وَأَحْسَنَ عِبَادَةَ رَبِّهِ كَانَ لَهُ أَجْرُهُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba sahaya setia kepada tuannya dan beribadah dengan baik kepada Tuhannya, maka baginya mendapat dua pahala\"."},"2365":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَمْلُوكُ الَّذِي يُحْسِنُ عِبَادَةَ رَبِّهِ وَيُؤَدِّي إِلَى سَيِّدِهِ الَّذِي لَهُ عَلَيْهِ مِنْ الْحَقِّ وَالنَّصِيحَةِ وَالطَّاعَةِ لَهُ أَجْرَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Alaa'] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang budak sahaya yang beribadah dengan baik kepada Tuhannya dan memenuhi hak-hak tuannya, sekaligus memenuhi kesetiaan dan ketaatan, maka baginya mendapat dua pahala\"."},"2366":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَقُلْ أَحَدُكُمْ أَطْعِمْ رَبَّكَ وَضِّئْ رَبَّكَ اسْقِ رَبَّكَ وَلْيَقُلْ سَيِّدِي مَوْلَايَ وَلَا يَقُلْ أَحَدُكُمْ عَبْدِي أَمَتِي وَلْيَقُلْ فَتَايَ وَفَتَاتِي وَغُلَامِي","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami ['Abdur RAzzaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] menceritakan dari Nabi shallallahu 'alaihi wasallam, Beliau bersabda: \"Janganlah seorang dari kalian memerintahkan (budaknya) dengan kalimat; Hidangkanlah makanan untuk rabb kamu, wudhukanlah rabbmu, sajikanlah minuman untuk rabbmu tapi hendaklah dia berkata dengan kalimat sayyidku, maulaku (pemeliharaku). Dan janganlah seorang dari kalian mengatakan 'abdiy (budak laki-laki) ku, atau amatiy (budak perempuan) ku tapi katakanlah: pemudaku, pemudiku dan ghulamku\"."},"2367":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ نَصِيبًا لَهُ مِنْ الْعَبْدِ فَكَانَ لَهُ مِنْ الْمَالِ مَا يَبْلُغُ قِيمَتَهُ يُقَوَّمُ عَلَيْهِ قِيمَةَ عَدْلٍ وَأُعْتِقَ مِنْ مَالِهِ وَإِلَّا فَقَدْ عَتَقَ مِنْهُ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Jarir bin HAzim] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membebaskan seorang budak yang dimilki secara berserikat, sedangkan dia memiliki harta yang dapat membayar harganya, maka budak tersebut harganya ditaksir secara adil, lalu dibebaskan dari hartanya itu. Kalaulah tidak, berarti ia telah membebaskan hak kepemilikannya\". "},"2368":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّكُمْ رَاعٍ فَمَسْئُولٌ عَنْ رَعِيَّتِهِ فَالْأَمِيرُ الَّذِي عَلَى النَّاسِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْهُمْ وَالرَّجُلُ رَاعٍ عَلَى أَهْلِ بَيْتِهِ وَهُوَ مَسْئُولٌ عَنْهُمْ وَالْمَرْأَةُ رَاعِيَةٌ عَلَى بَيْتِ بَعْلِهَا وَوَلَدِهِ وَهِيَ مَسْئُولَةٌ عَنْهُمْ وَالْعَبْدُ رَاعٍ عَلَى مَالِ سَيِّدِهِ وَهُوَ مَسْئُولٌ عَنْهُ أَلَا فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidulloh] berkata, telah menceritakan kepadaku [Nafi'] dari ['Abdullah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap kalian adalah pemimpin dan akan diminta pertanggung jawaban atas yang dipimpinnya. Amir (kepala Negara), dia adalah pemimpin manusia secara umum, maka dia akan diminta pertanggung jawaban atas mereka. Seorang suami dalam keluarganya adalah pemimpin dan akan diminta pertanggung jawaban atas mereka. Seorang isteri adalah pemimpin di dalam rumah tangga suaminya dan terhadap anak-anaknya dan dia akan diminta pertanggung jawaban atas mereka. Seorang hamba sahaya adalah pemimpin dalam urusan harta tuannya dia akan diminta pertanggung jawaban atasnya. Ketahuilah bahwa setiap kalian adalah pemimipin dan setiap kalian akan diminta pertanggung jawaban atas siapa yang dipimpinnya \"."},"2369":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ حَدَّثَنِي عُبَيْدُ اللَّهِ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ وَزَيْدَ بْنَ خَالِدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا زَنَتْ الْأَمَةُ فَاجْلِدُوهَا ثُمَّ إِذَا زَنَتْ فَاجْلِدُوهَا ثُمَّ إِذَا زَنَتْ فَاجْلِدُوهَا فِي الثَّالِثَةِ أَوْ الرَّابِعَةِ بِيعُوهَا وَلَوْ بِضَفِيرٍ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Sufyan] dari [Az Zuhriy] telah menceritakan kepadaku ['Ubaidullah]; aku mendengar [Abu Hurairah radliallahu 'anhu] dan [Zaid buin Khalid] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang budak wanita berzina, maka cambuklah dia kemudian jika berzina lagi maka cambuklah dia, kemudian jika berzina lagi maka cambuklah dia untuk yang ketiga kalinya atau keempat, kemudian juallah sekalipun dengan harga seuntai rambut\"."},"2370":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ زِيَادٍ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَى أَحَدَكُمْ خَادِمُهُ بِطَعَامِهِ فَإِنْ لَمْ يُجْلِسْهُ مَعَهُ فَليُنَاوِلْهُ لُقْمَةً أَوْ لُقْمَتَيْنِ أَوْ أُكْلَةً أَوْ أُكْلَتَيْنِ فَإِنَّهُ وَلِيَ عِلَاجَهُ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku [Muhammad bin Ziyad] aku mendengar [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam: \"Jika seorang dari kalian didatangi pembantunya dengan membawa makanan, lantas dia tidak mengajaknya duduk makan bersamanya, hendaklah dia berikan kepadanya satu suap atau dua suap atau satu makanan atau dua makanan, karena dia yang mendapatkan panasnya (ketika memasak) dan disebabkan dia pula makanan bisa dihidangkan\"."},"2371":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّكُمْ رَاعٍ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ فَالْإِمَامُ رَاعٍ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ وَالرَّجُلُ فِي أَهْلِهِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ وَالْمَرْأَةُ فِي بَيْتِ زَوْجِهَا رَاعِيَةٌ وَهِيَ مَسْئُولَةٌ عَنْ رَعِيَّتِهَا وَالْخَادِمُ فِي مَالِ سَيِّدِهِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ قَالَ فَسَمِعْتُ هَؤُلَاءِ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَحْسِبُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالرَّجُلُ فِي مَالِ أَبِيهِ رَاعٍ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepadaku [Salim bin 'Abdullah] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap kalian adalah pemimpin dan akan diminta pertanggung jawaban atas yang dipimpinnya. Seorang imam (kepala Negara) adalah pemimpin dan akan diminta pertanggung jawaban atas rakyatnya. Seorang suami dalam keluarganya adalah pemimpin dan akan diminta pertanggung jawaban atas orang yang dipimpinnya. Seorang isteri di dalam rumah tangga suaminya adalah pemimpin dia akan diminta pertanggung jawaban atas siapa yang dipimpinnya. Seorang pembantu dalam urusan harta tuannya adalah pemimpin dan dia akan diminta pertanggung jawaban atasnya. Dia berkata; \"Aku mendengar semuanya ini dari Nabi shallallahu 'alaihi wasallam dan aku menduga Nabi shallallahu 'alaihi wasallam juga bersabda: \"Dan seseorang dalam urusan harta ayahnya adalah pemimpin dan akan diminta pertanggung jawaban atasnya. Maka setiap kalian adalah pemimipin dan setiap kalian akan diminta pertanggung jawaban atas yang dipimpinnya \"."},"2372":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ قَالَ وَأَخْبَرَنِي ابْنُ فُلَانٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَاتَلَ أَحَدُكُمْ فَلْيَجْتَنِبْ الْوَجْهَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaidullah] telah menceritakan kepada kami [Ibnu Wahb] berkata, telah menceritakan kepadaku [Malik bin Anas] berkata, telah menceritakan kepadaku Ibnu Fulan dari [Sa'id Al Maqburiy] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam. Dan diriwayatkan pula, telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami ['Abdur RAzzaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang dari kalian berperang (membunuh) hendaklah dia menghindari wajah\"."},"2373":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّ بَرِيرَةَ جَاءَتْ تَسْتَعِينُهَا فِي كِتَابَتِهَا وَلَمْ تَكُنْ قَضَتْ مِنْ كِتَابَتِهَا شَيْئًا قَالَتْ لَهَا عَائِشَةُ ارْجِعِي إِلَى أَهْلِكِ فَإِنْ أَحَبُّوا أَنْ أَقْضِيَ عَنْكِ كِتَابَتَكِ وَيَكُونَ وَلَاؤُكِ لِي فَعَلْتُ فَذَكَرَتْ ذَلِكَ بَرِيرَةُ لِأَهْلِهَا فَأَبَوْا وَقَالُوا إِنْ شَاءَتْ أَنْ تَحْتَسِبَ عَلَيْكِ فَلْتَفْعَلْ وَيَكُونَ وَلَاؤُكِ لَنَا فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعِي فَأَعْتِقِي فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ قَالَ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَالُ أُنَاسٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ مَنْ اشْتَرَطَ شَرْطًا لَيْسَ فِي كِتَابِ اللَّهِ فَلَيْسَ لَهُ وَإِنْ شَرَطَ مِائَةَ مَرَّةٍ شَرْطُ اللَّهِ أَحَقُّ وَأَوْثَقُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] bahwa ['Aisyah radliallahu 'anha] bahwa dia mengabarkan bahwa Barirah datang meminta tolong kepadaku tentang ketetapan dirinya (untuk dibebaskan) sedang dia belum menerima ketetapan tersebut. Maka 'Aisyah radliallahu 'anha berkata, kepadanya: \"Kembalilah kamu kepada tuanmu. Jika mereka suka aku akan penuhi ketetapanmu dan perwalian kamu ada padaku, maka aku penuhi. Kemudian Barirah menceritakan hal itu kepada tuannya namun mereka menolak dan berkata: \"Jika dia mau silahkan dia berharap untuk memperolehmu, namun perwalian kamu tetap ada pada kami\". Kemudian 'Aisyah radliallahu 'anha menceritakan hali ini kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Belilah dan bebaskanlah karena perwalian menjadi milik orang yang membebaskannya\". Dia 'Urwah) berkata: Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri dan bersabda: \"Mengapa ada diantara kalian membuat persyaratan dengan syarat-syarat yang tidak ada pada Kitabulloh. Barangsiapa yang membuat persyaratan yang tidak ada pada Kitab Allah maka tidakberlaku baginya sekalipun dia membuat seratus kali persyaratan. Syarat dari Allah lebih berhak dan lebih kokoh\"."},"2374":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَرَادَتْ عَائِشَةُ أُمُّ الْمُؤْمِنِينَ أَنْ تَشْتَرِيَ جَارِيَةً لِتُعْتِقَهَا فَقَالَ أَهْلُهَا عَلَى أَنَّ وَلَاءَهَا لَنَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَمْنَعُكِ ذَلِكِ فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] berkata; \"'Aisyah, Ummul Mu'minin berniat membeli seorang budak wanita untuk dibebaskannya. Maka tuan dari budak tersebut berkata bahwa perwalian budak tersebut tetap milik kami. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hal itu janganlah menghalangi kamu, karena perwalian menjadi milik orang yang membebaskannya\"."},"2375":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْجَاءَتْ بَرِيرَةُ فَقَالَتْ إِنِّي كَاتَبْتُ أَهْلِي عَلَى تِسْعِ أَوَاقٍ فِي كُلِّ عَامٍ وَقِيَّةٌ فَأَعِينِينِي فَقَالَتْ عَائِشَةُ إِنْ أَحَبَّ أَهْلُكِ أَنْ أَعُدَّهَا لَهُمْ عَدَّةً وَاحِدَةً وَأُعْتِقَكِ فَعَلْتُ وَيَكُونَ وَلَاؤُكِ لِي فَذَهَبَتْ إِلَى أَهْلِهَا فَأَبَوْا ذَلِكَ عَلَيْهَا فَقَالَتْ إِنِّي قَدْ عَرَضْتُ ذَلِكَ عَلَيْهِمْ فَأَبَوْا إِلَّا أَنْ يَكُونَ الْوَلَاءُ لَهُمْ فَسَمِعَ بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَنِي فَأَخْبَرْتُهُ فَقَالَ خُذِيهَا فَأَعْتِقِيهَا وَاشْتَرِطِي لَهُمْ الْوَلَاءَ فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ قَالَتْ عَائِشَةُ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَمَا بَالُ رِجَالٍ مِنْكُمْ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ فَأَيُّمَا شَرْطٍ لَيْسَ فِي كِتَابِ اللَّهِ فَهُوَ بَاطِلٌ وَإِنْ كَانَ مِائَةَ شَرْطٍ فَقَضَاءُ اللَّهِ أَحَقُّ وَشَرْطُ اللَّهِ أَوْثَقُ مَا بَالُ رِجَالٍ مِنْكُمْ يَقُولُ أَحَدُهُمْ أَعْتِقْ يَا فُلَانُ وَلِيَ الْوَلَاءُ إِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata; \"Barirah datang seraya berkata: \"Aku tengah berusaha membebaskan diriku kepada tuanku dengan pembayaran sembilan waq, yang setiap tahunnya aku bayar satu waq, karenanya bantulah aku.\" Maka 'Aisyah radliallahu 'anha berkata: \"Jika tuanmu berkenan, aku bayar kepada mereka dengan satu pembayaran (cash, tunai) lalu aku bebaskan kamu dan perwalianmu menjadi milikku\". Maka Barirah pergi menemui tuannya namun mereka menolak ketentuan tersebut. Kemudian 'Aisyah radliallahu 'anha berkata: \"Sungguh aku telah menawarkan kepada mereka namun mereka menolaknya kecuali bila perwaliannya tetap menjadi milik mereka\". Hal ini didengar oleh Rasulullah shallallahu 'alaihi wasallam lalu Beliau menanyakannya kepadaku, lalu aku beri tahu Beliau maka Beliau bersabda: \"Ambillah dia lalu bebaskanlah dan ajukanlah persyaratan wala' kepada mereka karena wala' menjadi milik orang yang membebaskannya\". 'Aisyah radliallahu 'anha berkata: \"Maka kemudian Rasulullah shallallahu 'alaihi wasallam berdiri di hadapan manusia lalu memuji Allah dan mengangungkan-Nya kemudian bersabda: \"Kemudian dari pada itu, mengapakah ada orang-orang diantara kalian mereka membuat persyaratan dengan syarat-syarat yang tidak ada pada Kitabulloh. Maka syarat apa saja yang tidak ada pada Kitab Allah maka dia bathil sekalipun dengan seratus persyaratan. Ketetapan Allah dan syarat dari Allah lebih kuat. Dan apa alasannya orang-orang diantara kalian berkata: \"Bebaslah dia wahai fulan namun perwaliannya tetap milikku. Sesungguhnya perwalian menjadi milik orang yang membebaskannya\". "},"2376":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِأَنَّ بَرِيرَةَ جَاءَتْ تَسْتَعِينُ عَائِ��َةَ أُمَّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا فَقَالَتْ لَهَا إِنْ أَحَبَّ أَهْلُكِ أَنْ أَصُبَّ لَهُمْ ثَمَنَكِ صَبَّةً وَاحِدَةً فَأُعْتِقَكِ فَعَلْتُ فَذَكَرَتْ بَرِيرَةُ ذَلِكَ لِأَهْلِهَا فَقَالُوا لَا إِلَّا أَنْ يَكُونَ وَلَاؤُكِ لَنَا قَالَ مَالِكٌ قَالَ يَحْيَى فَزَعَمَتْ عَمْرَةُ أَنَّ عَائِشَةَ ذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْتَرِيهَا وَأَعْتِقِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti 'Abdurrahman] bahwa Barirah datang meminta bantuan kepada ['Aisyah Ummul Mu'minin] radliallahu 'anhu, maka 'Aisyah berkata kepadanya: \"Jika tuanmu berkenan, akan kubayar mereka harga jual kamu dengan satu pembayaran (cash, kontan) lalu aku bebaskan kamu dan perwalianmu menjadi milikku\". Maka Barirah menyampaikan hal ini kepada tuannya lalu mereka berkata: 'Tidak, kecuali bila perwalian kamu tetap milik kami\". Malik berkata, Yahya berkata; 'Amrah menduga bahwa 'Aisyah menceritakan hal ini kepada Rasulullah shallallahu 'alaihi wasallam maka Beliau bersabda: \"Kamu beli saja dia lalu bebaskanlah. Sesungguhnya perwalian menjadi milik orang yang membebaskannya\". "},"2377":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ قَالَ حَدَّثَنِي أَبِي أَيْمَنُ قَالَ دَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقُلْتُكُنْتُ غُلَامًا لِعُتْبَةَ بْنِ أَبِي لَهَبٍ وَمَاتَ وَوَرِثَنِي بَنُوهُ وَإِنَّهُمْ بَاعُونِي مِنْ عَبْدِ اللَّهِ بْنِ أَبِي عَمْرِو بْنِ عُمَرَ بْنِ عَبْدِ اللَّهِ المَخْزُومِيِّ فَأَعْتَقَنِي ابْنُ أَبِي عَمْرٍو وَاشْتَرَطَ بَنُو عُتْبَةَ الْوَلَاءَ فَقَالَتْ دَخَلَتْ بَرِيرَةُ وَهِيَ مُكَاتَبَةٌ فَقَالَتْ اشْتَرِينِي وَأَعْتِقِينِي قَالَتْ نَعَمْ قَالَتْ لَا يَبِيعُونِي حَتَّى يَشْتَرِطُوا وَلَائِي فَقَالَتْ لَا حَاجَةَ لِي بِذَلِكَ فَسَمِعَ بِذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ بَلَغَهُ فَذَكَرَ لِعَائِشَةَ فَذَكَرَتْ عَائِشَةُ مَا قَالَتْ لَهَا فَقَالَ اشْتَرِيهَا وَأَعْتِقِيهَا وَدَعِيهِمْ يَشْتَرِطُونَ مَا شَاءُوا فَاشْتَرَتْهَا عَائِشَةُ فَأَعْتَقَتْهَا وَاشْتَرَطَ أَهْلُهَا الْوَلَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَاءُ لِمَنْ أَعْتَقَ وَإِنْ اشْتَرَطُوا مِائَةَ شَرْطٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Abdul Wahid bin Aiman] berkata, telah menceritakan kepadaku bapakku [Aiman] berkata; Aku menemui ['Aisyah] lalu aku katakan: \"Aku ini dahulu adalah seorang ghulam (budak kecil) milik 'Utbah bin Abu Lahab kemudian dia mati. Lantas anak-anak mewarisiku, lalu mereka menjualku kepada 'Abdullah bin 'Amru bin 'Umar bin 'Abdullah Al Makhzumiy, kemudian Ibnu Abi 'Amru membebaskan aku namun anak-anak 'Utbah membuat persyaratan agar wala' tetap milik mereka\". Maka 'Aisyah berkata; \"Barirah pernah datang sedangkan saat itu dia sebagai budak mukatab (yang berusaha membebaskan status kebudakannya) lalu dia berkata: \"Belilah aku dan bebaskanlah\". 'Aisyah berkata: \"Ya\". Barirah berkata: \"Majikan-majikanku mereka tidak mau menjual aku hingga syarat mereka dipenuhi, yaitu wala' tetap milik mereka \". 'Aisyah berkata: \"Aku tidak tidak peduli dengan hal itu\". Kemudian Nabi shallallahu 'alaihi wasallam mendengar hal ini atau sampai kabar hal ini kepada Beliau, lalu Beliau menanyakannya kepada 'Aisyah dan 'Aisyah menyebutkan apa yang telah diucapkannya kepada Barirah. Maka Beliau bersabda: \"Belilah dia lalu bebaskanlah dan biarkanlah mereka dengan persyaratan yang mereka buat sesuka mereka. Maka 'Aisyah membelinya lalu membebaskannya sedangkan tuannya meminta perwaliannya. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Perwalian menjadi milik orang yang membebaskannya sekalipun mereka membuat seratus persyaratam\"."},"2378":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا نِسَاءَ الْمُسْلِمَاتِ لَا تَحْقِرَنَّ جَارَةٌ لِجَارَتِهَا وَلَوْ فِرْسِنَ شَاةٍ","id":"Telah menceritakan kepada kami ['Ashim bin 'Ali] telah menceritakan kepada kami [Ibnu Abi Dza'bi] dari [Al Maqburiy] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai wanita-wanita muslim, janganlah seorang budak wanita menganggap remeh memberi hadiah budak wanita lainnya sekalipun hanya sebesar kubangan karena diinjak kambing\"."},"2379":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْ لِعُرْوَةَابْنَ أُخْتِي إِنْ كُنَّا لَنَنْظُرُ إِلَى الْهِلَالِ ثُمَّ الْهِلَالِ ثَلَاثَةَ أَهِلَّةٍ فِي شَهْرَيْنِ وَمَا أُوقِدَتْ فِي أَبْيَاتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَارٌ فَقُلْتُ يَا خَالَةُ مَا كَانَ يُعِيشُكُمْ قَالَتْ الْأَسْوَدَانِ التَّمْرُ وَالْمَاءُ إِلَّا أَنَّهُ قَدْ كَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِيرَانٌ مِنْ الْأَنْصَارِ كَانَتْ لَهُمْ مَنَائِحُ وَكَانُوا يَمْنَحُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَلْبَانِهِمْ فَيَسْقِينَا","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah Al Awaisiy] telah menceritakan kepada kami [Ibnu Abi HAzim] dari [bapaknya] dari [YAzid bin Ruman] dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa dia berkata, kepada 'Urwah anak dari saudara perempuannya: \"Sesungguhnya kami memperhatikan hilal kemudian hilal untuk ketiga kalinya dalam satu bulan dan tidak ada api yang dinyalakan di rumah-rumah Rasulullah shallallahu 'alaihi wasallam. Aku berkata: \"Wahai bibi, apa yang dapat menjadikan kalian bertahan hidup?\". Dia berkata: \"Dua hal yang hitam, kurma dan air. Selain itu Rasulullah shallallahu 'alaihi wasallam mempunyai dua tetangga dari kalangan Anshar, yang mereka memiliki anak unta yang dapat diambil air susunya untuk Rasulullah shallallahu 'alaihi wasallam, lalu kedua tetangga itu memberi kami minum\". "},"2380":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ دُعِيتُ إِلَى ذِرَاعٍ أَوْ كُرَاعٍ لَأَجَبْتُ وَلَوْ أُهْدِيَ إِلَيَّ ذِرَاعٌ أَوْ كُرَاعٌ لَقَبِلْتُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ibnu Abi 'Abdiy] dari [Syu'bah] dari [Sulaiman] dari [Abu HAzim] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Seandainya aku diundang untuk jamuan makan sebesar satu paha depan (kambing) atau satu paha belakangnya, pasti aku penuhi dan seandainya aku diberi hadiah makanan satu paha depan (kambing) atau satu paha belakang pasti aku terima\". "},"2381":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَ إِلَى امْرَأَةٍ مِنْ الْمُهَاجِرِينَ وَكَانَ لَهَا غُلَامٌ نَجَّارٌ قَالَ لَهَا مُرِي عَبْدَكِ فَلْيَعْمَلْ لَنَا أَعْوَادَ الْمِنْبَرِ فَأَمَرَتْ عَبْدَهَا فَذَهَبَ فَقَطَعَ مِنْ الطَّرْفَاءِ فَصَنَعَ لَهُ مِنْبَرًا فَلَمَّا قَضَاهُ أَرْسَلَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ قَدْ قَضَاهُ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلِي بِهِ إِلَيَّ فَجَاءُوا بِهِ فَاحْتَمَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعَهُ حَيْثُ تَرَوْنَ","id":"Telah menceritakan kepada kami [Ibnu Abi Maryam] telah menceritakan kepada kami [Abu Ghossan] berkata, telah menceritakan kepadaku [Abu HAzim] dari [Sahal radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam mengutus seorang wanita Muhajirin yang wanita ini memiliki ghulam yang pandai olah mengolah kayu. Beliau berkata kepadanya; \"Perintahkanlah sahayamu agar membuatkan mimbar untuk kami\". Maka wanita itu memerintahkan ghulamnya. Maka ghulam itu pergi mencari kayu di hutan lalu dia membuat mimbar untuk Beliau. Ketika dia telah menyelesaikan pekerjaannya wanita itu mengirim mimbar tersebut kepada Nabi shallallahu 'alaihi wasallam. Beliau shallallahu 'alaihi wasallam berkata: \"Bawalah mimbar itu kepadaku\". Lalu orang-orang datang dengan membawa mimbar tersebut kemudian Nabi shallallahu 'alaihi wasallam menempatkan mimbar tersebut pada tempat yang sekarang kalian lihat."},"2382":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ أَبِي حَازِمٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ السَّلَمِيِّ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ يَوْمًا جَالِسًا مَعَ رِجَالٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَنْزِلٍ فِي طَرِيقِ مَكَّةَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَازِلٌ أَمَامَنَا وَالْقَوْمُ مُحْرِمُونَ وَأَنَا غَيْرُ مُحْرِمٍ فَأَبْصَرُوا حِمَارًا وَحْشِيًّا وَأَنَا مَشْغُولٌ أَخْصِفُ نَعْلِي فَلَمْ يُؤْذِنُونِي بِهِ وَأَحَبُّوا لَوْ أَنِّي أَبْصَرْتُهُ وَالْتَفَتُّ فَأَبْصَرْتُهُ فَقُمْتُ إِلَى الْفَرَسِ فَأَسْرَجْتُهُ ثُمَّ رَكِبْتُ وَنَسِيتُ السَّوْطَ وَالرُّمْحَ فَقُلْتُ لَهُمْ نَاوِلُونِي السَّوْطَ وَالرُّمْحَ فَقَالُوا لَا وَاللَّهِ لَا نُعِينُكَ عَلَيْهِ بِشَيْءٍ فَغَضِبْتُ فَنَزَلْتُ فَأَخَذْتُهُمَا ثُمَّ رَكِبْتُ فَشَدَدْتُ عَلَى الْحِمَارِ فَعَقَرْتُهُ ثُمَّ جِئْتُ بِهِ وَقَدْ مَاتَ فَوَقَعُوا فِيهِ يَأْكُلُونَهُ ثُمَّ إِنَّهُمْ شَكُّوا فِي أَكْلِهِمْ إِيَّاهُ وَهُمْ حُرُمٌ فَرُحْنَا وَخَبَأْتُ الْعَضُدَ مَعِي فَأَدْرَكْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْنَاهُ عَنْ ذَلِكَ فَقَالَ مَعَكُمْ مِنْهُ شَيْءٌ فَقُلْتُ نَعَمْ فَنَاوَلْتُهُ الْعَضُدَ فَأَكَلَهَا حَتَّى نَفِدَهَا وَهُوَ مُحْرِمٌفَحَدَّثَنِي بِهِ زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي قَتَادَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepadaku [Muhammad bin Ja'far] dari [Abu HAzim] dari ['Abdullah bin Abu Qatadah as-Salamiy] dari [bapaknya radliallahu 'anhu] berkata: \"Pada suatu hari aku pernah duduk-duduk bermajelis dengan para sahabat Nabi shallallahu 'alaihi wasallam di suatu rumah yang terletak di jalan menuju Makkah. Saat itu Rasulullah shallallahu 'alaihi wasallam singgah di depan kami sementara orang-orang sedang berihram sedangkan aku tidak. Tiba-tiba mereka melihat seekor keledai liar sementara aku sedang sibuk memperbaiki sandalku dan mereka tidak mau mengganggu aku dengan kehadiran keledai itu padahal mereka sangat ingin agar aku juga melihatnya. Maka sejenak kemudian aku melihat keledai itu lalu aku bangkit menuju kuda dan memasang pelananya kemudian aku menunggang kuda tersebut namun aku lupa cambuk dan tombak. Maka aku katakan kepada mereka: \"Berikan cambuk dan tombak itu kepadaku\". Mereka menjawab: \"Tidak, kami tidak akan membantu kamu dalam mengejar keledai tersebut\". Maka aku marah lalu aku turun dan mengambil cambuk dan tombak tersebut kemudian aku kembali menunggang kuda dan aku kejar keledai tersebut hingga aku dapat melukainya. Kemudian aku datang membawa keledai itu dalam keadaan sudah mati. Akhirnya mereka menerima bahkan memakan dagingnya. Kemudian mereka menjadi ragu dalam memakannya karena mereka sedang berihram. Kemudian kami berangkat dan aku menyembunyikan satu potong paha depan yang ada di tanganku hingga kami bertemu dengan Rasulullah shallallahu 'alaihi wasallam. Maka kami menanyakan kejadian tadi kepada Beliau. Maka Beliau bertanya: \"Apakah masih ada yang tersisa darinya?\". Aku jawab: \"Ya masih\". Maka aku sodorkan paha depan keledai tersebut lalu Beliau memakannya hingga habis sedang Beliau dalam keadaan berihram\". Dan [Zaid bin Aslam] telah menceritakan kepadaku dari ['Atha' bin Yasar] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam."},"2383":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَن��ي أَبُو طُوَالَةَ اسْمُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ يَقُولُأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي دَارِنَا هَذِهِ فَاسْتَسْقَى فَحَلَبْنَا لَهُ شَاةً لَنَا ثُمَّ شُبْتُهُ مِنْ مَاءِ بِئْرِنَا هَذِهِ فَأَعْطَيْتُهُ وَأَبُو بَكْرٍ عَنْ يَسَارِهِ وَعُمَرُ تُجَاهَهُ وَأَعْرَابِيٌّ عَنْ يَمِينِهِ فَلَمَّا فَرَغَ قَالَ عُمَرُ هَذَا أَبُو بَكْرٍ فَأَعْطَى الْأَعْرَابِيَّ فَضْلَهُ ثُمَّ قَالَ الْأَيْمَنُونَ الْأَيْمَنُونَ أَلَا فَيَمِّنُوا قَالَ أَنَسٌ فَهِيَ سُنَّةٌ فَهِيَ سُنَّةٌ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepadaku [Sulaiman bin Bilal] berkata, telah menceritakan kepadaku [Abu Thuwailah], yang namana adalah 'Abdullah bin 'Abdurrahman berkata; Aku mendengar [Anas radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam datang bertamu di rumah kami ini dan Beliau meminta minum. Maka kami siapkan susu dari hasil perasan kambing kami yang kami campur dengan air dari sumur kami ini lalu kami sugukan kepada Beliau. Saat itu Abu Bakar duduk di samping kiri Beliau sedangkan 'Umar di hadapan Beliau sementara ada seorang 'Arab Baduy di sebelah kanan Beliau. Ketika Beliau sudah selesai minum, 'Umar berkata: \"Ini ada Abu Bakar, (berikanlah kepadanya). Namun Beliau memberikan susu itu kepada orang Baduy tadi karena yang berhak atas gilirannya, seraya beliau sabdakan: \"Ke sebelah kanan dan ke kanan, ketahuilah dahulukanlah yang kanan\". Anas berkata: \"Ini adalah sunnah, ini adalah sunnah\". Diucapkannya tiga kali."},"2384":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدِ بْنِ أَنَسِ بْنِ مَالِكٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَنْفَجْنَا أَرْنَبًا بِمَرِّ الظَّهْرَانِ فَسَعَى الْقَوْمُ فَلَغَبُوا فَأَدْرَكْتُهَا فَأَخَذْتُهَا فَأَتَيْتُ بِهَا أَبَا طَلْحَةَ فَذَبَحَهَا وَبَعَثَ بِهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَرِكِهَا أَوْ فَخِذَيْهَا قَالَ فَخِذَيْهَا لَا شَكَّ فِيهِ فَقَبِلَهُ قُلْتُ وَأَكَلَ مِنْهُ قَالَ وَأَكَلَ مِنْهُ ثُمَّ قَالَ بَعْدُ قَبِلَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid bin Anas bin Malik] dari [Anas radliallahu 'anhu] berkata: \"Kami pernah disibukkan untuk menangkap kelinci di lembah Marru Azh-Zhohran, orang-orang berusaha menangkapnya hingga mereka keletihan. Kemudian aku bisa menangkapnya lalu aku bawa menghadap Abu Tholhah. Maka dia menyembelihnya kemudian dikirim daging paha depannya atau paha belakangnya kepada Rasulullah shallallahu 'alaihi wasallam. Dia (Anas) berkata: \"Daging pahanya dan tidak diragukan lagi. Lalu Beliau menerimanya\". Aku bertanya: \"Apakah Beliau memakannya?\". Dia berkata: \"Ya Beliau memakannya\". Kemudian dia sambung: \"Setelah menerimanya\"."},"2385":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ الصَّعْبِ بْنِ جَثَّامَةَ رَضِيَ اللَّهُ عَنْهُمْأَنَّهُ أَهْدَى لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِمَارًا وَحْشِيًّا وَهُوَ بِالْأَبْوَاءِ أَوْ بِوَدَّانَ فَرَدَّ عَلَيْهِ فَلَمَّا رَأَى مَا فِي وَجْهِهِ قَالَ أَمَا إِنَّا لَمْ نَرُدَّهُ عَلَيْكَ إِلَّا أَنَّا حُرُمٌ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] dari ['Abdullah bin 'Abbas] dari [As Sha'bi bin Jatstsamah] radliallahu 'anhum bahwa dia menghadiahkan Rasulullah shallallahu 'alaihi wasallam seekor keledai liar di Abwa; atau di Waddan namun Beliau menolaknya. Ketika Beliau melihat raut mukanya, Beliau berkata: \"Kami tidak bermaksud menolak keledai tersebut, tapi kami menolaknya karena kami sedang ihram\"."},"2386":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا عَبْدَةُ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّاسَ كَانُوا يَتَحَرَّوْنَ بِهَدَايَاهُمْ يَوْمَ عَائِشَةَ يَبْتَغُونَ بِهَا أَوْ يَبْتَغُونَ بِذَلِكَ مَرْضَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami ['Abdah] telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa orang-orang memilih barang yang terbaik sebagai hadiah dari mereka untuk hari pernikahan 'Aisyah dengan tujuan mengharap ridha Rasulullah shallallahu 'alaihi wasallam. "},"2387":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا جَعْفَرُ بْنُ إِيَاسٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَهْدَتْ أُمُّ حُفَيْدٍ خَالَةُ ابْنِ عَبَّاسٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقِطًا وَسَمْنًا وَأَضُبًّا فَأَكَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَقِطِ وَالسَّمْنِ وَتَرَكَ الضَّبَّ تَقَذُّرًا قَالَ ابْنُ عَبَّاسٍ فَأُكِلَ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوْ كَانَ حَرَامًا مَا أُكِلَ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Ja'far bin Iyas] berkata, aku mendengar [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Ummu Hufaid, bibi dari Ibnu 'Abbas menghadiahkan kepada Nabi shallallahu 'alaihi wasallam keju, minyak samin dan daging biawak. Maka Nabi shallallahu 'alaihi wasallam memakan keju dan minyak samin tapi membiarkan daging biawak karena tidak menyukainya\". Ibnu 'Abbas berkata: \"Semua itu dihidangkan pada makanan Rasulullah shallallahu 'alaihi wasallam, seandainya diharamkan tentu tidak akan dihidangkan pada makanan Rasulullah shallallahu 'alaihi wasallam \". "},"2388":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُتِيَ بِطَعَامٍ سَأَلَ عَنْهُ أَهَدِيَّةٌ أَمْ صَدَقَةٌ فَإِنْ قِيلَ صَدَقَةٌ قَالَ لِأَصْحَابِهِ كُلُوا وَلَمْ يَأْكُلْ وَإِنْ قِيلَ هَدِيَّةٌ ضَرَبَ بِيَدِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَ مَعَهُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Ma'an] berkata, telah menceritakan kepadaku [Ibrahim bin Thohman] dari [Muhammad bin Ziyad] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Adalah Rasulullah shallallahu 'alaihi wasallam apabila diberikan makanan, Beliau bertanya tentangnya, apakah ini sebagai hadiah atau shadaqah?\". Jika dijawab shadaqah maka Beliau berkata kepada para sahabat Beliau; \"Makanlah\". Dan Beliau tidak ikut makan\". Namun bila dikatakan hadiah, maka Beliau mengulurkan tangan Beliau lalu makan bersama mereka.\" "},"2389":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمٍ فَقِيلَ تُصُدِّقَ عَلَى بَرِيرَةَ قَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam pernah diberikan daging lalu dikatakan bahwa daging itu adalah shadaqah yang diterima Barirah. Maka Beliau berkata: \"Daging ini baginya shadaqah (zakat) dan bagi kita ini sebagai hadiah.\""},"2390":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ قَالَ سَمِعْتُهُ مِنْهُ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا أَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ وَأَنَّهُمْ اشْتَرَطُوا وَلَاءَهَا فَذُكِرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرِيهَا فَأَعْتِقِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ وَأُهْدِيَ لَهَا لَحْمٌ فَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا تُصُدِّقَ عَلَى بَرِيرَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ وَخُيِّرَتْقَالَ عَبْدُ الرَّحْمَنِ زَوْجُهَا حُرٌّ أَوْ عَبْدٌ قَالَ شُعْبَةُ سَأَلْتُ عَبْدَ الرَّحْمَنِعَنْ زَوْجِهَا قَالَ لَا أَدْرِي أَحُرٌّ أَمْ عَبْدٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari ['Abdur Rahman bin Al Qasim] berkata, aku mendengar cerita ini dari [Al Qasim] dari ['Aisyah radliallahu 'anha] bahwa dia berkehendak untuk membeli Barirah sementara mereka (tuannya) memberi persyaratan bahwa wala' tetap ada pada mereka. Kemudian hal diceritakan kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam berkata: \"Belilah kemudian bebaskanlah, karena hak perwalian bagi orang yang membebaskannya\". Kemudian Barirah diberi zakat berupa daging lalu dikatakan kepada Nabi shallallahu 'alaihi wasallam: 'Ini shadaqah yang diterima Barirah\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Daging ini baginya shadaqah (zakat) dan bagi kita ini sebagai hadiah\". Maka Barirah memilih untuk dirinya. 'AbdurRahman berkata: \"Suaminya orang merdeka atau budak sahaya?\" Syu'bah berkata: \"Aku bertanya kepada 'Abdurrahman tentang suaminya, maka dia menjawab: \"Aku tidak tahu apakah suaminya orang merdeka atau budak sahaya\". "},"2391":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَ عِنْدَكُمْ شَيْءٌ قَالَتْ لَا إِلَّا شَيْءٌ بَعَثَتْ بِهِ أُمُّ عَطِيَّةَ مِنْ الشَّاةِ الَّتِي بَعَثْتَ إِلَيْهَا مِنْ الصَّدَقَةِ قَالَ إِنَّهَا قَدْ بَلَغَتْ مَحِلَّهَا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abu Al Hasan] telah mengabarkan kepada kami [Khalid bin 'Abdullah] dari [Khalid Al Hadzdza'] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah] berkata: \"Nabi shallallahu 'alaihi wasallam datang menemui 'Aisyah radliallahu 'anha seraya berkata: \"Apakah kalian masih memilliki sesuatu (untuk dimakan)?\". 'Aisyah berkata: \"Tidak, kecuali sesuatu yang dikirim oleh Ummu 'Athiyyah dari daging kambing yang engkau kirim kepadanya sebagai shadaqah\". Beliau bersabda: \"Shadaqah itu berarti sudah sampai pada tempatnya\"."},"2392":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّاسُ يَتَحَرَّوْنَ بِهَدَايَاهُمْ يَوْمِي وَقَالَتْ أُمُّ سَلَمَةَ إِنَّ صَوَاحِبِي اجْتَمَعْنَ فَذَكَرَتْ لَهُ فَأَعْرَضَ عَنْهَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata: \"Orang-orang memilih barang yang terbaik sebagai hadiah dari mereka untuk hari pernikahanku\". Dan Ummu Salamah berkata: \"Kemudian para shahaabiyah (isteri-isteri Beliau) berkumpul lalu dia ingin menceritakan hal itu kepada Beliau, namun Beliau menolaknya.\""},"2393":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ نِسَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنَّ حِزْبَيْنِ فَحِزْبٌ فِيهِ عَائِشَةُ وَحَفْصَةُ وَصَفِيَّةُ وَسَوْدَةُ وَالْحِزْبُ الْآخَرُ أُمُّ سَلَمَةَ وَسَائِرُ نِسَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ الْمُسْلِمُ��نَ قَدْ عَلِمُوا حُبَّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَائِشَةَ فَإِذَا كَانَتْ عِنْدَ أَحَدِهِمْ هَدِيَّةٌ يُرِيدُ أَنْ يُهْدِيَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَّرَهَا حَتَّى إِذَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ عَائِشَةَ بَعَثَ صَاحِبُ الْهَدِيَّةِ بِهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ عَائِشَةَ فَكَلَّمَ حِزْبُ أُمِّ سَلَمَةَ فَقُلْنَ لَهَا كَلِّمِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَلِّمُ النَّاسَ فَيَقُولُ مَنْ أَرَادَ أَنْ يُهْدِيَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَدِيَّةً فَلْيُهْدِهِ إِلَيْهِ حَيْثُ كَانَ مِنْ بُيُوتِ نِسَائِهِ فَكَلَّمَتْهُ أُمُّ سَلَمَةَ بِمَا قُلْنَ فَلَمْ يَقُلْ لَهَا شَيْئًا فَسَأَلْنَهَا فَقَالَتْ مَا قَالَ لِي شَيْئًا فَقُلْنَ لَهَا فَكَلِّمِيهِ قَالَتْ فَكَلَّمَتْهُ حِينَ دَارَ إِلَيْهَا أَيْضًا فَلَمْ يَقُلْ لَهَا شَيْئًا فَسَأَلْنَهَا فَقَالَتْ مَا قَالَ لِي شَيْئًا فَقُلْنَ لَهَا كَلِّمِيهِ حَتَّى يُكَلِّمَكِ فَدَارَ إِلَيْهَا فَكَلَّمَتْهُ فَقَالَ لَهَا لَا تُؤْذِينِي فِي عَائِشَةَ فَإِنَّ الْوَحْيَ لَمْ يَأْتِنِي وَأَنَا فِي ثَوْبِ امْرَأَةٍ إِلَّا عَائِشَةَ قَالَتْ فَقَالَتْ أَتُوبُ إِلَى اللَّهِ مِنْ أَذَاكَ يَا رَسُولَ اللَّهِ ثُمَّ إِنَّهُنَّ دَعَوْنَ فَاطِمَةَ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُ إِنَّ نِسَاءَكَ يَنْشُدْنَكَ اللَّهَ الْعَدْلَ فِي بِنْتِ أَبِي بَكْرٍ فَكَلَّمَتْهُ فَقَالَ يَا بُنَيَّةُ أَلَا تُحِبِّينَ مَا أُحِبُّ قَالَتْ بَلَى فَرَجَعَتْ إِلَيْهِنَّ فَأَخْبَرَتْهُنَّ فَقُلْنَ ارْجِعِي إِلَيْهِ فَأَبَتْ أَنْ تَرْجِعَ فَأَرْسَلْنَ زَيْنَبَ بِنْتَ جَحْشٍ فَأَتَتْهُ فَأَغْلَظَتْ وَقَالَتْ إِنَّ نِسَاءَكَ يَنْشُدْنَكَ اللَّهَ الْعَدْلَ فِي بِنْتِ ابْنِ أَبِي قُحَافَةَ فَرَفَعَتْ صَوْتَهَا حَتَّى تَنَاوَلَتْ عَائِشَةَ وَهِيَ قَاعِدَةٌ فَسَبَّتْهَا حَتَّى إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَنْظُرُ إِلَى عَائِشَةَ هَلْ تَكَلَّمُ قَالَ فَتَكَلَّمَتْ عَائِشَةُ تَرُدُّ عَلَى زَيْنَبَ حَتَّى أَسْكَتَتْهَا قَالَتْ فَنَظَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَائِشَةَ وَقَالَ إِنَّهَا بِنْتُ أَبِي بَكْرٍقَالَ الْبُخَارِيُّ الْكَلَامُ الْأَخِيرُ قِصَّةُ فَاطِمَةَ يُذْكَرُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ رَجُلٍ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ وَقَالَ أَبُو مَرْوَانَ عَنْ هِشَامٍ عَنْ عُرْوَةَ كَانَ النَّاسُ يَتَحَرَّوْنَ بِهَدَايَاهُمْ يَوْمَ عَائِشَةَ وَعَنْ هِشَامٍ عَنْ رَجُلٍ مِنْ قُرَيْشٍ وَرَجُلٍ مِنَ المَوَالِي عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ قَالَتْ عَائِشَةُ كُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَتْ فَاطِمَةُ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [saudaraku] dari [Sulaiman] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa isteri-isteri Rasulullah shallallahu 'alaihi wasallam terbagi menjadi dua kubu. Kubu pertama adalah terdiri 'Aisyah, Hafshah, Shafiyyah, Sawdah. Dan kelompok kedua diikutsertai oleh Ummu Salamah dan isri-isteri Rasulullah shallallahu 'alaihi wasallam yang lain. Saat itu Kaum Muslimun mengetahui kalau Rasulullah shallallahu 'alaihi wasallam sangat mencintai 'Aisyah. Apabila salah seorang dari mereka memiliki hadiah yang akan dihadiahkan untuk Rasulullah shallallahu 'alaihi wasallam, dia menangguhkannya. Ketika Rasulullah shallallahu 'alaihi wasallam sudah berada di rumah 'Aisyah, barulah pemilik hadiah mengirim hadiahnya kepada Rasulullah shallallahu 'alaihi wasallam di rumah 'Aisyah radliallahu 'anha. Kebiasaan ini menbuat kelompok 'Ummu Salamah memperbincangkannya. Mereka berkata, kepada Ummu Salamah; \"Coba kamu bicara kepada Rasulullah shallallahu 'alaihi wasallam agar beliau menyampaikan kepada orang banyak bahwa siapa yang hendak memberi hadiah kepada Rasulullah shallallahu 'alaihi wasallam hendaklah hadiah itu diberikan kepada beliau dimana saja saat beliau berada di rumah-rumah isteri beliau\". Maka Ummu Salamah menyampaikan apa yang dikatakan oleh mereka kepada beliau namun beliau tidak berkomentar sepatah katapun kepadanya. Kemudian kami tanyakan kepadanya, maka dia berkata,; \"Beliau tidak berkata, sepatah kata pun kepadaku\". Lalu mereka kembali berkata,; \"Coba berbicaralah kembali dengan beliau\". Maka Ummu Salamah kembali mengajak beliau berbicara saat giliran beliau di rumahnya namun beliau tetap tidak berkata sepatah katapun kepadanya. Kemudian kami tanyakan kepadanya, maka dia berkata,; \"Beliau tidak berbicara sepatah kata pun kepadaku\". Lalu mereka kembali berkata,; \"Berbicaralah dengan beliau hingga beliau mau berbicara denganmu?\". Kemudian ketika giliran beliau di rumahnya, Ummu Salamah mengajak bicara beliau, maka beliau shallallahu 'alaihi wasallam berkata kepadanya: \"Jangan kamu sakiti aku dalam masalah 'Aisyah, karena tidak satu wahyu pun yang turun kepadaku saat aku berada dalam pakaian seorang isteri kecuali 'Aisyah\". 'Aisyah berkata,; \"Maka Ummu Salamah berkata,; Aku bertobat kepada Allah karena telah menyakitimu wahai Rasulullah?\". Kemudian isteri-isteri Beliau memanggil Fathimah, putri Rasulullah shallallahu 'alaihi wasallam untuk mengutusnya menemui Rasulullah shallallahu 'alaihi wasallam dan mereka berpesan; \"Katakanlah kepada beliau, sesungguhnya isteri-isteri ayahanda mencari keadilan Allah kepada ayahanda dalam perkara putri Abu Bakar\". Maka Fathimah menyampaikannya. Lalu beliau berkata,: \"Wahai ananda, apakah kamu menyukai sesuatu yang aku sukai?\". Fathimah menjawab; \"Ya tentu\". Maka Fathimah menemui mereka seraya mengabarkan kepada mereka. Maka mereka berkata,; 'Kembalilah menemui beliau\". Namun Fathimah enggan untuk kembali. Akhirnya mereka mengutus Zainab binti Jahsyi. Maka Zainab menemui beliau dengan perkataan yang keras, katanya: \"Sesungguhnya isteri-isteri anda mencari keadilan Allah kepada anda dalam perkara putri Ibnu Abi Quhafah\". Dia mengeraskan suaranya hingga sampai kepada 'Aisyah yang saat itu dia sedang duduk lalu dia mencelanya hingga Rasulullah shallallahu 'alaihi wasallam memandang 'Aisyah apakah 'Aisyah akan membalasnya. Maka 'Aisyah membalas apa yang ducapkan Zainab hingga membuatnya berhenti. Dia (Fathimah) berkata,; \"Maka Nabi shallallahu 'alaihi wasallam memandang kepada 'Aisyah dan berkata: \"Dia ini adalah putri dari Abu Bakar\". Al Bukhari berkata,; \"Kalimat terakhir ini adalah kisah Fathimah yang diceritakan oleh [Hisyam bin 'Urwah] dari [seseorang] dari [Az Zuhriy] dari [Muhammad bin 'Abdurrahman]. Dan berkata, [Abu Marwan] dari [Hisyam] dari ['Urwah]; \"Bahwa orang-orang memilih barang yang terbaik sebagai hadiah dari mereka untuk hari pernikahan 'Aisyah\". Dan dari [Hisyam] dari [seseorang kalangan Quraisy] dari [seorang dari suku Al Mawaliy] dari [Az Zuhriy] dari [Muhammad bin 'Abdurrahman bin Al Harits bin Hisyam]; ['Aisyah radliallahu 'anha] berkata,; 'Aku sedang bersama Nabi shallallahu 'alaihi wasallam lalu datang Fathimah meminta izin masuk\"."},"2394":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي ثُمَامَةُ بْنُ عَبْدِ اللَّهِ قَالَ دَخَلْتُ عَلَيْهِ فَنَاوَلَنِي طِيبًا قَالَ كَانَ أَنَسٌ رَضِيَ اللَّهُ عَنْهُ لَا يَرُدُّ الطِّيبَ قَالَ وَزَعَمَ أَنَسٌأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَرُدُّ الطِّيبَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami ['Azrah bin Tsabit Al Anshariy] berkata, telah menceritakan kepadaku [Tsumamah bin 'Abdullah] berkata; \"Aku menemuinya lalu ia menyodorkan minyak wangi kepadaku seraya berkata; Anas radliallahu 'anhu tidak menolak minyak wangi\". Dia berkata; \"Dan [Anas] yakin bahwa Nabi shallallahu 'alaihi wasallam tidak menolak jika ditawarkan minyak wangi\"."},"2395":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ ذَكَرَ عُرْوَةُ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ رَضِيَ اللَّهُ عَنْهُمَا وَمَرْوَانَ أَخْبَرَاهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ جَاءَهُ وَفْدُ هَوَازِنَ قَامَ فِي النَّاسِ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ إِخْوَانَكُمْ جَاءُونَا تَائِبِينَ وَإِنِّي رَأَيْتُ أَنْ أَرُدَّ إِلَيْهِمْ سَبْيَهُمْ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يُطَيِّبَ ذَلِكَ فَلْيَفْعَلْ وَمَنْ أَحَبَّ أَنْ يَكُونَ عَلَى حَظِّهِ حَتَّى نُعْطِيَهُ إِيَّاهُ مِنْ أَوَّلِ مَا يُفِيءُ اللَّهُ عَلَيْنَا فَقَالَ النَّاسُ طَيَّبْنَا لَكَ","id":"Telah menceritakan kepada kami [Sa'id bin Abi Maryam] telah menceritakan kepada kami [Al Laits] berkata, telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] berkata, bahwa ['Urwah] menyebutkan bahwa [Al Miswar bin Makhramah radliallahu 'anhu] dan [Marwan] keduanya mengabarkan bahwa Nabi shallallahu 'alaihi wasallam ketika datang kepada Beliau utusan suku HawAzin, Beliau berdiri di hadapan manusia lalu memuji Allah Dzat yang paling berhak dipuji kemudian bersabda: \"Kemudian dari pada itu, bahwa saudara-saudara kalian telah datang dengan bertobat dan aku berpikir untuk mengembalikan tawanan mereka. Maka itu siapa diantara kalian yang suka berbuat baik (untuk membebaskannya) maka lakukanlah dan siapa yang ingin mendapatkan haknya maka kami akan berikan haknya kepadanya dari sejak awal harta fa'i yang Allah karuniakan kepada kita\". Maka orang-orang berkata: \"Kami memilih berbuat kebaikan untuk anda.\""},"2396":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْبَلُ الْهَدِيَّةَ وَيُثِيبُ عَلَيْهَالَمْ يَذْكُرْ وَكِيعٌ وَمُحَاضِرٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Isa bin Yunus] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata: \"Adalah Rasulullah shallallahu 'alaihi wasallam menerima pemberiah hadiah dan membalasnya\". [Waki'] dan [Muhadhir] tidak menebutkan dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha]. "},"2397":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ وَمُحَمَّدِ بْنِ النُّعْمَانِ بْنِ بَشِيرٍ أَنَّهُمَا حَدَّثَاهُ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ أَبَاهُ أَتَى بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي نَحَلْتُ ابْنِي هَذَا غُلَامًا فَقَالَ أَكُلَّ وَلَدِكَ نَحَلْتَ مِثْلَهُ قَالَ لَا قَالَ فَارْجِعْهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] dan [Muhammad bin An Nu'man bin Basyir] bahwa keduanya menceritakan kepada [An Nu'man bin Basyir] bahwa bapaknya datang bersamanya menemui Rasulullah shallallahu 'alaihi wasallam lalu berkata; \"Aku hadiahkan anakku ini sebagai ghulam (pembantu) \". Maka Beliau bertanya: \"Apakah semua anakmu kamu hadiahkan seperti ini?\". Dia menjawab: \"Tidak\". Maka Beliau bersabda: \"Kalau begitu, lebih baik kamu bawa pulang kembali.\""},"2398":{"ar":"حَدَّثَنَا حَامِدُ بْنُ عُمَرَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ حُصَيْنٍ عَنْ عَامِرٍ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُمَا وَهُوَ عَلَى الْمِنْبَرِ يَقُولُأَعْطَانِي أَبِي عَطِيَّةً فَقَالَتْ عَمْرَةُ بِنْتُ رَوَاحَةَ لَا أَرْضَى حَتَّى تُشْهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أَعْطَيْتُ ابْنِي مِنْ عَمْرَةَ بِنْتِ رَوَاحَةَ عَطِيَّةً فَأَمَرَتْنِي أَنْ أُشْهِدَكَ يَا رَسُولَ اللَّهِ قَالَ أَعْطَيْتَ سَائِرَ وَلَدِكَ مِثْلَ هَذَا قَالَ لَا قَالَ فَاتَّقُوا اللَّهَ وَاعْدِلُوا بَيْنَ أَوْلَادِكُمْ قَالَ فَرَجَعَ فَرَدَّ عَطِيَّتَهُ","id":"Telah menceritakan kepada kami [Hamid bin 'Umar] telah menceritakan kepada kami [Abu 'Awanah] dari [Hushain] dari ['Amir] berkata; aku mendengar [An Nu'man bin Basyir radliallahu 'anhuma] berkhutbah diatas mimbar, katanya: \"Bapakku memberiku sebuah hadiah (pemberian tanpa imbalan). Maka 'Amrah binti Rawahah berkata; \"Aku tidak rela sampai kamu mempersaksikannya kepada Rasulullah shallallahu 'alaihi wasallam.\" Maka bapakku menemui Rasulullah shallallahu 'alaihi wasallam dan berkata: \"Aku memberi anakku sebuah hadiah yang berasal dari 'Amrah binti Rawahah, namun dia memerintahkan aku agar aku mempersaksikannya kepada anda, wahai Rasulullah\". Beliau bertanya: \"Apakah semua anakmu kamu beri hadiah seperti ini?\". Dia menjawab: \"Tidak\". Beliau bersabda: \"Bertaqwalah kalian kepada Allah dan berbuat adillah diantara anak-anak kalian\". An-Nu'man berkata: \"Maka dia kembali dan Beliau menolak pemberian bapakku\"."},"2399":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَالَمَّا ثَقُلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاشْتَدَّ وَجَعُهُ اسْتَأْذَنَ أَزْوَاجَهُ أَنْ يُمَرَّضَ فِي بَيْتِي فَأَذِنَّ لَهُ فَخَرَجَ بَيْنَ رَجُلَيْنِ تَخُطُّ رِجْلَاهُ الْأَرْضَ وَكَانَ بَيْنَ الْعَبَّاسِ وَبَيْنَ رَجُلٍ آخَرَفَقَالَ عُبَيْدُ اللَّهِ فَذَكَرْتُ لِابْنِ عَبَّاسٍ مَا قَالَتْ عَائِشَةُ فَقَالَ لِي وَهَلْ تَدْرِي مَنْ الرَّجُلُ الَّذِي لَمْ تُسَمِّ عَائِشَةُ قُلْتُ لَا قَالَ هُوَ عَلِيُّ بْنُ أَبِي طَالِبٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhriy] berkata, telah menceritakan kepadaku ['Ubaidullah bin 'Abdullah]; ['Aisyah radliallahu 'anha] berkata; \"Ketika Nabi shallallahu 'alaihi wasallam menderita sakit dan terasa bertambah berat, Beliau meminta izin kepada isteri-isteri Beliau agar Beliau dirawat di rumahku lalu Beliau diijinkan. Beliau keluar dengan berjalan tertatih, dan kedua kaki Beliau diseret di atas tanah. Saat itu Beliau dibantu oleh Al 'Abbas dan seseorang yang lain\". ['Ubaidullah] berkata: \"Aku menceritakan kepada [Ibnu 'Abbas] apa yang diceritakan oleh 'Aisyah. Maka dia berkata, kepadaku: \"Tahukah kamu siapa orang yang lain itu, yang tidak disebut namannya oleh 'Aisyah?\". Aku katakan: \"Aku tidak tahu\". Dia berkata: \"Orang itu adalah 'Ali bin Abi Tholib\"."},"2400":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَائِدُ فِي هِبَتِهِ كَالْكَلْبِ يَقِيءُ ثُمَّ يَعُودُ فِي قَيْئِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang meminta kembali apa yang telah dihibahkannya bagaikan anjing yang muntah lalu menelan kembali apa yang dimuntahkannya ke dalam mulutnya\"."},"2401":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ عَنْ أَسْمَاءَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ مَا لِيَ مَالٌ إِلَّا مَا أَدْخَلَ عَلَيَّ الزُّبَيْرُ فَأَتَصَدَّقُ قَالَ تَصَدَّقِي وَلَا تُوعِي فَيُوعَى عَلَيْكِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abi Mulaikah] dari ['Abbad bin 'Abdullah] dari [Asma' radliallahu 'anhu] berkata; Aku berkata: \"Wahai Rasulullah, aku tidak memiliki harta kecuali apa yang diberikan oleh Az Zubair Apakah aku boleh bershadaqah dengannya?\" Beliau menjawab: \"Bershadaqalah dan jangan kamu tutup rapat guci tempat menyimpan makanan itu, karena nanti Allah menutup rezekimu\"."},"2402":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنْفِقِي وَلَا تُحْصِي فَيُحْصِيَ اللَّهُ عَلَيْكِ وَلَا تُوعِي فَيُوعِيَ اللَّهُ عَلَيْكِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami ['Abdullah bin Numair] telah menceritakan kepada kami [Hisyam bin \"Urwah] dari [Fathimah] dari [Asma'] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berinfaqlah dan jangan kamu hitung-hitung (pelit) karena nanti Allah akan berhitung kepadamu dan jangan kamu tutup rapat guci tempat menyimpan makanan itu karena nanti Allah akan menutup rezekimu\"."},"2403":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ عَنْ اللَّيْثِ عَنْ يَزِيدَ عَنْ بُكَيْرٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ مَيْمُونَةَ بِنْتَ الْحَارِثِ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّهَا أَعْتَقَتْ وَلِيدَةً وَلَمْ تَسْتَأْذِنْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا كَانَ يَوْمُهَا الَّذِي يَدُورُ عَلَيْهَا فِيهِ قَالَتْ أَشَعَرْتَ يَا رَسُولَ اللَّهِ أَنِّي أَعْتَقْتُ وَلِيدَتِي قَالَ أَوَفَعَلْتِ قَالَتْ نَعَمْ قَالَ أَمَا إِنَّكِ لَوْ أَعْطَيْتِهَا أَخْوَالَكِ كَانَ أَعْظَمَ لِأَجْرِكِوَقَالَ بَكْرُ بْنُ مُضَرَ عَنْ عَمْرٍو عَنْ بُكَيْرٍ عَنْ كُرَيْبٍ إِنَّ مَيْمُونَةَ أَعْتَقَتْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] dari [Al Laits] dari [Yazid] dari [Bukair] dari [Kuraib, maula Iabnu 'Abbas] bahwa [Maimunah binti Al Harits radliallahu 'anha] mengabarkan kepadanya bahwa dia telah membebaskan budak wanitanya namun dia tidak meminta izin terlebih dahulu kepada Nabi shallallahu 'alaihi wasallam. Ketika hari giliran Beliau di rumahnya, Maimunah berkata: \"Apakah kakanda telah mengetahui bahwa saya telah membebaskan budak wanita saya, wahai Rasulullah\". Beliau bertanya: \"Apakah kamu sudah melakukannya?\" Dia menjawab: \"Ya, sudah\". Beliau bersabda: \"Jika seandainya kamu hibahkan budak itu kepada bibi-bibi kamu tentu kamu akan mendapatkan pahala yang besar\". Dan berkata, [Bakar bin Mudhor] dari ['Amru] dari [Bukair] dari [Kuraib] bahwa [Maimunah] telah membebaskan (budaknya)."},"2404":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ سَفَرًا أَقْرَعَ بَيْنَ نِسَائِهِ فَأَيَّتُهُنَّ خَرَجَ سَهْمُهَا خَرَجَ بِهَا مَعَهُ وَكَانَ يَقْسِمُ لِكُلِّ امْرَأَةٍ مِنْهُنَّ يَوْمَهَا وَلَيْلَتَهَا غَيْرَ أَنَّ سَوْدَةَ بِنْتَ زَمْعَةَ وَهَبَتْ يَوْمَهَا وَلَيْلَتَهَا لِعَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبْتَغِي بِذَلِكَ رِضَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hibban bin Musa] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy] dari ['Urwah] dari ['Aisyah radliallahu 'anha] berkata: \"Adalah Rasulullah shallallahu 'alaihi wasallam apabila hendak mengadakan suatu perjalanan, Beliau melakukan undian siapa diantara isteri-isteri Beliau yang keluar namanya untuk turut serta bersama Beliau. Dan juga Beliau selalu menggilir isteri-isteri Beliau untuk setiap hari dan malamnya kecuali Saudah binti Zam'ah yang dia telah menghibahkan jatah giliran hari dan malamnya kepada 'Aisyah isteri Nabi shallallahu 'alaihi wasallam, dengan tujuan mencari ridho Rasulullah shallallahu 'alaihi wasallam."},"2405":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ رَجُلٍ مِنْ بَنِي تَيْمِ بْنِ مُرَّةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ قُلْتُيَا رَسُولَ اللَّهِ إِنَّ لِي جَارَيْنِ فَإِلَى أَيِّهِمَا أُهْدِي قَالَ إِلَى أَقْرَبِهِمَا مِنْكِ بَابًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu 'Imran AlJawniy] dari [Thalhah bin 'Abdullah, seorang dari suku Bani Tamim bin Murrah] dari ['Aisyah radliallahu 'anha] berkata; Aku bertanya: \"Wahai Rasulullah, aku mempunyai dua tetangga. Kepada yang manakah dari keduanya bila aku memberikan hadiah?\" Beliau menjawab: \"Kepada yang terdekat pintu rumahnya denganmu diantara keduanya\"."},"2406":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ أَنَّهُ سَمِعَ الصَّعْبَ بْنَ جَثَّامَةَ اللَّيْثِيَّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخْبِرُ أَنَّهُأَهْدَى لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِمَارَ وَحْشٍ وَهُوَ بِالْأَبْوَاءِ أَوْ بِوَدَّانَ وَهُوَ مُحْرِمٌ فَرَدَّهُ قَالَ صَعْبٌ فَلَمَّا عَرَفَ فِي وَجْهِي رَدَّهُ هَدِيَّتِي قَالَ لَيْسَ بِنَا رَدٌّ عَلَيْكَ وَلَكِنَّا حُرُمٌ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah] bahwa ['Abdullah bin 'Abbas radliallahu 'anhu] mengabarkannya bahwa dia mendengar [Ash Sha'bah bin Jatstsamah Al Laitsiy] seorang sahabat Nabi shallallahu 'alaihi wasallam mengabarkan bahwa dia memberi hadiah kepada Rasulullah shallallahu 'alaihi wasallam seekor keledai liar saat Beliau sedang berada di Abwa' atau Waddan dalam keadaan berihram lalu Beliau menolaklnya\". Sha'bu berkata: \"Ketika Beliau mengetahui raut wajahku karena hadiahku ditolak, Beliau berkata: \"Kami tidak bermaksud menolak hadiahmu namun kami sedang dalam keadaan berihram\"."},"2407":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَاسْتَعْمَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ الْأَزْدِ يُقَالُ لَهُ ابْنُ الْأُتْبِيَّةِ عَلَى الصَّدَقَةِ فَلَمَّا قَدِمَ قَالَ هَذَا لَكُمْ وَهَذَا أُهْدِيَ لِي قَالَ فَهَلَّا جَلَسَ فِي بَيْتِ أَبِيهِ أَوْ بَيْتِ أُمِّهِ فَيَنْظُرَ يُهْدَى لَهُ أَمْ لَا وَالَّذِي نَفْسِي بِيَدِهِ لَا يَأْخُذُ أَحَدٌ مِنْهُ شَيْئًا إِلَّا جَاءَ بِهِ يَوْمَ الْقِيَامَةِ يَحْمِلُهُ عَلَى رَقَبَتِهِ إِنْ كَانَ بَعِيرًا لَهُ رُغَاءٌ أَوْ بَقَرَةً لَهَا خُوَارٌ أَوْ شَاةً تَيْعَرُ ثُمَّ رَفَعَ بِيَدِهِ حَتَّى رَأَيْنَا عُفْرَةَ إِبْطَيْهِ اللَّهُمَّ هَلْ بَلَّغْتُ اللَّهُمَّ هَلْ بَلَّغْتُ ثَلَاثًا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhriy] dari ['Urwah bin Az Zubair] dari [Abu Humaid as-Sa'idiy radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam memperkerjakan seorang laki-laki dari suku Al azdiy sebagai pemungut zakat. Ketika datang dari tugasnya, dia berkata: \"Ini untuk kalian sebagai zakat dan ini dihadiahkan untukku\". Beliau berkata: \"Biarkanlah dia tinggal di rumah ayahnya atau ibunya lalu dia lihat apakah benar itu dihadiahkan untuknya atau tidak. Dan demi Dzat yag jiwaku di tangan-Nya, tidak seoragpun yang mengambil sesuatu dari zakt kecuali dia akan datang pada hari qiyamat dengan dipikulkan di atas lehernya berupa unta yang berteriak, atau sapi yang melembuh atau kambing yang mengembik\". Kemudia Beliau mengangkat tangan Beliau sehingga terlihatt oleh kami ketiak Beliau yang putih dan (berkata,): \"Ya Allah bukankah aku sudah sampaikan, bukankah aku sudah sampaikan\"…. sebanyak tiga kali\"."},"2408":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ الْمُنْكَدِرِ سَمِعْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ جَاءَ مَالُ الْبَحْرَيْنِ أَعْطَيْتُكَ هَكَذَا ثَلَاثًا فَلَمْ يَقْدَمْ حَتَّى تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ أَبُو بَكْرٍ مُنَادِيًا فَنَادَى مَنْ كَانَ لَهُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِدَةٌ أَوْ دَيْنٌ فَلْيَأْتِنَا فَأَتَيْتُهُ فَقُلْتُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَدَنِي فَحَثَى لِي ثَلَاثًا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Al Munkadir] dia mendengar [Jabir radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam berkata, kepadaku: \"Seandainya tiba kepada kita harta dari negeri Bahrain aku pasti memberikan kepadamu sekian\". Beliau mengucapkannya tiga kali. Dan harta Bahrain itu belum juga datang hingga Nabi shallallahu 'alaihi wasallam keburu wafat. Kemudian (Setelah harta datang) Abu Bakar memanggil penyeru lalu berkata: \"Siapa yang kepadanya Nabi shallallahu 'alaihi wasallam pernah berjanji atau mempunyai hutang hendaklah datang kepada kami\". Maka aku datangi dia dan aku katakana; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam pernah menjanjikan aku\". Maka Abu Bakar memberiku sebanyak tiga tangkup (ukuran dua belah telapak tangan) \"."},"2409":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبِيَةً وَلَمْ يُعْطِ مَخْرَمَةَ مِنْهَا شَيْئًا فَقَالَ مَخْرَمَةُ يَا بُنَيَّ انْطَلِقْ بِنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ مَعَهُ فَقَالَ ادْخُلْ فَادْعُهُ لِي قَالَ فَدَعَوْتُهُ لَهُ فَخَرَجَ إِلَيْهِ وَعَلَيْهِ قَبَاءٌ مِنْهَا فَقَالَ خَبَأْنَا هَذَا لَكَ قَالَ فَنَظَرَ إِلَيْهِ فَقَالَ رَضِيَ مَخْرَمَةُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu Abi Mulaikah] dari [Al Miswar bin Makhramah radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam membagi-bagikan pakaian (rida') namun Beliau tidak memberi satupun kepada Makhramah. Maka Makhramah berkata: \"Wahai anakku marilah kita menemui Rasulullah shallallahu 'alaihi wasallam\". Maka aku berangkat bersamanya lalu dia berkata: \"Masuk dan mintakanlah untukku\". Dia berkata: \"Maka aku pintakan untuknya lalu Beliau keluar menemuinya dengan membawa rida' lalu berkata: \"Kami sengaja menyimpan ini untukmu\". Dia (Al Miswar) berkata: \"Bapakku memandangnya lalu berkata, Makhramah telah ridho'?."},"2410":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَكْتُ فَقَالَ وَمَا ذَاكَ قَالَ وَقَعْتُ بِأَهْلِي فِي رَمَضَانَ قَالَ تَجِدُ رَقَبَةً قَالَ لَا قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تَصُومَ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا قَالَ فَ��َسْتَطِيعُ أَنْ تُطْعِمَ سِتِّينَ مِسْكِينًا قَالَ لَا قَالَ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ بِعَرَقٍ وَالْعَرَقُ الْمِكْتَلُ فِيهِ تَمْرٌ فَقَالَ اذْهَبْ بِهَذَا فَتَصَدَّقْ بِهِ قَالَ عَلَى أَحْوَجَ مِنَّا يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا بَيْنَ لَابَتَيْهَا أَهْلُ بَيْتٍ أَحْوَجُ مِنَّا قَالَ اذْهَبْ فَأَطْعِمْهُ أَهْلَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Mahbub] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhriy] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] berkata: Ada seorang laki-laki datang kepada Sahabat dan berkata: \"Celaka aku\". Maka Beliau bertanya: \"Kenapa?\" Orang itu menjawab: \"Aku berhubungan dengan isteriku di bulan Ramadhan\". Beliau bertanya: \"Apakah kamu punya budak?\" Orang itu menjawab: \"Tidak\". Beliau bertaya lagi: \"Apakah kamu sanggup berpuasa dua bulan berturut-turut?\" Orang itu menjawab: \"Tidak\". Beliau bertaya lagi: \"Apakah kamu sanggup memberi makan enam puluh orang miskin?\" Orang itu menjawab: \"Tidak\". Abu Hurairah radliallahu 'anhu berkata: \"Lalu datang seseorang dari kalangan Anshar dengan membawa karung besar yang penuh berisi kurma, lalu Beliau berkata: \"Pegilah dengan kurma ini dan shadaqahkanlah\". Orang itu berkata: \"Untuk orang yang lebih membutuhkan dari pada kami wahai Rasulullah?. Demi Dzat Yang mengutus anda dengan haq, tidak ada diantara penduduk yang keluarganya lebih membutuhkan dibandingkan kami\". Maka Beliau berkata: \"Pulanglah kamu dan berilah untuk makan keluargamu\""},"2411":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي ابْنُ كَعْبِ بْنِ مَالِكٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ أَبَاهُ قُتِلَ يَوْمَ أُحُدٍ شَهِيدًا فَاشْتَدَّ الْغُرَمَاءُ فِي حُقُوقِهِمْ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمْتُهُ فَسَأَلَهُمْ أَنْ يَقْبَلُوا ثَمَرَ حَائِطِي وَيُحَلِّلُوا أَبِي فَأَبَوْا فَلَمْ يُعْطِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَائِطِي وَلَمْ يَكْسِرْهُ لَهُمْ وَلَكِنْ قَالَ سَأَغْدُو عَلَيْكَ إِنْ شَاءَ اللَّهُ فَغَدَا عَلَيْنَا حِينَ أَصْبَحَ فَطَافَ فِي النَّخْلِ وَدَعَا فِي ثَمَرِهِ بِالْبَرَكَةِ فَجَدَدْتُهَا فَقَضَيْتُهُمْ حُقُوقَهُمْ وَبَقِيَ لَنَا مِنْ ثَمَرِهَا بَقِيَّةٌ ثُمَّ جِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَالِسٌ فَأَخْبَرْتُهُ بِذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعُمَرَ اسْمَعْ وَهُوَ جَالِسٌ يَا عُمَرُ فَقَالَ أَلَّا يَكُونُ قَدْ عَلِمْنَا أَنَّكَ رَسُولُ اللَّهِ وَاللَّهِ إِنَّكَ لَرَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dan berkata, [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] berkata, telah menceritakan kepadaku [Ibnu Ka'ab bin Malik] bahwa [Jabir bin 'Abdullah radliallahu 'anhuma] mengabarkan kepadanya bahwa bapaknya terbunuh sebagai syahid dalam perang Uhud lalu orang-orang yang mempunyai piutang datang, mereka mendesak meminta pelunasan hak-hak mereka, maka aku menemui Rasulullah shallallahu 'alaihi wasallam lalu aku berbicara dengan Beliau, lalu Beliau meminta kepada mereka untuk mau menerima buah-buahan dari kebunku dan agar mereka membebaskan beban hutang bapakku namun mereka tidak mau dan Rasulullah shallallahu 'alaihi wasallam tidak memberikan kebunku dan juga tidak membagi-bagikannya kepada mereka seraya berkata: \"Aku akan datang besok pagi kepadamu\". Maka Beliau datang kepada kami pagi-pagi lalu Beliau mengelilingi pepohonan kurma lalu berdo'a untuk keberkahan buah-buahnya. Maka aku memetik buah-buah kurma tersebut, aku lunasi hak-hak mereka dan masih ada tersisa untuk kami buah-buah kurma tersebut, lalu aku temui Rasulullah shallallahu 'alaihi wasallam ketika Beliau sedang duduk, lalu aku beritahukan kejadian tadi maka Rasulullah shallallahu 'alaihi wasallam berkata kepada 'Umar: \"Dengan wahai 'Umar\", sementara 'Umar dalam keadaan duduk. Maka 'Umar berkata: \"Peristiwa ini membuktikan bahwa kami mengetahui bahwa anda adalah Rasululoh. Demi Allah, anda adalah Rasulullah."},"2412":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِشَرَابٍ فَشَرِبَ وَعَنْ يَمِينِهِ غُلَامٌ وَعَنْ يَسَارِهِ الْأَشْيَاخُ فَقَالَ لِلْغُلَامِ إِنْ أَذِنْتَ لِي أَعْطَيْتُ هَؤُلَاءِ فَقَالَ مَا كُنْتُ لِأُوثِرَ بِنَصِيبِي مِنْكَ يَا رَسُولَ اللَّهِ أَحَدًا فَتَلَّهُ فِي يَدِهِ","id":"Telah menceritakan kepadaku [Yahya bin Qaza'ah] telah menceritakan kepada kami [Malik] dari [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] bahwa, Nabi shallallahu 'alaihi wasallam diberi suguhan minuman, Beliau meminumnya sementara disamping kanan Beliau ada seorang anak kecil sedangkan di sebelah kiri Beliau ada orang-orang tua. Beliau berkata kepada anak kecil itu: \"Jika kamu izinkan, aku akan berikan kepada mereka\". Anak kecil itu berkata: \"Aku tidak lebih mementingkan seorangpun selain anda\". Maka Beliau memberikan apa yang di tangan Beliau kepadanya."},"2413":{"ar":"حَدَّثَنَا ثَابِتٌ حَدَّثَنَا مِسْعَرٌ عَنْ مُحَارِبٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فَقَضَانِي وَزَادَنِي","id":"Telah menceritakan kepada kami [Tsabit] telah menceritakan kepada kami [Mis'ar] dari [Muharib] dari [Jabir radliallahu 'anhu] berkata: \"Aku menemui Nabi shallallahu 'alaihi wasallam saat Beliau berada di masjid, lalu Beliau membayar hutangnya kepadaku dan memberi lebih kepadaku.\""},"2414":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مُحَارِبٍ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُبِعْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعِيرًا فِي سَفَرٍ فَلَمَّا أَتَيْنَا الْمَدِينَةَ قَالَ ائْتِ الْمَسْجِدَ فَصَلِّ رَكْعَتَيْنِ فَوَزَنَ قَالَ شُعْبَةُ أُرَاهُ فَوَزَنَ لِي فَأَرْجَحَ فَمَا زَالَ مَعِي مِنْهَا شَيْءٌ حَتَّى أَصَابَهَا أَهْلُ الشَّأْمِ يَوْمَ الْحَرَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Muharib] aku medengar [Jabir bin 'Abdullah radliallahu 'anhuma] berkata: \"Aku menjual seekor unta kepada Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan. Ketika kami sudah sampai di Madinah, Beliau berkata; \"Datanglah ke masjid dan shalatlah dua raka'at\". Lalu Beliau menimbang\". Syu'bah berkata: \"Aku kira dia berkata; Lalu Beliau menimbang untukku\". Maka Beliau memberi lebih untukku sehingga masih terus ada kelebihan itu hingga kmai menghadapi bangsa Romawi dalam perang sulit di musim panas\"."},"2415":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِشَرَابٍ وَعَنْ يَمِينِهِ غُلَامٌ وَعَنْ يَسَارِهِ أَشْيَاخٌ فَقَالَ لِلْغُلَامِ أَتَأْذَنُ لِي أَنْ أُعْطِيَ هَؤُلَاءِ فَقَالَ الْغُلَامُ لَا وَاللَّهِ لَا أُوثِرُ بِنَصِيبِي مِنْكَ أَحَدًا فَتَلَّهُ فِي يَدِهِ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] bahwa, Rasulullah shallallahu 'alaihi wasallam diberi suguhan minuman sementara disamping kanan Beliau ada seorang anak kecil sedangkan di sebelah kiri Beliau ada para orang-orang tua. Maka Beliau berkata kepada anak kecil itu: \"Apakah kamu mengizinkan aku untuk aku berikan minuman ini kepada mereka?\". Anak kecil itu berkata: \"Tidak wahai Rasulullah, Aku tidak lebih mementingkan terhadap seorangpun selain anda\". Maka Beliau memberikan apa yang di tangan Beliau kepadanya."},"2416":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ جَبَلَةَ قَالَ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ سَلَمَةَ قَالَ سَمِعْتُ أَبَا سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ لِرَجُلٍ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَيْنٌ فَهَمَّ بِهِ أَصْحَابُهُ فَقَالَ دَعُوهُ فَإِنَّ لِصَاحِبِ الْحَقِّ مَقَالًا وَقَالَ اشْتَرُوا لَهُ سِنًّا فَأَعْطُوهَا إِيَّاهُ فَقَالُوا إِنَّا لَا نَجِدُ سِنًّا إِلَّا سِنًّا هِيَ أَفْضَلُ مِنْ سِنِّهِ قَالَ فَاشْتَرُوهَا فَأَعْطُوهَا إِيَّاهُ فَإِنَّ مِنْ خَيْرِكُمْ أَحْسَنَكُمْ قَضَاءً","id":"Telah menceritakan kepada kami ['Abdullah bin 'Utsman bin Jabalah] berkata, telah menceritakan kepadaku [bapakku] dari [Syu'bah] dari [Salamah] berkata, aku mendengar [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] berkata; Ada seorang laki-laki yang kepadanya Rasulullah shallallahu 'alaihi wasallam mempunyai hutang lalu para sahabat ingin (memberina pelajaran) namun Beliau berkata: \"Biarkanlah dia, karena bagi pemegang kebenaran berhak menyatakan kebenarannya\". Lalu Beliau berkata: \"Belilah satu ekor anak unta lalu berikanlah kepadanya\". Orang-orang berkata: \"Kami tidak mendapatkan anak unta yang dimaksud melainkan ada seekor anak unta yang umurnya lebih\". Beliau berkata: \"Beli dan berikanlah kepadanya karena sesungguhnya yang terbaik diantara kalian adalah siapa yang paling baik menunaikan janji\"."},"2417":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ مَرْوَانَ بْنَ الْحَكَمِ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَاهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حِينَ جَاءَهُ وَفْدُ هَوَازِنَ مُسْلِمِينَ فَسَأَلُوهُ أَنْ يَرُدَّ إِلَيْهِمْ أَمْوَالَهُمْ وَسَبْيَهُمْ فَقَالَ لَهُمْ مَعِي مَنْ تَرَوْنَ وَأَحَبُّ الْحَدِيثِ إِلَيَّ أَصْدَقُهُ فَاخْتَارُوا إِحْدَى الطَّائِفَتَيْنِ إِمَّا السَّبْيَ وَإِمَّا الْمَالَ وَقَدْ كُنْتُ اسْتَأْنَيْتُ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتَظَرَهُمْ بِضْعَ عَشْرَةَ لَيْلَةً حِينَ قَفَلَ مِنْ الطَّائِفِ فَلَمَّا تَبَيَّنَ لَهُمْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ رَادٍّ إِلَيْهِمْ إِلَّا إِحْدَى الطَّائِفَتَيْنِ قَالُوا فَإِنَّا نَخْتَارُ سَبْيَنَا فَقَامَ فِي الْمُسْلِمِينَ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ إِخْوَانَكُمْ هَؤُلَاءِ جَاءُونَا تَائِبِينَ وَإِنِّي رَأَيْتُ أَنْ أَرُدَّ إِلَيْهِمْ سَبْيَهُمْ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يُطَيِّبَ ذَلِكَ فَلْيَفْعَلْ وَمَنْ أَحَبَّ أَنْ يَكُونَ عَلَى حَظِّهِ حَتَّى نُعْطِيَهُ إِيَّاهُ مِنْ أَوَّلِ مَا يُفِيءُ اللَّهُ عَلَيْنَا فَلْيَفْعَلْ فَقَالَ النَّاسُ طَيَّبْنَا يَا رَسُولَ اللَّهِ لَهُمْ فَقَالَ لَهُمْ إِنَّا لَا نَدْرِي مَنْ أَذِنَ مِنْكُمْ فِيهِ مِمَّنْ لَمْ يَأْذَنْ فَارْجِعُوا حَتَّى يَرْفَعَ إِلَيْنَا عُرَفَاؤُكُمْ أَمْرَكُمْ فَرَجَعَ النَّاسُ فَكَلَّمَهُمْ عُرَفَاؤُهُمْ ثُمَّ رَجَعُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرُوهُ أَنَّهُمْ طَيَّبُوا وَأَذِنُواوَهَذَا الَّذِي بَلَغَنَا مِنْ سَبْيِ هَوَازِنَ هَذَا آخِرُ قَوْلِ الزُّهْرِيِّ يَعْنِي فَهَذَا الَّذِي بَلَغَنَا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] bahwa [Marwan bin Al Hakam] dan [Al Miswar bin Makhramah] keduanya mengabarkan kepadanya, Nabi shallallahu 'alaihi wasallam didatangi oleh utusan suku Hawazin yang telah memeluk Islam lalu mereka meminta kepada Beliau agar mengembalikan harta dan para tawanan mereka. Maka Beliau berkata kepada mereka: \"Bersamaku sekarang ada orang-orang sebagaimana kalian lihat dan ucapan yang paling aku sukai adalah yang paling benar. Maka pilihlah salah satu dari dua hal, apakah tawanan atau harta dan sungguh aku akan memberi kesempatan terhadap mereka\". Nabi shallallahu 'alaihi wasallam menanti mereka sekitar sepuluh malam ketika mereka kembali dari Tha'if. Setelah jelas bagi mereka bahwa Rasulullah shallallahu 'alaihi wasallam tidak akan mengembalikan kepada mereka kecuali salah satu dari dua pilihan, mereka berkata; \"Kami memilih tawanan\". Beliau berdiri di hadapan Kaum Muslimin kemudian memuji Allah yang memang Dia paling berhak untuk dipuji lalu bersabda: \"Kemudian dari pada itu, saudara-saudara kalian ini datang kepada kita dengan bertobat dan sungguh aku berpikir akan mengembalikan para tawanan. Maka siapa diantara kalian yang suka berbuat baik (dengan membebaskan tawanan) dalam masalah ini maka lakukanlah, dan siapa diantara kalian yang ingin tetap menjadikannya sebagai haknya maka kami akan berikan kepadanya harta fa'i yang sejak awal Allah mengaruniakannya kepada kita, lakukanlah\". Maka orang-orang berkata: \"Kami memilih berbuat baik (menyerahkan mereka wahai Rasulullah\". Lalu Beliau berkata, kepada mereka: \"Kami tidak tahu siapa diantara kalian yang berhak memberi izin dan siapa yang bukan, maka itu kembalilah hingga kalian bawa para pimpinan yang mengurusi urusan kalian\". Akhirnya mereka pulang dan berbicara dengan para pimpinan mereka lalu kembali menghadap Rasulullah shallallahu 'alaihi wasallam dan mereka mengabarkan bahwa mereka telah menyetujui dan memberi izin\". Inilah kisah yang sampai kepada kami tentang para tawanan suku Hawazin\". Kalimat terakhir (inilah kisah…) adalah ucapan Az Zuhriy."},"2418":{"ar":"حَدَّثَنَا ابْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَخَذَ سِنًّا فَجَاءَ صَاحِبُهُ يَتَقَاضَاهُ فَقَالُوا لَهُ فَقَالَ إِنَّ لِصَاحِبِ الْحَقِّ مَقَالًا ثُمَّ قَضَاهُ أَفْضَلَ مِنْ سِنِّهِ وَقَالَ أَفْضَلُكُمْ أَحْسَنُكُمْ قَضَاءً","id":"Telah menceritakan kepada kami [Ibnu Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Syu'bah] dari [Salamah Kuhail] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam, bahwa pernah Beliau mengambil seekor anak unta lalu datang pemiliknya menagih. Orang-orang pun memberi komentar yang negatif terhadap orang yang menagih itu. Lalu beliau bersabda: \"Sesungguhnya bagi pemilik kebenaran boleh menyatakan terus terang keinginannya\". Lalu Beliau membayar dengan anak unta yang umurnya lebih tua daripada unta orang itu lalu bersabda: \"Sesungguhnya yang terbaik diantara kalian adalah yang paling baik menunaikan janji.\""},"2419":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ كَانَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَكَانَ عَلَى بَكْرٍ لِعُمَرَ صَعْبٍ فَكَانَ يَتَقَدَّمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولُ أَبُوهُ يَا عَبْدَ اللَّهِ لَا يَتَقَدَّمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعْنِيهِ فَقَالَ عُمَرُ هُوَ لَكَ فَاشْتَرَاهُ ثُمَّ قَالَ هُوَ لَكَ يَا عَبْدَ اللَّهِ فَاصْنَعْ بِهِ مَا شِئْتَ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amru] dari [Ibnu'Umar radliallahu 'anhuma] bahwa dia pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan dengan menunggang unta yang masih muda milik 'Umar. Saat itu dia mendahului laju Nabi shallallahu 'alaihi wasallam maka bapaknya berkata: \"Wahai 'Abdullah, janganlah seseorang mendahului Nabi shallallahu 'alaihi wasallam\". Maka Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Juallah unta itu kepadaku\". Maka 'Umar berkata: \"Unta ini untuk baginda\". Maka Beliau membelinya kemudian berkata: \"Unta ini untukmu wahai 'Abdullah dan pergunakanlah sesukamu\"."},"2420":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَى عُمَرُ بْنُ الْخَطَّابِ حُلَّةً سِيَرَاءَ عِنْدَ بَابِ الْمَسْجِدِ فَقَالَ يَا رَسُولَ اللَّهِ لَوْ اشْتَرَيْتَهَا فَلَبِسْتَهَا يَوْمَ الْجُمُعَةِ وَلِلْوَفْدِ قَالَ إِنَّمَا يَلْبَسُهَا مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ ثُمَّ جَاءَتْ حُلَلٌ فَأَعْطَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمَرَ مِنْهَا حُلَّةً وَقَالَ أَكَسَوْتَنِيهَا وَقُلْتَ فِي حُلَّةِ عُطَارِدٍ مَا قُلْتَ فَقَالَ إِنِّي لَمْ أَكْسُكَهَا لِتَلْبَسَهَا فَكَسَاهَا عُمَرُ أَخًا لَهُ بِمَكَّةَ مُشْرِكًا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] berkata, 'Umar bin Al Khaththob melihat pakaian terbuat dari sutera di depan pintu masjid, lalu dia berkata: \"Wahai Rasulullah, alangkah baiknya seandainya anda beli pakaian ini lalu Baginda kenakan pada hari Jum'at atau saat menyambut utusan (delegasi) \". Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Sesungguhnya orang yang memakai pakaian seperti ini tidak akan mendapat bagian di akhirat\". Kemudian datang (hadiah diantaranya ada pakain) sutera. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan pakaian sutera tersebut kepada 'Umar bin Al Khaththob radliallahu 'anhu. Umar berkata: \"Baginda menyuruh aku mengenakannya sedang Baginda sendiri dahulu pernah berkomentar pakaian ini tak layak dipakai\". Maka Beliau shallallahu 'alaihi wasallam berkata, \"Aku memberikannya kepadamu bukan untuk kamu pakai\". Lalu 'Umar memberikan pakaian sutera tersebut kepada saudaranya yang musyrik di kota Makkah\"."},"2421":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَبُو جَعْفَرٍ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ فَاطِمَةَ فَلَمْ يَدْخُلْ عَلَيْهَا وَجَاءَ عَلِيٌّ فَذَكَرَتْ لَهُ ذَلِكَ فَذَكَرَهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي رَأَيْتُ عَلَى بَابِهَا سِتْرًا مَوْشِيًّا فَقَالَ مَا لِي وَلِلدُّنْيَا فَأَتَاهَا عَلِيٌّ فَذَكَرَ ذَلِكَ لَهَا فَقَالَتْ لِي��أْمُرْنِي فِيهِ بِمَا شَاءَ قَالَ تُرْسِلُ بِهِ إِلَى فُلَانٍ أَهْلِ بَيْتٍ بِهِمْ حَاجَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Ibnu Fudhoil] dari [bapaknya] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata, Nabi shallallahu 'alaihi wasallam mendatangi rumah Fathimah namun Beliau tidak segera masuk. Kemudian 'Ali datang, dan Fathimah ceritakan peristiwa ini kepadanya. Kemudian 'Ali menceritakan kepada Nabi shallallahu 'alaihi wasallam, maka Beliau berkata: \"Aku melihat di pintu ada tabir yang ada lukisannya\". Maka 'Ali berkata: \"Aku tidak punya kepentingan dengan dunia\". Lalu 'Ali menemui Fathimah dan menceritakan, maka Fathimah berkata: \"Silakan Beliau memerintahkanaku apa saja sesuka Beliau\". 'Ali berkata: \"Sebaiknya kamu kirimkan saja tabir itu untuk si fulan yang barangkali keluarga mereka membutuhkannya.\""},"2422":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ مَيْسَرَةَ قَالَ سَمِعْتُ زَيْدَ بْنَ وَهْبٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَأَهْدَى إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةَ سِيَرَاءَ فَلَبِسْتُهَا فَرَأَيْتُ الْغَضَبَ فِي وَجْهِهِ فَشَقَقْتُهَا بَيْنَ نِسَائِي","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepadaku ['Abdul Malik bin Maisarah] berkata, aku mendengar [Zaid bin Wahb] dari ['Ali radliallahu 'anhu] berkata: \"Aku diberi hadiah kain bermotif garis dari sutera oleh Nabi shallallahu 'alaihi wasallam lalu aku kenakan, maka nampak aku lihat kemarahan dari raut wajah Beliau. Kemudian aku bagikan untuk isteri-isteriku\"."},"2423":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسٌ رَضِيَ اللَّهُ عَنْهُ قَالَأُهْدِيَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُبَّةُ سُنْدُسٍ وَكَانَ يَنْهَى عَنْ الْحَرِيرِ فَعَجِبَ النَّاسُ مِنْهَا فَقَالَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَمَنَادِيلُ سَعْدِ بْنِ مُعَاذٍ فِي الْجَنَّةِ أَحْسَنُ مِنْ هَذَاوَقَالَ سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ إِنَّ أُكَيْدِرَ دُومَةَ أَهْدَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Syaiban] dari [Qatadah] telah menceritakan kepada kami [Anas radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam dihadiahi baju jubah terbuat dari sutera tipis dan sebelumnya Beliau telah melarang memakai sutera lalu orang-orang menjadi heran karenanya. Maka Beliau bersabda: \"Demi Dzat Yang jiwa Muhammad di tangan-Nya, sungguh sapu tangan Sa'ad bin 'Ubadah di surga lebih baik dari ini\". Dan berkata, [Sa'id] dari [Qatadah] dari [Anas]; Bahwa Ukaidar Dumah yang menghadiahkan kepada Nabi shallallahu 'alaihi wasallam."},"2424":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ يَهُودِيَّةً أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَاةٍ مَسْمُومَةٍ فَأَكَلَ مِنْهَا فَجِيءَ بِهَا فَقِيلَ أَلَا نَقْتُلُهَا قَالَ لَا فَمَا زِلْتُ أَعْرِفُهَا فِي لَهَوَاتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Su'bah] dari [Hisyam bin Zaid] dari [Anas bin Malik radliallahu 'anhu] bahwa, ada seorang wanita Yahudi yang datang menemui Nabi shallallahu 'alaihi wasallam dengan membawa seekor kambing yang telah diracun lalu Beliau memakannya. Kemudian wanita itu diringkus dengan bukti daging tersebut dan dikatakan; \"Tidak sebaiknyakah kita bunuh saja?\" Beliau menjawab: \"Jangan\". Sejak itu aku senantiasa aku melihat bekas racun tersebut pada anak lidah Rasulullah shallallahu 'alaihi wasallam."},"2425":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثِينَ وَمِائَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ مَعَ أَحَدٍ مِنْكُمْ طَعَامٌ فَإِذَا مَعَ رَجُلٍ صَاعٌ مِنْ طَعَامٍ أَوْ نَحْوُهُ فَعُجِنَ ثُمَّ جَاءَ رَجُلٌ مُشْرِكٌ مُشْعَانٌّ طَوِيلٌ بِغَنَمٍ يَسُوقُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْعًا أَمْ عَطِيَّةً أَوْ قَالَ أَمْ هِبَةً قَالَ لَا بَلْ بَيْعٌ فَاشْتَرَى مِنْهُ شَاةً فَصُنِعَتْ وَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَوَادِ الْبَطْنِ أَنْ يُشْوَى وَايْمُ اللَّهِ مَا فِي الثَّلَاثِينَ وَالْمِائَةِ إِلَّا قَدْ حَزَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ حُزَّةً مِنْ سَوَادِ بَطْنِهَا إِنْ كَانَ شَاهِدًا أَعْطَاهَا إِيَّاهُ وَإِنْ كَانَ غَائِبًا خَبَأَ لَهُ فَجَعَلَ مِنْهَا قَصْعَتَيْنِ فَأَكَلُوا أَجْمَعُونَ وَشَبِعْنَا فَفَضَلَتْ الْقَصْعَتَانِ فَحَمَلْنَاهُ عَلَى الْبَعِيرِ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [bapaknya] dari [Abu 'Utsman] dari ['Abdurrahman bin Abu Bakar radliallahu 'anhuma] berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam (dalam perjalanan) berjumlah seratus tiga puluh orang lalu Beliau berkata: \"Apakah diantara kalian yang memiliki makanan?\" Maka jika ada sebanyak satu sha'makanan atau sejenisnya, dibuatlah adonan. Kemudian datang seorang musyrik yang berambut panjang namun agak semrawut membawa kambing yang digiringnya. Nabi shallallahu 'alaihi wasallam berkata: \"Apakah kambing ini untuk dijual atau untuk dihadiahkan?\" atau Beliau berkata dengan redaksi: \"Atau dihibahkan?\" Orang itu menjawab: \"Tidak, tapi untuk dijual\". Maka Beliau membeli seekor darinya\". Lalu kambing itu dimasak dan Nabi shallallahu 'alaihi wasallam memerintahkan agar hatinya dibagi-bagikan. Demi Allah, tidak ada dari kami yang berjumlah seratus tiga puluh orang melainkan telah diberikan oleh Nabi shallallahu 'alaihi wasallam potongan jantung dari isi perut kambing tersebut. Jika ada yang hadir disitu, musti diberi, dan jika sedang tidak ada, disisakan baginya. Maka dibuat dalam dua kuali, lalu mereka makan semuanya dan kami merasa kenyang dan masih tersisa dua kuali lalu kami bawa diatas unta, atau sebagaimana dikatakannya\"."},"2426":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَى عُمَرُ حُلَّةً عَلَى رَجُلٍ تُبَاعُ فَقَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَعْ هَذِهِ الْحُلَّةَ تَلْبَسْهَا يَوْمَ الْجُمُعَةِ وَإِذَا جَاءَكَ الْوَفْدُ فَقَالَ إِنَّمَا يَلْبَسُ هَذَا مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا بِحُلَلٍ فَأَرْسَلَ إِلَى عُمَرَ مِنْهَا بِحُلَّةٍ فَقَالَ عُمَرُ كَيْفَ أَلْبَسُهَا وَقَدْ قُلْتَ فِيهَا مَا قُلْتَ قَالَ إِنِّي لَمْ أَكْسُكَهَا لِتَلْبَسَهَا تَبِيعُهَا أَوْ تَكْسُوهَا فَأَرْسَلَ بِهَا عُمَرُ إِلَى أَخٍ لَهُ مِنْ أَهْلِ مَكَّةَ قَبْلَ أَنْ يُسْلِمَ","id":"Telah menceritakan kepada kami [Kholid bin Makhlad] telah menceritakan kepada kami [Sulaiman bin Bilal] berkata, telah menceritakan kepadaku ['Abdullah bin Dinar] dari [Ibnu'Umar radliallahu 'anhuma] berkata; 'Umar melihat pakaian terbuat dari sutera dijajakan oleh seseorang lalu dia berkata kepada Nabi shallallahu 'alaihi wasallam: \"Belilah pakaian ini untuk Baginda kenakan pada hari Jum'at dan saat menyambut utusan (delegasi) \". Maka Beliau bersabda: \"Sesungguhnya orang yang memakai pakaian seperti ini adalah orang yang tidak akan mendapat bagian di akhirat\". Kemudian Rasulullah shallallahu 'alaihi wasallam diberikan pakaian diantaranya ada yang terbuat dari sutera lalu Beliau berikan diantaranya kepada 'Umar. Maka 'Umar berkata: \"Baginda menyuruh aku mengenakannya sedang Baginda telah berkomentar negatif tentangnya!\". Beliau berkata, \"Aku memberikannya kepadamu bukan untuk kamu pakai, tapi juallah atau hadiahkan\". Lalu 'Umar memberikan pakaian sutera tersebut kepada saudaranya yang tinggal di kota Makkah sebelum masuk Islam."},"2427":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْقَدِمَتْ عَلَيَّ أُمِّي وَهِيَ مُشْرِكَةٌ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَفْتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ وَهِيَ رَاغِبَةٌ أَفَأَصِلُ أُمِّي قَالَ نَعَمْ صِلِي أُمَّكِ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Bapaknya] dari [Asma' binti Abi Bakr radliallahu 'anhuma] berkata; Ibuku menemuiku saat itu dia masih musyrik pada zaman Rasulullah shallallahu 'alaihi wasallam lalu aku meminta pendapat kepada Rasulullah shallallahu 'alaihi wasallam. Aku katakan; \"Ibuku sangat ingin (aku berbuat baik padanya), apakah aku harus menjalin hubungan dengan ibuku?\" Beliau menjawab: \"Ya, sambunglah silaturrahim dengan ibumu\"."},"2428":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ وَشُعْبَةُ قَالَا حَدَّثَنَا قَتَادَةُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dan [Syu'bah] keduanya berkata, telah menceritakan kepada kami [Qatadah] dari [Sa'id bin Al Musayyab] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang meminta kembali apa yang telah dihibahkannya bagaikan orang yang menelan kembali muntahnya\"."},"2429":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَنَا مَثَلُ السَّوْءِ الَّذِي يَعُودُ فِي هِبَتِهِ كَالْكَلْبِ يَرْجِعُ فِي قَيْئِهِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Al Mubarak] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak patut bagi kita (orang beriman) sengaja membuat perumpamaan yang buruk. Orang yang meminta kembali apa yang telah dihibahkannya bagaikan anjing yang menelan kembali apa yang dimuntahkannya\"."},"2430":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُحَمَلْتُ عَلَى فَرَسٍ فِي سَبِيلِ اللَّهِ فَأَضَاعَهُ الَّذِي كَانَ عِنْدَهُ فَأَرَدْتُ أَنْ أَشْتَرِيَهُ مِنْهُ وَظَنَنْتُ أَنَّهُ بَائِعُهُ بِرُخْصٍ فَسَأَلْتُ عَنْ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَشْتَرِهِ وَإِنْ أَعْطَاكَهُ بِدِرْهَمٍ وَاحِدٍ فَإِنَّ الْعَائِدَ فِي صَدَقَتِهِ كَالْكَلْبِ يَعُودُ فِي قَيْئِهِ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari [bapaknya] aku mendengar ['Umar bin Al Khaththob radliallahu 'anhu] berkata: \"Aku memberi (seseorang) kuda yang untuk tujuan digunakan berperang di jalan Allah lalu orang itu tidak memanfaatkan sebagaimana mestinya. Kemudian aku berniat membelinya kembali darinya karena aku menganggap membelinya lagi adalah suatu hal yang (diringankan) dibolehkan. Lalu aku tanyakan hal ini kepada Nabi shallallahu 'alaihi wasallam, maka Beliau bersabda: \"Jangan kamu membelinya sekalipun orang itu menjualnya dengan harga satu dirham, karena orang yang mengambil kembali shadaqahnya seperti anjing yang menjilat kembali ludahnya\"."},"2431":{"ar":"بَاب حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَأَنَّ بَنِي صُهَيْبٍ مَوْلَى ابْنِ جُدْعَانَ ادَّعَوْا بَيْتَيْنِ وَحُجْرَةً أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَى ذَلِكَ صُهَيْبًا فَقَالَ مَرْوَانُ مَنْ يَشْهَدُ لَكُمَا عَلَى ذَلِكَ قَالُوا ابْنُ عُمَرَ فَدَعَاهُ فَشَهِدَ لَأَعْطَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُهَيْبًا بَيْتَيْنِ وَحُجْرَةً فَقَضَى مَرْوَانُ بِشَهَادَتِهِ لَهُمْ","id":"Bab. Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] mengabarkan mereka berkata, telah menceritakan kepadaku ['Abdullah bin 'Ubaidullah bin Abi Mulaikah] bahwa anak-anak Shuhaib maula Ibnu Jud'an mereka mengklaim dua rumah dan sebuah kamar yang diberi Rasulullah shallallahu 'alaihi wasallam kepada Shuhaib. Maka Marwan berkata: \"Siapa yang menjadi saksi atas kalian berdua dalam perkara ini?\" Mereka menjawab: \" [Ibnu 'Umar] \". Lalu Marwan memanggilnya dan ia bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam memang telah memberi Shuhaib dua rumah dengan satu kamar. Kemudian Marwan memutuskan untuk mereka dengan persaksiannya."},"2432":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعُمْرَى أَنَّهَا لِمَنْ وُهِبَتْ لَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Jabir radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam menetapkan bahwa 'umra adalah milik orang yang diberi hibah\". "},"2433":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ قَالَ حَدَّثَنِي النَّضْرُ بْنُ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى جَائِزَةٌوَقَالَ عَطَاءٌ حَدَّثَنِي جَابِرٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] berkata, telah menceritakan kepadaku [An Nadhor bun Anas] dari [Basyir bin Nahik] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"'Umra adalah hibah yang diperbolehkan\". Dan berkata, ['Atho'] telah menceritakan kepadaku [Jabir] dari Nabi shallallahu 'alaihi wasallam seperti ini juga."},"2434":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يَقُولُكَانَ فَزَعٌ بِالْمَدِينَةِ فَاسْتَعَارَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَسًا مِنْ أَبِي طَلْحَةَ يُقَالُ لَهُ الْمَنْدُوبُ فَرَكِبَ فَلَمَّا رَجَعَ قَالَ مَا رَأَيْنَا مِنْ شَيْءٍ وَإِنْ وَجَدْنَاهُ لَبَحْرًا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] berkata, aku mendengar [Anas] berkata: \"Di Madinah terjadi kegaduhan, lalu Nabi shallallahu 'alaihi wasallam meminjam kuda milik Abu Thalhah yang bernama Al Mandub, lalu Beliau pacu kudanya menuju suara itu. Kemudian beliau kembali dan berkata: \"Kami tidak melihat sesuatupun, dan sungguh aku dapatkan kuda ini sedemikian cepat larinya, bagaikan ombak menggulung lautan."},"2435":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ قَالَ حَدَّثَنِي أَبِي قَالَ دَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَعَلَيْهَا دِرْعُ قِطْرٍ ثَمَنُ خَمْسَةِ دَرَاهِمَ فَقَالَتْارْفَعْ بَصَرَكَ إِلَى جَارِيَتِي انْظُرْ إِلَيْهَا فَإِنَّهَا تُزْهَى أَنْ تَلْبَسَهُ فِي الْبَيْتِ وَقَدْ كَانَ لِي مِنْهُنَّ دِرْعٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا كَانَتْ امْرَأَةٌ تُقَيَّنُ بِالْمَدِينَةِ إِلَّا أَرْسَلَتْ إِلَيَّ تَسْتَعِيرُهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Abdul Wahid bin Aiman] berkata, telah menceritakan kepadaku [bapakku] berkata; Aku menemui ['Aisyah radliallahu 'anha] yang mengenakan kain yang tebal dengan harga lima dirham, ia berkata: \"Tolong sorotkan pandanganmu kearah budakku, lihatlah padanya bahwa ia menyombongkan diri dengan memakainya di rumah, dan aku dulu memiliki pakaian pada masa Rasulullah shallallahu 'alaihi wasallam yang tidak ada seorang wanitapun di Madinah yang berhias diri kecuali mereka diberi saran menemuiku untuk meminjamnya."},"2436":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الْمَنِيحَةُ اللِّقْحَةُ الصَّفِيُّ مِنْحَةً وَالشَّاةُ الصَّفِيُّ تَغْدُو بِإِنَاءٍ وَتَرُوحُ بِإِنَاءٍحَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ وَإِسْمَاعِيلُ عَنْ مَالِكٍ قَالَ نِعْمَ الصَّدَقَةُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baiknya pemberian adalah unta yang baru melahirkan yang banyak susunya, yang didapatkan dari ghanimah yang belum dibagi sebagai anugerah dari Allah, dan kambing yang didapatkan dari harta ghanimah yang belum dibagi, ia berangkat pagi hari dengan kantung kosong, namun pulang dengan kantung yang penuh berisi\". Telah menceritakan kepada kami ['Abdullah bin Yusuf] dan [Isma'il] dari [Malik] berkata: \"Sebaik-baik shadaqah\"."},"2437":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا قَدِمَ الْمُهَاجِرُونَ الْمَدِينَةَ مِنْ مَكَّةَ وَلَيْسَ بِأَيْدِيهِمْ يَعْنِي شَيْئًا وَكَانَتْ الْأَنْصَارُ أَهْلَ الْأَرْضِ وَالْعَقَارِ فَقَاسَمَهُمْ الْأَنْصَارُ عَلَى أَنْ يُعْطُوهُمْ ثِمَارَ أَمْوَالِهِمْ كُلَّ عَامٍ وَيَكْفُوهُمْ الْعَمَلَ وَالْمَئُونَةَ وَكَانَتْ أُمُّهُ أُمُّ أَنَسٍ أُمُّ سُلَيْمٍ كَانَتْ أُمَّ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ فَكَانَتْ أَعْطَتْ أُمُّ أَنَسٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِذَاقًا فَأَعْطَاهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَّ أَيْمَنَ مَوْلَاتَهُ أُمَّ أُسَامَةَ بْنِ زَيْدٍ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا فَرَغَ مِنْ قَتْلِ أَهْلِ خَيْبَرَ فَانْصَرَفَ إِلَى الْمَدِينَةِ رَدَّ الْمُهَاجِرُونَ إِلَى الْأَنْصَارِ مَنَائِحَهُمْ الَّتِي كَانُوا مَنَحُوهُمْ مِنْ ثِمَارِهِمْ فَرَدَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أُمِّهِ عِذَاقَهَا وَأَعْطَى رَسُولُ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَّ أَيْمَنَ مَكَانَهُنَّ مِنْ حَائِطِهِوَقَالَ أَحْمَدُ بْنُ شَبِيبٍ أَخْبَرَنَا أَبِي عَنْ يُونُسَ بِهَذَا وَقَالَ مَكَانَهُنَّ مِنْ خَالِصِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Anas bin Malik radliallahu 'anhu] berkata; Ketika orang-orang Muhajirin sampai di Madinah dari Makkah tanpa bekal sesuatupun ditangan mereka, sedangkan orang-orang Anshar adalah pemilik tanah dan perabotan, maka orang-orang Anshar berjanji kepada mereka untuk memberi buah dari harta mereka itu setiap tahun dan mencukupi mereka dengan pekerjaan dan keamanan. Adalah ibunya yakni ibunya Anas, bernama Ummu Sulaim, yang juga adalah ibunya 'Abdullah bin Abi Thalhah, Ibu Anas pernah memberi Rasulullah shallallahu 'alaihi wasallam buah kurma, lalu Nabi shallallahu 'alaihi wasallam memberikannya kepada ummu Aiman, maula ummu Usamah bin Zaid. Ibnu Syihab berkata, maka Anas bin Malik mengabariku bahwasanya ketika Nabi shallallahu 'alaihi wasallam selesai dari perang Khaibar, Beliau kembali ke Madinah dan orang-orang muhajirin mengembalikan apa yang diberikan orang-orang Anshar kepada mereka berupa buah-buahan. Kemudian Nabi shallallahu 'alaihi wasallam mengembalikan kepada ibunya (Anas) buah kurmanya dan Rasulullah shallallahu 'alaihi wasallam memberi ummu Aiman pengganti dari kebunnya. Dan [Ahmad bin Syabib] berkata, telah mengabarkan kepada kami [bapakku] dari [Yunus] dengan hadits ini, dan berkata: \"menggantinya dari harta miliknya sendiri\"."},"2438":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ أَبِي كَبْشَةَ السَّلُولِيِّ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعُونَ خَصْلَةً أَعْلَاهُنَّ مَنِيحَةُ الْعَنْزِ مَا مِنْ عَامِلٍ يَعْمَلُ بِخَصْلَةٍ مِنْهَا رَجَاءَ ثَوَابِهَا وَتَصْدِيقَ مَوْعُودِهَا إِلَّا أَدْخَلَهُ اللَّهُ بِهَا الْجَنَّةَقَالَ حَسَّانُ فَعَدَدْنَا مَا دُونَ مَنِيحَةِ الْعَنْزِ مِنْ رَدِّ السَّلَامِ وَتَشْمِيتِ الْعَاطِسِ وَإِمَاطَةِ الْأَذَى عَنْ الطَّرِيقِ وَنَحْوِهِ فَمَا اسْتَطَعْنَا أَنْ نَبْلُغَ خَمْسَ عَشْرَةَ خَصْلَةً","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Isa bin Yunus] telah menceritakan kepada kami [Al Awza'iy] dari [Hassan bin 'Athiyyah] dari [Abu Kabsyah] (Kabsyah tabi'in, tak jumpa Sahabat) -Saluliy aku mendengar ['Abdullah bin 'Amru radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada empat puluh kebiasaan baik, yang tertingginya adalah memberi seekor kambing. Tidaklah seseorang beramal dari perbuatan-perbuatan kebaikan tersebut dengan harapan dia mengharap pahala darinya dan membenarkan apa yang dijanjikan padanya, melainkan Allah memasukkannya dengan amalnya ke dalam surga\". Hassan berkata: \"Maka kami menghitung kebiasaan baik itu setelah pemberian kambing mulai dari menjawab salam, menjawab orang yang bersin, menyingkirkan halangan dari jalan dan yang semisalnya namun kami tidak sanggup untuk sampai pada lima belas kebiasaan baik tersebut\"."},"2439":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي عَطَاءٌ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَتْ لِرِجَالٍ مِنَّا فُضُولُ أَرَضِينَ فَقَالُوا نُؤَاجِرُهَا بِالثُّلُثِ وَالرُّبُعِ وَالنِّصْفِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ لِيَمْنَحْهَا أَخَاهُ فَإِنْ أَبَى فَلْيُمْسِكْ أَرْضَهُوَقَالَ مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي الزُّهْرِيُّ حَدَّثَنِي عَطَاءُ بْنُ يَزِيدَ حَدَّثَنِي أَبُو سَعِيدٍ قَالَ جَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ الْهِجْرَةِ فَقَالَ وَيْحَكَ إِنَّ الْهِجْرَةَ شَأْنُهَا شَدِيدٌ فَهَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَتُعْطِي صَدَقَتَهَا قَالَ نَعَمْ قَالَ فَهَلْ تَمْنَحُ مِنْهَا شَيْئًا قَالَ نَعَمْ قَالَ فَتَحْلُبُهَا يَوْمَ وِرْدِهَا قَالَ نَعَمْ قَالَ فَاعْمَلْ مِنْ وَرَاءِ الْبِحَارِ فَإِنَّ اللَّهَ لَنْ يَتِرَكَ مِنْ عَمَلِكَ شَيْئًا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al Awza'iy] berkata, telah menceritakan kepadaku ['Atho'] dari [Jabir radliallahu 'anhu] berkata; Ada orang-orang dari kami yang memiliki banyak lahan tanah. Mereka berkata: \"Kami akan sewakan dengan pembagian sepertiga, seperempat dan atau setengah\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang memiliki lahan hendaklah dia tanami atau dia berikan kepada saudaranya untuk digarap. Jika dia tidak mau, hendaklah dia biarkan tanahnya\". Dan Mujahid bin Yusuf berkata, telah menceritakan kepada kami Al Awza'iy telah menceritakan kepadaku Az Zuhriy telah menceritakan kapadaku 'Atho' bin Yazid telah menceritakan kapadaku Abu Sa'id berkata: \"Datang seorang Baduy kepada Nabi shallallahu 'alaihi wasallam lalu bertanya tentang hijrah. Maka Beliau menjawab: \"Bagaimana kamu ini, sesungguhnya hijrah adalah perkara yang berat. Apakah kamu ada memiliki unta?\" Dia menjawab: \"Ya punya\". Lalu Beliau bertanya: \"Apakah kamu mengeluarkan zakatnya?\" Dia menjawab: \"Ya\". Beliau bertanya lagi: \"Apakah ada darinya yang kamu berikan (hadiahkan)?\" Dia menjawab: \"Ya\". Beliau bertanya lagi: \"Apakah kamu memberinya susu saat kehausan?\" Dia menjawab: \"Ya\". Maka Beliau bersabda: \"Beramallah kamu dari seberang lautan karena Allah tidak akan mengurangi sedikitpun dari amalan kamu\"."},"2440":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ عَمْرٍو عَنْ طَاوُسٍ قَالَ حَدَّثَنِي أَعْلَمُهُمْ بِذَاكَ يَعْنِي ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى أَرْضٍ تَهْتَزُّ زَرْعًا فَقَالَ لِمَنْ هَذِهِ فَقَالُوا اكْتَرَاهَا فُلَانٌ فَقَالَ أَمَا إِنَّهُ لَوْ مَنَحَهَا إِيَّاهُ كَانَ خَيْرًا لَهُ مِنْ أَنْ يَأْخُذَ عَلَيْهَا أَجْرًا مَعْلُومًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari ['Amru] dari [Thawus] berkata, telah menceritakan kepadaku orang yang paling mengerti diantara mereka yakni [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam keluar menuju suatu lahan tanah yang ditumbuhi tanaman lalu Beliau berkata: \"Milik siapakah ini?\" Mereka berkata: \"Si fulan menyewakannya\". Maka Beliau berkata: \"Seandainya dia menghadiahkannya kepadanya itu, kebih baik baginya dari pada dia mengambil upah tertentu\"."},"2441":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَاجَرَ إِبْرَاهِيمُ بِسَارَةَ فَأَعْطَوْهَا آجَرَ فَرَجَعَتْ فَقَالَتْ أَشَعَرْتَ أَنَّ اللَّهَ كَبَتَ الْكَافِرَ وَأَخْدَمَ وَلِيدَةًوَقَالَ ابْنُ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْدَمَهَا هَاجَرَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nabi Ibrahim Alaihissalam berhijrah bersama Sarah lalu diberi Ajara (Siti Hajar), lalu Sarah kembali dan berkata: \"Apakah kamu mengerti bahwa Allah telah mengenyahkan orang kafir dan menghadiahi seorang hamba sahaya?\" Dan berkata [Ibnu Sirin] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam: \"Menghadiahkan Hajar sebagai pelayan\"."},"2442":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ أَخْبَرَنَا سُفْيَانُ قَالَ سَمِعْتُ مَالِكًا يَسْأَلُ زَيْدَ بْنَ أَسْلَمَ قَالَ سَمِعْتُ أَبِي يَقُولُ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُحَمَلْتُ عَلَى فَرَسٍ فِي سَبِيلِ اللَّهِ فَرَأَيْتُهُ يُبَاعُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَشْتَرِهِ وَلَا تَعُدْ فِي صَدَقَتِكَ","id":"Telah menceritakan kepada kami [Al Humaidiy] telah mengabarkan kepada kami [Sufyan] berkata, aku mendengar Malik bertanya kepada [Zaid bin Aslam] berkata, aku mendengar [Bapakku] berkata; ['Umar radliallahu 'anhu] berkata: \"Aku membawa (menghibahkan) kuda di jalan Allah kemudian aku melihat kuda itu dijual. Aku tanyakan hal ini kepada Rasulullah shallallahu 'alaihi wasallam maka Beliau bersabda: \"Jangan kamu beli dan jangan pula kamu minta kembali shadaqahmu\"."},"2443":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ النُّمَيْرِيُّ حَدَّثَنَا يُونُسُ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَابْنُ الْمُسَيَّبِ وَعَلْقَمَةُ بْنُ وَقَّاصٍ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ حَدِيثِ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَبَعْضُ حَدِيثِهِمْ يُصَدِّقُ بَعْضًاحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيًّا وَأُسَامَةَ حِينَ اسْتَلْبَثَ الْوَحْيُ يَسْتَأْمِرُهُمَا فِي فِرَاقِ أَهْلِهِ فَأَمَّا أُسَامَةُ فَقَالَ أَهْلُكَ وَلَا نَعْلَمُ إِلَّا خَيْرًا وَقَالَتْ بَرِيرَةُ إِنْ رَأَيْتُ عَلَيْهَا أَمْرًا أَغْمِصُهُ أَكْثَرَ مِنْ أَنَّهَا جَارِيَةٌ حَدِيثَةُ السِّنِّ تَنَامُ عَنْ عَجِينِ أَهْلِهَا فَتَأْتِي الدَّاجِنُ فَتَأْكُلُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَعْذِرُنَا فِي رَجُلٍ بَلَغَنِي أَذَاهُ فِي أَهْلِ بَيْتِي فَوَاللَّهِ مَا عَلِمْتُ مِنْ أَهْلِي إِلَّا خَيْرًا وَلَقَدْ ذَكَرُوا رَجُلًا مَا عَلِمْتُ عَلَيْهِ إِلَّا خَيْرًا","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami ['Abdullah bin 'Umar an-Numairiy] telah menceritakan kepada kami [Yunus] dan berkata, [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] berkata, telah mengabarkan kepada kami ['Urwah bin Az Zubair] dan [Ibnu Al Musayyab] dan ['Alqamah bin Waqqash] dan ['Ubaidullah bin 'Abdullah] tentang peristiwa yang menimpa ['Aisyah radliallahu 'anha], yang sebagian ghosip mereka membenarkan lainnya, tepatnya ketika Ahlul Ifki (orang-orang yang menyebarkan isu bahwa 'Aisyah selingkuh) melemparkan tuduhan kepadanya. Maka Rasulullah shallallahu 'alaihi wasallam memanggil 'Ali dan Usamah ketika wahyu tidak kunjung turun, Beliau meminta pendapat keduanya tentang niat menceraikan isteri Beliau. Adapun Usamah, dia berpendapat: \"Keluarga baginda, tidak kami ketahui kecuali kebaikan semata. Sedangkan Barirah berkata: \"Kalaupun aku melihat kekurangan pada 'Aisyah, tidak lebih sekedar ketika masih sebagai gadis kecil dibawah umur, ia ketiduran ketika menunggu adonan keluarganya lalu datang hewan kecil kemudian memakannya\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang bisa memberiku alasan kepada kami tentang seseorang yang beritanya telah sampai kepadaku bahwa dia telah melancarkan gangguan keluargaku. Demi Allah tidaklah aku ketahui keluargaku melainkan kebaikan semata, dan sungguh orang-orang telah menyebut seseorang laki-laki padahal aku tidak mengenal orang itu melainkan kebaikan\"."},"2444":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ سَالِمٌ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُانْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُبَيُّ بْنُ كَعْبٍ الْأَنْصَارِيُّ يَؤُمَّانِ النَّخْلَ الَّتِي فِيهَا ابْنُ صَيَّادٍ حَتَّى إِذَا دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَفِقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَّقِي بِجُذُوعِ النَّخْلِ وَهُوَ يَخْتِلُ أَنْ يَسْمَعَ مِنْ ابْنِ صَيَّادٍ شَيْئًا قَبْلَ أَنْ يَرَاهُ وَابْنُ صَيَّادٍ مُضْطَجِعٌ عَلَى فِرَاشِهِ فِي قَطِيفَةٍ لَهُ فِيهَا رَمْرَمَةٌ أَوْ زَمْزَمَةٌ فَرَأَتْ أُمُّ ابْنِ صَيَّادٍ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَّقِي بِجُذُوعِ النَّخْلِ فَقَالَتْ لِابْنِ صَيَّادٍ أَيْ صَافِ هَذَا مُحَمَّدٌ فَتَنَاهَى ابْنُ صَيَّادٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَرَكَتْهُ بَيَّنَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, [Salim] aku mendengar ['Abdullah bin 'Umar radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam dan Ubay bin Ka'ab Al Anshariy pergi menuju pepohonan kurma yang disana ada Ibnu Shayyad, hingga ketika Rasulullah shallallahu 'alaihi wasallam menemuinya, Ibnu Shoyyad sedang bersandar di bawah pohon kurma dan Beliau ingin mendengar sesuatu dari Ibnu Shayyad secara rahasia sebelum dia melihat Beliau. Ketika itu Ibnu Shayyad berbaring diatas tikarnya dan mengeluarkan suara samar-samar yang nyaris takbisa dipahami. Ibu Ibnu Shayyad rupanya melihat Nabi shallallahu 'alaihi wasallam saat Ibnu Shayad masih bersandar di bawah pohon kurma tersebut lalu ia berkata kepada Ibnu Shayyad: \"Wahai anakku ini Muhammad datang\". Akhirnya Ibnu Shayyad terjaga. Rasulullah shallallahu 'alaihi wasallam kemudian berkata: \"Seandainya ibunya membiarkannya tentu akan jelas (Ibnu Shayyad dajjal atau bukan)."},"2445":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاجَاءَتْ امْرَأَةُ رِفاعَةَ الْقُرَظِيِّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كُنْتُ عِنْدَ رِفَاعَةَ فَطَلَّقَنِي فَأَبَتَّ طَلَاقِي فَتَزَوَّجْتُ عَبْدَ الرَّحْمَنِ بْنَ الزَّبِيرِ إِنَّمَا مَعَهُ مِثْلُ هُدْبَةِ الثَّوْبِ فَقَالَ أَتُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى تَذُوقِي عُسَيْلَتَهُ وَيَذُوقَ عُسَيْلَتَكِ وَأَبُو بَكْرٍ جَالِسٌ عِنْدَهُ وَخَالِدُ بْنُ سَعِيدِ بْنِ الْعَاصِ بِالْبَابِ يَنْتَظِرُ أَنْ يُؤْذَنَ لَهُ فَقَالَ يَا أَبَا بَكْرٍ أَلَا تَسْمَعُ إِلَى هَذِهِ مَا تَجْهَرُ بِهِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhriy] dari ['Urwah] dari ['Aisyah radliallahu 'anha]; Isteri Rifa'ah Al Qurazhiy datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata: \"Aku hidup berkeluarga bersama Rifa'ah lalu dia menceraikan aku dengan tholaq tiga lalu aku menikah dengan 'Abdurrahman bin Az Zubair namun dia ternyata lebih mementingkan dirinya sendiri. Maka Beliau berkata: \"Apakah kamu mau kembali dengan Rifa'ah sehingga kamu dapat merasakan kemesraannya dan dia dapat pula merasakan kemesraan darimu\". Saat itu Abu Bakar sedang duduk di dekat Beliau sedangkan Khalid bin Sa'id bin Al 'Ash berada di pintu menunggu diizinkan masuk lalu dia berkata: \"Wahai Abu Bakar, apakah kamu mendengar apa yang dikatakan perempuan ini di hadapan Nabi shallallahu 'alaihi wasallam?\""},"2446":{"ar":"حَدَّثَنَا حِبَّانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عُمَرُ بْنُ سَعِيدِ بْنِ أَبِي حُسَيْنٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِأَنَّهُ تَزَوَّجَ ابْنَةً لِأَبِي إِهَابِ بْنِ عَزِيزٍ فَأَتَتْهُ امْرَأَةٌ فَقَالَتْ قَدْ أَرْضَعْتُ عُقْبَةَ وَالَّتِي تَزَوَّجَ فَقَالَ لَهَا عُقْبَةُ مَا أَعْلَمُ أَنَّكِ أَرْضَعْتِنِي وَلَا أَخْبَرْتِنِي فَأَرْسَلَ إِلَى آلِ أَبِي إِهَابٍ يَسْأَلُهُمْ فَقَالُوا مَا عَلِمْنَا أَرْضَعَتْ صَاحِبَتَنَا فَرَكِبَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ فَسَأَلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ وَقَدْ قِيلَ فَفَارَقَهَا وَنَكَحَتْ زَوْجًا غَيْرَهُ","id":"Telah menceritakan kepada kami [Habban] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami ['Umar bin Sa'id bin Abi Husain] berkata, telah menceritakan kepadaku ['Abdullah bin Abi Mulaikah] dari ['Uqbah bin Al Harits] bahwa dia mengawini putri dari Abu Ihab bin 'aziz lalu datang seorang wanita dan berkata; \"Sungguh aku pernah menyusui 'Uqbah dan wanita yang sekarang dikawininya\". Kemudian 'Uqbah berkata, kepadanya: \"Aku tidak tahu kalau kamu telah menyusui aku dan kamu tidak memberitahu aku\". Maka dia pergi menuju keluarga Abu Ihab untuk menanyakan mereka, maka mereka berkata: \"Kami tidak tahu kalau wanita itu telah menyusui perempuan-perempuan kami\". Lalu dia mengendarai tunggangan untuk menemui Nabi shallallahu 'alaihi wasallam di Madinah lalu dia bertanya, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mau bagaimana lagi, wanita itu sudah mengatakannya\". Maka 'Uqbah menceraikan isterinya itu lalu menikahi wanita lain."},"2447":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُتْبَةَ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُإِنَّ أُنَاسًا كَانُوا يُؤْخَذُونَ بِالْوَحْيِ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّ الْوَحْيَ قَدْ انْقَطَعَ وَإِنَّمَا نَأْخُذُكُمْ الْآنَ بِمَا ظَهَرَ لَنَا مِنْ أَعْمَالِكُمْ فَمَنْ أَظْهَرَ لَنَا خَيْرًا أَمِنَّاهُ وَقَرَّبْنَاهُ وَلَيْسَ إِلَيْنَا مِنْ سَرِيرَتِهِ شَيْءٌ اللَّهُ يُحَاسِبُهُ فِي سَرِيرَتِهِ وَمَنْ أَظْهَرَ لَنَا سُوءًا لَمْ نَأْمَنْهُ وَلَمْ نُصَدِّقْهُ وَإِنْ قَالَ إِنَّ سَرِيرَتَهُ حَسَنَةٌ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepadaku [Humaid bin 'Abdurrahman bin 'Auf] bahwa ['Abdullah bin 'Utbah] berkata, aku mendengar ['Umar bin Al Khaththob radliallahu 'anhu] berkata: \"Sesungguhnya orang-orang telah mengambil wahyu (sebagai pedoman) pada masa hidup Rasulullah shallallahu 'alaihi wasallam dan hari ini wahyu sudah terputus. Dan hari ini kita menilai kalian berdasarkan amal amal yang nampak (zhahir). Maka siapa yang secara zhahir menampakkan perbuatan baik kepada kita, kita percaya kepadanya dan kita dekat dengannya dan bukan urusan kita apa yang tersembunyi darinya karena hal itu sesuatu yang menjadi urusan Allah dan Dia yang akan menghitungnya. Dan siapa yang menampakkan perbuatan yang jelek kepada kita, maka kita tidak percaya kepadanya dan tidak membenarkannya sekalipun dibalik itu ada yang mengatakan baik\"."},"2448":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَمُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَنَازَةٍ فَأَثْنَوْا عَلَيْهَا خَيْرًا فَقَالَ وَجَبَتْ ثُمَّ مُرَّ بِأُخْرَى فَأَثْنَوْا عَلَيْهَا شَرًّا أَوْ قَالَ غَيْرَ ذَلِكَ فَقَالَ وَجَبَتْ فَقِيلَ يَا رَسُولَ اللَّهِ قُلْتَ لِهَذَا وَجَبَتْ وَلِهَذَا وَجَبَتْ قَالَ شَهَادَةُ الْقَوْمِ الْمُؤْمِنُونَ شُهَدَاءُ اللَّهِ فِي الْأَرْضِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas radliallahu 'anhu] berkata; Ada jenazah yang diusung lewat di hadapan Nabi shallallahu 'alaihi wasallam lalu orang-orang memuji jenazah tersebut dengan kebaikan lalu Beliau berkata: \"Pasti\". Kemudian lewat jenazah yang lain dan orang-orang mengatakan keburukan kepadanya atau lain dari yang pertama tadi lalu Beliau berkata: \"Pasti\". Maka ditanya kepada Rasulullah shallallahu 'alaihi wasallam: \"(Apa maksudnya) Baginda mengatakan untuk yang ini pasti dan untuk yang itu pasti?\" Beliau bersabda: \"Persaksian orang-orang beriman adalah saksi-saksinya Allah di muka bumi\"."},"2449":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي الْفُرَاتِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ قَالَ أَتَيْتُ الْمَدِينَةَ وَقَدْ وَقَعَ بِهَا مَرَضٌ وَهُمْ يَمُوتُونَ مَوْتًا ذَرِيعًا فَجَلَسْتُ إِلَى عُمَرَ رَضِيَ اللَّهُ عَنْهُفَمَرَّتْ جَنَازَةٌ فَأُثْنِيَ خَيْرًا فَقَالَ عُمَرُ وَجَبَتْ ثُمَّ مُرَّ بِأُخْرَى فَأُثْنِيَ خَيْرًا فَقَالَ وَجَبَتْ ثُمَّ مُرَّ بِالثَّالِثَةِ فَأُثْنِيَ شَرًّا فَقَالَ وَجَبَتْ فَقُلْتُ وَمَا وَجَبَتْ يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ قُلْتُ كَمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا مُسْلِمٍ شَهِدَ لَهُ أَرْبَعَةٌ بِخَيْرٍ أَدْخَلَهُ اللَّهُ الْجَنَّةَ قُلْنَا وَثَلَاثَةٌ قَالَ وَثَلَاثَةٌ قُلْتُ وَاثْنَانِ قَالَ وَاثْنَانِ ثُمَّ لَمْ نَسْأَلْهُ عَنْ الْوَاحِدِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Daud bin Abi Al Furat] telah menceritakan kepada kami ['Abdullah bin Buraidah] dari [Abu Al Aswad] berkata: \"Aku mengunjungi Madinah saat banyak orang sakit yang membawa kepada kematian mereka kemudia aku duduk di sisi ['Umar] radliallahu 'anhu saat lewat jenazah lalu jenazah itu dipuji dengan kebaikan maka 'Umar berkata: \"Pasti\". Kemudian lewat jenazah lain lalu dipuji pula dengan kebaikan maka 'Umar berkata: \"Pasti\". Kemudian lewat jenazah ketiga namun dicela dengan kejelekkan lalu diapun berkata: \"Pasti\". Maka aku tanyakan: \"Apa yang dimaksud pasti wahai amirul mu'minin?\" Maka 'Umar berkata: \"Sebagaimana Nabi shallallahu 'alaihi wasallam pernah mengatakannya: \"Siapa saja dari muslim (yang meninggal dunia) lalu dipersaksikan dengan kebaikan oleh empat orang maka dia pasti akan dimasukkan oleh Allah kedalam surga\". Kami bertanya: \"Bagaimana kalau hanya disaksikan oleh tiga orang?\" Beliau menjawab: \"Ya juga oleh tiga orang\". Aku katakan: \"Bagaimana kalau dua orang?\" Beliau menjawab: \"Ya juga oleh dua orang\". Kemudian kami tidak bertanya bila hanya oleh satu orang\"."},"2450":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا الْحَكَمُ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَأْذَنَ عَلَيَّ أَفْلَحُ فَلَمْ آذَنْ لَهُ فَقَالَ أَتَحْتَجِبِينَ مِنِّي وَأَنَا عَمُّكِ فَقُلْتُ وَكَيْفَ ذَلِكَ قَالَ أَرْضَعَتْكِ امْرَأَةُ أَخِي بِلَبَنِ أَخِي فَقَالَتْ سَأَلْتُ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَدَقَ أَفْلَحُ ائْذَنِي لَهُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami [Al Hakam] dari ['Irak bin Malik] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha] berkata: \"Aflah meminta ijin kepadaku namun aku tidak mengijinkannya. Dia berkata: \"Apakah kamu menghindari aku padahal aku ini pamanmu?\" Aku katakan: \"Bagaimana bisa (engkau sebagai pamanku)?\" Dia menjawab: \"Isteri saudaraku telah menyusuimu\". Maka 'Aisyah berkata: \"Lalu aku tanyakan hal ini kepada Rasulullah shallallahu 'alaihi wasallam, lalu Beliau bersabda: \"Aflah benar, ijinkanlah ia masuk\"."},"2451":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بِنْتِ حَمْزَةَ لَا تَحِلُّ لِي يَحْرُمُ مِنْ الرَّضَاعِ مَا يَحْرُمُ مِنْ النَّسَبِ هِيَ بِنْتُ أَخِي مِنْ الرَّضَاعَةِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Jabir bin Zaid] dari [Ibnu 'Abbas radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam berkata tentang putri Hamzah: \"Dia tidak halal bagiku karena apa yang diharamkan karena sepersusuan sama diharamkan karena keturunan sedangkan dia adalah putri dari saudaraku sepersusuan\"."},"2452":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَهَا وَأَنَّهَا سَمِعَتْ صَوْتَ رَجُلٍ يَسْتَأْذِنُ فِي بَيْتِ حَفْصَةَ قَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا رَجُلٌ يَسْتَأْذِنُ فِي بَيْتِكَ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرَاهُ فُلَانًا لِعَمِّ حَفْصَةَ مِنْ الرَّضَاعَةِ فَقَالَتْ عَائِشَةُ لَوْ كَانَ فُلَانٌ حَيًّا لِعَمِّهَا مِنْ الرَّضَاعَةِ دَخَلَ عَلَيَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِنَّ الرَّضَاعَةَ تُحَرِّمُ مَا يَحْرُمُ مِنْ الْوِلَادَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Abu Bakar] dari ['Amrah binti 'Abdurrahman] bahwa ['Aisyah radliallahu 'anha], isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pada suatu hari berada bersamanya dan saat itu dia mendengar suatu suara seorang laki-laki yang meminta ijin di rumah Hafshah. 'Aisyah radliallahu 'anha berkata: \"Lalu aku katakan kepada Rasulullah shallallahu 'alaihi wasallam: \"Ada seorang laki-laki minta izin masuk di rumah baginda?\" 'Aisyah berkata: \"Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Aku mengenal bahwa laki-laki itu adalah menjadi paman Hafshah karena sesusuan\". Maka 'Aisyah radliallahu 'anha berkata: \"Seandainya si fulan masih hidup yang dia menjadi pamannya karena sesusuan berarti boleh masuk menemuiku?\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya benar, karena satu susuan menjadikan sesuatu diharamkan seperti apa yang diharamkan karena (kelahiran) keturunan\"."},"2453":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدِي رَجُلٌ قَالَ يَا عَائِشَةُ مَنْ هَذَا قُلْتُ أَخِي مِنْ الرَّضَاعَةِ قَالَ يَا عَائِشَةُ انْظُرْنَ مَنْ إِخْوَانُكُنَّ فَإِنَّمَا الرَّضَاعَةُ مِنْ الْمَجَاعَةِتَابَعَهُ ابْنُ مَهْدِيٍّ عَنْ سُفْيَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Asy'ats bin Abi Asy-Sya'naa'] dari [bapaknya] dari [Masruq] bahwa ['Aisyah Radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam menemuiku dan saat itu disampingku ada seorang pemuda. Beliau bertanya: \"Wahai 'Aisyah, siapakah orang ini?\" Aku menjawab: \"Ia saudara sesusuanku\". Beliau bersabda: \"Wahai 'Aisyah lihatlah siapa yang menjadi saudara-saudara kalian, karena sesusuan itu terjadi karena kelaparan\". [Ibnu Mahdiy] juga meriwayatkannya dari [Sufyan]."},"2454":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِأَنَّ امْرَأَةً سَرَقَتْ فِي غَزْوَةِ الْفَتْحِ فَأُتِيَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَمَرَ بِهَا فَقُطِعَتْ يَدُهَا قَالَتْ عَائِشَةُ فَحَسُنَتْ تَوْبَتُهَا وَتَزَوَّجَتْ وَكَانَتْ تَأْتِي بَعْدَ ذَلِكَ فَأَرْفَعُ حَاجَتَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Ibnu Wahb] dari [Yunus]. Dan berkata, [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kapadaku ['Urwah bin Az Zubair] bahwa ada seorang wanita yang mencuri saat peperangan pembebasan Makkah, kemudian wanita dibawa ke hadapan Rasulullah shallallahu 'alaihi wasallam, lalu Beliau memerintahkan untuk memotong tangan wanita tersebut. ['Aisyah radliallahu 'anha] berkata: \"Wanita tersebut menindaklanjuti taubatnya dengan baik, lalu wanita itu menikah. Setelah itu, suatu hari wanita itu datang untuk menyampaikan kebutuhannya kepada Rasulullah shallallahu 'alaihi wasallam\"."},"2455":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ زَيْدِ بْنِ خَالِدٍ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَمَرَ فِيمَنْ زَنَى وَلَمْ يُحْصَنْ بِجَلْدِ مِائَةٍ وَتَغْرِيبِ عَامٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidulloh bin 'Abdullah] dari [Zaid bin Khalid radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam, bahwa Beliau memerintahkan bagi siapa yang berzina dan belum pernah menikah agar dicambuk seratus kali dan diasingkan selama setahun\"."},"2456":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا أَبُو حَيَّانَ التَّيْمِيُّ عَنْ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَأَلَتْ أُمِّي أَبِي بَعْضَ الْمَوْهِبَةِ لِي مِنْ مَالِهِ ثُمَّ بَدَا لَهُ فَوَهَبَهَا لِي فَقَالَتْ لَا أَرْضَى حَتَّى تُشْهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ بِيَدِي وَأَنَا غُلَامٌ فَأَتَى بِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُمَّهُ بِنْتَ رَوَاحَةَ سَأَلَتْنِي بَعْضَ الْمَوْهِبَةِ لِهَذَا قَالَ أَلَكَ وَلَدٌ سِوَاهُ قَالَ نَعَمْ قَالَ فَأُرَاهُ قَالَ لَا تُشْهِدْنِي عَلَى جَوْرٍوَقَالَ أَبُو حَرِيزٍ عَنْ الشَّعْبِيِّ لَا أَشْهَدُ عَلَى جَوْرٍ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Abu Hayyan an-Taimiy] dari [Asy-Sya'biy] dari [An Nu'man bin Basyir radliallahu 'anhuma] berkata: \"Ibuku bertanya bapakku perihal sebagian pemberiannya kepadaku dari hartanya kemudian dia ingin memberikannya semua kepadaku, maka ibuku berkata: \"Aku tidak rela sampai kamu persaksikan kepada Nabi shallallahu 'alaihi wasallam. Maka ayahku membawaku, saat itu aku masih kecil, menemui Nabi shallallahu 'alaihi wasallam lalu berkata: \"Sesungguhnya ibunya, binti Ruwahah, bertanya kepadaku tentang sebagaian pemberianku kepada anak ini\". Beliau bertanya: \"Apakah kamu memiliki anak selain dia ini\". Bapakku menjawab: \"Ya punya\". Dia berkata: \"Aku menduga Beliau bersabda: \"Janganlah engkau ajak aku dalam persaksian yang curang\". Dan berkata, [Abu Hariz] dari [Asy Sya'biy]: \"Aku tidak mau bersaksi diatas kecurangan\"."},"2457":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو جَمْرَةَ قَالَ سَمِعْتُ زَهْدَمَ بْنَ مُضَرِّبٍ قَالَ سَمِعْتُ عِمْرَانَ بْنَ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُكُمْ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ قَالَ عِمْرَانُ لَا أَدْرِي أَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ قَرْنَيْنِ أَوْ ثَلَاثَةً قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَعْدَكُمْ قَوْمًا يَخُونُونَ وَلَا يُؤْتَمَنُونَ وَيَشْهَدُونَ وَلَا يُسْتَشْهَدُونَ وَيَنْذِرُونَ وَلَا يَفُونَ وَيَظْهَرُ فِيهِمْ السِّمَنُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Jamrah] berkata,, aku mendengar [Zahdam bin Mudharrib] berkata; aku mendengar ['Imran bin Hushain radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah yang hidup pada zamanku (generasiku) kemudian orang-orang yang datang setelah mereka kemudian orang-orang yang datang setelah mereka\". 'Imran berkata: \"Aku tidak tahu apakah Nabi shallallahu 'alaihi wasallam menyebutkan lagi setelah (generasi beliau) dua atau tiga generasi setelahnya\". Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setelah kalian akan ada kaum yang suka berkhianat (sehingga) mereka tidak dipercaya, mereka suka bersaksi padahal tidak diminta persaksian mereka, mereka juga suka memberi peringatan padahal tidak diminta berfatwa dan nampak dari ciri mereka orangnya berbadan gemuk-gemuk\"."},"2458":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ النَّاسِ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَجِيءُ أَقْوَامٌ تَسْبِقُ شَهَادَةُ أَحَدِهِمْ يَمِينَهُ وَيَمِينُهُ شَهَادَتَهُقَالَ إِبْرَاهِيمُ وَكَانُوا يَضْرِبُونَنَا عَلَى الشَّهَادَةِ وَالْعَهْدِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Ubaidah] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik manusia adalah orang-orang yang hidup pada zamanku (generasiku) kemudian orang-orang setelah mereka kemudian orang-orang setelah mereka. Kemudian akan datang sebuah kaum yang persaksian seorang dari mereka mendahului sumpahnya dan sumpahnya mendahului persaksiannya\". Ibrahim berkata; \"Dahulu, mereka (para shahabat) mengajarkan kami tentang bersaksi dan memegang janji (Mereka memukul kami bila melanggar perjanjian dan persaksian) \"."},"2459":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ وَهْبَ بْنَ جَرِيرٍ وَعَبْدَ الْمَلِكِ بْنَ إِبْرَاهِيمَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكَبَائِرِ قَالَ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ وَشَهَادَةُ الزُّورِتَابَعَهُ غُنْدَرٌ وَأَبُو عَامِرٍ وَبَهْزٌ وَعَبْدُ الصَّمَدِ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Munir] dia mendengar [Wahb bin Jarir] dan ['Abdul Malik bin Ibrahim] keduanya berkata, telah menceritakan kepadaku [Syu'bah] dari ['Ubaidullah bin Abi Bakar bin Anas] dari [Anas radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam ditanya tentang kaba'ir (dosa-dosa besar). Maka Beliau bersabda: \"Menyekutukan Allah, durhaka kepada kedua orangtua, membunuh orang dan bersumpah palsu\". Hadits ini diikuti pula oleh [Ghundar], [Abu 'Amir], [Bahz] dan ['Abdush Shamad] dari [Syu'bah]."},"2460":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُنَبِّئُكُمْ بِأَكْبَرِ الْكَبَائِرِ ثَلَاثًا قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَجَلَسَ وَكَانَ مُتَّكِئًا فَقَالَ أَلَا وَقَوْلُ الزُّورِ قَالَ فَمَا زَالَ يُكَرِّرُهَا حَتَّى قُلْنَا لَيْتَهُ سَكَتَوَقَالَ إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْجُرَيْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyir bin Al Mufadhdhol] telah menceritakan kepada kami [Al Jurairiy] dari ['Abdurrahman bin Abi Bakrah] dari [bapaknya radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam berkata: \"Apakah kalian mau aku beritahu dosa besar yang paling besar?\" Beliau menyatakannya tiga kali. Mereka menjawab: \"Mau, wahai Rasulullah\". Maka Beliau bersabda: \"Menyekutukan Allah, durhaka kepada kedua orangtua\". Lalu Beliau duduk dari sebelumnya berbaring kemudian melanjutkan sabdanya: \"Ketahuilah, juga ucapan keji (curang) \". Dia berkata: \"Beliau terus saja mengatakannya berulang-ulang hingga kami mengatakannya ' Duh sekiranya Beliau diam\". Dan berkata, [Isma'il bin Ibrahim] telah menceritakan kepada kami [Al Jurairiy] dari ['Abdurrahman]."},"2461":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَقْرَأُ فِي الْمَسْجِدِ فَقَالَ رَحِمَهُ اللَّهُ لَقَدْ أَذْكَرَنِي كَذَا وَكَذَا آيَةً أَسْقَطْتُهُنَّ ��ِنْ سُورَةِ كَذَا وَكَذَاوَزَادَ عَبَّادُ بْنُ عَبْدِ اللَّهِ عَنْ عَائِشَةَ تَهَجَّدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي فَسَمِعَ صَوْتَ عَبَّادٍ يُصَلِّي فِي الْمَسْجِدِ فَقَالَ يَا عَائِشَةُ أَصَوْتُ عَبَّادٍ هَذَا قُلْتُ نَعَمْ قَالَ اللَّهُمَّ ارْحَمْ عَبَّادًا","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid bin Maimun] telah mengabarkan kepada kami ['Isa bin Yunus] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata; Rasulullah shallallahu 'alaihi wasallam mendengar sesoerang membaca Al Qur'an di masjid lalu Beliau bersabda: \"Semoga Allah merahmati orang itu. Sungguh dia telah mengingatkan aku tentang ayat ini dan itu yang aku telah lupa dari surat ini dan itu\". Dan ['Abbad bin 'Abdullah] menambahkan dari ['Aisyah radliallahu 'anha]: \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat tahajjud di rumahku lalu Beliau mendengar suara 'Abbad yang sedang shalat di masjid lalu Beliau berkata: \"Wahai 'Aisyah, apakah itu suara 'Abbad?\" Aku jawab: \"Ya\". Maka Beliau bersabda: \"Ya Allah rahmatilah 'Abbad\"."},"2462":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُؤَذِّنَ أَوْ قَالَ حَتَّى تَسْمَعُوا أَذَانَ ابْنِ أُمِّ مَكْتُومٍ وَكَانَ ابْنُ أُمِّ مَكْتُومٍ رَجُلًا أَعْمَى لَا يُؤَذِّنُ حَتَّى يَقُولَ لَهُ النَّاسُ أَصْبَحْتَ","id":"Telah menceritakan kepada kami [Malik bin isma'il] telah menceritakan kepada kami ['Abdul 'aziz bin Abu Salamah] telah mengabarkan kepada kami [Ibnu Syihab] dari [Salim bin 'Abdullah] dari ['Abdullah bin 'Umar radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bilal mengumandangkan adzan di tengah malam, maka silahkan kalian makan dan minum hingga adzan dikumandangkan\", atau Beliau bersabda; \"Hingga kalian dengar adzan Ibnu Ummi Maktum\". Dan Ibnu Ummi Maktum adalah seorang sahabat yang buta, yang dia tidak mengumandangkan adzan kecuali setelah orang-orang berkata kepadanya 'Heih, sekarang engkau telah berada di waktu pagi (sekarang giliranmu) \"."},"2463":{"ar":"حَدَّثَنَا زِيَادُ بْنُ يَحْيَى حَدَّثَنَا حَاتِمُ بْنُ وَرْدَانَ حَدَّثَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبِيَةٌ فَقَالَ لِي أَبِي مَخْرَمَةُ انْطَلِقْ بِنَا إِلَيْهِ عَسَى أَنْ يُعْطِيَنَا مِنْهَا شَيْئًا فَقَامَ أَبِي عَلَى الْبَابِ فَتَكَلَّمَ فَعَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَوْتَهُ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ قَبَاءٌ وَهُوَ يُرِيهِ مَحَاسِنَهُ وَهُوَ يَقُولُ خَبَأْتُ هَذَا لَكَ خَبَأْتُ هَذَا لَكَ","id":"Telah menceritakan kepada kami [Ziyad bin Yahya] telah menceritakan kepada kami [Hatim bin Wardan] telah menceritakan kepada kami [Ayyub] dari ['Abdullah bin Abi Mulaikah] dari [Al Miswar bin Makhramah radliallahu 'anhu] berkata, Nabi shallallahu 'alaihi wasallam diberi beberapa potong pakaian. Lalu bapakku, Makhramah, berkata kepadaku: \"Mari kita berangkat semoga Beliau memberikan sesuatu darinya\". Maka bapakku berdiri di depan pintu lalu berbicara hingga Nabi shallallahu 'alaihi wasallam mengenal suaranya kemudian Nabi shallallahu 'alaihi wasallam keluar dengan membawa baju dengan menampakkan keindahannya seraya bersabda: \"Sengaja kami simpan buatmu, sengaja kami simpan buatmmu\"."},"2464":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي زَيْدٌ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَيْسَ شَهَادَةُ الْمَرْأَةِ مِثْلَ نِصْفِ شَهَادَةِ الرَّجُلِ قُلْنَ بَلَى قَالَ فَذَلِكَ مِنْ نُقْصَانِ عَقْلِهَا","id":"Telah menceritakan kepada kami [Ibnu Abi Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepadaku [Zaid] dari ['Iyadh bin 'Abdullah] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Bukankah persaksian seorang wanita sama dengan setengah persaksian seorang laki-laki?\" Para wanita menjawab: \"Benar\". Beliau melanjutkan: \"Itulah tanda setengah akalnya\"."},"2465":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ ح و حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُقْبَةُ بْنُ الْحَارِثِ أَوْ سَمِعْتُهُ مِنْهُأَنَّهُ تَزَوَّجَ أُمَّ يَحْيَى بِنْتَ أَبِي إِهَابٍ قَالَ فَجَاءَتْ أَمَةٌ سَوْدَاءُ فَقَالَتْ قَدْ أَرْضَعْتُكُمَا فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْرَضَ عَنِّي قَالَ فَتَنَحَّيْتُ فَذَكَرْتُ ذَلِكَ لَهُ قَالَ وَكَيْفَ وَقَدْ زَعَمَتْ أَنْ قَدْ أَرْضَعَتْكُمَا فَنَهَاهُ عَنْهَا","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abi Mulaikah] dari ['Uqbah bin Al Harits]. Dan diriwayatkan pula, telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] berkata, aku mendengar [Ibnu Abi Mulaikah] berkata, telah menceritakan kepadaku ['Uqbah bin Al Harits] atau aku mendengar darinya bahwa dia menikahi Ummu Yahya binti Ihab. Dia berkata: \"Kemudian datang seorang sahaya wanita berkulit hitam lalu berkata: \"Aku telah menyusui kalian berdua\". Peristiwa ini aku ceritakan kepada Nabi shallallahu 'alaihi wasallam, namun Beliau berpaling dariku. Kemudian aku berbicara dengan bertatapan muka dengan Beliau lalu aku ceritakan lagi masalahku kepada Beliau, maka Beliau bersabda: \"Mau bagaimana lagi, wanita itu telah mengungkapkannya atau dia telah menyusui kalian berdua\". Maka Beliau melarang dari menikahinya."},"2466":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَتَزَوَّجْتُ امْرَأَةً فَجَاءَتْ امْرَأَةٌ فَقَالَتْ إِنِّي قَدْ أَرْضَعْتُكُمَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَكَيْفَ وَقَدْ قِيلَ دَعْهَا عَنْكَ أَوْ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari ['Umar bin Sa'id] dari [Ibnu Abi Mulaikah] dari ['Uqbah bin Al Harits] berkata; \"Aku menikah dengan seorang wanita lalu datang wanita lain seraya berkata: \"Aku telah menyusui kalian berdua\". Lalu aku menemui Nabi shallallahu 'alaihi wasallam, maka Beliau bersabda: \"Wanita itu telah mengatakannya. biarkanlah wanita itu\" Atau ucapan semisalnya."},"2467":{"ar":"حَدَّثَنَا أَبُو الرَّبِيعِ سُلَيْمَانُ بْنُ دَاوُدَ وَأَفْهَمَنِي بَعْضَهُ أَحْمَدُ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ ابْنِ شِهَابٍ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَسَعِيدِ بْنِ الْمُسَيَّبِ وَعَلْقَمَةَ بْنِ وَقَّاصٍ اللَّيْثِيِّ وَعُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا فَبَرَّأَهَا اللَّهُ مِنْهُ قَالَ الزُّهْرِيُّ وَكُلُّهُمْ حَدَّثَنِي طَائِفَةً مِنْ حَدِيثِهَا وَبَعْضُهُمْ أَوْعَى مِنْ بَعْضٍ وَأَثْبَتُ لَهُ اقْتِصَاصًا وَقَدْ وَعَيْتُ عَنْ كُلِّ وَاحِدٍ مِنْهُمْ الْحَدِيثَ الَّذِي حَدَّثَنِي عَنْ عَائِشَةَ وَبَعْضُ حَدِيثِهِمْ يُصَدِّقُ بَعْضًا زَعَمُوا أَنَّ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَخْرُجَ سَفَرًا أَقْرَعَ بَيْنَ أَزْوَاجِهِ فَأَيَّتُهُنَّ خَرَجَ سَهْمُهَا خَرَجَ بِهَا مَعَهُ فَأَقْرَعَ بَيْنَنَا فِي غَزَاةٍ غَزَاهَا فَخَرَجَ سَهْمِي فَخَرَجْتُ مَعَهُ بَعْدَ مَا أُنْزِلَ الْحِجَابُ فَأَنَا أُحْمَلُ فِي هَوْدَجٍ وَأُنْزَلُ فِيهِ فَسِرْنَا حَتَّى إِذَا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَتِهِ تِلْكَ وَقَفَلَ وَدَنَوْنَا مِنْ الْمَدِينَةِ آذَنَ لَيْلَةً بِالرَّحِيلِ فَقُمْتُ حِينَ آذَنُوا بِالرَّحِيلِ فَمَشَيْتُ حَتَّى جَاوَزْتُ الْجَيْشَ فَلَمَّا قَضَيْتُ شَأْنِي أَقْبَلْتُ إِلَى الرَّحْلِ فَلَمَسْتُ صَدْرِي فَإِذَا عِقْدٌ لِي مِنْ جَزْعِ أَظْفَارٍ قَدْ انْقَطَعَ فَرَجَعْتُ فَالْتَمَسْتُ عِقْدِي فَحَبَسَنِي ابْتِغَاؤُهُ فَأَقْبَلَ الَّذِينَ يَرْحَلُونَ لِي فَاحْتَمَلُوا هَوْدَجِي فَرَحَلُوهُ عَلَى بَعِيرِي الَّذِي كُنْتُ أَرْكَبُ وَهُمْ يَحْسِبُونَ أَنِّي فِيهِ وَكَانَ النِّسَاءُ إِذْ ذَاكَ خِفَافًا لَمْ يَثْقُلْنَ وَلَمْ يَغْشَهُنَّ اللَّحْمُ وَإِنَّمَا يَأْكُلْنَ الْعُلْقَةَ مِنْ الطَّعَامِ فَلَمْ يَسْتَنْكِرْ الْقَوْمُ حِينَ رَفَعُوهُ ثِقَلَ الْهَوْدَجِ فَاحْتَمَلُوهُ وَكُنْتُ جَارِيَةً حَدِيثَةَ السِّنِّ فَبَعَثُوا الْجَمَلَ وَسَارُوا فَوَجَدْتُ عِقْدِي بَعْدَ مَا اسْتَمَرَّ الْجَيْشُ فَجِئْتُ مَنْزِلَهُمْ وَلَيْسَ فِيهِ أَحَدٌ فَأَمَمْتُ مَنْزِلِي الَّذِي كُنْتُ بِهِ فَظَنَنْتُ أَنَّهُمْ سَيَفْقِدُونَنِي فَيَرْجِعُونَ إِلَيَّ فَبَيْنَا أَنَا جَالِسَةٌ غَلَبَتْنِي عَيْنَايَ فَنِمْتُ وَكَانَ صَفْوَانُ بْنُ الْمُعَطَّلِ السُّلَمِيُّ ثُمَّ الذَّكْوَانِيُّ مِنْ وَرَاءِ الْجَيْشِ فَأَصْبَحَ عِنْدَ مَنْزِلِي فَرَأَى سَوَادَ إِنْسَانٍ نَائِمٍ فَأَتَانِي وَكَانَ يَرَانِي قَبْلَ الْحِجَابِ فَاسْتَيْقَظْتُ بِاسْتِرْجَاعِهِ حِينَ أَنَاخَ رَاحِلَتَهُ فَوَطِئَ يَدَهَا فَرَكِبْتُهَا فَانْطَلَقَ يَقُودُ بِي الرَّاحِلَةَ حَتَّى أَتَيْنَا الْجَيْشَ بَعْدَ مَا نَزَلُوا مُعَرِّسِينَ فِي نَحْرِ الظَّهِيرَةِ فَهَلَكَ مَنْ هَلَكَ وَكَانَ الَّذِي تَوَلَّى الْإِفْكَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ فَقَدِمْنَا الْمَدِينَةَ فَاشْتَكَيْتُ بِهَا شَهْرًا وَالنَّاسُ يُفِيضُونَ مِنْ قَوْلِ أَصْحَابِ الْإِفْكِ وَيَرِيبُنِي فِي وَجَعِي أَنِّي لَا أَرَى مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللُّطْفَ الَّذِي كُنْتُ أَرَى مِنْهُ حِينَ أَمْرَضُ إِنَّمَا يَدْخُلُ فَيُسَلِّمُ ثُمَّ يَقُولُ كَيْفَ تِيكُمْ لَا أَشْعُرُ بِشَيْءٍ مِنْ ذَلِكَ حَتَّى نَقَهْتُ فَخَرَجْتُ أَنَا وَأُمُّ مِسْطَحٍ قِبَلَ الْمَنَاصِعِ مُتَبَرَّزُنَا لَا نَخْرُجُ إِلَّا لَيْلًا إِلَى لَيْلٍ وَذَلِكَ قَبْلَ أَنْ نَتَّخِذَ الْكُنُفَ قَرِيبًا مِنْ بُيُوتِنَا وَأَمْرُنَا أَمْرُ الْعَرَبِ الْأُوَلِ فِي الْبَرِّيَّةِ أَوْ فِي التَّنَزُّهِ فَأَقْبَلْتُ أَنَا وَأُمُّ مِسْطَحٍ بِنْتُ أَبِي رُهْمٍ نَمْشِي فَعَثَرَتْ فِي مِرْطِهَا فَقَالَتْ تَعِسَ مِسْطَحٌ فَقُلْتُ لَهَا بِئْسَ مَا قُلْتِ أَتَسُبِّينَ رَجُلًا شَهِدَ بَدْرًا فَقَالَتْ يَا هَنْتَاهْ أَلَمْ تَسْمَعِي مَا قَالُوا فَأَخْبَرَتْنِي بِقَوْلِ أَهْلِ الْإِفْكِ فَازْدَدْتُ مَرَضًا عَلَى مَرَضِي فَلَمَّا رَجَعْتُ إِلَى بَيْتِي دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ فَقَالَ كَيْفَ تِيكُمْ فَقُلْتُ ائْذَنْ لِي إِلَى أَبَوَيَّ قَالَتْ وَأَنَا حِينَئِذٍ أُرِيدُ أَنْ أَس��تَيْقِنَ الْخَبَرَ مِنْ قِبَلِهِمَا فَأَذِنَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُ أَبَوَيَّ فَقُلْتُ لِأُمِّي مَا يَتَحَدَّثُ بِهِ النَّاسُ فَقَالَتْ يَا بُنَيَّةُ هَوِّنِي عَلَى نَفْسِكِ الشَّأْنَ فَوَاللَّهِ لَقَلَّمَا كَانَتْ امْرَأَةٌ قَطُّ وَضِيئَةٌ عِنْدَ رَجُلٍ يُحِبُّهَا وَلَهَا ضَرَائِرُ إِلَّا أَكْثَرْنَ عَلَيْهَا فَقُلْتُ سُبْحَانَ اللَّهِ وَلَقَدْ يَتَحَدَّثُ النَّاسُ بِهَذَا قَالَتْ فَبِتُّ تِلْكَ اللَّيْلَةَ حَتَّى أَصْبَحْتُ لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ ثُمَّ أَصْبَحْتُ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيَّ بْنَ أَبِي طَالِبٍ وَأُسَامَةَ بْنَ زَيْدٍ حِينَ اسْتَلْبَثَ الْوَحْيُ يَسْتَشِيرُهُمَا فِي فِرَاقِ أَهْلِهِ فَأَمَّا أُسَامَةُ فَأَشَارَ عَلَيْهِ بِالَّذِي يَعْلَمُ فِي نَفْسِهِ مِنْ الْوُدِّ لَهُمْ فَقَالَ أُسَامَةُ أَهْلُكَ يَا رَسُولَ اللَّهِ وَلَا نَعْلَمُ وَاللَّهِ إِلَّا خَيْرًا وَأَمَّا عَلِيُّ بْنُ أَبِي طَالِبٍ فَقَالَ يَا رَسُولَ اللَّهِ لَمْ يُضَيِّقْ اللَّهُ عَلَيْكَ وَالنِّسَاءُ سِوَاهَا كَثِيرٌ وَسَلْ الْجَارِيَةَ تَصْدُقْكَ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَرِيرَةَ فَقَالَ يَا بَرِيرَةُ هَلْ رَأَيْتِ فِيهَا شَيْئًا يَرِيبُكِ فَقَالَتْ بَرِيرَةُ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ إِنْ رَأَيْتُ مِنْهَا أَمْرًا أَغْمِصُهُ عَلَيْهَا قَطُّ أَكْثَرَ مِنْ أَنَّهَا جَارِيَةٌ حَدِيثَةُ السِّنِّ تَنَامُ عَنْ الْعَجِينِ فَتَأْتِي الدَّاجِنُ فَتَأْكُلُهُ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ يَوْمِهِ فَاسْتَعْذَرَ مِنْ عَبْدِ اللَّهِ بْنِ أُبَيٍّ ابْنِ سَلُولَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَعْذُرُنِي مِنْ رَجُلٍ بَلَغَنِي أَذَاهُ فِي أَهْلِي فَوَاللَّهِ مَا عَلِمْتُ عَلَى أَهْلِي إِلَّا خَيْرًا وَقَدْ ذَكَرُوا رَجُلًا مَا عَلِمْتُ عَلَيْهِ إِلَّا خَيْرًا وَمَا كَانَ يَدْخُلُ عَلَى أَهْلِي إِلَّا مَعِي فَقَامَ سَعْدُ بْنُ مُعَاذٍ فَقَالَ يَا رَسُولَ اللَّهِ أَنَا وَاللَّهِ أَعْذُرُكَ مِنْهُ إِنْ كَانَ مِنْ الْأَوْسِ ضَرَبْنَا عُنُقَهُ وَإِنْ كَانَ مِنْ إِخْوَانِنَا مِنْ الْخَزْرَجِ أَمَرْتَنَا فَفَعَلْنَا فِيهِ أَمْرَكَ فَقَامَ سَعْدُ بْنُ عُبَادَةَ وَهُوَ سَيِّدُ الْخَزْرَجِ وَكَانَ قَبْلَ ذَلِكَ رَجُلًا صَالِحًا وَلَكِنْ احْتَمَلَتْهُ الْحَمِيَّةُ فَقَالَ كَذَبْتَ لَعَمْرُ اللَّهِ لَا تَقْتُلُهُ وَلَا تَقْدِرُ عَلَى ذَلِكَ فَقَامَ أُسَيْدُ بْنُ حُضَيْرٍ فَقَالَ كَذَبْتَ لَعَمْرُ اللَّهِ وَاللَّهِ لَنَقْتُلَنَّهُ فَإِنَّكَ مُنَافِقٌ تُجَادِلُ عَنْ الْمُنَافِقِينَ فَثَارَ الْحَيَّانِ الْأَوْسُ وَالْخَزْرَجُ حَتَّى هَمُّوا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ فَنَزَلَ فَخَفَّضَهُمْ حَتَّى سَكَتُوا وَسَكَتَ وَبَكَيْتُ يَوْمِي لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ فَأَصْبَحَ عِنْدِي أَبَوَايَ وَقَدْ بَكَيْتُ لَيْلَتَيْنِ وَيَوْمًا حَتَّى أَظُنُّ أَنَّ الْبُكَاءَ فَالِقٌ كَبِدِي قَالَتْ فَبَيْنَا هُمَا جَالِسَانِ عِنْدِي وَأَنَا أَبْكِي إِذْ اسْتَأْذَنَتْ امْرَأَةٌ مِنْ الْأَنْصَارِ فَأَذِنْتُ لَهَا فَجَلَسَتْ تَبْكِي مَعِي فَبَيْنَا نَحْنُ كَذَلِكَ إِذْ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ وَلَمْ يَجْلِسْ عِنْدِي مِنْ يَوْمِ قِيلَ فِيَّ مَا قِيلَ قَبْلَهَا وَقَدْ مَكَثَ شَهْرًا لَا يُوحَى إِلَيْهِ فِي شَأْنِي شَيْءٌ قَالَتْ فَتَشَهَّدَ ثُمَّ قَالَ يَا عَائِشَةُ فَإِنَّهُ بَلَغَنِي عَنْكِ كَذَا وَكَذَا فَإِنْ كُنْتِ بَرِيئَةً فَسَيُبَرِّئُكِ اللَّهُ وَإِنْ كُنْتِ أَلْمَمْتِ بِذَنْبٍ فَاسْتَغْفِرِي اللَّهَ وَتُوبِي إِلَيْهِ فَإِنَّ الْعَبْدَ إِذَا اعْتَرَفَ بِذَنْبِهِ ثُمَّ تَابَ تَابَ اللَّهُ عَلَيْهِ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَالَتَهُ قَلَصَ دَمْعِي حَتَّى مَا أُحِسُّ مِنْهُ قَطْرَةً وَقُلْتُ لِأَبِي أَجِبْ عَنِّي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَاللَّهِ مَا أَدْرِي مَا أَقُولُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لِأُمِّي أَجِيبِي عَنِّي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا قَالَ قَالَتْ وَاللَّهِ مَا أَدْرِي مَا أَقُولُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ وَأَنَا جَارِيَةٌ حَدِيثَةُ السِّنِّ لَا أَقْرَأُ كَثِيرًا مِنْ الْقُرْآنِ فَقُلْتُ إِنِّي وَاللَّهِ لَقَدْ عَلِمْتُ أَنَّكُمْ سَمِعْتُمْ مَا يَتَحَدَّثُ بِهِ النَّاسُ وَوَقَرَ فِي أَنْفُسِكُمْ وَصَدَّقْتُمْ بِهِ وَلَئِنْ قُلْتُ لَكُمْ إِنِّي بَرِيئَةٌ وَاللَّهُ يَعْلَمُ إِنِّي لَبَرِيئَةٌ لَا تُصَدِّقُونِي بِذَلِكَ وَلَئِنْ اعْتَرَفْتُ لَكُمْ بِأَمْرٍ وَاللَّهُ يَعْلَمُ أَنِّي بَرِيئَةٌ لَتُصَدِّقُنِّي وَاللَّهِ مَا أَجِدُ لِي وَلَكُمْ مَثَلًا إِلَّا أَبَا يُوسُفَ إِذْ قَالَ{ فَصَبْرٌ جَمِيلٌ وَاللَّهُ الْمُسْتَعَانُ عَلَى مَا تَصِفُونَ }ثُمَّ تَحَوَّلْتُ عَلَى فِرَاشِي وَأَنَا أَرْجُو أَنْ يُبَرِّئَنِي اللَّهُ وَلَكِنْ وَاللَّهِ مَا ظَنَنْتُ أَنْ يُنْزِلَ فِي شَأْنِي وَحْيًا وَلَأَنَا أَحْقَرُ فِي نَفْسِي مِنْ أَنْ يُتَكَلَّمَ بِالْقُرْآنِ فِي أَمْرِي وَلَكِنِّي كُنْتُ أَرْجُو أَنْ يَرَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّوْمِ رُؤْيَا يُبَرِّئُنِي اللَّهُ فَوَاللَّهِ مَا رَامَ مَجْلِسَهُ وَلَا خَرَجَ أَحَدٌ مِنْ ","id":"Telah menceritakan kepada kami [Abu Ar Rabi' Sulaiman bin Daud] dan [Ahmad] memberiku sebagian kepahaman, telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Ibnu Syihab Az Zuhriy] dari ['Urwah bin Az Zubair] dan [Sa'id bin Al Musayyab] dan ['Alqamah bin Waqashsh Al Laitsiy] dan ['Ubaidullah bin 'Abdullah bin 'Uqbah] dari ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam ketika orang-orang penuduh berkata kepadanya seperti apa yang sudah mereka katakan lalu Allah membersihlan dirinya dari fitnah keji ini. Berkata Az Zuhriy; dan semua mereka menceritakan kepadaku sekumpulan cerita 'Aisyah, sebagian mereka lebih cermat daripada sebagian lain dan lebih kuat kisahnya, lalu aku cermati hadis dari masing-masing mereka yang mereka ceritakan padaku dari 'Aisyah. Hadis-hadis tersebut satu sama lainnya saling menguatkan, mereka menduga bahwa 'Aisyah radliallahu 'anha berkata: \"Adalah Rasulullah shallallahu 'alaihi wasallam bila berniat hendak mengadakan suatu perjalanan, Beliau mengundi diantara isteri-isteri Beliau. Bila nama seorang dari mereka keluar berarti dia ikut bepergian bersama Beliau. Pada suatu hari Beliau mengundi nama-nama kami untuk suatu peperangan yang Beliau lakukan, maka keluar namaku hingga aku turut serta bersama Beliau setelah turun ayat hijab, aku dibawa didalam sekedup dan ditempatkan didalamnya. Kami berangkat, hingga ketika Rasulullah shallallahu 'alaihi wasallam telah selesai dari peperangan tersebut kami kembali pulang. Ketika hampir dekat dengan Madinah, Beliau mengumumkan untuk beristirahat malam. Maka aku keluar dari sekedup saat Beliau dan rambongan berhenti lalu aku berjalan hingga aku meninggalkan pasukan. Setelah aku selesai menunaikan keperluanku, aku kembali menuju rombongan namun aku meraba dadaku ternyata kalungku yang terbuat dari batu akik telah jatuh. Maka aku kembali untuk mencari kalungku. Kemudian orang-orang yang membawaku menuntun kembali unta yang aku tunggangi sedang mereka menduga aku sudah berada didalam sekedup. Memang masa itu para wanita berbadan ringan-ringan, tidak berat, dan mereka tidak memakan daging, yang mereka makan hanyalah sesuap makanan hingga orang-orang tidak dapat membedakan berat sekedup ketika diangkat apakah ada wanita didalamnya atau tidak. Saat itu aku adalah wanita yang masih muda. Maka mereka menggiring unta-unta dan berjalan. Dan aku baru mendapatkan kembali kalungku setelah pasukan sudah berlalu. Maka aku datangi tempat yang semula rombongan berhenti namun tidak ada seorangpun disana, lalu aku kembali ke tempatku saat tadi berhenti dengan harapan mereka merasa kehilangan aku lalu kembali ke tempatku. Ketika aku duduk, aku merasa sangat ngantuk hingga akhirnya aku tertidur. Adalah Sofwan bin Al Mu'aththol as-Sulamiy adz-Dzakwan datang dari belakang rombongan pasukan hingga dia menghampiri tempatku dan dia melihat ada tanda orang sedang tidur. Maka dia mendatangiku. Dahulu sebelum turun ayat hijab, dia pernah melihat aku. Aku terbangun dengan sangat kaget ketika dia menghentikan hewan tunggangannya dan merundukkannya hingga aku menaiki tunggangannya itu lalu dia menuntunnya hingga kami dapat menyusul rombongan setelah mereka singgah untuk melepas lelah ketika siang berada di puncaknya. Maka binasalah siapa yang binasa. Dan orang yang berperan menyebarkan tuduhan adalah 'Abdullah bin Ubay bin Salul. Kami tiba di Madinah dan aku menderita sakit selama satu bulan sementara orang-orang mulai terpengaruh dengan berita bohong (tuduhan) ini dan mereka membiarkan aku dalam kondisi sakit apalagi aku tidak melihat dari Nabi shallallahu 'alaihi wasallam kelembutan yang biasa aku dapatkan jika aku sakit. Beliau hanya menjenguk aku lalu memberi salam lalu bertanya tentang keadaanku hanya dengan memberi isyarat sedang aku tidak menyadari sedikitpun apa yang sedang terjadi. Hingga ketika aku berangsur pulih dari sakit aku keluar bersama Ummu Misthoh menuju tempat kami biasa membuang hajat, kami tidak keluar kesana kecuali di malam hari, itu terjadi sebelum kami mengambil tabir dekat dengan rumah kami, kebiasaan kami saat itu yaitu kebiasaan orang-orang Arab dahulu (arab tradisional) bila berada diluar rumah atau di lapangan terbuka. Maka kami, aku dan Ummu Misthoh binti Abi Ruhum berjalan lalu dia tergelincir karena kainnya seraya dia mengumpat: \"Celakalah Misthoh\". Aku katakan: \"Sungguh buruk apa yang kamu ucapkan tadi. Apakah kamu mencela seorang yang pernah ikut perang Badar?\" Dia berkata: \"Wahai baginda putri, apakah Baginda belum mendenar apa yang mereka perbincangkan?\" Lalu dia mengebarkan kepadaku tentang berita bohong (tuduhan keji). Kejadian ini semakin menambah sakitku diatas sakit yang sudah aku rasakan. Ketika aku sudah kembali ke rumahku, Rasulullah shallallahu 'alaihi wasallam masuk menemuiku lalu memberi salam dan berkata: \"Bagaimana keadaanmu?\" Aku jawab: \"izinkan aku untuk pulang ke rumah kedua orangtuaku\". 'Aisyah berkata: \"Saat itu aku ingin mencari kepastian berita dari pihak kedua orang tuaku\". Maka Rasulullah shallallahu 'alaihi wasallam memberiku izin dan akhirnya aku menemui kedua orangtuaku lalu aku tanyakan kepada ibuku: \"Apa yang sedang dibicarakan oleh orang-orang?\" Ibuku menjawab: \"Wahai ananda, anggaplah ringankan urusan yang sedang menimpa dirimu ini. Sungguh demi Allah, sangat jarang seorang wanita yang tinggal bersama seorang suami yang dia mencintainya padahal ia mempunyai isteri lain, melainkan isteri-isteri lainnya akan menyebarluaskan aibnya\". Aku katakan: \"Subhanallah, sungguh orang-orang sudah memperbincangkan masalah ini?\" Aisyah berkata: \"Maka aku melewati malam itu hingga pagi dengan air mata tak bisa lagi menetes karena habis dan aku tidak bisa tidur karenanya hingga ketika pagi hari, Rasulullah shallallahu 'alaihi wasallam memanggil 'Ali bin Abi Thalib dan Usamah bin Zaid ketika wahyu belum juga turun untuk mengajak keduanya bermusyawarah perihal rencana menceraikan isteri-isteri Beliau. Adapun Usamah, ia memberi isyarat kepadanya dengan apa yang diketahuinya secara persis karena kecintaannya kepada rumah tangga Rasulullah. Usamah berkata: \"Keluarga Baginda wahai Rasulullah, demi Allah tidaklah kami mengenalnya melainkan kebaikan semata\". Sedangkan 'Ali bin Abi Thalib berkata: \"Wahai Rasulullah, Allah tidak akan menyusahkan Baginda sebab masih banyak wanita-wanita lain selain dia dan tanyakanlah kepada sahaya wanitanya yang dia akan membenarkan baginda\". Maka Rasulullah shallallahu 'alaihi wasallam memanggil Barirah lalu berkata: \"Wahai Barirah, apakah kamu melihat pada diri Aisyah sesuatu yang meragukan kamu tentangnya?\" Barirah menjawab: \"Demi Dzat Yang mengutus Baginda dengan benar, sama sekali aku belum pernah melihat aib pada diri Aisyah yang bisa kugunakan untuk membongkar aibnya, kalaupun aku melihat sesuatu padanya tidak lebih dari sekedar perkara kecil, yang ketika dia masih sangat muda dia pernah ketiduran saat menjaga adonan rotinya, lantas ada hewan ternak datang dan memakan adonan tersebut\". Maka pada suatu hari Rasulullah shallallahu 'alaihi wasallam berdiri untuk kemudian meminta pertanggung jawaban 'Abdullah bin Ubay bin Salul. Rasulullah shallallahu 'alaihi wasallam berkata: \"Siapakah yang bisa mengemukakan pertanggungjawaban terhadapku terhadap seseorang yang telah kudengar telah menyakiti keluargaku?. Demi Allah, aku tidak mengetahui keluarga melainkan kebaikan semata. Sungguh mereka telah menyebut-nyebut seseorang laki-laki (maksudnya Shofwan yang diisukan selingkuh) yang aku tidak mengenalnya melainkan kebaikan semata, yang dia tidak pernah mendatangi keluargaku melainkan selalu bersamaku\". Maka Sa'ad bin Mu'adz berdiri lalu berkata: \"Wahai Rasulullah, aku akan membalaskan penghinaan ini buat anda. Seandainya orang itu dari kalangan suku Aus, kami akan penggal batang lehernya dan seandainya dari saudara-saudara kami suku Khazraj, perintahkanlah kami pasti akan kami laksanakan perintah Baginda tersebut\". Lalu beridirlah Sa'ad bin 'Ubadah, pimpinan suku Khazraj, yang sebelumnya dia adalah orang yang shalih namun hari itu terbawa oleh sikap kesukuan: \"Dusta kamu, kamu tidak akan pernah bisa membunuhnya dan tidak akan bisa membalaskannya\". Kemudian Usaid bin Hudhoir berdiri seraya berkata: \"Justru kamu yang dusta, kami pasti akan membunuhnya. Sungguh kamu sudah menjadi munafiq karena membela orang-orang munafiq\". Maka terjadilah perang mulut antara suku Aus dan Khazraj hingga sudah saling ingin melampiaskan kekesalannya padahal Rasulullah shallallahu 'alaihi wasallam masih berdiri di atas mimbar hingga akhirnya Beliau turun lalu menenangkan mereka hingga akhirnya mereka terdiam dan Beliau pun diam. Maka aku menangis sepanjang hariku hingga air mataku tak bisa lagi menetes karena kering dan aku tidak bisa tidur karenanya hingga akhirnya kedua orangtuaku berada di sisiku sedangkan aku sudah menangis selama dua malam satu hari hingga aku menyangka hatiku jangan-jangan menjadi pecah\". Aisyah berkata: \"Ketika kedua orantuaku sedang duduk di dekatku sementara aku terus saja menangis tiba-tiba ada seorang wanita Anshar yang meminta izin masuk lalu aku ijinkan kemudian dia duduk sambil menangis bersamaku. Ketika dalam keadaan seperti itu tiba-tiba Rasulullah shallallahu 'alaihi wasallam datang lalu duduk, namun tidak duduk di dekat aku sebagaimana saat Beliau menyampaikan apa yang telah terjadi denganku sebelum ini, sedangkan peristiwa ini sudah berlalu selama satu bulan dan wahyu belum juga turun untuk menjelaskan perkara yang menimpaku ini\". Aisyah berkata: \"Maka Beliau bersaksi membaca dua kalimah syahadah kemudian berkata: \"Wahai 'Aisyah, sungguh telah sampai kepadaku berita tentang dirimu begini begini. Jika kamu bersih tidak bersalah pasti nanti Allah akan membersihkanmu. Namun jika kamu jatuh pada perbuatan dosa maka mohonlah ampun kepada Allah dan bertobatlah kepada-Nya karena seorang hamba bila dia mengakui telah berbuat dosa lalu bertobat maka Allah pasti akan menerima tobatnya\". Setelah Rasulullah shallallahu 'alaihi wasallam menyelesaikan kalimat yang disampaikan, air mataku mengering hingga tak kurasakan setetes pun. Lalu aku katakan kepada bapakku: \"Jawablah kepada Rasulullah shallallahu 'alaihi wasallam tentang aku\". Bapakku berkata: \"Demi Allah, aku tidak mengetahui apa yang harus aku katakan kepada Rasulullah shallallahu 'alaihi wasallam\". Lalu aku katakan kepada ibuku: \"Jawablah kepada Rasulullah shallallahu 'alaihi wasallam tentang aku dari apa yang barusan Beliau katakan\". Ibuku pun menjawab: \"Demi Allah, aku tidak mengetahui apa yang harus aku katakan kepada Rasulullah shallallahu 'alaihi wasallam\". 'Aisyah berkata: \"Aku hanyalah seorang anak perempuan yang masih muda yang aku tidak banyak membaca Al Qur'an\". Aku katakan: \"Sesungguhnya aku, demi Allah, aku telah mengetahui bahwa kalian telah mendengar apa yang diperbincangkan oleh orang banyak dan kalian pun telah memasukkannya dalam hati kalian lalu membenarkan berita tersebut. Seandainya aku katakan kepada kalian bahwa aku bersih dan demi Allah, Dia Maha Mengetahui bahwa aku bersih, kalian pasti tidak akan membenarkan aku tentang ini. Dan seandainya aku mengakui kepada kalian tentang urusan ini padahal Allah Maha Mengetahui bahwa aku bersih, kalian pasti membenarkannya. Demi Allah, aku tidak menemukan antara aku dan kalian suatu perumpamaan melainkan seperti ayahnya Nabi Yusuf ketika dia berkata: (\"Bersabarlah dengan sabar yang baik, dan Allah tempat meminta pertolongan dari segala yang kalian gambarkan\").(QS. Yusuf 18). Kemudian setelah itu aku pergi menuju tempat tidurku dengan berharap Allah akan membersihkan aku, akan tetapi demi Allah, aku tidak menduga kalau Allah menurunkan suatu wahyu tentang urusan yang menimpaku ini. Karena tidak pantas kalau Al Qur'an turun untuk membicarakan masalahku ini. Tetapi aku hanya berharap Rasulullah shallallahu 'alaihi wasallam mendapatkan wahyu lewat mimpi yang Allah membersihkan diriku. Dan demi Allah, belum beliau menuju majelisnya dan belum pula dari Ahlu Bait yang keluarl, hingga diturunkan wahyu kepada Beliau. Maka Beliau menerima wahyu tersebut sebagaimana Beliau biasa menerimanya dalam keadaan demam sangat berat dengan bercucuran keringat. Setelah selesai wahyu turun kepada Beliau, nampak Beliau tertawa dan kalimat pertama yang Beliau ucapkan adalah saat Beliau berkata kepadaku: \"Wahai 'Aisyah, pujilah Allah, sungguh Allah telah membersihkan kamu\". Lalu ibuku berkata, kepadaku: \"Bangkitlah untuk menemui Rasulullah\". Aku katakan kepada ibuku: \"Demi Allah, aku tidak akan berdiri menemuinya dan tidak akan aku memuji siapapun selain Allah Ta'ala. Maka Allah menurunkan ayat (\"Sesungguhnya orang-orang yang menyebarkan berita bohong diantata kalian adalah masih golongan kalian juga. Janganlah kalian menduganya sebagai keburukan bahkan dia merupakan kebaikan buat kalian…\"). (QS. Annur 11). Ketika turun ayat ini yang menjelaskan terlepasnya diriku dari segala tuduhan, Abu Bakar ash-Shiddiq radliallahu 'anhu yang selalu menanggung hidup Misthah bin Utsatsah karena memang masih kerabatnya berkata: \"Demi Allah, setelah ini aku tidak akan lagi memberi nafkah kepada Misthah untuk selamanya karena dia sudah ikut menyebarkan berita bohong tentang 'Aisyah\". Maka kemudian Allah menurunkan ayat: (\"Dan janganlah orang-orang yang memiliki kelebihan dan kelapangan diantara kalian bersumpah untuk tidak lagi memberikan kepada …..hingga ayat…. Allah Maha Pengampun lagi Maha Penyayang\") (QS. Annur 22).. Maka Abu Bakar berkata: \"Ya, demi Allah, sungguh aku sangat berkeinginan bila Allah mengampuniku\". Maka Abu Bakar kembali memberi nafkah kepada Misthah sebagaimana sebelumnya. Dan Rasulullah shallallahu 'alaihi wasallam bertanya kepada Zainab binti Jahsy tentang masalah aku seraya berkata: \"Wahai Zainab, apa yang kamu ketahui dan apa pendapatmu?\" Maka Zainab berkata: \"Wahai Rasulullah, aku menjaga pendengaran dan penglihatanku, demi Allah aku tidak mengeahui tentang dia melainkan kebaikan\". Kata 'Aisyah: \" Padahal Zainab orangnya sebelumnya merasa lebih mulia daripadaku, yang kemudian Allah menjaganya dengan kewara'an\". Dia berkata,, dan telah menceritakan kepada kami [Fulaih] dari [Hisyam bin 'Urwah] dari ['Urwah] dari ['Aisyah radliallahu 'anha] dan ['Abdullah bin Az Zubair] seperti hadits ini. Berkata,, dan telah menceritakan kepada kami [Fulaih] dari [Rabi'ah bin ABi 'Abdurrahman] dan [Yahya bin Sa'id] dari [Al Qasim bin Muhammad bin Abu Bakar] seperti ini juga."},"2468":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَأَثْنَى رَجُلٌ عَلَى رَجُلٍ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَيْلَكَ قَطَعْتَ عُنُقَ صَاحِبِكَ قَطَعْتَ عُنُقَ صَاحِبِكَ مِرَارًا ثُمَّ قَالَ مَنْ كَانَ مِنْكُمْ مَادِحًا أَخَاهُ لَا مَحَالَةَ فَلْيَقُلْ أَحْسِبُ فُلَانًا وَاللَّهُ حَسِيبُهُ وَلَا أُزَكِّي عَلَى اللَّهِ أَحَدًا أَحْسِبُهُ كَذَا وَكَذَا إِنْ كَانَ يَعْلَمُ ذَلِكَ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Khalid Al Khadzdza'] dari ['Abdurrahman bin Abu Bakrah] dari [bapaknya] berkata; Ada seseorang menyanjung orang lain di hadapan Nabi shallallahu 'alaihi wasallam maka Beliau berkata: \"Celaka kamu, kamu telah memenggal leher sahabatmu, kamu telah mememggal leher sahabatmu\". Kalimat ini diucapkan oleh Beliau berulang kali, kemudian Beliau bersabda: \"Siapa diantara kalian yang ingin memuji saudaranya tidak pada tempatnya hendaklah ia mengucapkan; Aku mengira si fulan, demi Allah aku menduga dia, dan aku tidak menganggap suci seorangpun di hadapan Allah, aku mengira dia begini begini, sekalipun dia mengetahui tentang diri saudaranya itu\"."},"2469":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ صَبَّاحٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ زَكَرِيَّاءَ حَدَّثَنَا بُرَيْدُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُثْنِي عَلَى رَجُلٍ وَيُطْرِيهِ فِي مَدْحِهِ فَقَالَ أَهْلَكْتُمْ أَوْ قَطَعْتُمْ ظَهَرَ الرَّجُلِ","id":"Telah menceritakan kepada kami [Muhammad bin Shabbah] telah menceritakan kepada kami [Isma'il bin Zakariya'] telah menceritakan kepada kami [Buraid bin 'Abdullah] dari [Abu Burdah] dari [Abu Musa radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam mendengar seseorang memuji seseorang dan berlebihan dalam memujinya, maka Beliau bersabda: \"Kalian telah binasa atau dengan redaksi berarti kalian telah memotong punggung seseorang\"."},"2470":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ قَالَ حَدَّثَنِي ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَضَهُ يَوْمَ أُحُدٍ وَهُوَ ابْنُ أَرْبَعَ عَشْرَةَ سَنَةً فَلَمْ يُجِزْنِي ثُمَّ عَرَضَنِي يَوْمَ الْخَنْدَقِ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ سَنَةً فَأَجَازَنِي قَالَ نَافِعٌ فَقَدِمْتُ عَلَى عُمَرَ بْنِ عَبْدِ الْعَزِيزِ وَهُوَ خَلِيفَةٌ فَحَدَّثْتُهُ هَذَا الْحَدِيثَ فَقَالَ إِنَّ هَذَا لَحَدٌّ بَيْنَ الصَّغِيرِ وَالْكَبِيرِ وَكَتَبَ إِلَى عُمَّالِهِ أَنْ يَفْرِضُوا لِمَنْ بَلَغَ خَمْسَ عَشْرَةَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepadaku ['Ubaidullah] berkata, telah menceritakan kepadaku [Nafi'] telah menceritakan kapadaku [Ibnu'Umar radliallahu 'anhuma] bahwa dia pernah menawarkan diri kepada Rasulullah shallallahu 'alaihi wasallam untuk ikut dalam perang Uhud, saat itu umurnya masih empat belas tahun namun Beliau tidak mengijinkannya. Kemudian ia menawarkan lagi pada perang Khandaq saat itu usiaku lima belas tahun dan Beliau mengijinkanku\". Nafi' berkata; \"Aku menemui 'Umar bin 'Abdul 'aziz saat itu dia adalah khalifah lalu aku menceritakan hadis ini, dia berkata: \"Ini adalah batas antara anak kecil dan orang dewasa\". Maka kemudian dia menetapkan pegawainya untuk mewajibkan kepada siapa saja yang telah berusia lima belas tahun."},"2471":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا صَفْوَانُ بْنُ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غُسْلُ يَوْمِ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Shafwan bin Sulaim] dari ['Atho' bin YAsar] dari [Abu Sa'id Al Khudriy] telah sampai kepadanya sabda Nabi shallallahu 'alaihi wasallam: \"Mandi pada hari Jum'at adalah wajib bagi setiap orang yang sudah mimpi (baligh) \"."},"2472":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ وَهُوَ فِيهَا فَاجِرٌ لِيَقْتَطِعَ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُقَالَ فَقَالَ الْأَشْعَثُ بْنُ قَيْسٍ فِيَّ وَاللَّهِ كَانَ ذَلِكَ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قَالَ قُلْتُ لَا قَالَ فَقَالَ لِلْيَهُودِيِّ احْلِفْ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفَ وَيَذْهَبَ بِمَالِي قَالَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari ['Abdullah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah dengan sumpah curang, dan bermaksud mengambil harta seorang muslim maka nanti dia akan berjumpa dengan Allah, sedang Allah murka kepadanya\". Dia berkata,, maka [Al Ays'ats bin Qais] berkata: \"Demi Allah, hadits itu berkenaan dengan aku, yang antara aku dan seorang Yahudi ada sebidang lahan, lalu dia mempermasalahkannya sehingga aku adukan kepada Nabi shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Apakah kamu memiliki bukti?\" Aku katakan: \"Tidak\". Lalu Beliau berkata kepada si Yahudi: \"Bersumpahlah kamu\". 'Abdullah berkata; Aku katakan: \"Wahai Rasulullah, kalau dia bersumpah nanti dia musti membawa hartaku\". 'Abdullah berkata: \"Maka turunlah firman Allah yang artinya: (\"Sesungguhnya orang-orang yang menjualjanjinya dengan Allah dan sumpah mereka dengan harga yang murah …hingga akhir ayat\") (QS. Ali Imran 77)."},"2473":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ كَتَبَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْيَمِينِ عَلَى الْمُدَّعَى عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Nafi' bin 'Umar] dari [Ibnu Abi Mulaikah]; [Ibnu 'Abbas] radliallahu 'anhuma telah menulis bahwa Nabi shallallahu 'alaihi wasallam menetapkan sumpah bagi orang yang terdakwa (dituduh)."},"2474":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِمَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالًا لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ ثُمَّ أَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ إِلَى عَذَابٌ أَلِيمٌ }ثُمَّ إِنَّ الْأَشْعَثَ بْنَ قَيْسٍ خَرَجَ إِلَيْنَا فَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ فَحَدَّثْنَاهُ بِمَا قَالَ فَقَالَ صَدَقَ لَفِيَّ أُنْزِلَتْ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ خُصُومَةٌ فِي شَيْءٍ فَاخْتَصَمْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ شَاهِدَاكَ أَوْ يَمِينُهُ فَقُلْتُ لَهُ إِنَّهُ إِذًا يَحْلِفُ وَلَا يُبَالِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالًا وَهُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ عَزَّ وَجَلَّ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ ثُمَّ اقْتَرَأَ هَذِهِ الْآيَةَ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] berkata; ['Abdullah] berkata: \"Siapa yang bersumpah yang dengan sumpahnya bermaksud untuk menguasai harta maka dia akan berjumpa Allah dan Allah dalam keadaan murka kepadanya. Kemudian turunlah firman Allah sebagai pembenaran atas ini: (\"Sesungguhnya orang-orang yang menjual janjinya dengan Allah dan sumpah mereka dengan harga yang murah …hingga ayat berbunyi…. siksa yang pedih) (QS. Ali'Imran.77). Kemudian [Al Asy'ats bin Qais] menemui kami lalu berkata: \"Apa yang diceritakan kepada kalian oleh Abu 'Abdurrahman?\" Maka kami ceritakan kepadanya apa yang disampaikan oleh Abu 'Abdurrahman. Maka dia berkata: \"Dia benar, karena memang ayat itu turun berkenaan dengan aku, yang antara aku dan seseorang ada perselisihan tentang sesuatu sehingga kami bawa persoalan tersebut kepada Rasulullah shallallahu 'alaihi wasallam lalu Beliau bertanya: \"Siapa dua orang saksimu atau orang itu menyatakan sumpahnya\". Aku katakan kepada Beliau: \"Kalau sumpah, dia pasti mau bersumpah lalu dia tidak mempedulikan aku\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah dengan tujuan bermaksud mengambil harta seseorang padahal dia bersumpah dengan curang (dusta) maka nanti dia akan berjumpa Allah 'azza wajalla, dan Allah murka kepadanya\". Maka turunlah ayat sebagai pembenaran dari hal ini, lalu dia membacanya."},"2475":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامٍ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ هِلَالَ بْنَ أُمَيَّةَ قَذَفَ امْرَأَتَهُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرِيكِ ابْنِ سَحْمَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّنَةُ أَوْ حَدٌّ فِي ظَهْرِكَ فَقَالَ يَا رَسُولَ اللَّهِ إِذَا رَأَى أَحَدُنَا عَلَى امْرَأَتِهِ رَجُلًا يَنْطَلِقُ يَلْتَمِسُ الْبَيِّنَةَ فَجَعَلَ يَقُولُ الْبَيِّنَةَ وَإِلَّا حَدٌّ فِي ظَهْرِكَ فَذَكَرَ حَدِيثَ اللِّعَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ibnu Abi 'Adiy] dari [Hisyam] telah menceritakan kepada kami ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Hilal bin Umayyah menuduh isterinya berbuat serong (selingkuh) dengan Syarik bin Sahma' di hadapan Nabi shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah kamu punya bukti atau punggungmu dipukul?\" Maka dia berkata: \"Wahai Rasulullah, bila seorang dari kami melihat ada seorang laki-laki bersama isterinya, apakah dia harus mencari bukti?\" Beliau kontan mengatakan 'Harus ada bukti, punggungmu harus didera (atas tuduhan ini). Lalu diceritakanlah tentang hadits Li'an (saling melaknat antara yang menuduh dengan yang dituduh)."},"2476":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ وَلَا يَنْظُرُ إِلَيْهِمْ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ عَلَى فَضْلِ مَاءٍ بِطَرِيقٍ يَمْنَعُ مِنْهُ ابْنَ السَّبِيلِ وَرَجُلٌ بَايَعَ رَجُلًا لَا يُبَايِعُهُ إِلَّا لِلدُّنْيَا فَإِنْ أَعْطَاهُ مَا يُرِيدُ وَفَى لَهُ وَإِلَّا لَمْ يَفِ لَهُ وَرَجُلٌ سَاوَمَ رَجُلًا بِسِلْعَةٍ بَعْدَ الْعَصْرِ فَحَلَفَ بِاللَّهِ لَقَدْ أَعْطَى بِهَا كَذَا وَكَذَا فَأَخَذَهَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Jarir bin 'AbdulHamid] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga golongan yang Allah tidak akan mengajak mereka bicara pada hari kiamat, tidak memandang mereka dan tidak pula mensucikan mereka, serta bagi mereka disediakan siksa yang pedih, yaitu seseorang yang memiliki kelebihan air di jalan lalu dia enggan memberikannya kepada ibnu sabil, seseorang yang berbai'at kepada seorang (pemimpin) dan dia tidak berbai'at kepadanya kecuali demi kepentingan duniawi, bila dia diberikan apa yang sesuai dengan keinginannya maka dia memelihara janjinya, namun bila tidak maka dia tidak memelihara janjinya, dan seseorang yang menawar barang dagangan kepada seseorang setelah waktu 'Ashar, lalu dia bersumpah atas nama Allah; sungguh dengan harga sekian sekian aku memperoleh barang seperti ini, padahal dia dusta belaka\"."},"2477":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ لِيَقْتَطِعَ بِهَا مَالًا لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Wahid] dari [Al A'masy] dari [Abu Wa'il] dari [Ibnu Mas'ud radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah (yang dengan sumpahnya itu) dia bermaksud mengambil harta (orang), maka dia berjumpa Allah dan Allah murka kepadanya\"."},"2478":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَضَ عَلَى قَوْمٍ الْيَمِينَ فَأَسْرَعُوا فَأَمَرَ أَنْ يُسْهَمَ بَيْنَهُمْ فِي الْيَمِينِ أَيُّهُمْ يَحْلِفُ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami ['Abdur Razzaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam menawarkan sumpah kepada suatu kaum lalu merekapun segera bersumpah. Maka Beliau memerintahkan agar diundi siapa diantara mereka yang lebih dahulu bersumpah."},"2479":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْعَوَّامُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ أَبُو إِسْمَاعِيلَ السَّكْسَكِيُّ سَمِعَ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَقَامَ رَجُلٌ سِلْعَتَهُ فَحَلَفَ بِاللَّهِ لَقَدْ أَعْطَى بِهَا مَا لَمْ يُعْطِهَا فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }وَقَالَ ابْنُ أَبِي أَوْفَى النَّاجِشُ آكِلُ رِبًا خَائِنٌ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al 'Awwam] berkata, telah menceritakan kepadaku [Ibrahim Abu Isma'il as-Saksakiy] dia mendengar ['Abdullah bin Abu Awfaa radliallahu 'anhuma] berkata; Ada seseorang yang menunggui barang dagangannya, lalu dia bersumpah atas nama Allah bahwa dia hanya memberikan dagangannya dengan harga sekian-sekian padahal bohong belaka, maka turunlah firman Allah yang artinya: (\"Sesungguhnya orang-orang yang menjual janjinya kepada Allah dan sumpah mereka dengan harga yang murah..) (QS. Ali'Imran 77). Dan berkata Ibnu Abi Awfaa: \"Orang yang menipu orang lain, sama artinya dengan pemakan riba dan pengkhianat\"."},"2480":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبًا لِيَقْتَطِعَ مَالَ رَجُلٍ أَوْ قَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ تَصْدِيقَ ذَلِكَ فِي الْقُرْآنِ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا الْآيَةَ إِلَى قَوْلِهِ عَذَابٌ أَلِيمٌ }فَلَقِيَنِي الْأَشْعَثُ فَقَالَ مَا حَدَّثَكُمْ عَبْدُ اللَّهِ الْيَوْمَ قُلْتُ كَذَا وَكَذَا قَالَ فِيَّ أُنْزِلَتْ","id":"Telah menceritakan kepada kami [Bisyir bin Khalid] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah palsu (berdusta) yang dengan sumpahnya itu dia bermaksud mengambil harta orang lain atau Beliau bersabda dengan redaksi 'saudaranya', maka dia berjumpa Allah sedang Allah murka kepadanya\". Lalu Allah menurunkan ayat Al Qur'an sebagai pembenaran atas sabda Beliau ini yang artinya: (\"Sesungguhnya orang-orang yang menjual janjinya kepada Allah dan sumpah mereka dengan harga yang murah.. hingga firman-Nya …siksa yang pedih) (QS. Ali'Imran 77). Kemudian [Al Asy'ats] menemuiku seraya berkata: \"Apa yang diceritakan 'Abdullah kepada kalian hari ini?\" Aku katakan: \"Begini-begini\". Maka dia berkata: \"Ayat itu turun berkenaan dengan aku\"."},"2481":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَمِّهِ أَبِي سُهَيْلِ بْنِ مَالِكٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ يَقُولُجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ يَسْأَلُهُ عَنْ الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسُ صَلَوَاتٍ فِي الْيَوْمِ وَاللَّيْلَةِ فَقَالَ هَلْ عَلَيَّ غَيْرُهَا قَالَ لَا إِلَّا أَنْ تَطَّوَّعَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصِيَامُ شَهْرِ رَمَضَانَ قَالَ هَلْ عَلَيَّ غَيْرُهُ قَالَ لَا إِلَّا أَنْ تَطَّوَّعَ قَالَ وَذَكَرَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الزَّكَاةَ قَالَ هَلْ عَلَيَّ غَيْرُهَا قَالَ لَا إِلَّا أَنْ تَطَّوَّعَ فَأَدْبَرَ الرَّجُلُ وَهُوَ يَقُولُ وَاللَّهِ لَا أَزِيدُ عَلَى هَذَا وَلَا أَنْقُصُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ إِنْ صَدَقَ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepadaku [Malik] dari [pamannya, Abu Suhail bin Malik] dari [bapaknya] bahwa dia mendengar [Thalhah bin 'Ubaidullah] berkata; Ada seorang laki-laki datang menemui Rasulullah shallallahu 'alaihi wasallam lalu dia bertanya tentang Islam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima kali shalat dalam sehari semalam\". Lalu orang itu berkata: \"Apakah untukku ada lagi selain itu?\" Beliau bersabda: \"Tidak ada, kecuali jika kamu mau mengerjakan yang tathowwu' (sunnat) \". 'Ubaidullah berkata: \"Kemudian Rasulullah shallallahu 'alaihi wasallam menyebutkan kepada orang itu tentang zakat, lalu orang itu bertanya lagi: \"Apakah untukku ada lagi selain itu?\" Beliau bersabda: \"Tidak ada, kecuali jika kamu mau mengerjakan yang tathowwu' (sunnat) \". Kemudian orang itu pergi sambil berkata: \"Demi Allah aku tidak akan menambah atau mengurangi dari ini semua\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia akan beruntung bila jujur\"."},"2482":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ قَالَ ذَكَرَ نَافِعٌ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ حَالِفًا فَلْيَحْلِفْ بِاللَّهِ أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] berkata, [Nafi'] menyebutkan dari ['Abdullah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah hendaklah dia bersumpah atas nama Allah atau kalau tidak, lebih baik diam\"."},"2483":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ تَخْتَصِمُونَ إِلَيَّ وَلَعَلَّ بَعْضَكُمْ أَلْحَنُ بِحُجَّتِهِ مِنْ بَعْضٍ فَمَنْ قَضَيْتُ لَهُ بِحَقِّ أَخِيهِ شَيْئًا بِقَوْلِهِ فَإِنَّمَا أَقْطَعُ لَهُ قِطْعَةً مِنْ النَّارِ فَلَا يَأْخُذْهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari [Zainab] dari [Ummu Salamah radliallahu 'anhah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh kalian seringkali mengadukan sengketa kepadaku, barang kali diantara kalian ada yang lebih pandai bersilat lidah daripada yang lain. Maka barangsiapa yang kuputuskan menang dengan mencederai hak saudaranya berdasarkan kepandaian argumentasnya, berarti telah kuambil sundutan api neraka baginya, maka janganlah dia mengambilnya\"."},"2484":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ قَالَ أَخْبَرَنِي أَبُو سُفْيَانَأَنَّ هِرَقْلَ قَالَ لَهُ سَأَلْتُكَ مَاذَا يَأْمُرُكُمْ فَزَعَمْتَ أَنَّهُ أَمَرَكُمْ بِالصَّلَاةِ وَالصِّدْقِ وَالْعَفَافِ وَالْوَفَاءِ بِالْعَهْدِ وَأَدَاءِ الْأَمَانَةِ قَالَ وَهَذِهِ صِفَةُ نَبِيٍّ","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] dari ['Ubaidulloih bin 'Abdullah] bahwa ['Abdullah bin 'Abbas radliallahu 'anhuma] mengabarkannya berkata, telah mengabarkan kepada kami [Abu Sufyan] bahwa Raja Heraklius berkata kepadanya: \"Aku telah bertanya kepadamu apa yang dia perintahkan kepada kalian, lalu kamu menjawab bahwa dia memerintahkan kalian untuk shalat, bershadaqah (zakat), menjauhkan diri dari berbuat buruk, menunaikan janji dan melaksankan amanah\". Lalu dia berkata; \"Ini adalah diantara sifat-sifat seorang Nabi\"."},"2485":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ أَبِي سُهَيْلٍ نَافِعِ بْنِ مَالِكِ بْنِ أَبِي عَامِرٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ آيَةُ الْمُنَافِقِ ثَلَاثٌ إِذَا حَدَّثَ كَذَبَ وَإِذَا اؤْتُمِنَ خَانَ وَإِذَا وَعَدَ أَخْلَفَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Abu Suhail, Nafi' bin Malik bin Abu 'Amir] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tanda-tanda munafiq ada tiga; jika berbicara dusta, jika diberi amanat dia khiyanat dan jika berjanji mengingkari\"."},"2486":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمْ قَالَلَمَّا مَاتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ أَبَا بَكْرٍ مَالٌ مِنْ قِبَلِ الْعَلَاءِ بْنِ الْحَضْرَمِيِّ فَقَالَ أَبُو بَكْرٍ مَنْ كَانَ لَهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَيْنٌ أَوْ كَانَتْ لَهُ قِبَلَهُ عِدَةٌ فَلْيَأْتِنَا قَالَ جَابِرٌ فَقُلْتُ وَعَدَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعْطِيَنِي هَكَذَا وَهَكَذَا وَهَكَذَا فَبَسَطَ يَدَيْهِ ثَلَاثَ مَرَّاتٍ قَالَ جَابِرٌ فَعَدَّ فِي يَدِي خَمْسَ مِائَةٍ ثُمَّ خَمْسَ مِائَةٍ ثُمَّ خَمْسَ مِائَةٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku ['Amru bin Dinar] dari [Muhammad bin 'Ali] dari [Jabir bin 'Abdullah radliallahu 'anhum] berkata; Ketika Nabi shallallahu 'alaihi wasallam wafat, Abu Bakar datang dengan membawa harta yang didapat dari Al 'Alaa' bin Al Hadhramiy lalu Abu Bakar berkata; \"Siapa yang kepadanya Nabi shallallahu 'alaihi wasallam memiliki hutang atau siapa yang pernah dijanjikan Beliau sesuatu hendaklah dia menemui kami\". Jabir berkata; Aku katakan: Rasulullah shallallahu 'alaihi wasallam pernah berjanji kepadaku untuk memberikan aku sesuatu sekian sekian\". Maka dia mengulurkan tangannya tiga kali. Jabir berkata: \"Maka Abu Bakar memberikan ke tanganku lima ratus kemudian lima ratus kemudian lima ratus lagi\"."},"2487":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا مَرْوَانُ بْنُ شُجَاعٍ عَنْ سَالِمٍ الْأَفْطَسِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلَنِي يَهُودِيٌّ مِنْ أَهْلِ الْحِيرَةِ أَيَّ الْأَجَلَيْنِ قَضَى مُوسَى قُلْتُ لَا أَدْرِي حَتَّى أَقْدَمَ عَلَى حَبْرِ الْعَرَبِ فَأَسْأَلَهُ فَقَدِمْتُ فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَقَضَى أَكْثَرَهُمَا وَأَطْيَبَهُمَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ فَعَلَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdur Rahim] telah mengabarkan kepada kami [Sa'id bin Sulaiman] telah menceritakan kepada kami [Marwan bin Syuja'] dari [Salim Al Aqthos] dari [Sa'id bin Jubair] berkata; Ada seorang Yahudi dari penduduk Hirah bertanya kepadaku tentang dua ketetapan yang dipilih oleh Nabi Musa Alaihissalam. Aku menjawab tidak tahu, hingga aku mendatangi orang 'alim (pemuka) orang Arab dan bertanya kepadanya. Akhirnya aku menemui dan bertanya kepada [Ibnu 'Abbas], maka dia menjawab: \"Musa Alaihissalam memilih mengerjakan yang terbanyak dan terbaik diantara keduanya, sesungguhnya Rasulullah shallallahu 'alaihi wasallam jika Beliau bersabda maka pasti beliau lakukan."},"2488":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَيَا مَعْشَرَ الْمُسْلِمِينَ كَيْفَ تَسْأَلُونَ أَهْلَ الْكِتَابِ وَكِتَابُكُمْ الَّذِي أُنْزِلَ عَلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْدَثُ الْأَخْبَارِ بِاللَّهِ تَقْرَءُونَهُ لَمْ يُشَبْ وَقَدْ حَدَّثَكُمْ اللَّهُ أَنَّ أَهْلَ الْكِتَابِ بَدَّلُوا مَا كَتَبَ اللَّهُ وَغَيَّرُوا بِأَيْدِيهِمْ الْكِتَابَ فَقَالُوا هُوَ مِنْ عِنْدِ اللَّهِ{ لِيَشْتَرُوا بِهِ ثَمَنًا قَلِيلًا }أَفَلَا يَنْهَاكُمْ مَا جَاءَكُمْ مِنْ الْعِلْمِ عَنْ مُسَاءَلَتِهِمْ وَلَا وَاللَّهِ مَا رَأَيْنَا مِنْهُمْ رَجُلًا قَطُّ يَسْأَلُكُمْ عَنْ الَّذِي أُنْزِلَ عَلَيْكُمْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari ['Abdullah bin 'Abbas radliallahu 'anhuma] berkata: \"Wahai sekalian kaum muslimin, bagaimana bisa kalian bertanya kepada Ahli kitab sedangkan kitab kalian yang diturunkan kepada nabi-Nya shallallahu 'alaihi wasallam adalah kitab paling baru tentang Allah. Kalian membacanya dengan tidak dicampur aduk, dan Allah telah memberitahu kalian bahwa orang-orang ahli kitab telah merubah apa yang telah Allah tetapkan, dan mereka merubahnya dengan tangan mereka, lalu mereka berkata ini dari Allah dengan maksud (menjualnya dengan harga yang sedikit). Bukankah dengan ilmu yang telah datang kepada kalian berarti Dia melarang kalian untuk bertanya kepada mereka?. Tidak, demi Allah, kami tidak melihat seorangpun dari mereka yang bertanya tentang apa yang diturunkan kepada kalian\"."},"2489":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي الشَّعْبِيُّ أَنَّهُ سَمِعَ النُّعْمَانَ بْنَ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُدْهِنِ فِي حُدُودِ اللَّهِ وَالْوَاقِعِ فِيهَا مَثَلُ قَوْمٍ اسْتَهَمُوا سَفِينَةً فَصَارَ بَعْضُهُمْ فِي أَسْفَلِهَا وَصَارَ بَعْضُهُمْ فِي أَعْلَاهَا فَكَانَ الَّذِي فِي أَسْفَلِهَا يَمُرُّونَ بِالْمَاءِ عَلَى الَّذِينَ فِي أَعْلَاهَا فَتَأَذَّوْا بِهِ فَأَخَذَ فَأْسًا فَجَعَلَ يَنْقُرُ أَسْفَلَ السَّفِينَةِ فَأَتَوْهُ فَقَالُوا مَا لَكَ قَالَ تَأَذَّيْتُمْ بِي وَلَا بُدَّ لِي مِنْ الْمَاءِ فَإِنْ أَخَذُوا عَلَى يَدَيْهِ أَنْجَوْهُ وَنَجَّوْا أَنْفُسَهُمْ وَإِنْ تَرَكُوهُ أَهْلَكُوهُ وَأَهْلَكُوا أَنْفُسَهُمْ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepadaku [Asy Sya'biy] bahwa dia mendengar [An Nu'man bin Basyir radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam telah bersabda: \"Perumpamaan orang yang menerjang hukum Allah dan orang berada padanya seperti sekelompok orang yang berlayar dengan sebuah kapal, lalu sebagian dari mereka ada yang mendapat tempat di bagian bawah dan sebagian lagi di atas perahu. Lalu orang yang berada di bawah perahu bila mereka mencari air untuk minum, mereka harus melewati orang-orang yang berada di atas sehingga mengganggu orang yang diatas. Lalu salah seorang yang dibawa mengambil kapak untuk membuat lubang di bawah kapal. Maka orang-orang yang di atas mendatanginya dan berkata: \"Apa yang kamu lakukan?\" Orang yang di bawah berkata: \"Kalian telah terganggu karena aku sedangkan aku memerlukan air\". Maka bila orang yang berada di atas mencegah dengan tangan mereka maka mereka telah menyelamatkan orang tadi dan menyelamatkan diri mereka sendiri, namun apabila mereka membiarkan saja apa berarti dia telah membinasakan orang itu dan diri mereka sendiri\"."},"2490":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي خَارِجَةُ بْنُ زَيْدٍ الْأَنْصَارِيُّ أَنَّ أُمَّ الْعَلَاءِ امْرَأَةً مِنْ نِسَائِهِمْ قَدْ بَايَعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ عُثْمَانَ بْنَ مَظْعُونٍ طَارَ لَهُ سَهْمُهُ فِي السُّكْنَى حِينَ أَقْرَعَتْ الْأَنْصَارُ سُكْنَى الْمُهَاجِرِينَ قَالَتْ أُمُّ الْعَلَاءِ فَسَكَنَ عِنْدَنَا عُثْمَانُ بْنُ مَظْعُونٍ فَاشْتَكَى فَمَرَّضْنَاهُ حَتَّى إِذَا تُوُفِّيَ وَجَعَلْنَاهُ فِي ثِيَابِهِ دَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ رَحْمَةُ اللَّهِ عَلَيْكَ أَبَا السَّائِبِ فَشَهَادَتِي عَلَيْكَ لَقَدْ أَكْرَمَكَ اللَّهُ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا يُدْرِيكِ أَنَّ اللَّهَ أَكْرَمَهُ فَقُلْتُ لَا أَدْرِي بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا عُثْمَانُ فَقَدْ جَاءَهُ وَاللَّهِ الْيَقِينُ وَإِنِّي لَأَرْجُو لَهُ الْخَيْرَ وَاللَّهِ مَا أَدْرِي وَأَنَا رَسُولُ اللَّهِ مَا يُفْعَلُ بِهِ قَالَتْ فَوَاللَّهِ لَا أُزَكِّي أَحَدًا بَعْدَهُ أَبَدًا وَأَحْزَنَنِي ذَلِكَ قَالَتْ فَنِمْتُ فَأُرِيتُ لِعُثْمَانَ عَيْنًا تَجْرِي فَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ ذَاكِ عَمَلُهُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepadaku [Kharijah bin Zaid Al Anshariy] bahwa [Ummu Al 'Alaa'], seorang wanita dari kalangan mereka yang telah berbai'at kepada Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya bahwa 'Utsman bin Mazh'un diberikan bagiannya ketika Kaum Anshar menawarkan tempat tinggal kepada Kaum Muhajirin\" Berkata Ummu Al 'Alaa': \"Lalu 'Utsman bin Mazh'un mendapatkan bagiannya untuk tinggal bersama kami. Namun kemudian dia menderita sakit yang membawa kepada kematianya. Lalu dia kami mandikan dan kafani dengan baju yang dikenakannnya. Tak lama kemudian Rasulullah shallallahu 'alaihi wasallam datang, lalu aku berkata kepada Beliau: \"Semoga rahmat Allah tercurah atasmu wahai Abu As-Sa'ib ('Utsman bin Mazh'un). Dan persaksianku atasmu bahwa Allah telah memuliakanmu\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Dari mana kamu tahu bahwa Allah telah memuliakannya?\" Aku jawab: \"Demi bapak ibuku untuk anda, aku tidak tahu wahai Rasulullah\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun 'Utsman, demi Allah, telah datang kepadanya Al Yaqin (kematian) dan aku berharap dia berada diatas kebaikan. Demi Allah, meskipun aku ini Rasulullah, aku sendiri tidak tahu apa yang akan dilakukan-Nya terhadapku\". Dia (Ummu Al 'Ala') berkata: \"Demi Allah, tidak seorangpun yang aku sucikan setelah peristiwa itu selamanya dan peristiwa ini membuatku bersedih\". Dia berkata: \"Kemudian aku tidur dan bermimpi, aku melihat ada air yang mengalir untuk 'Utsman. Kemudian aku temui Rasulullah shallallahu 'alaihi wasallam lalu aku kabarkan tentang mimpiku itu, maka Beliau bersabda: \"Itulah amal dia\"."},"2491":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ سَفَرًا أَقْرَعَ بَيْنَ نِسَائِهِ فَأَيَّتُهُنَّ خَرَجَ سَهْمُهَا خَرَجَ بِهَا مَعَهُ وَكَانَ يَقْسِمُ لِكُلِّ امْرَأَةٍ مِنْهُنَّ يَوْمَهَا وَلَيْلَتَهَا غَيْرَ أَنَّ سَوْدَةَ بِنْتَ زَمْعَةَ وَهَبَتْ يَوْمَهَا وَلَيْلَتَهَا لِعَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبْتَغِي بِذَلِكَ رِضَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy] berkata, telah menceritakan kepadaku ['Urwah] dari ['Aisyah radliallahu 'anha] berkata: \"Rasulullah shallallahu 'alaihi wasallam apabila hendak bepergian Beliau mengundi diantara isteri-isteri Beliau, siapa yang keluar namanya berarti dialah yang ikut bepergian bersama Beliau. Dan Beliau juga membagi sama antara siang dan malam saat giliran untuk setiap isteri-isteri Beliau kecuali Saudah binti Zam'ah yang dia telah memberikan hak giliran siang dan malamnya untuk 'Aisyah, isteri Nabi shallallahu 'alaihi wasallam demi mengharapkan ridho Rasulullah shallallahu 'alaihi wasallam."},"2492":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ يَعْلَمُ النَّاسُ مَا فِي النِّدَاءِ وَالصَّفِّ الْأَوَّلِ ثُمَّ لَمْ يَجِدُوا إِلَّا أَنْ يَسْتَهِمُوا عَلَيْهِ لَاسْتَهَمُوا وَلَوْ يَعْلَمُونَ مَا فِي التَّهْجِيرِ لَاسْتَبَقُوا إِلَيْهِ وَلَوْ يَعْلَمُونَ مَا فِي الْعَتَمَةِ وَالصُّبْحِ لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Sumayya, maula Abu Bakar] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya manusia mengetahui (kebaikan) apa yang terdapat pada panggilan shalat dan shaf pertama lalu mereka tidak dapat meraihnya melainkan dengan mengundi tentulah mereka akan mengundinya. Seandainya mereka mengetahui apa yang terdapat pada bersegera melaksanakan shalat tentulah mereka akan berlomba untuk melakukannya dan seandainya mereka mengetahui apa yang terdapat pada 'Atmah (shalat 'Isya') dan Shubuh tentulah mereka akan mendatanginya walaupun harus dengan merangkak\"."},"2493":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ أُنَاسًا مِنْ بَنِي عَمْرِو بْنِ عَوْفٍ كَانَ بَيْنَهُمْ شَيْءٌ فَخَرَجَ إِلَيْهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُنَاسٍ مِنْ أَصْحَابِهِ يُصْلِحُ بَيْنَهُمْ فَحَضَرَتْ الصَّلَاةُ وَلَمْ يَأْتِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ بِلَالٌ فَأَذَّنَ بِلَالٌ بِالصَّلَاةِ وَلَمْ يَأْتِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ إِلَى أَبِي بَكْرٍ فَقَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُبِسَ وَقَدْ حَضَرَتْ الصَّلَاةُ فَهَلْ لَكَ أَنْ تَؤُمَّ النَّاسَ فَقَالَ نَعَمْ إِنْ شِئْتَ فَأَقَامَ الصَّلَاةَ فَتَقَدَّمَ أَبُو بَكْرٍ ثُمَّ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي فِي الصُّفُوفِ حَتَّى قَامَ فِي الصَّفِّ الْأَوَّلِ فَأَخَذَ النَّاسُ بِالتَّصْفِيحِ حَتَّى أَكْثَرُوا وَكَانَ أَبُو بَكْرٍ لَا يَكَادُ يَلْتَفِتُ فِي الصَّلَاةِ فَالْتَفَتَ فَإِذَا هُوَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَاءَهُ فَأَشَارَ إِلَيْهِ بِيَدِهِ فَأَمَرَهُ أَنْ يُصَلِّيَ كَمَا هُوَ فَرَفَعَ أَبُو بَكْرٍ يَدَهُ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ رَجَعَ الْقَهْقَرَى وَرَاءَهُ حَتَّى دَخَلَ فِي الصَّفِّ وَتَقَدَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ فَلَمَّا فَرَغَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ يَا أَيُّهَا النَّاسُ إِذَا نَابَكُمْ شَيْءٌ فِي صَلَاتِكُمْ أَخَذْتُمْ بِالتَّصْفِيحِ إِنَّمَا التَّصْفِيحُ لِلنِّسَاءِ مَنْ نَابَهُ شَيْءٌ فِي صَلَاتِهِ فَلْيَقُلْ سُبْحَانَ اللَّهِ فَإِنَّهُ لَا يَسْمَعُهُ أَحَدٌ إِلَّا الْتَفَتَ يَا أَبَا بَكْرٍ مَا مَنَعَكَ حِينَ أَشَرْتُ إِلَيْكَ لَمْ تُصَلِّ بِالنَّاسِ فَقَالَ مَا كَانَ يَنْبَغِي لِابْنِ أَبِي قُحَافَةَ أَنْ يُصَلِّيَ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sa'id bin Abi Maryam] telah menceritakan kepada kami [Abu Ghossan] berkata, telah menceritakan kepadaku [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu]; Bahwa orang-orang di kalangan suku Bani 'Amru bin 'Auf bin Al Harits telah terjadi maslah diantara mereka, maka Nabi shallallahu 'alaihi wasallam bersama sebagian sahabat Beliau pergi mendatangi mereka untuk menyelesaikan masalah yang terjadi. Kemudian Bilal mengumandangkan adzan untuk shalat namun Nabi shallallahu 'alaihi wasallam belum juga datang. Akhirnya Bilal menemui Abu Bakar radliallahu 'anhu seraya berkata: \"Sesungguhnya Nabi shallallahu 'alaihi wasallam telah tertahan, sedangkan waktu shalat sudah masuk, apakah engkau bersedia memimpin orang-orang untuk shalat berjama'ah?. Dia (Abu Bakar) menjawab: \"Ya bersedia, jika kamu menghendaki\". Maka Bilal membacakan iqamat lalu Abu Bakar maju untuk memimpin shalat. Tak lama kemudian datang Nabi shallallahu 'alaihi wasallam berjalan di tengah-tengan shaf hingga berdiri di shaf pertama. Maka orang-orang memberi isyarat dengan bertepuk tangan hingga semakin ramai sedangkan Abu Bakar tidak bereaksi dalam shalatnya. (Ketika orang-orang yang memberi tepukan semakin banyak), Abu Bakar baru berbalik dan ternyata ada Nabi shallallahu 'alaihi wasallam di belakangnya, lalu Beliau memberi isyarat dengan tangan Beliau untuk memerintahkan Abu Bakar meneruskan shalat seperti semula. Maka Abu Bakar mengangkat kedua tangannya lalu memuji Allah dan mensucikan-Nya kemudian dia mundur hingga masuk di barisan, lalu Nabi shallallahu 'alaihi wasallam maju untuk memimpin shalat berjama'ah. Setelah selesai Beliau berbalik menghadap jama'ah lalu bersabda: \"Wahai sekalian manusia, jika kalian mendapatkan sesuatu dalam shalat, mengapa kalian melakukannya dengan bertepuk tangan?. Sesungguhnya bertepuk tangan itu adalah isyarat yang layak dilakukan kaum wanita. Maka siapa yang mendapatkan sesuatu yang keliru dalam shalat hendaklah mengucapkan subhaanallah, karena tidaklah seseorang mendengar ucapan subhaanallah kecuali dia harus memperhatikannya. Dan kamu wahai Abu Bakar, apa yang menghalangimu ketika aku sudah memberi isyarat kepadamu agar meneruskannya, mengapa kamu tidak melanjutkan shalat bersama orang banyak?. Maka Abu Bakar menjawab: \"Tidak patut bagi putra Abu Quhafah memimpin shalat di hadapan Nabi shallallahu 'alaihi wasallam\"."},"2494":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي أَنَّ أَنَسًا رَضِيَ اللَّهُ عَنْهُ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَتَيْتَ عَبْدَ اللَّهِ بْنَ أُبَيٍّ فَانْطَلَقَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَكِبَ حِمَارًا فَانْطَلَقَ الْمُسْلِمُونَ يَمْشُونَ مَعَهُ وَهِيَ أَرْضٌ سَبِخَةٌ فَلَمَّا أَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِلَيْكَ عَنِّي وَاللَّهِ لَقَدْ آذَانِي نَتْنُ حِمَارِكَ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ مِنْهُمْ وَاللَّهِ لَحِمَارُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْيَبُ رِيحًا مِنْكَ فَغَضِبَ لِعَبْدِ اللَّهِ رَجُلٌ مِنْ قَوْمِهِ فَشَتَمَهُ فَغَضِبَ لِكُلِّ وَاحِدٍ مِنْهُمَا أَصْحَابُهُ فَكَانَ بَيْنَهُمَا ضَرْبٌ بِالْجَرِيدِ وَالْأَيْدِي وَالنِّعَالِ فَبَلَغَنَا أَنَّهَا أُنْزِلَتْ{ وَإِنْ طَائِفَتَانِ مِنْ الْمُؤْمِنِينَ اقْتَتَلُوا فَأَصْلِحُوا بَيْنَهُمَا }","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mu'tamir] berkata, aku mendengar [bapakku] bahwa [Anas radliallahu 'anhu] berkata: \"Dikatakan kepada Nabi shallallahu 'alaihi wasallam \"Sebaiknya Baginda menemui 'Abdullah bin Ubay.\" Maka Nabi shallallahu 'alaihi wasallam menemuinya dengan menunggang keledai sedangkan Kaum Muslimin berangkat bersama Beliau dengan berjalan kaki melintasi tanah yang tandus. Ketika Nabi shallallahu 'alaihi wasallam menemuinya, ia berkata: \"Menjauhlah dariku, demi Allah, bau keledaimu menggangguku\". Maka berkatalah seseorang dari kaum Anshar diantara mereka: \"Demi Allah, sungguh keledai Rasulullah shallallahu 'alaihi wasallam lebih baik daripada kamu\". Maka seseorang dari kaumnya marah demi membela 'Abdullah bin Ubay dan ia mencelanya sehingga marahlah setiap orang dari masing-masing kelompok. Saat itu kedua kelompok saling memukul dengan pelepah kurma, tangan, dan sandal. Kemudian sampai kepada kami bahwa telah turun ayat QS. Al Hujurat: 10 yang artinya (\"jika dua kelompok dari kaum muslimin berperang maka damaikanlah keduanya\")."},"2495":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّ أُمَّهُ أُمَّ كُلْثُومٍ بِنْتَ عُقْبَةَ أَخْبَرَتْهُ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ الْكَذَّابُ الَّذِي يُصْلِحُ بَيْنَ النَّاسِ فَيَنْمِي خَيْرًا أَوْ يَقُولُ خَيْرًا","id":"Telah menceritakan kepada kami ['Abdul 'aziz bin 'Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] bahwa [Humaid bin 'Abdurrahman] mengabarkan kepadanya bahwa [ibunya, Ummu Kultsum binti 'Uqbah] mengabarkan kepadanya bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah disebut pendusta orang yang menyelesaikan perselisihan diantara manusia lalu dia menyampaikan hal hal yang baik (dari satu pihak yang bertikai) atau dia berkata, hal hal yang baik\"."},"2496":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ وَإِسْحَاقُ بْنُ مُحَمَّدٍ الْفَرْوِيُّ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ أَهْلَ قُبَاءٍ اقْتَتَلُوا حَتَّى تَرَامَوْا بِالْحِجَارَةِ فَأُخْبِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ فَقَالَ اذْهَبُوا بِنَا نُصْلِحُ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah] telah menceritakan kepada kami ['Abdul 'aziz bin 'Abdullah Al Uwaisiy] dan [Ishaq bin Muhammad Al Farwiy] keduanya berkata, telah menceritakan kepadaku [Muhammad bin Ja'far] dari [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] bahwa penduduk Quba' telah bertikai hingga saling melempar dengan batu, lalu Rasulullah shallallahu 'alaihi wasallam dikabarkan tentang peristiwa itu, maka Beliau bersabda: \"Mari kalian pergi bersama kami untuk mendamaikan mereka\"."},"2497":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ هُوَ الرَّجُلُ يَرَى مِنْ امْرَأَتِهِ مَا لَا يُعْجِبُهُ كِبَرًا أَوْ غَيْرَهُ فَيُرِيدُ فِرَاقَهَا فَتَقُولُ أَمْسِكْنِي وَاقْسِمْ لِي مَا شِئْتَ قَالَتْ فَلَا بَأْسَ إِذَا تَرَاضَيَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'ad] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa ayat yang berbunyi: QS An-Nisaa: 128): (\"Apabila seorang isteri takut suaminya akan berbuat nusyuz (tidak mau menggaulinya) atau berlaku kasar terhadapnya\"), dia ('Aisyah radliallahu 'anha) berkata: \"Itu adalah seorang suami yang melihat pada isterinya apa-apa yang tidak menyenangkannya berupa pelanggaran dosa besar atau lainnya lalu dia berniat menceraikan isterinya lalu isterinya itu berkata: \"Pertahankanlah aku dan bersumpahlah kepadaku terserah apa saja yang kamu kehendaki\". 'Aisyah radliallahu 'anha berkata: \"Maka tidak berdosa bila keduanya saling ridho\"."},"2498":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ رَضِيَ اللَّهُ عَنْهُمَا قَالَاجَاءَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَامَ خَصْمُهُ فَقَالَ صَدَقَ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَالَ الْأَعْرَابِيُّ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا فَزَنَى بِامْرَأَتِهِ فَقَالُوا لِي عَلَى ابْنِكَ الرَّجْمُ فَفَدَيْتُ ابْنِي مِنْهُ بِمِائَةٍ مِنْ الْغَنَمِ وَوَلِيدَةٍ ثُمَّ سَأَلْتُ أَهْلَ الْعِلْمِ فَقَالُوا إِنَّمَا عَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ أَمَّا الْوَلِيدَةُ وَالْغَنَمُ فَرَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَأَمَّا أَنْتَ يَا أُنَيْسُ لِرَجُلٍ فَاغْدُ عَلَى امْرَأَةِ هَذَا فَارْجُمْهَا فَغَدَا عَلَيْهَا أُنَيْسٌ فَرَجَمَهَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abi Dza'bi] telah menceritakan kepada kami [Az Zuhriy] dari ['Ubaidullah bin 'Abdullah] dari [Abu Hurairah radliallahu 'anhu] dan [Zaid bin Khalid Al Juhaniy radliallahu 'anhuma], keduanya berkata; Datang seorang Arab Baduy lalu berkata: \"Wahai Rasulullah, putuskan perkara diantara kami dengan Kitab Allah. Lalu lawan sengketanya berdiri seraya berkata: \"Dia benar, putuskan perkara diantara kami dengan Kitab Allah\". Berkata Arab Baduy itu: \"Sesunguhnya anakku adalah seorang yang bekerja pada orang ini lalu dia berzina dengan isterinya. Kemudian mereka berkata kepadaku: \"Anakmu wajib dirajam\". Lalu aku tebus anakku dengan seratus ekor kambing dan seorang hamba sahaya, kemudian aku bertanya kepada ahli ilmu maka mereka berkata: \"Sesunguhnya atas anakmu cukup dicambuk seratus kali dan diasingkan selama setahun\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku putuskan buat kalian berdua dengan menggunakan Kitab Allah. Adapun hamba sahaya dan kambing seharusnya dikembalikan kepadamu dan untuk anakmu dikenakan hukum cambuk sebanyak seratus kali dan diasingkan selama setahun. Adapun kamu, wahai Unais, --yaitu seorang sahabat bani Aslam-- datangilah si wanita dan rajamlah dia! Maka Unais berangkat dan merajam si wanita."},"2499":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحْدَثَ فِي أَمْرِنَا هَذَا مَا لَيْسَ فِيهِ فَهُوَ رَدٌّرَوَاهُ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الْمَخْرَمِيُّ وَعَبْدُ الْوَاحِدِ بْنُ أَبِي عَوْنٍ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [bapaknya] dari [Al Qasim bin Muhammad] dari ['Aisyah radliallahu 'anha] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang membuat perkara baru dalam urusan kami ini yang tidak ada perintahnya maka perkara itu tertolak\". Diriwayatkan pula oleh ['Abdullah bin Ja'far Al Makhramiy] dan ['Abdul Wahid bin Abu 'Aun] dari [Sa'ad bin Ibrahim]."},"2500":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا صَالَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهْلَ الْحُدَيْبِيَةِ كَتَبَ عَلِيُّ بْنُ أَبِي طَالِبٍ بَيْنَهُمْ كِتَابًا فَكَتَبَ مُحَمَّدٌ رَسُولُ اللَّهِ فَقَالَ الْمُشْرِكُونَ لَا تَكْتُبْ مُحَمَّدٌ رَسُولُ اللَّهِ لَوْ كُنْتَ رَسُولًا لَمْ نُقَاتِلْكَ فَقَالَ لِعَلِيٍّ امْحُهُ فَقَالَ عَلِيٌّ مَا أَنَا بِالَّذِي أَمْحَاهُ فَمَحَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ وَصَالَحَهُمْ عَلَى أَنْ يَدْخُلَ هُوَ وَأَصْحَابُهُ ثَلَاثَةَ أَيَّامٍ وَلَا يَدْخُلُوهَا إِلَّا بِجُلُبَّانِ السِّلَاحِ فَسَأَلُوهُ مَا جُلُبَّانُ السِّلَاحِ فَقَالَ الْقِرَابُ بِمَا فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata, aku mendengar [Al Bara' bin 'azib radliallahu 'anhuma] berkata; Ketika Rasulullah shallallahu 'alaihi wasallam mengadakan perjanjian damai dengan penduduk Hudaibiyah, 'Ali bin Abu Thalib adalah juru tulis (sekretaris) yang menulis surat perjanjian yang dibuat diantara mereka, dalam ikrar itu dia menulis \"Muhammad Rasulullah\", maka kaum Musyrikin berkata: \"Jangan kamu tulis \"Muhammad Rasulullah\", sebab seandainya kamu seorang rasul tentu kami tidak akan memerangimu\". Maka Beliau berkata, kepada 'Ali: \"Hapuslah\". Maka 'Ali berkata: \"Aku tidak mau menjadi orang yang menghapusnya\". Maka Rasulullah shallallahu 'alaihi wasallam menghapusnya dengan tangan Beliau. Lalu Beliau membuat perjanjian dengan mereka, yang isinya Beliau dan para sahabat boleh memasuki kota selama tiga hari dan mereka tidak memasukinya kecuali dalam keadaan pedang-pedang mereka ditutupi (dalam sarung) \". Mereka bertanya kepada Beliau: Apa maksudnya menutupi senjata?\" Maka Beliau menjawab: \"Dimasukkan kedalam sarungnya\"."}};
